// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1 (2 pieces)
    // Cut s into s_1 and s_2. Rearrange to s_2 + s_1.
    // s_1 = s.substr(0, i), s_2 = s.substr(i, n-i)
    // New string is s.substr(i) + s.substr(0, i)
    for (int i = 1; i < n; ++i) { // i is the length of the first part, s.substr(0, i)
        std::string s_new = s.substr(i) + s.substr(0, i);
        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (3 pieces)
    // If k=1 didn't work, we need to check if k=2 is always possible or if it can be impossible.
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any rearrangement of substrings
    // will result in the same string "aaaa". In this case, it's impossible to get s' != s.
    // We can check this by counting distinct characters.

    // Count distinct characters
    std::vector<bool> seen(26, false);
    int distinct_chars = 0;
    for (char c : s) {
        if (!seen[c - 'a']) {
            seen[c - 'a'] = true;
            distinct_chars++;
        }
    }

    if (distinct_chars <= 1) { // All characters are the same, e.g., "aaaa"
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If n is odd and all characters except the middle one are the same, e.g., "aaabaaa"
    // This is covered by the distinct_chars check. If distinct_chars is 1, it's impossible.
    // If distinct_chars is > 1, then there are at least two different characters.
    // For example, "nolon". Distinct chars: n, o, l.
    // For example, "otto". Distinct chars: o, t.

    // Consider the structure of a palindrome s.
    // s[0] == s[n-1], s[1] == s[n-2], etc.
    // If s is not composed of all identical characters, then there must be at least one pair
    // s[i] != s[i+1] for some i < n/2.
    // Or, if n is odd, s[i] != s[n/2] for some i.
    //
    // If we can't find a solution with k=1, it means that for any cyclic shift s',
    // either s' == s or s' is not a palindrome.
    //
    // Let's consider the first half of the string s.substr(0, n/2).
    // If this substring is itself a palindrome, e.g., "abacaba", first half "aba".
    // Or "kinnikkinnik", first half "kinnik".
    // If s.substr(0, n/2) consists of all identical characters, e.g., "aaaaa", first half "aa".
    // If s.substr(0, n/2) is not a palindrome, e.g., "abccba", first half "abc".
    //
    // The problem states that if k=1 doesn't work, and it's not the "all same characters" case,
    // then k=2 is always the answer.
    // This is a known property for palindromes. If a palindrome `s` is not composed of
    // identical characters, and no cyclic shift `s'` (formed by 1 cut) is a different palindrome,
    // then it's always possible to achieve a different palindrome with 2 cuts.
    //
    // Example: "nolon"
    // n=5.
    // k=1:
    // "olon" + "n" = "olonn" (not palindrome)
    // "lon" + "no" = "lonno" (not palindrome)
    // "on" + "nol" = "onnol" (not palindrome)
    // "n" + "nolo" = "nnolo" (not palindrome)
    // So k=1 doesn't work.
    // Distinct chars: n, o, l (3 distinct). Not all same.
    // Output should be 2.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
