#include <numeric> // For std::abs in C++23, though cmath's std::abs is fine for long long

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C's stdio and disables flushing cout before cin.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;

        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }

        long long diff = std::abs(a - b);
        long long presses = 0;

        // Use as many 5s as possible
        presses += diff / 5;
        diff %= 5;

        // Handle the remaining difference (0, 1, 2, 3, 4)
        if (diff == 1 || diff == 2) {
            presses += 1;
        } else if (diff == 3 || diff == 4) {
            presses += 2;
        }
        // If diff is 0, no additional presses are needed.

        std::cout << presses << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    for (int p_idx = 0; p_idx < m; ++p_idx) {
        // Find the first head that can potentially cover p[p_idx]
        // A head h[head_idx] can cover p[p_idx] if h[head_idx] - T <= p[p_idx]
        // Since h and p are sorted, we can advance head_idx.
        while (head_idx < n && h[head_idx] + T < p[p_idx]) {
            head_idx++;
        }

        if (head_idx == n) {
            // No head can reach p[p_idx] or any subsequent p_j
            return false;
        }

        // Now, h[head_idx] is the first head such that h[head_idx] + T >= p[p_idx].
        // We need to find the rightmost track this head (and potentially subsequent heads) can cover.
        // This is the maximum of h[k] + T for k >= head_idx.
        // However, we are trying to cover p[p_idx] and subsequent tracks.
        // The current head h[head_idx] can cover tracks up to h[head_idx] + T.
        // We need to cover p[p_idx].
        // If h[head_idx] - T > p[p_idx], then even this head cannot cover p[p_idx].
        // This means no head from head_idx onwards can cover p[p_idx] because h is sorted.
        // So, we must have h[head_idx] - T <= p[p_idx].
        if (h[head_idx] - T > p[p_idx]) {
            return false;
        }

        // If we reach here, h[head_idx] can cover p[p_idx].
        // We use this head (and potentially subsequent heads) to cover as many tracks as possible.
        // The current head h[head_idx] can cover tracks up to h[head_idx] + T.
        // We need to find the maximum reach among heads starting from head_idx.
        // This is not quite right. We need to cover a contiguous block of p_j's.
        // Let's re-evaluate the greedy strategy.

        // If we use head `head_idx` to cover `p[p_idx]`, it can cover up to `h[head_idx] + T`.
        // We want to cover `p[p_idx]` and as many subsequent `p_j` as possible using this head.
        // The range covered by `h[head_idx]` is `[h[head_idx] - T, h[head_idx] + T]`.
        // We need to cover `p[p_idx]`.
        // If `p[p_idx]` is covered by `h[head_idx]`, then `h[head_idx] - T <= p[p_idx] <= h[head_idx] + T`.
        // The `while` loop above ensures `h[head_idx] + T >= p[p_idx]`.
        // We still need to check `h[head_idx] - T <= p[p_idx]`.
        // If this condition is not met, then `h[head_idx]` cannot cover `p[p_idx]`.
        // Since `h` is sorted, any `h[k]` for `k > head_idx` will be even further to the right,
        // so `h[k] - T` will be even larger, making it impossible for them to cover `p[p_idx]`.
        // So, if `h[head_idx] - T > p[p_idx]`, it's impossible.
        // This check is already done above.

        // Now we know `h[head_idx]` can cover `p[p_idx]`.
        // We want to cover `p[p_idx]` and subsequent tracks `p[p_idx+1], p[p_idx+2], ...`
        // using `h[head_idx]` and subsequent heads `h[head_idx+1], h[head_idx+2], ...`.
        // The key insight for the greedy approach is:
        // If we are at `p[p_idx]`, we must use some head `h_k` to cover it.
        // To maximize the number of `p_j` covered by `h_k` and subsequent heads,
        // we should pick the `h_k` that can reach furthest to the right, while still covering `p[p_idx]`.
        // This means we should pick the `h_k` such that `h_k - T <= p[p_idx]` and `h_k + T` is maximized.
        // Since `h` is sorted, this means we should pick the largest `h_k` that satisfies `h_k - T <= p[p_idx]`.
        // Let's find this `h_k`.

        // `head_idx` is the first head such that `h[head_idx] + T >= p[p_idx]`.
        // We need to find the rightmost head `h_k` (where `k >= head_idx`) such that `h_k - T <= p[p_idx]`.
        // Let's call this `best_head_idx`.
        int current_best_head_idx = head_idx;
        while (current_best_head_idx + 1 < n && h[current_best_head_idx + 1] - T <= p[p_idx]) {
            current_best_head_idx++;
        }
        // Now `h[current_best_head_idx]` is the rightmost head that can cover `p[p_idx]`
        // (among heads `h[head_idx]` to `h[n-1]`).
        // This head can cover tracks up to `h[current_best_head_idx] + T`.
        long long max_reach = h[current_best_head_idx] + T;

        // Advance `p_idx` past all tracks covered by this head.
        while (p_idx < m && p[p_idx] <= max_reach) {
            p_idx++;
        }
        p_idx--; // Decrement because the outer loop will increment it.

        // Move to the next available head for the next uncovered track.
        // The heads from `head_idx` to `current_best_head_idx` have been "used" in some sense.
        // We should start looking for the next head from `current_best_head_idx + 1`.
        head_idx = current_best_head_idx + 1;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible distance is 10^10. So max time could be 10^10.
    // A safe upper bound for T is max(p_i) - min(h_i) or max(h_i) - min(p_i)
    // or simply 2 * 10^10 (max coordinate difference).
    long long high = 20000000000LL; // 2 * 10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // as many times as possible without exceeding k.
        // The number of times is (k - a[i]) / min_val.
        // Integer division automatically handles the floor.
        operations += (k - a[i]) / min_val;
    }

    std::cout << operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

