#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItemsAsc(const Item& a, const Item& b) {
    return a.value < b.value;
}

bool compareItemsDesc(const Item& a, const Item& b) {
    return a.value > b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a_items(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a_items[i].value;
            a_items[i].original_index = i;
        }
        std::vector<Item> b_items(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> b_items[i].value;
            b_items[i].original_index = i;
        }

        std::sort(a_items.begin(), a_items.end(), compareItemsAsc);
        std::sort(b_items.begin(), b_items.end(), compareItemsDesc);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[i] = a_items[i].value;
            y[i] = b_items[i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int max_a1 = a[0]; // Initial haybales in pile 1

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        int cost_per_haybale = i; // Cost to move one haybale from pile (i+1) to pile 1
                                  // (0-indexed pile i corresponds to 1-indexed pile i+1)
                                  // Distance is i, so cost is i days.

        if (d >= cost_per_haybale) {
            // Calculate how many haybales can be moved from this pile
            int haybales_to_move = std::min(a[i], d / cost_per_haybale);

            max_a1 += haybales_to_move;
            d -= haybales_to_move * cost_per_haybale;
        } else {
            // Not enough days to move even one haybale from this pile
            // Since we iterate from closest piles, we won't be able to move
            // haybales from further piles either.
            break; 
        }
    }
    std::cout << max_a1 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

