#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // For any permutation p, its reverse p_rev will have the same set of adjacent sums.
    // p = [p_1, p_2, ..., p_{n-1}, p_n]
    // Adjacent sums: [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n]
    // p_rev = [p_n, p_{n-1}, ..., p_2, p_1]
    // Adjacent sums for p_rev: [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1]
    // These two sets of sums are identical, just in reverse order.
    // Sorting them will result in the same fingerprint.
    // The only case where p_rev == p is if p is a palindrome.
    // A permutation of 1 to n can only be a palindrome if n=1 (not allowed, n>=2)
    // or if n=2 and p=[1,2] or p=[2,1].
    // For n=2, p=[1,2], p_rev=[2,1]. p_rev != p.
    // For n=2, p=[2,1], p_rev=[1,2]. p_rev != p.
    // For n > 2, a permutation of 1 to n cannot be a palindrome.
    // For example, if n=3, p=[1,2,3], p_rev=[3,2,1].
    // If p is a palindrome, p_i = p_{n-i+1}.
    // For n > 2, p_1 = 1 and p_n = n (or vice versa) would be required for a palindrome.
    // But then p_2 and p_{n-1} would need to be equal, which is impossible for distinct elements.
    // E.g., if p_1=1, p_n=1, not a permutation.
    // If p_1=1, p_n=X, p_2=Y, p_{n-1}=Y. This is not possible for distinct elements.
    // So, for n >= 2, reversing the permutation always yields a different permutation.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

