#include <iostream>
#include <string>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        if (n == 1) {
            std::cout << -1 << "\n";
        } else {
            // For n >= 2, we can construct a number.
            // A simple construction is to use '2' as the first digit,
            // and '3' for all subsequent digits.
            // This forms a number like 233...3.
            // Let's check divisibility:
            // The digits are 2 and 3.
            // A number consisting of 2 followed by (n-1) 3s.
            // Example: n=2 -> 23. 23%2 != 0, 23%3 != 0.
            // Example: n=3 -> 233. 233%2 != 0, 233%3 != 0 (sum of digits 8).
            // Example: n=4 -> 2333. 2333%2 != 0, 2333%3 != 0 (sum of digits 11).
            // In general, 23...3 (n digits) is an odd number, so not divisible by 2.
            // The sum of digits is 2 + (n-1)*3.
            // If n=2, sum=2+3=5. Not div by 3.
            // If n=3, sum=2+6=8. Not div by 3.
            // If n=4, sum=2+9=11. Not div by 3.
            // If n=5, sum=2+12=14. Not div by 3.
            // The sum of digits 2 + 3*(n-1) is never divisible by 3.
            // 2 + 3*(n-1) = 2 + 3n - 3 = 3n - 1.
            // 3n - 1 is never divisible by 3, because 3n is divisible by 3, so 3n-1 leaves a remainder of 2 when divided by 3.
            // So, this construction works for all n >= 2.
            std::cout << '2';
            for (int i = 0; i < n - 1; ++i) {
                std::cout << '3';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

