    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last price

    // Iterate from right to left, excluding the last element
    // The last element can never be a bad price as there are no later days.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            min_suffix_price = a[i]; // Update minimum suffix price if current price is smaller
        }
    }

    std::cout << bad_prices_count << std::endl;
}

