int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // This is because if p[i] were n-1, then there would be no p[k] such that min(p[i], p[k]) = n-1
        // and p[k] > n-1. But if p[i] = n-1, then max_val_in_row would be n-1.
        // If p[i] = n, then max_val_in_row would be n-1 (if there is some p[k]=n-1).
        // The only way max_val_in_row can be n-1 is if p[i] is n.
        // If p[i] is not n, then p[i] <= n-1.
        // In this case, max_val_in_row = max_{j!=i} min(p[i], p[j]) <= p[i] <= n-1.
        // So if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] = max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate differences up to k

    // Generate k distinct differences: 1, 2, ..., k
    // We use numbers from 1 to k+1 to achieve this.
    // The pattern is: 1, k+1, 2, k, 3, k-1, ...
    // This generates differences: k, k-1, k-2, ..., 1
    // For example, if k=4, numbers are 1,2,3,4,5.
    // Sequence: 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1
    // This generates all differences from 1 to k.

    int current_idx = 0;
    bool use_left = true;
    while (left <= right) {
        if (use_left) {
            p[current_idx++] = left++;
        } else {
            p[current_idx++] = right--;
        }
        use_left = !use_left;
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // We append them in increasing order to ensure the differences are 1.
    // This does not introduce new distinct differences if k >= 1.
    // If k=1, the first part is 1, 2. Differences: |1-2|=1.
    // Then append 3, 4, ..., n. Differences: |2-3|=1, |3-4|=1, etc.
    // The set of differences remains {1}.
    for (int i = k + 2; i <= n; ++i) {
        p[current_idx++] = i;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
