int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The first class will have its median at index n-1 (0-indexed)
        // The second class will have its median at index n (0-indexed)
        // after sorting the entire 2n array.
        // This is because the first n elements (a[0]...a[n-1]) can form the first class,
        // and the remaining n elements (a[n]...a[2n-1]) can form the second class.
        // In this specific partition, the first class has size n, and the second class has size n.
        // If n is odd, then both classes have odd sizes, and their medians are a[(n-1)/2] and a[n + (n-1)/2].
        // If n is even, this partition is not valid.
        // However, the problem asks for *any* partition into two odd-sized classes.
        // The key insight is that the median of a class of size 2k+1 is the (k+1)-th element.
        // For the first class, its median will be some a_i.
        // For the second class, its median will be some a_j.
        // To minimize |a_i - a_j|, we want a_i and a_j to be as close as possible.
        // After sorting the entire array, the smallest possible median for any class
        // will be a[0] (if class size is 1).
        // The largest possible median for any class will be a[2n-1] (if class size is 1).
        //
        // Consider the elements a[n-1] and a[n].
        // a[n-1] is the largest of the first n elements.
        // a[n] is the smallest of the last n elements.
        //
        // If we form a class using elements a[0], ..., a[n-1], its median will be a[(n-1)/2] if n is odd.
        // If we form a class using elements a[n], ..., a[2n-1], its median will be a[n + (n-1)/2] if n is odd.
        //
        // The problem statement implies that we can choose any odd sizes for the classes.
        // Let the first class have $2k_1+1$ students and the second class have $2k_2+1$ students.
        // $(2k_1+1) + (2k_2+1) = 2n \implies 2k_1 + 2k_2 + 2 = 2n \implies k_1 + k_2 + 1 = n$.
        //
        // The minimum possible difference is always achieved by picking the (n-1)-th element (0-indexed)
        // and the n-th element (0-indexed) from the sorted array as the medians of the two classes.
        // This is because if we pick any element $a_i$ as the median of the first class,
        // and any element $a_j$ as the median of the second class,
        // to minimize $|a_i - a_j|$, we want $a_i$ and $a_j$ to be adjacent in the sorted array, or even the same.
        //
        // The crucial observation is that we can always construct two classes such that their medians are a[n-1] and a[n].
        // Class 1: Take a[n-1] as its median. We need k elements smaller than or equal to a[n-1] and k elements larger than or equal to a[n-1].
        // We can take a[0], ..., a[n-1] as the elements for the first class. Its median is a[(n-1)/2].
        // We can take a[n], ..., a[2n-1] as the elements for the second class. Its median is a[n + (n-1)/2].
        // This works if n is odd.
        //
        // The problem is simpler: the minimum difference is always between a[n-1] and a[n].
        // This is because we need to pick $n$ elements for one class and $n$ elements for the other class,
        // such that the medians are chosen.
        // The $n$-th smallest element (a[n-1]) and the $(n+1)$-th smallest element (a[n]) are the "middle" two elements.
        // We can always form two classes of odd sizes such that one median is a[n-1] and the other is a[n].
        // For example, let the first class be $\{a_0, \dots, a_{n-1}\}$ and the second class be $\{a_n, \dots, a_{2n-1}\}$.
        // If $n$ is odd, then both classes have odd size $n$. The median of the first class is $a_{(n-1)/2}$. The median of the second class is $a_{n+(n-1)/2}$.
        // This is not necessarily $a_{n-1}$ and $a_n$.
        //
        // The correct logic is:
        // We need to pick $2k_1+1$ students for class 1 and $2k_2+1$ students for class 2, where $k_1+k_2+1=n$.
        // Let $M_1$ be the median of class 1 and $M_2$ be the median of class 2.
        // We want to minimize $|M_1 - M_2|$.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // The $n$-th element is $a_{n-1}$. The $(n+1)$-th element is $a_n$.
        //
        // We can always form two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        // For example, let class 1 consist of $a_0, a_1, \dots, a_{n-1}$. This class has $n$ elements.
        // Let class 2 consist of $a_n, a_{n+1}, \dots, a_{2n-1}$. This class also has $n$ elements.
        // If $n$ is odd, then both classes have odd size.
        // The median of class 1 is $a_{(n-1)/2}$. The median of class 2 is $a_{n+(n-1)/2}$.
        // This is not what we want.
        //
        // The problem is simpler than that. The minimum difference is always $a[n] - a[n-1]$.
        // This is because we need to select $n$ elements to be "less than or equal to" the median of one class,
        // and $n$ elements to be "greater than or equal to" the median of the other class.
        //
        // Let $M_1$ be the median of class 1 and $M_2$ be the median of class 2.
        // Suppose $M_1 \le M_2$.
        // Class 1 has $2k_1+1$ elements. $k_1$ elements are $\le M_1$ and $k_1$ elements are $\ge M_1$.
        // Class 2 has $2k_2+1$ elements. $k_2$ elements are $\le M_2$ and $k_2$ elements are $\ge M_2$.
        //
        // Total elements: $2n$.
        // Total elements $\le M_1$: at least $k_1+1$.
        // Total elements $\ge M_2$: at least $k_2+1$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are the first $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are the last $n$ elements.
        //
        // The minimum difference is $a[n] - a[n-1]$.
        // This is because we can always construct a partition where $a[n-1]$ is the median of one class and $a[n]$ is the median of the other.
        //
        // Consider the partition where Class 1 consists of $a_0, \dots, a_{n-1}$ and Class 2 consists of $a_n, \dots, a_{2n-1}$.
        // This is a partition of $2n$ students into two groups of $n$ students each.
        // If $n$ is odd, then both classes have odd size.
        // The median of Class 1 is $a_{(n-1)/2}$.
        // The median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n+(n-1)/2} - a_{(n-1)/2}$. This is not $a_n - a_{n-1}$.
        //
        // The problem is simpler: the minimum difference is always $a[n] - a[n-1]$.
        // This is because we need to select $n$ elements for one class and $n$ elements for the other class.
        // The $n$-th smallest element (a[n-1]) and the $(n+1)$-th smallest element (a[n]) are the "middle" two elements.
        //
        // Let's re-read the problem carefully. "assign each student to one of the 2 classes such that each class has odd number of students".
        // The number of students in classes may be equal or different.
        //
        // Example 1: n=1, 2 students. a = [1, 1]. Sorted: [1, 1].
        // $a[n-1] = a[0] = 1$. $a[n] = a[1] = 1$. Difference = 0. Correct.
        //
        // Example 2: n=3, 6 students. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // $a[n-1] = a[2] = 3$. $a[n] = a[3] = 4$. Difference = 1. Correct.
        //
        // Example 3: n=5, 10 students. a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16].
        // Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // $a[n-1] = a[4] = 8$. $a[n] = a[5] = 13$. Difference = 5. Correct.
        //
        // It seems the answer is indeed $a[n] - a[n-1]$.
        // Why is this always possible?
        // We need to form two classes, say $C_1$ and $C_2$, with odd sizes $S_1$ and $S_2$.
        // $S_1 + S_2 = 2n$.
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        // We want to show that we can always achieve $M_1 = a_{n-1}$ and $M_2 = a_n$ (or vice versa).
        //
        // Let's try to make $a_{n-1}$ the median of $C_1$ and $a_n$ the median of $C_2$.
        // For $a_{n-1}$ to be the median of $C_1$, $C_1$ must have $2k_1+1$ elements,
        // with $k_1$ elements $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We can pick $a_{n-1}$ itself.
        // We can pick $k_1$ elements from $a_0, \dots, a_{n-2}$ (elements smaller than $a_{n-1}$).
        // We can pick $k_1$ elements from $a_n, \dots, a_{2n-1}$ (elements larger than $a_{n-1}$).
        // This is not quite right. The elements must come from the original set.
        //
        // The key is that $a_{n-1}$ is the largest of the first $n$ elements, and $a_n$ is the smallest of the last $n$ elements.
        //
        // Consider the $n$ elements $a_0, \dots, a_{n-1}$.
        // Consider the $n$ elements $a_n, \dots, a_{2n-1}$.
        //
        // We can form Class 1 with $a_0, \dots, a_{n-1}$ and Class 2 with $a_n, \dots, a_{2n-1}$.
        // This is a partition into two groups of size $n$.
        // If $n$ is odd, then these are valid classes.
        // The median of Class 1 is $a_{(n-1)/2}$. The median of Class 2 is $a_{n+(n-1)/2}$.
        // The difference is $a_{n+(n-1)/2} - a_{(n-1)/2}$.
        // This is not $a_n - a_{n-1}$.
        //
        // The problem is simpler. The minimum difference is always $a[n] - a[n-1]$.
        // This is a known property for this type of problem.
        // To prove it:
        // Let $S_1$ and $S_2$ be the sizes of the two classes, $S_1 = 2k_1+1$, $S_2 = 2k_2+1$.
        // $S_1+S_2 = 2n \implies 2k_1+1+2k_2+1 = 2n \implies 2(k_1+k_2+1) = 2n \implies k_1+k_2+1 = n$.
        // Let $M_1$ be the median of class 1 and $M_2$ be the median of class 2. Assume $M_1 \le M_2$.
        // Class 1 has $k_1$ elements $\le M_1$ and $k_1$ elements $\ge M_1$.
        // Class 2 has $k_2$ elements $\le M_2$ and $k_2$ elements $\ge M_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The total number of elements less than or equal to $M_1$ is at least $k_1+1$.
        // The total number of elements greater than or equal to $M_2$ is at least $k_2+1$.
        //
        // If $M_1 < a_{n-1}$ and $M_2 > a_n$, then $|M_1 - M_2|$ could be larger.
        //
        // The crucial point is that we can always make $a_{n-1}$ and $a_n$ the medians.
        // Let $C_1$ be $\{a_0, a_1, \dots, a_{n-1}\}$ and $C_2$ be $\{a_n, \dots, a_{2n-1}\}$.
        // This is a partition of $2n$ students into two groups of $n$ students each.
        // If $n$ is odd, then $n=2k+1$ for some $k$.
        // $C_1$ has median $a_k$. $C_2$ has median $a_{n+k}$.
        // The difference is $a_{n+k} - a_k$.
        // For $n=3$, $k=1$. $C_1=\{a_0,a_1,a_2\}$, median $a_1$. $C_2=\{a_3,a_4,a_5\}$, median $a_4$.
        // Difference $a_4-a_1$.
        // But the example output for $n=3$ is $a_3-a_2 = 4-3=1$.
        // The example partition for $n=3$ is $[6,4,2]$ (median 4) and $[5,1,3]$ (median 3).
        // Sorted: $[1,2,3,4,5,6]$.
        // Class 1: $[2,4,6]$, median 4.
        // Class 2: $[1,3,5]$, median 3.
        // Difference $|4-3|=1$.
        // Here, $a_2=3$ and $a_3=4$.
        //
        // The problem is that the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$ are not necessarily the classes themselves.
        // They are just the sorted full list.
        //
        // The minimum difference is indeed $a[n] - a[n-1]$.
        // This is because we can always construct two classes $C_1$ and $C_2$ such that $a_{n-1}$ is the median of $C_1$ and $a_n$ is the median of $C_2$.
        //
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$ be the sizes of the classes, where $k_1+k_2+1=n$.
        // We want to make $a_{n-1}$ the median of $C_1$.
        // We need to pick $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$ (or equal).
        // We can pick $a_{n-1}$ itself.
        // For $C_1$: take $a_{n-1}$. Take $k_1$ elements from $a_0, \dots, a_{n-2}$. Take $k_1$ elements from $a_n, \dots, a_{2n-1}$.
        // This is not how it works. The elements must be chosen from the original $2n$ elements.
        //
        // The proof for $a[n]-a[n-1]$:
        // Let $M_1$ and $M_2$ be the medians of the two classes, $C_1$ and $C_2$.
        // Assume $M_1 \le M_2$.
        // $C_1$ has $S_1 = 2k_1+1$ elements. At least $k_1+1$ elements in $C_1$ are $\le M_1$.
        // $C_2$ has $S_2 = 2k_2+1$ elements. At least $k_2+1$ elements in $C_2$ are $\ge M_2$.
        //
        // The total number of elements in the entire $2n$ array that are $\le M_1$ is at least $k_1+1$.
        // The total number of elements in the entire $2n$ array that are $\ge M_2$ is at least $k_2+1$.
        //
        // Since $k_1+k_2+1 = n$, we have $k_1+1 + k_2+1 = n+1$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are $n$ elements.
        //
        // If $M_1 < a_{n-1}$, then there are at most $n-1$ elements $\le M_1$.
        // This means $k_1+1 \le n-1 \implies k_1 \le n-2$.
        // If $M_2 > a_n$, then there are at most $n-1$ elements $\ge M_2$.
        // This means $k_2+1 \le n-1 \implies k_2 \le n-2$.
        //
        // This line of reasoning is getting complicated.
        // The simplest explanation is that $a_{n-1}$ and $a_n$ are the two "middle" elements.
        // We can always construct a partition such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        // We can form Class 1 with $a_0, \dots, a_{n-1}$ and Class 2 with $a_n, \dots, a_{2n-1}$.
        // This is a partition of $2n$ students into two groups of $n$ students each.
        // If $n$ is odd, then these are valid classes.
        // The median of Class 1 is $a_{(n-1)/2}$. The median of Class 2 is $a_{n+(n-1)/2}$.
        // The difference is $a_{n+(n-1)/2} - a_{(n-1)/2}$.
        // This is not $a_n - a_{n-1}$.
        //
        // The problem is simpler: the minimum difference is always $a[n] - a[n-1]$.
        // This is a standard result for this type of problem.
        // The proof relies on the fact that if you have $2n$ items, and you partition them into two sets of odd size,
        // the medians of these two sets must "straddle" the $n$-th and $(n+1)$-th elements of the full sorted list.
        //
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // Suppose $M_1 < a_{n-1}$ and $M_2 > a_n$.
        // The number of elements $\le M_1$ is at most $n-1$.
        // The number of elements $\ge M_2$ is at most $n-1$.
        //
        // Let $C_1$ have $2k_1+1$ elements and $C_2$ have $2k_2+1$ elements. $k_1+k_2+1=n$.
        // $M_1$ is the $(k_1+1)$-th element of $C_1$.
        // $M_2$ is the $(k_2+1)$-th element of $C_2$.
        //
        // The total number of elements in the entire $2n$ array that are $\le M_1$ is at least $k_1+1$.
        // The total number of elements in the entire $2n$ array that are $\ge M_2$ is at least $k_2+1$.
        //
        // If $M_1 < a_{n-1}$, then $a_{n-1}$ must be in $C_2$.
        // If $M_2 > a_n$, then $a_n$ must be in $C_1$.
        //
        // This is a known result. The minimum difference is $a[n] - a[n-1]$.
        // The proof is that you can always construct the classes such that $a[n-1]$ is the median of one class and $a[n]$ is the median of the other.
        //
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$ be the sizes of the classes, where $k_1+k_2+1=n$.
        // We want to make $a_{n-1}$ the median of $C_1$ and $a_n$ the median of $C_2$.
        //
        // To make $a_{n-1}$ the median of $C_1$:
        // $C_1$ must contain $a_{n-1}$.
        // $C_1$ must contain $k_1$ elements from $a_0, \dots, a_{n-2}$.
        // $C_1$ must contain $k_1$ elements from $a_n, \dots, a_{2n-1}$.
        //
        // To make $a_n$ the median of $C_2$:
        // $C_2$ must contain $a_n$.
        // $C_2$ must contain $k_2$ elements from $a_0, \dots, a_{n-1}$.
        // $C_2$ must contain $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // This is a constructive proof.
        // Let $k_1 = 0$, $k_2 = n-1$. So $S_1=1$, $S_2=2n-1$.
        // $C_1 = \{a_{n-1}\}$. Median is $a_{n-1}$.
        // $C_2 = \{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // The elements of $C_2$ are all elements except $a_{n-1}$.
        // The median of $C_2$ is $a_n$.
        // This is because $C_2$ has $2n-1$ elements. Its median is the $n$-th element.
        // The elements of $C_2$ are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The $n$-th element in this sorted list is $a_n$.
        // So, we can always achieve $a_n - a_{n-1}$.
        //
        // The logic is:
        // 1. Sort the array $a$.
        // 2. The minimum difference is $a[n] - a[n-1]$.
        // This is because we can always form two classes, one of size 1 and one of size $2n-1$.
        // Let $C_1 = \{a_{n-1}\}$. Its median is $a_{n-1}$.
        // Let $C_2$ be all other $2n-1$ elements.
        // The elements in $C_2$ are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // When sorted, $C_2$ has $2n-1$ elements. Its median is the $n$-th element.
        // The $n$-th element of $C_2$ (when $C_2$ is sorted) is $a_n$.
        // So, the medians are $a_{n-1}$ and $a_n$. The difference is $|a_n - a_{n-1}|$.
        // Since $a$ is sorted, $a_n \ge a_{n-1}$, so the difference is $a_n - a_{n-1}$.
        // This construction is always valid because $1$ and $2n-1$ are always odd numbers.
        // And $n \ge 1$, so $2n-1 \ge 1$.
        //
        // This simple construction proves that $a_n - a_{n-1}$ is an achievable difference.
        // It is also the minimum possible difference because any two medians $M_1, M_2$ must satisfy $M_1 \le a_n$ and $M_2 \ge a_{n-1}$ (or vice versa).
        // More formally, if $M_1$ is the median of $C_1$ and $M_2$ is the median of $C_2$.
        // $C_1$ has $2k_1+1$ elements, $C_2$ has $2k_2+1$ elements, $k_1+k_2+1=n$.
        // There are at least $k_1+1$ elements in $C_1$ that are $\le M_1$.
        // There are at least $k_2+1$ elements in $C_2$ that are $\ge M_2$.
        //
        // The total number of elements $\le M_1$ in the entire $2n$ array is at least $k_1+1$.
        // The total number of elements $\ge M_2$ in the entire $2n$ array is at least $k_2+1$.
        //
        // If $M_1 > a_n$, then there are at least $n+1$ elements $\le M_1$.
        // If $M_2 < a_{n-1}$, then there are at least $n+1$ elements $\ge M_2$.
        //
        // This is a standard result. The minimum difference is $a[n] - a[n-1]$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

