int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for n=1 staircase
        long long sum_of_powers_of_2 = 1; // 2^1 - 1

        while (true) {
            if (x >= current_cost) {
                x -= current_cost;
                count++;
            } else {
                break;
            }

            // Calculate cost for the next staircase (n = 2*k + 1)
            // The next k is 2*k_prev + 1.
            // So, the next n is 2*(2*k_prev + 1) + 1 = 4*k_prev + 3.
            // This is equivalent to saying the next n is 2*n_prev + 1.
            // The cost for a staircase with n stairs is n*(n+1)/2.
            // The cost for a nice staircase with n = 2^k - 1 stairs is 2^k * (2^k - 1) / 2 = (2^k-1) * 2^(k-1).
            // Let's use the derived formula: cost_k = 2^k * (2^k - 1) / 2.
            // The sequence of n values for nice staircases is 1, 3, 7, 15, ... (2^k - 1).
            // The costs are:
            // n=1 (k=1): 1*(1+1)/2 = 1
            // n=3 (k=2): 3*(3+1)/2 = 6
            // n=7 (k=3): 7*(7+1)/2 = 28
            // n=15 (k=4): 15*(15+1)/2 = 120
            // The costs are (2^k - 1) * 2^(k-1).
            // Let's denote the current n as n_curr. The cost is n_curr * (n_curr + 1) / 2.
            // The next n is 2 * n_curr + 1.
            // The next cost is (2 * n_curr + 1) * (2 * n_curr + 2) / 2 = (2 * n_curr + 1) * (n_curr + 1).
            // This is not what the pattern implies.
            // The pattern of costs is 1, 6, 28, 120, ...
            // The difference between consecutive costs is not constant.
            // The costs are (2^k - 1) * 2^(k-1).
            // For k=1, cost = (2^1 - 1) * 2^0 = 1 * 1 = 1.
            // For k=2, cost = (2^2 - 1) * 2^1 = 3 * 2 = 6.
            // For k=3, cost = (2^3 - 1) * 2^2 = 7 * 4 = 28.
            // For k=4, cost = (2^4 - 1) * 2^3 = 15 * 8 = 120.
            // The next cost is (2 * current_n + 1) * (current_n + 1).
            // Let's use the sum_of_powers_of_2 variable.
            // sum_of_powers_of_2 represents 2^k - 1.
            // The current cost is (sum_of_powers_of_2) * (sum_of_powers_of_2 + 1) / 2.
            // The next sum_of_powers_of_2 will be 2 * sum_of_powers_of_2 + 1.
            // This is equivalent to 2^(k+1) - 1.

            // The cost for a staircase with n = 2^k - 1 stairs is (2^k - 1) * 2^(k-1).
            // Let's track 2^k.
            // Initially, k=1, 2^k=2. Cost is (2-1)*2^(1-1) = 1*1 = 1.
            // Next, k=2, 2^k=4. Cost is (4-1)*2^(2-1) = 3*2 = 6.
            // Next, k=3, 2^k=8. Cost is (8-1)*2^(3-1) = 7*4 = 28.
            // So, if current_cost is (2^k - 1) * 2^(k-1),
            // then the next cost is (2^(k+1) - 1) * 2^k.
            // This can be written as (2 * (2^k - 1) + 1) * 2^k.
            // Or, (2 * (current_cost / 2^(k-1)) + 1) * 2^k. This is getting complicated.

            // Let's use the simpler recurrence:
            // The sequence of n values for nice staircases is 1, 3, 7, 15, ...
            // Let n_k be the number of stairs for the k-th nice staircase. n_k = 2^k - 1.
            // The cost for n_k stairs is C_k = n_k * (n_k + 1) / 2.
            // C_k = (2^k - 1) * (2^k) / 2 = (2^k - 1) * 2^(k-1).
            // We can compute C_{k+1} from C_k.
            // C_{k+1} = (2^(k+1) - 1) * 2^k = (2 * (2^k - 1) + 1) * 2^k.
            // We know 2^k - 1 = n_k. So C_{k+1} = (2 * n_k + 1) * 2^k.
            // Also, n_k = 2^k - 1 => 2^k = n_k + 1.
            // So C_{k+1} = (2 * n_k + 1) * (n_k + 1).
            // Let's track n_k.
            // Initially, n_k = 1. Cost = 1.
            // Next n_k = 2*1 + 1 = 3. Cost = (2*1+1)*(1+1) = 3*2 = 6.
            // Next n_k = 2*3 + 1 = 7. Cost = (2*3+1)*(3+1) = 7*4 = 28.
            // This is correct.

            long long n_prev = (current_cost * 2) / (sum_of_powers_of_2 + 1); // n_prev = 2^k - 1
            // n_prev = sum_of_powers_of_2

            sum_of_powers_of_2 = 2 * sum_of_powers_of_2 + 1; // This is the next n (2^(k+1) - 1)
            current_cost = sum_of_powers_of_2 * (sum_of_powers_of_2 + 1) / 2; // Cost for the next n

            if (current_cost > x && x < 0) { // Check for overflow and if it's too large
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' must satisfy three conditions:
        // 1. We need at least 'k' coders: k <= c
        // 2. We need at least 'k' mathematicians: k <= m
        // 3. We need 3*k total students: 3*k <= c + m + x
        // Combining these, k must be less than or equal to min(c, m, (c + m + x) / 3).
        // This minimum value is always achievable.
        // If we form 'k' teams, we use 'k' coders and 'k' mathematicians (minimum).
        // The remaining students are (c - k) coders, (m - k) mathematicians, and 'x' no-specialization students.
        // The total number of remaining students is (c - k) + (m - k) + x.
        // Each team needs 3 members. We've already accounted for 1 coder and 1 mathematician per team.
        // So, each team needs 1 more student. For 'k' teams, we need 'k' more students.
        // The total available remaining students must be at least 'k'.
        // (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // (c + m + x) / 3 >= k
        // This confirms that the third condition (k <= (c + m + x) / 3) is indeed the total student count constraint.
        // So, the maximum number of teams is simply the minimum of these three upper bounds.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

