    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // We can add a ')' if:
            // 1. We still need ')' characters (close_count < k/2).
            // 2. Adding it won't make the balance negative (balance > 0).
            // 3. We have enough remaining open brackets to match the remaining close brackets needed.
            //    Specifically, if we add this ')', the number of remaining ')' needed is (k/2 - close_count - 1).
            //    The number of remaining '(' we can still add is (k/2 - open_count).
            //    We must ensure that (k/2 - open_count) >= (k/2 - close_count - 1).
            //    This simplifies to open_count <= close_count + 1.
            //    Combined with balance > 0, this means open_count > close_count.
            //    So, if balance > 0, then open_count > close_count.
            //    The condition (k/2 - open_count) >= (k/2 - close_count - 1) is equivalent to
            //    open_count <= close_count + 1.
            //    Since we are trying to maintain balance >= 0, and we only add ')' if balance > 0,
            //    it implies open_count > close_count.
            //    So, open_count >= close_count + 1.
            //    This means open_count is always >= close_count + 1 when balance > 0.
            //    Thus, (k/2 - open_count) will always be <= (k/2 - close_count - 1).
            //    This logic is flawed. Let's re-evaluate.

            // The condition for adding ')' is:
            // 1. We still need ')' characters: close_count < k / 2.
            // 2. The current balance is positive: balance > 0.
            // 3. After adding this ')', we must be able to complete the sequence.
            //    The number of remaining characters to add is k - (open_count + close_count + 1).
            //    This remaining length must be even.
            //    The number of remaining open brackets we can still pick is (k/2 - open_count).
            //    The number of remaining close brackets we can still pick is (k/2 - close_count - 1).
            //    The total number of characters we still need to pick is (k - (open_count + close_count + 1)).
            //    This must be equal to (k/2 - open_count) + (k/2 - close_count - 1).
            //    The crucial part is that the number of remaining open brackets we can pick
            //    must be at least the number of remaining close brackets we need to pick
            //    to ensure a valid sequence can be formed.
            //    (k/2 - open_count) >= (k/2 - close_count - 1)
            //    -open_count >= -close_count - 1
            //    open_count <= close_count + 1
            //    This condition is always true if balance > 0, because balance = open_count - close_count.
            //    If balance > 0, then open_count > close_count, which implies open_count >= close_count + 1.
            //    So, the only conditions are close_count < k/2 and balance > 0.

            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

