void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'p' such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // If such a 'p' exists, then a[p-1] > a[p].
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // After this loop, a[p...n-1] is non-decreasing.
    // If p=0, the whole array is non-decreasing.
    // If p>0, then a[p-1] < a[p] is NOT necessarily true.
    // It means a[p-1] < a[p] is false, i.e., a[p-1] >= a[p].
    // The loop condition is a[p-1] >= a[p].
    // So, after the loop, a[p] is the first element of the longest non-decreasing suffix.
    // Example: [1,2,3,4] -> p=0
    // Example: [4,3,3,8,4,5,2] -> p=n-1=6, a[5]=5, a[6]=2. a[5]>=a[6] is false. p=6.
    // Example: [1,3,1,4,5,3,2] -> p=n-1=6, a[5]=3, a[6]=2. a[5]>=a[6] is true. p=5.
    // p=5, a[4]=5, a[5]=3. a[4]>=a[5] is true. p=4.
    // p=4, a[3]=4, a[4]=5. a[3]>=a[4] is false. p=4.
    // So, a[4...6] = [5,3,2] is the suffix. This is not non-decreasing.
    // The logic for finding the non-decreasing suffix should be:
    // Find the first index `i` from right such that `a[i] < a[i+1]`.
    // Then `a[i+1...n-1]` is non-decreasing.
    // Let's re-evaluate `p`.
    // `p` should be the start of the longest non-decreasing suffix.
    // `p = n - 1;`
    // `while (p > 0 && a[p-1] <= a[p]) { p--; }`
    // This finds the start of the longest non-decreasing suffix.
    // Example: [1,2,3,4] -> p=0
    // Example: [4,3,3,8,4,5,2] -> p=6. a[5]=5, a[6]=2. a[5]<=a[6] is false. p=6.
    // Example: [1,3,1,4,5,3,2] -> p=6. a[5]=3, a[6]=2. a[5]<=a[6] is false. p=6.
    // Example: [1,1,1] -> p=0
    // Example: [5,4,3,2,3] -> p=4. a[3]=2, a[4]=3. a[3]<=a[4] is true. p=3.
    // p=3. a[2]=3, a[3]=2. a[2]<=a[3] is false. p=3.
    // So, a[3...4] = [2,3] is the longest non-decreasing suffix.

    // Let's find the rightmost peak.
    // The array must look like: ... increasing part ... decreasing part ...
    // We want to find the first element from the right that breaks the non-decreasing suffix.
    // Example: [1,3,1,4,5,3,2]
    // Suffix: [2] (len 1)
    // Suffix: [3,2] (len 2) - not non-decreasing
    // Suffix: [5,3,2] (len 3) - not non-decreasing
    // Suffix: [4,5,3,2] (len 4) - not non-decreasing
    // Suffix: [1,4,5,3,2] (len 5) - not non-decreasing
    // Suffix: [3,1,4,5,3,2] (len 6) - not non-decreasing
    // Suffix: [1,3,1,4,5,3,2] (len 7) - not non-decreasing

    // The problem states: "find the length of the smallest (shortest) prefix of elements you need to erase from a to make it a good array."
    // A good array can be formed by taking elements from ends to form a non-decreasing sequence.
    // This implies that the remaining suffix must be "bitonic" or "V-shaped" if we consider the elements in the order they are picked.
    // More precisely, the remaining suffix `a[k...n-1]` must be such that it can be split into two parts:
    // `a[k...i]` and `a[i+1...n-1]` where `a[k...i]` is decreasing and `a[i+1...n-1]` is increasing.
    // Or, `a[k...n-1]` is decreasing, or `a[k...n-1]` is increasing.
    // This is equivalent to saying that there is at most one "peak" or "valley" in the sequence.
    // The elements are picked from ends. The smallest elements are picked first.
    // The sequence of elements picked from `a[k...n-1]` will be `a[k], a[k+1], ..., a[i]` and `a[n-1], a[n-2], ..., a[i+1]`
    // in some interleaved order.
    // The elements `a[k], ..., a[i]` must be picked in increasing order.
    // The elements `a[n-1], ..., a[i+1]` must be picked in increasing order.
    // And the last element picked from `a[k...i]` must be <= first element picked from `a[i+1...n-1]` (if any).
    // This is a standard property for "good" arrays.
    // A sequence `b` is good if and only if it can be written as `X Y` where `X` is non-increasing and `Y` is non-decreasing.
    // Example: `[1,2,3,4,4,2,1]`
    // `X = [4,4,2,1]` (non-increasing)
    // `Y = [1,2,3]` (non-decreasing)
    // This is not quite right. The example `[1,2,3,4,4,2,1]` is good.
    // It can be seen as `[1,2,3,4]` and `[4,2,1]`.
    // The elements are picked from ends.
    // The elements picked from the left form a non-decreasing sequence.
    // The elements picked from the right form a non-decreasing sequence.
    // And the overall sequence is non-decreasing.
    // This means the remaining suffix `a[k...n-1]` must be such that it can be split into two parts:
    // `a[k...i]` and `a[i+1...n-1]` where `a[k...i]` is non-decreasing and `a[i+1...n-1]` is non-increasing.
    // This is the "mountain" shape.
    // Example: `[1,2,3,4,4,2,1]`
    // `[1,2,3,4,4]` is non-decreasing. `[4,2,1]` is non-increasing.
    // The split point is after the second `4`.
    // So, we need to find the longest suffix `a[k...n-1]` that has this "mountain" property.
    // A mountain array is an array that first increases and then decreases.
    // More precisely, there exists an index `i` such that `a[k] <= a[k+1] <= ... <= a[i]` and `a[i] >= a[i+1] >= ... >= a[n-1]`.
    // This is the condition for an array to be "good".

    // Find the rightmost index `i` such that `a[i] < a[i-1]`. This marks the end of the non-increasing suffix.
    // Example: `[1,3,1,4,5,3,2]`
    // `n-1 = 6`. `a[6]=2`.
    // `i=6`: `a[6]=2`.
    // `i=5`: `a[5]=3`. `a[5] > a[6]`. This is part of the non-increasing suffix.
    // `i=4`: `a[4]=5`. `a[4] > a[5]`. This is part of the non-increasing suffix.
    // `i=3`: `a[3]=4`. `a[3] < a[4]`. This is where the non-increasing suffix ends.
    // So, `a[4...6]` is `[5,3,2]`, which is non-increasing.
    // Let `idx_decreasing_start` be the first index of the non-increasing suffix.
    // `idx_decreasing_start = n - 1;`
    // `while (idx_decreasing_start > 0 && a[idx_decreasing_start - 1] >= a[idx_decreasing_start]) { idx_decreasing_start--; }`
    // Example: `[1,3,1,4,5,3,2]`
    // `idx_decreasing_start = 6`. `a[5]=3, a[6]=2`. `3 >= 2` is true. `idx_decreasing_start = 5`.
    // `idx_decreasing_start = 5`. `a[4]=5, a[5]=3`. `5 >= 3` is true. `idx_decreasing_start = 4`.
    // `idx_decreasing_start = 4`. `a[3]=4, a[4]=5`. `4 >= 5` is false. Loop terminates.
    // So, `idx_decreasing_start = 4`. The suffix `a[4...n-1]` is `[5,3,2]`. This is non-increasing.

    // Now, we need to find the start of the non-decreasing prefix that comes before this non-increasing suffix.
    // Let `idx_increasing_start` be this index.
    // `idx_increasing_start = idx_decreasing_start;`
    // `while (idx_increasing_start > 0 && a[idx_increasing_start - 1] <= a[idx_increasing_start]) { idx_increasing_start--; }`
    // Example: `[1,3,1,4,5,3,2]`, `idx_decreasing_start = 4`.
    // `idx_increasing_start = 4`. `a[3]=4, a[4]=5`. `4 <= 5` is true. `idx_increasing_start = 3`.
    // `idx_increasing_start = 3`. `a[2]=1, a[3]=4`. `1 <= 4` is true. `idx_increasing_start = 2`.
    // `idx_increasing_start = 2`. `a[1]=3, a[2]=1`. `3 <= 1` is false. Loop terminates.
    // So, `idx_increasing_start = 2`.
    // The good suffix starts at `idx_increasing_start = 2`.
    // The length of prefix to erase is `idx_increasing_start`.
    // For `[1,3,1,4,5,3,2]`, the answer is `2`. This matches the example.

    // Let's test with other examples:
    // `[1,2,3,4]`
    // `idx_decreasing_start = 3`. `a[2]=3, a[3]=4`. `3 >= 4` is false. `idx_decreasing_start = 3`.
    // `idx_increasing_start = 3`. `a[2]=3, a[3]=4`. `3 <= 4` is true. `idx_increasing_start = 2`.
    // `idx_increasing_start = 2`. `a[1]=2, a[2]=3`. `2 <= 3` is true. `idx_increasing_start = 1`.
    // `idx_increasing_start = 1`. `a[0]=1, a[1]=2`. `1 <= 2` is true. `idx_increasing_start = 0`.
    // Result: `0`. Correct.

    // `[4,3,3,8,4,5,2]`
    // `idx_decreasing_start = 6`. `a[5]=5, a[6]=2`. `5 >= 2` is true. `idx_decreasing_start = 5`.
    // `idx_decreasing_start = 5`. `a[4]=4, a[5]=5`. `4 >= 5` is false. Loop terminates.
    // So, `idx_decreasing_start = 5`. Suffix `a[5...6]` is `[5,2]`. This is non-increasing.
    // `idx_increasing_start = 5`. `a[4]=4, a[5]=5`. `4 <= 5` is true. `idx_increasing_start = 4`.
    // `idx_increasing_start = 4`. `a[3]=8, a[4]=4`. `8 <= 4` is false. Loop terminates.
    // So, `idx_increasing_start = 4`.
    // Result: `4`. Correct.

    // `[1,1,1]`
    // `idx_decreasing_start = 2`. `a[1]=1, a[2]=1`. `1 >= 1` is true. `idx_decreasing_start = 1`.
    // `idx_decreasing_start = 1`. `a[0]=1, a[1]=1`. `1 >= 1` is true. `idx_decreasing_start = 0`.
    // So, `idx_decreasing_start = 0`. Suffix `a[0...2]` is `[1,1,1]`. This is non-increasing.
    // `idx_increasing_start = 0`. Loop condition `idx_increasing_start > 0` is false. Loop terminates.
    // So, `idx_increasing_start = 0`.
    // Result: `0`. Correct.

    // `[5,4,3,2,3]`
    // `idx_decreasing_start = 4`. `a[3]=2, a[4]=3`. `2 >= 3` is false. `idx_decreasing_start = 4`.
    // Suffix `a[4...4]` is `[3]`. This is non-increasing.
    // `idx_increasing_start = 4`. `a[3]=2, a[4]=3`. `2 <= 3` is true. `idx_increasing_start = 3`.
    // `idx_increasing_start = 3`. `a[2]=3, a[3]=2`. `3 <= 2` is false. Loop terminates.
    // So, `idx_increasing_start = 3`.
    // Result: `3`. Correct.

    // The logic seems solid.
    // The length of the prefix to erase is `idx_increasing_start`.

    int idx_decreasing_start = n - 1;
    while (idx_decreasing_start > 0 && a[idx_decreasing_start - 1] >= a[idx_decreasing_start]) {
        idx_decreasing_start--;
    }

    int idx_increasing_start = idx_decreasing_start;
    while (idx_increasing_start > 0 && a[idx_increasing_start - 1] <= a[idx_increasing_start]) {
        idx_increasing_start--;
    }

    std::cout << idx_increasing_start << std::endl;
}

