#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements in the sorted array 'a' that we want to place
    for (int i = 0; i < n; ++i) { // Pointer for elements in the sorted array 'a' that are original positions
        // We are trying to find an element a[j] to place at position i
        // such that a[j] > a[i].
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1], a[j+2], ...
        // will also be greater than or equal to a[j], and thus greater than a[i].
        // To maximize the count, we should use the smallest possible a[j] that satisfies a[j] > a[i].
        // This is achieved by advancing j only when a[j] is strictly greater than a[i].
        if (a[j] > a[i]) {
            count++;
            j++; // Move to the next element to be placed
        }
        // If a[j] <= a[i], we cannot place a[j] at position i to satisfy the condition.
        // We must try to find a larger element for position i.
        // However, we are iterating through i (original positions) and j (elements to place).
        // The key insight is that we want to match a[i] with some a[j] where j > i.
        // If a[j] <= a[i], it means a[j] is too small for a[i].
        // We should try to use a[j] for an earlier position (which is not possible as we iterate i from 0).
        // Or, we should try to use a larger element for a[i].
        // The current logic correctly implements the greedy strategy:
        // For each a[i] (original element), we try to find the smallest available a[j] (element to place)
        // such that a[j] > a[i].
        // If we find such an a[j], we increment count and move to the next available a[j] (by incrementing j).
        // If we don't find such an a[j] (i.e., a[j] <= a[i]), we keep a[j] for a later a[i'] (where i' > i).
        // This is because a[j] might be greater than a[i'] if a[i'] is smaller than a[i].
        // The pointer j only advances when a match is made.
        // The pointer i always advances.
        // This ensures that we are always trying to match the smallest available 'original' element (a[i])
        // with the smallest available 'permutation' element (a[j]) that is strictly greater.
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // For 0-indexed array, this is (n-1)/2

    // Step 1: Make the median element equal to s
    operations += std::abs(a[mid_idx] - s);
    a[mid_idx] = s; // Conceptually change it to s for subsequent checks

    // Step 2: Ensure elements to the left of median are <= s
    // These are elements at indices 0 to mid_idx - 1
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Step 3: Ensure elements to the right of median are >= s
    // These are elements at indices mid_idx + 1 to n - 1
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b.begin(), b.end(), std::greater<long long>());

    // Create pairs (A_i, B_i) such that A_i is sorted ascending and B_i is sorted descending.
    // This maximizes F(A_i, B_i) = A_i * B_i / (B_i + 1)
    // The function F(n, k) = n * k / (k + 1) is increasing in n and increasing in k.
    // To maximize sum F(A'_i, B_i), we should pair largest A'_i with largest B_i.
    // However, the problem states F(n, k) = k * (n + 1) / (k + 1).
    // Let's re-derive F(n, k).
    // E[X] = sum_{x=1}^{n-k+1} P(X >= x)
    // P(X >= x) = C(n-x+1, k) / C(n, k)
    // E[X] = sum_{x=1}^{n-k+1} C(n-x+1, k) / C(n, k)
    // Using Hockey-stick identity: sum_{i=r}^N C(i, r) = C(N+1, r+1)
    // Let j = n-x+1. When x=1, j=n. When x=n-k+1, j=k.
    // E[X] = (1 / C(n, k)) * sum_{j=k}^n C(j, k)
    // E[X] = (1 / C(n, k)) * C(n+1, k+1)
    // C(n+1, k+1) = (n+1)! / ((k+1)! * (n-k)!)
    // C(n, k) = n! / (k! * (n-k)!)
    // E[X] = ((n+1)! / ((k+1)! * (n-k)!)) / (n! / (k! * (n-k)!))
    // E[X] = ((n+1) * n! / ((k+1) * k! * (n-k)!)) * (k! * (n-k)! / n!)
    // E[X] = (n+1) / (k+1)
    // This is the correct formula for F(n, k).

    // We want to maximize sum_{i=1}^m F(A'_i, B_i) = sum_{i=1}^m (A'_i + 1) / (B_i + 1).
    // Let C_i = 1 / (B_i + 1). We want to maximize sum_{i=1}^m (A'_i + 1) * C_i.
    // This is sum A'_i * C_i + sum C_i.
    // To maximize sum A'_i * C_i, we should pair largest A'_i with largest C_i.
    // Largest C_i corresponds to smallest B_i.
    // So, we should pair largest A'_i with smallest B_i.
    // This means A should be sorted ascending, and B should be sorted ascending.
    // Then A'_i = A[i] and B_i = B[i] (after sorting).
    // The problem statement says "For all i, j such that 1 <= i, j <= m the condition A_i >= B_j holds."
    // This implies A_i >= B_j for all i, j.
    // This condition is important for the definition of F(n, k) to be valid (n >= k).
    // Since A_i >= B_j for all i, j, it means min(A) >= max(B).
    // So A_i >= B_i for any pairing.

    // So, to maximize sum (A'_i + 1) / (B_i + 1), we sort A ascending and B ascending.
    // Then we pair A[i] with B[i].
    // The problem asks to rearrange A.
    // So, we need to output A' such that A'_i is the value paired with original B_i.
    // Let's store original B values with their indices.
    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        b_elements[i].value = b[i]; // b already contains sorted values
        b_elements[i].original_index = i;
    }

    // Sort B values along with their original indices in ascending order.
    // This is already done if we use the `b` vector directly, as it was sorted ascending.
    // But we need to know the original positions of B values.
    // Let's re-read the problem: "rearrange the numbers in the array A so that the sum ... is maximally possible".
    // This means we need to find a permutation A' of A.
    // The B array is fixed.
    // So we have A_1, ..., A_m and B_1, ..., B_m.
    // We want to find a permutation P of {1, ..., m} such that sum_{i=1}^m F(A_{P_i}, B_i) is maximized.
    // F(n, k) = (n+1) / (k+1).
    // We want to maximize sum_{i=1}^m (A_{P_i} + 1) / (B_i + 1).
    // Let x_i = A_{P_i} + 1 and y_i = 1 / (B_i + 1).
    // We want to maximize sum x_i * y_i.
    // By rearrangement inequality, this sum is maximized when x_i and y_i are sorted in the same order.
    // So, A_{P_i} + 1 should be sorted in the same order as 1 / (B_i + 1).
    // This means A_{P_i} should be sorted in the same order as 1 / (B_i + 1).
    // Since 1 / (B_i + 1) is decreasing with B_i, this means A_{P_i} should be sorted in decreasing order of B_i.
    // So, if B_i is small, A_{P_i} should be large.
    // If B_i is large, A_{P_i} should be small.

    // Strategy:
    // 1. Sort A in ascending order. Let this be A_sorted.
    // 2. Sort B in ascending order, keeping track of original indices. Let this be B_sorted_with_indices.
    // 3. The largest A_sorted value should be paired with the smallest B_sorted_with_indices value.
    //    The second largest A_sorted value should be paired with the second smallest B_sorted_with_indices value, and so on.
    //    This means A_sorted (ascending) should be paired with B_sorted_with_indices (ascending) in reverse order.
    //    A_sorted[0] (smallest A) should be paired with B_sorted_with_indices[m-1] (largest B).
    //    A_sorted[1] (second smallest A) should be paired with B_sorted_with_indices[m-2] (second largest B).
    //    ...
    //    A_sorted[m-1] (largest A) should be paired with B_sorted_with_indices[0] (smallest B).

    // Let's re-verify the rearrangement inequality application.
    // We want to maximize sum_{i=1}^m (A_{P_i} + 1) * (1 / (B_i + 1)).
    // Let X_j = A_j + 1 for j=1..m.
    // Let Y_i = 1 / (B_i + 1) for i=1..m.
    // We want to maximize sum_{i=1}^m X_{P_i} * Y_i.
    // This is maximized when X and Y are sorted in the same order.
    // So, if we sort X values (which means sorting A values) in ascending order: X_1 <= X_2 <= ... <= X_m.
    // And we sort Y values (which means sorting 1/(B_i+1) values) in ascending order: Y'_1 <= Y'_2 <= ... <= Y'_m.
    // Then we pair X_j with Y'_j.
    // Y_i = 1 / (B_i + 1). Y_i is ascending if B_i is descending.
    // So, A values should be sorted ascending.
    // B values should be sorted descending.
    // Then A_sorted[j] is paired with B_sorted_descending[j].

    // Let's use the original B array and sort A.
    // We need to output A' which is a permutation of A.
    // The output array A' has elements A'_1, A'_2, ..., A'_m.
    // A'_i is the value from original A that is paired with original B_i.
    // So, we need to construct an array `result` of size `m`.
    // `result[original_index_of_B_i]` will store the A value paired with B_i.

    // 1. Sort A values (a_elements) in ascending order.
    //    a_elements[0].value is smallest A, a_elements[m-1].value is largest A.
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // 2. Create pairs of (B_value, original_index_of_B_value).
    std::vector<Element> b_original_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_original_indexed[i].value = b[i];
        b_original_indexed[i].original_index = i;
    }

    // 3. Sort these B pairs in descending order of B_value.
    //    b_original_indexed[0].value is largest B, b_original_indexed[m-1].value is smallest B.
    std::sort(b_original_indexed.begin(), b_original_indexed.end(), [](const Element& x, const Element& y) {
        return x.value > y.value;
    });

    // 4. Now, pair a_elements[j] with b_original_indexed[j].
    //    a_elements[0] (smallest A) is paired with b_original_indexed[0] (largest B).
    //    a_elements[1] (second smallest A) is paired with b_original_indexed[1] (second largest B).
    //    ...
    //    a_elements[m-1] (largest A) is paired with b_original_indexed[m-1] (smallest B).
    // This ensures that A values are sorted ascending, and B values are sorted descending.
    // This maximizes sum (A_i + 1) / (B_i + 1).

    std::vector<long long> result(m);
    for (int i = 0; i < m; ++i) {
        // a_elements[i].value is the i-th smallest A value.
        // b_original_indexed[i].original_index is the original index of the i-th largest B value.
        // So, the i-th smallest A value should be placed at the original index of the i-th largest B value.
        result[b_original_indexed[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

