        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real, d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, we need d - 4 >= 0, which means d >= 4.
        // If d = 0, it's a special case handled above.
        // If 0 < d < 4, then d - 4 < 0, so d(d - 4) < 0. No real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // a^2 - d*a + d = 0
            // a = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b = d - a

            // The problem asks for non-negative real numbers.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is positive. So a1 is positive.
            // For b1 = d - a1 to be non-negative:
            // d - (d + sqrt(d^2 - 4d)) / 2 >= 0
            // (2d - d - sqrt(d^2 - 4d)) / 2 >= 0
            // (d - sqrt(d^2 - 4d)) / 2 >= 0
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since both sides are non-negative)
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both a1 and b1 are non-negative.

            // The other solution for a would be a2 = (d - sqrt_discriminant) / 2.0
            // and b2 = d - a2.
            // These would just be a swap of a1 and b1.
            // For example, if a1 is the larger root, then b1 is the smaller root.
            // a2 would be the smaller root, and b2 would be the larger root.
            // The problem doesn't specify order, so (a1, b1) is a valid pair.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = min_a + elements[1].value
    // max_f = max_a + elements[n-2].value
    // Goodness = (max_a + elements[n-2].value) - (min_a + elements[1].value)
    // This is only valid if n >= 2.
    long long goodness1 = (max_a + elements[n - 2].value) - (min_a + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put min_a and max_a into different subsequences.
    // This creates f values like min_a + max_a + h.
    // The other elements are placed to minimize the range.
    // The optimal strategy for this case is to put min_a into one group (say, group 1)
    // and max_a into another group (say, group 2).
    // All other elements are put into group 2.
    //
    // Group 1: {min_a}
    // Group 2: {a_2, ..., a_n} (where a_2 is the second smallest, a_n is the largest)
    //
    // Possible f values:
    // 1. Pairs within Group 1: None (only one element)
    // 2. Pairs within Group 2:
    //    Smallest: elements[1].value + elements[2].value
    //    Largest: elements[n-1].value + elements[n-2].value
    // 3. Pairs across Group 1 and Group 2:
    //    Smallest: min_a + elements[1].value + h
    //    Largest: min_a + elements[n-1].value + h
    //
    // Overall min_f: min(elements[1].value + elements[2].value, min_a + elements[1].value + h)
    // Overall max_f: max(elements[n-1].value + elements[n-2].value, min_a + elements[n-1].value + h)
    //
    // This strategy is only better if h is small enough.
    // The key observation is that if we split min_a and max_a, the values `min_a + max_a + h`
    // and `min_a + elements[1].value + h` and `max_a + elements[n-2].value + h`
    // are likely to be part of the range.
    //
    // Consider the partition:
    // Group 1: {elements[0].value}
    // Group 2: {elements[1].value, ..., elements[n-1].value}
    //
    // min_f_same = elements[1].value + elements[2].value (if n >= 3)
    // min_f_diff = elements[0].value + elements[1].value + h
    //
    // max_f_same = elements[n-1].value + elements[n-2].value (if n >= 3)
    // max_f_diff = elements[0].value + elements[n-1].value + h
    //
    // If n=2: Group 1: {elements[0].value}, Group 2: {elements[1].value}
    // Only one pair: (elements[0].value, elements[1].value) -> f = elements[0].value + elements[1].value + h
    // min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    // This is covered by the general logic below.

    long long current_min_f;
    long long current_max_f;

    if (n == 2) {
        current_min_f = elements[0].value + elements[1].value + h;
        current_max_f = elements[0].value + elements[1].value + h;
    } else { // n >= 3
        current_min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        current_max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
    }

    long long goodness2 = current_max_f - current_min_f;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that (l, r) is a "good" pair.
                                                // Initialize with n+1, meaning no such r found yet.

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through possible common differences k.
        // The maximum k is such that x + 2k < n.
        // So 2k < n - x, k < (n - x) / 2.
        // Since k must be at least 1, we start k from 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a triplet (x, x+k, x+2k) with identical characters.
                // This triplet covers the range [x, x+2k].
                // Any (l, r) such that l <= x and x+2k <= r will be counted.
                // We are interested in the smallest possible r for a given l.
                // For a fixed l, the smallest r that satisfies the condition is x+2k.
                // So, for any l' from 0 to x, the pair (l', x+2k) is a "good" pair.
                // We want to update min_r_for_l[l'] with min(min_r_for_l[l'], x+2k).
                // Since we iterate x from left to right, and k from small to large,
                // x+2k will be increasing.
                // This means for a fixed l', the first x+2k we find will be the smallest.
                // However, we need to consider that a smaller x might yield a larger x+2k,
                // but a larger x might yield a smaller x+2k.
                // Example: s = 000000, x=0, k=1 -> [0,2]. x=1, k=1 -> [1,3].
                // For l=0, min_r_for_l[0] = 2.
                // For l=1, min_r_for_l[1] = 3.
                // For l=0, min_r_for_l[0] could be 2 (from x=0, k=1) or 3 (from x=1, k=1).
                // The condition is l <= x. So for l=0, x can be 0 or 1.
                // If x=0, k=1, range [0,2]. For l=0, r=2 is valid.
                // If x=1, k=1, range [1,3]. For l=0, r=3 is valid.
                // We need to find the minimum r for each l.
                // So for each l from 0 to x, we update min_r_for_l[l] = min(min_r_for_l[l], x+2k).

                // The maximum k is limited. If k > 4, then 2k > 8.
                // The problem constraints on n are up to 300,000.
                // If k is large, say k=5, then x+2k = x+10.
                // If s[x] == s[x+5] == s[x+10], then this triplet is found.
                // The maximum k we need to check is small.
                // If k >= 5, then x+2k >= x+10.
                // If s[x] == s[x+k] == s[x+2k], then for any l <= x, r >= x+2k, (l,r) is counted.
                // The crucial observation is that if there is a triplet (x, k) with k >= 5,
                // then there must be a triplet (x', k') with k' < 5 that covers the same or a smaller range.
                // This is not necessarily true. Consider 00000000000000000000 (20 zeros)
                // x=0, k=10. s[0]=s[10]=s[20]. Range [0,20].
                // No smaller k would work for x=0.
                // However, the problem asks for *any* x, k.
                // If s[x] == s[x+k] == s[x+2k], then for any l <= x and r >= x+2k, (l,r) is counted.
                // The minimum r for a given l is `x+2k`.
                // So, for each `l` from `0` to `x`, we update `min_r_for_l[l] = min(min_r_for_l[l], x+2k)`.
                // This is an O(N*K_max) update for each x, where K_max is the maximum k.
                // If K_max is N/2, this is O(N^2), too slow.

                // The key insight for optimization:
                // If s[x] == s[x+k] == s[x+2k], then the range [x, x+2k] is "good".
                // For any l' <= x, the pair (l', x+2k) is good.
                // We want to find the minimum r for each l'.
                // The maximum k we need to check is small.
                // If k >= 5, then x+2k >= x+10.
                // If s[x] == s[x+k] == s[x+2k], then this implies that for any l <= x, r >= x+2k, (l,r) is good.
                // The maximum k we need to check is 4.
                // Why? Consider a triplet (x, k) with k >= 5.
                // This means s[x] = s[x+k] = s[x+2k].
                // The length of this pattern is 2k+1.
                // If k >= 5, then 2k+1 >= 11.
                // Any string of length 11 or more that contains three identical characters in arithmetic progression
                // must contain three identical characters in arithmetic progression with common difference k' <= 4.
                // This is a known result from combinatorics on words (related to Van der Waerden's Theorem).
                // Specifically, for binary strings, if there is a monochromatic arithmetic progression of length 3,
                // there must be one with common difference at most 4.
                // So we only need to check k from 1 to 4.
                // This makes the inner loop constant time.
                // The overall complexity for finding all relevant (x, k) is O(N * K_max) where K_max is 4.
                // So it's O(N).

                // Update min_r_for_l for all l from 0 to x.
                // This is a range update.
                // We can use a suffix minimum approach.
                // min_r_for_l[l] = min(min_r_for_l[l], x+2k).
                // After iterating through all x and k, we can compute suffix minimums:
                // min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l+1]).
                // This ensures that if (l+1, R) is good, then (l, R) is also good.
                // And if (l, R) is good, then (l, R') for R' > R is also good.

                // The current triplet (x, k) makes all pairs (l', r') with l' <= x and r' >= x+2k valid.
                // For each l' from 0 to x, we want to find the minimum r' that makes (l', r') valid.
                // This minimum r' is x+2k.
                // So, for each l' in [0, x], we update min_r_for_l[l'] = min(min_r_for_l[l'], x+2k).
                // This is a range minimum update.
                // Instead of doing it directly, we can just update min_r_for_l[x] = min(min_r_for_l[x], x+2k).
                // And then propagate this minimum backwards.
                // After the loops, min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l+1]) for l from n-1 down to 0.
                // This is because if (l+1, R) is a good pair, then (l, R) is also a good pair.
                // So min_r_for_l[l] must be at most min_r_for_l[l+1].

                min_r_for_l[x] = std::min(min_r_for_l[x], x + 2 * k);
            }
            if (k == 4) break; // Optimization: only check k up to 4.
        }
    }

    // Propagate minimums backwards:
    // For each l, min_r_for_l[l] should be the minimum of all x+2k where x >= l.
    // This is equivalent to min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l+1]).
    for (int l = n - 2; l >= 0; --l) { // Iterate from n-2 down to 0 (0-indexed)
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long total_good_pairs = 0;
    // Count the good pairs (l, r)
    // For each l (0-indexed), if min_r_for_l[l] is not n+1 (meaning a good r exists),
    // then any r from min_r_for_l[l] to n-1 (inclusive) forms a good pair with l.
    // The number of such r's is (n-1) - min_r_for_l[l] + 1.
    for (int l = 0; l < n; ++l) {
        if (min_r_for_l[l] <= n - 1) { // If a valid r exists (r is 0-indexed, so max is n-1)
            total_good_pairs += (n - 1) - min_r_for_l[l] + 1;
        }
    }

    std::cout << total_good_pairs << std::endl;

    return 0;
}

#include <iostream>
