// Function to convert a long long integer to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    for (int i = 0; i < 18; ++i) {
        if ((n % 10) % 2 == 0) {
            pattern_str += '0';
        } else {
            pattern_str += '1';
        }
        n /= 10;
    }
    std::reverse(pattern_str.begin(), pattern_str.end()); // Reverse to get MSB first
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int k = 0; k < t; ++k) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad pattern s with '0's from the left to length 18
            std::string padded_s = std::string(18 - s.length(), '0') + s;

            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check for prefix permutations
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is technically not possible due to constraints a_i <= n-1, but good for robustness
            possible_prefix = false;
            break;
        }
        seen_prefix[a[i]] = true;
        max_val_prefix = std::max(max_val_prefix, a[i]);
        if (max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = possible_prefix;
        } else {
            is_prefix_perm[i + 1] = false;
        }
    }

    // Check for suffix permutations
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen_suffix[a[i]]) { // a[i] > n is technically not possible due to constraints a_i <= n-1
            possible_suffix = false;
            break;
        }
        seen_suffix[a[i]] = true;
        max_val_suffix = std::max(max_val_suffix, a[i]);
        if (max_val_suffix == n - i) {
            is_suffix_perm[n - i] = possible_suffix;
        } else {
            is_suffix_perm[n - i] = false;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

