#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the minimum required values for the increasing prefix
    // b[i] = minimum value a[i] must take to satisfy a_1 < ... < a_i
    // b[0] = 0
    // b[i] = b[i-1] + 1
    // So b[i] = i
    // We need a[i] >= b[i] for all i in the increasing part.
    // This means a[i] >= i for i from 0 to k-1.

    // Calculate the minimum required values for the decreasing suffix
    // c[i] = minimum value a[i] must take to satisfy a_i > ... > a_n
    // c[n-1] = 0
    // c[i] = c[i+1] + 1
    // So c[i] = (n-1) - i
    // We need a[i] >= c[i] for all i in the decreasing part.
    // This means a[i] >= (n-1) - i for i from k to n-1.

    // The peak element a_k (0-indexed: a[k-1]) must satisfy both conditions.
    // For a peak at index `p` (0-indexed):
    // a[p] must be >= p (from increasing part)
    // a[p] must be >= (n-1) - p (from decreasing part)
    // So a[p] must be >= max(p, (n-1)-p)

    // We need to find if there exists *any* peak index `p` (0-indexed)
    // such that we can satisfy the conditions.
    // For a given `p`, we need:
    // 1. a[i] >= i for 0 <= i <= p
    // 2. a[i] >= (n-1) - i for p <= i <= n-1

    // Let's check if a peak can exist at index `p`.
    // The conditions are:
    // For i from 0 to p-1: a[i] >= i
    // For i from p+1 to n-1: a[i] >= (n-1) - i
    // For i = p: a[p] >= p AND a[p] >= (n-1) - p.
    // The second condition for a[p] is implicitly covered by the first two sets of conditions.
    // If a[p] >= p and a[p] >= (n-1)-p, then it can be the peak.
    // The crucial part is that the value at the peak must be strictly greater than its neighbors.
    // However, we can decrease values. So if a[p] is large enough, we can make it strictly greater.
    // The minimum value for a[p] to be a peak is max(p, (n-1)-p).
    // If a[p] >= max(p, (n-1)-p), then we can set a[p] to max(p, (n-1)-p) and its neighbors to max(p, (n-1)-p) - 1.
    // This is always possible if a[p] is large enough.

    // The problem simplifies to:
    // Can we find a `p` (0-indexed) such that:
    // a[i] >= i for all i from 0 to p
    // a[i] >= (n-1) - i for all i from p to n-1

    // Let's find the maximum possible `p` such that `a[i] >= i` for all `0 <= i <= p`.
    int max_left_reach = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            max_left_reach = i;
        } else {
            break;
        }
    }

    // Let's find the minimum possible `p` such that `a[i] >= (n-1) - i` for all `p <= i <= n-1`.
    int min_right_reach = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1) - i) {
            min_right_reach = i;
        } else {
            break;
        }
    }

    // If there is an overlap between the possible peak indices from the left and right conditions,
    // then a sharpened array is possible.
    // This means we need to find if there exists a `p` such that `p <= max_left_reach` AND `p >= min_right_reach`.
    // Such a `p` exists if `max_left_reach >= min_right_reach`.
    if (max_left_reach >= min_right_reach) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

