// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x is a divisor of p and x is not divisible by q.
        // This means x must not be divisible by at least one prime factor of q (with sufficient power).

        // Get prime factors of q
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        long long max_x = 1;

        // Iterate through each distinct prime factor f of q
        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            // int q_exponent = factor_pair.second; // Not directly needed for this approach

            // Calculate the highest power of f that divides p
            long long current_p = p;
            long long p_f_power = 0;
            while (current_p > 0 && current_p % f == 0) {
                current_p /= f;
                p_f_power++;
            }

            // Calculate the highest power of f that divides q
            long long current_q = q;
            long long q_f_power = 0;
            while (current_q > 0 && current_q % f == 0) {
                current_q /= f;
                q_f_power++;
            }

            // We need to remove enough factors of f from p such that the resulting number is not divisible by q.
            // Specifically, we need to remove enough factors of f such that the resulting number is not divisible by f^(q_f_power).
            // The smallest number of factors of f to remove is (p_f_power - q_f_power + 1).
            // This ensures that the new exponent of f in x is (p_f_power - (p_f_power - q_f_power + 1)) = q_f_power - 1.
            // So x will have f^(q_f_power - 1) as a factor, which is not divisible by f^(q_f_power).

            // The divisor we are looking for is p / (f ^ (p_f_power - q_f_power + 1))
            // This is equivalent to (p / f^p_f_power) * f^(q_f_power - 1)
            // Or simply p / (f ^ (q_f_power)) * f^(q_f_power - 1)
            // Or p / f^(q_f_power) * f^(q_f_power - 1) = p / f
            // No, this is not correct.
            // Let p = A * f^P_exp and q = B * f^Q_exp, where A and B are not divisible by f.
            // We want x = p / f^k such that x is not divisible by q.
            // If x is not divisible by q, it must not be divisible by f^Q_exp.
            // So, the exponent of f in x must be less than Q_exp.
            // The exponent of f in x is P_exp - k.
            // We need P_exp - k < Q_exp.
            // To maximize x, we need to minimize k.
            // The smallest k that satisfies P_exp - k < Q_exp is k = P_exp - Q_exp + 1.
            // So, x = p / (f ^ (P_exp - Q_exp + 1)).
            // This x is a divisor of p, and its f-exponent is Q_exp - 1, so it's not divisible by f^Q_exp, hence not by q.
            // We want the maximum such x. We calculate this x for each prime factor f of q and take the maximum.

            long long current_x = p;
            for (int i = 0; i < p_f_power - q_f_power + 1; ++i) {
                current_x /= f;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

