        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        } else {
            s_prime[i] = '0';
