void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length of the segment is 1. min is 1, max is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The current segment covers values from 1 to m-1.
        // We need to find the position of 'm' and update current_min_idx and current_max_idx.
        if (m > 1) {
            int m_idx = pos[m];
            current_min_idx = std::min(current_min_idx, m_idx);
            current_max_idx = std::max(current_max_idx, m_idx);
        }

        // Check if the current segment [current_min_idx, current_max_idx]
        // is a permutation of 1 to m.
        // This requires its length to be m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

