int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible numbers of items taken from the left
    // num_left can range from 0 to n
    for (int num_left = 0; num_left <= n; ++num_left) {
        int num_right = n - num_left;

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[num_left] * l;

        // Energy for items taken from the right
        // The sum of weights for items taken from the right is total_sum - prefix_sum[num_left]
        // which is prefix_sum[n] - prefix_sum[num_left]
        // Or, more directly, sum of weights from index n - num_right to n - 1
        current_energy += (prefix_sum[n] - prefix_sum[n - num_right]) * r;

        // Add extra energy for Ql or Qr
        if (num_left > num_right) {
            // More items taken from left. The last item taken must have been from the left.
            // The difference is num_left - num_right.
            // This means num_left - num_right - 1 times, the robot took a left item
            // when the previous item was also left, and there were still items on the right.
            // The problem statement implies Ql/Qr is added if the *previous* action was the same.
            // If num_left > num_right, it means we took num_left items from left and num_right items from right.
            // The "excess" items from the left are num_left - num_right.
            // For each of these excess items, if it was taken consecutively from the left, it incurs Ql.
            // The number of times we take an item from the left when the previous was also left,
            // and there are no more items on the right to balance it, is (num_left - num_right - 1).
            // Example: L L L R R. num_left=3, num_right=2. Diff=1.
            // The last item taken was L. The previous was L. So Ql is added.
            // The number of "extra" items from the left is num_left - num_right.
            // If num_left = 3, num_right = 2, diff = 1.
            // This means one item from the left was taken when there were no more items from the right to balance it.
            // This implies (num_left - num_right - 1) times, an item was taken from the left when the previous was also left,
            // and there were no items from the right to balance it.
            // The cost is (num_left - num_right - 1) * Ql.
            // If num_left = num_right + 1, then diff = 1. No extra cost.
            // If num_left = num_right + 2, then diff = 2. One extra cost.
            // So, (num_left - num_right - 1) * Ql.
            current_energy += (num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items taken from right.
            // Similar logic: (num_right - num_left - 1) * Qr.
            current_energy += (num_right - num_left - 1) * Qr;
        }
        // If num_left == num_right, no extra cost.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
