void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int p = 0; p <= 9; ++p) {
        std::string colors(n, ' ');
        char last1 = '0' - 1; // Smallest possible digit is '0', so -1 is safe
        char last2 = '0' - 1;
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < p + '0') {
                // Must be color 1
                if (digit < last1) {
                    possible = false;
                    break;
                }
                colors[i] = '1';
                last1 = digit;
            } else if (digit > p + '0') {
                // Must be color 2
                if (digit < last2) {
                    possible = false;
                    break;
                }
                colors[i] = '2';
                last2 = digit;
            } else { // digit == p + '0'
                // Can be color 1 or 2
                if (digit >= last2) {
                    // Prefer color 2 if possible and valid
                    colors[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) {
                    // Otherwise, try color 1 if valid
                    colors[i] = '1';
                    last1 = digit;
                } else {
                    // Cannot be color 1 or 2
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            // Final check: last digit of S1 <= first digit of S2
            // This is implicitly handled by the `last1` and `last2` logic.
            // If a digit `d` is colored 1, `d >= last1`.
            // If a digit `d` is colored 2, `d >= last2`.
            // If `d` is colored 1, it must be `d <= p`.
            // If `d` is colored 2, it must be `d >= p`.
            // The critical condition is that `last1` (max of S1) must be <= `first2` (min of S2).
            // Our greedy choice for `p` digits ensures this:
            // If `d == p` is colored '1', it means `d < last2` was true.
            // If `d == p` is colored '2', it means `d >= last2` was true.
            // This means all '1's are <= p, and all '2's are >= p.
            // So max(S1) <= p <= min(S2) is guaranteed.
            std::cout << colors << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

