    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1 is odd. Opponent takes 1. Then N-2.
                // This path is generally worse for Chanek if N/2 is a good move.
                // If N/2 is 1, then N=2. Chanek takes 1, N=1. Opponent takes 1. Chanek gets 1.
                // If N/2 is 2, then N=4. Chanek takes 2, N=2. Opponent takes 1, N=1. Chanek takes 1. Chanek gets 3.
                // If N/2 is 3, then N=6. Chanek takes 3, N=3. Opponent takes 1, N=2. Chanek takes 1, N=1. Opponent takes 1. Chanek gets 4.
                // If N/2 is 4, then N=8. Chanek takes 4, N=4. Opponent takes 2, N=2. Chanek takes 1, N=1. Opponent takes 1. Chanek gets 5.

                // Option 2: Take N/2 coins
                // If N/2 is odd, opponent will take 1.
                // If N/2 is even, opponent will take N/4.

                if (n == 4) { // Special case for N=4, Chanek takes 2.
                    chanek_coins += 2;
                    n -= 2;
                } else if ((n / 2) % 2 != 0) { // N is even, N/2 is odd
                    // If Chanek takes N/2, remaining is N/2 (odd). Opponent takes 1.
                    // If Chanek takes 1, remaining is N-1 (odd). Opponent takes 1.
                    // Taking N/2 is better as N/2 > 1 for N > 2.
                    // For N=2, N/2=1. Take 1.
                    // For N=6, N/2=3. Take 3. Remaining 3. Opponent takes 1. Remaining 2. Chanek takes 1. Remaining 1. Opponent takes 1.
                    // Chanek gets 3+1=4.
                    // If Chanek takes 1. Remaining 5. Opponent takes 1. Remaining 4. Chanek takes 2. Remaining 2. Opponent takes 1. Remaining 1. Chanek takes 1.
                    // Chanek gets 1+2+1=4.
                    // Both give 4. Taking N/2 is simpler.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even, N/2 is even
                    // If Chanek takes N/2, remaining is N/2 (even). Opponent takes N/4.
                    // If Chanek takes 1, remaining is N-1 (odd). Opponent takes 1.
                    // Taking N/2 is better.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 4) { // Special case for N=4, opponent takes 2.
                    n -= 2;
                } else if ((n / 2) % 2 != 0) { // N is even, N/2 is odd
                    n /= 2;
                } else { // N is even, N/2 is even
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

