int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char c0 = s[k_actual];

        std::vector<int> possible_k_values;
        for (int idx : char_indices[c0 - 'a']) {
            possible_k_values.push_back(idx);
        }

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < n; ++p) {
            char cp = s[(k_actual + p) % n];

            int count_unique_k = 0;
            for (int k_cand : possible_k_values) {
                if (s[(k_cand + p) % n] == cp) {
                    count_unique_k++;
                }
            }

            if (count_unique_k == 1) {
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 1.0);
            } else {
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 0.0);
            }
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append two elements: X and S + X.
        // Let the current sum be S and current XOR sum be X.
        // We want to find b1, b2 such that:
        // (S + b1 + b2) = 2 * (X ^ b1 ^ b2)
        // Let b1 = X.
        // Then the new XOR sum becomes X ^ X = 0.
        // The new sum becomes S + X + b2.
        // The condition becomes S + X + b2 = 2 * 0 = 0.
        // This implies S + X + b2 = 0. Since S, X, b2 are non-negative, this only works if S=X=b2=0.
        // This approach is flawed.

        // Let's try to append two elements, b1 and b2.
        // New sum: S' = S + b1 + b2
        // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
        // We want S' = 2 * X'

        // A known trick for this type of problem is to append X and then S+X.
        // Let b1 = current_xor_sum.
        // New XOR sum: current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0.
        // New sum: current_sum + b1 = current_sum + current_xor_sum.
        // Now we need to append a second element, b2, such that:
        // (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2)
        // (current_sum + current_xor_sum + b2) = 2 * b2
        // current_sum + current_xor_sum = b2
        // So, b2 = current_sum + current_xor_sum.

        // The two elements to append are:
        // b1 = current_xor_sum
        // b2 = current_sum + current_xor_sum

        // Let's verify:
        // New total sum = current_sum + b1 + b2
        //               = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        //               = 2 * (current_sum + current_xor_sum)
        // New total XOR sum = current_xor_sum ^ b1 ^ b2
        //                   = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        //                   = 0 ^ (current_sum + current_xor_sum)
        //                   = current_sum + current_xor_sum
        // Is New total sum = 2 * (New total XOR sum)?
        // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
        // Yes, it holds.

        // The problem states a_i are non-negative.
        // current_sum >= 0, current_xor_sum >= 0.
        // So b1 = current_xor_sum >= 0.
        // And b2 = current_sum + current_xor_sum >= 0.
        // The values can be large, up to 10^9 for a_i.
        // current_sum can be up to 10^5 * 10^9 = 10^14.
        // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
        // b2 can be up to 10^14 + 10^9, which fits in long long (max 9*10^18).

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

