        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current_val_0 and current_val_1 for each bit.
    // current_val_0[b] stores the final state of bit b if initial bit b was 0.
    // current_val_1[b] stores the final state of bit b if initial bit b was 1.
    // Initially, if bit b was 0, it's 0. If bit b was 1, it's 1.
    std::vector<int> current_val_0(10); // All zeros
    std::vector<int> current_val_1(10); // All ones
    for (int i = 0; i < 10; ++i) {
        current_val_1[i] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int b = 0; b < 10; ++b) {
            int bit_val = (val >> b) & 1;
            if (op_char == '&') {
                current_val_0[b] &= bit_val;
                current_val_1[b] &= bit_val;
            } else if (op_char == '|') {
                current_val_0[b] |= bit_val;
                current_val_1[b] |= bit_val;
            } else { // '^'
                current_val_0[b] ^= bit_val;
                current_val_1[b] ^= bit_val;
            }
        }
    }

    // Now, for each bit b, we know the mapping:
    // 0 -> current_val_0[b]
    // 1 -> current_val_1[b]

    // We need to find A_AND, A_OR, A_XOR such that:
    // (x & A_AND | A_OR) ^ A_XOR
    // For each bit b:
    // (x_b & (A_AND)_b | (A_OR)_b) ^ (A_XOR)_b = current_val_x_b[b]

    // Let's determine A_AND, A_OR, A_XOR bit by bit.
    int A_AND = 1023; // Initialize to all ones (no effect for AND)
    int A_OR = 0;     // Initialize to all zeros (no effect for OR)
    int A_XOR = 0;    // Initialize to all zeros (no effect for XOR)

    for (int b = 0; b < 10; ++b) {
        int f0 = current_val_0[b]; // Result for input bit 0
        int f1 = current_val_1[b]; // Result for input bit 1

        // We are looking for (x_b & and_b | or_b) ^ xor_b
        // Case 1: x_b = 0
        // (0 & and_b | or_b) ^ xor_b = (0 | or_b) ^ xor_b = or_b ^ xor_b = f0
        // Case 2: x_b = 1
        // (1 & and_b | or_b) ^ xor_b = (and_b | or_b) ^ xor_b = f1

        // From these two equations, we can deduce and_b, or_b, xor_b.
        // There are 4 possible (f0, f1) pairs: (0,0), (0,1), (1,0), (1,1)

        if (f0 == 0 && f1 == 0) { // Both 0 -> 0
            // or_b ^ xor_b = 0  => or_b = xor_b
            // (and_b | or_b) ^ xor_b = 0 => and_b | or_b = xor_b
            // If or_b = xor_b, then and_b | or_b = or_b. This implies and_b must be 0.
            // So, and_b = 0, or_b = 0, xor_b = 0.
            // (x_b & 0 | 0) ^ 0 = 0. This works.
            A_AND &= ~(1 << b); // Set and_b to 0
            // A_OR remains 0 for this bit
            // A_XOR remains 0 for this bit
        } else if (f0 == 0 && f1 == 1) { // 0 -> 0, 1 -> 1 (identity)
            // or_b ^ xor_b = 0  => or_b = xor_b
            // (and_b | or_b) ^ xor_b = 1 => and_b | or_b = 1 ^ xor_b
            // If or_b = xor_b, then and_b | or_b = 1 ^ or_b.
            // This implies and_b must be 1 and or_b must be 0.
            // So, and_b = 1, or_b = 0, xor_b = 0.
            // (x_b & 1 | 0) ^ 0 = x_b. This works.
            // A_AND remains 1 for this bit
            // A_OR remains 0 for this bit
            // A_XOR remains 0 for this bit
        } else if (f0 == 1 && f1 == 0) { // 0 -> 1, 1 -> 0 (NOT)
            // or_b ^ xor_b = 1  => or_b != xor_b
            // (and_b | or_b) ^ xor_b = 0 => and_b | or_b = xor_b
            // If or_b != xor_b, and and_b | or_b = xor_b, then:
            // If or_b = 0, xor_b = 1. Then and_b | 0 = 1 => and_b = 1.
            // So, and_b = 1, or_b = 0, xor_b = 1.
            // (x_b & 1 | 0) ^ 1 = x_b ^ 1. This works.
            // A_AND remains 1 for this bit
            // A_OR remains 0 for this bit
            A_XOR |= (1 << b); // Set xor_b to 1
        } else { // f0 == 1 && f1 == 1 (Both 1 -> 1)
            // or_b ^ xor_b = 1  => or_b != xor_b
            // (and_b | or_b) ^ xor_b = 1 => and_b | or_b = 1 ^ xor_b
            // If or_b != xor_b, and and_b | or_b = 1 ^ xor_b, then:
            // If or_b = 1, xor_b = 0. Then and_b | 1 = 1 ^ 0 = 1. This is always true for any and_b.
            // So, and_b = 0 (to be minimal), or_b = 1, xor_b = 0.
            // (x_b & 0 | 1) ^ 0 = 1. This works.
            A_AND &= ~(1 << b); // Set and_b to 0
            A_OR |= (1 << b);   // Set or_b to 1
            // A_XOR remains 0 for this bit
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_AND != 1023) { // If A_AND is not all ones, we need an AND operation
        result_ops.push_back({'&', A_AND});
    }
    if (A_OR != 0) { // If A_OR is not all zeros, we need an OR operation
        result_ops.push_back({'|', A_OR});
    }
    if (A_XOR != 0) { // If A_XOR is not all zeros, we need an XOR operation
        result_ops.push_back({'^', A_XOR});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

