#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop, >=0: final y
    std::vector<int> dp_x(n + 1, 0);     // 0: uncomputed, -1: infinite loop, >0: final x

    // Base cases for DP:
    // If x + a[x] takes it out of bounds, it terminates.
    // If x - a[x] takes it out of bounds, it terminates.
    // For x = 1, a[1] is variable.
    // For x > 1, a[x] is fixed.

    // Iterate x from 2 to n.
    // For each x, we want to find the result of starting the sequence of operations
    // with x as the current position, and y as the current accumulated value.
    // The problem states that the sequence of operations is:
    // 1. x = x + a[x], y = y + a[x]
    // 2. y = y + a[x], x = x - a[x]
    // This means the value a[x] is used twice for y, and once for x (add), once for x (subtract).
    // The state after these two steps is (x - a[x] + a[x], y + a[x] + a[x]) = (x, y + 2*a[x])
    // No, this is wrong. The problem states:
    // 1. x = x + a[x], y = y + a[x] (let's call this x_new, y_new)
    // 2. y = y_new + a[x_new], x = x_new - a[x_new]
    // So the value a[x] is used for the first step.
    // The value a[x_new] is used for the second step.

    // Let's define solve(current_x, current_y) as the function that returns the final y.
    // We need to compute this for initial (1, 0) with a[1] = i.
    // The state is (x, y).
    // The sequence of operations is:
    // 1. x_next = x + a[x], y_next = y + a[x]
    // 2. If x_next <= 0 or x_next > n, return y_next.
    // 3. x_final = x_next - a[x_next], y_final = y_next + a[x_next]
    // 4. If x_final <= 0 or x_final > n, return y_final.
    // 5. Else, recurse on (x_final, y_final).

    // We can use DP for states (x, y) where y is the accumulated sum from previous steps.
    // However, y can be very large. The key observation is that y only accumulates.
    // The state that determines the next step is only x.
    // So, we can define dp_y[x] as the *additional* y accumulated from state x until termination,
    // and dp_x[x] as the *final* x when starting from state x.
    // The total y will be initial_y + dp_y[x].

    // Let's compute dp_y[x] and dp_x[x] for x from 2 to n.
    // For a given x (current_x):
    // Step 1: x_add = current_x + a[current_x], y_add_val = a[current_x]
    // If x_add <= 0 or x_add > n:
    //   dp_y[current_x] = y_add_val
    //   dp_x[current_x] = x_add
    // Else:
    //   Step 2: x_sub = x_add - a[x_add], y_sub_val = a[x_add]
    //   If x_sub <= 0 or x_sub > n:
    //     dp_y[current_x] = y_add_val + y_sub_val
    //     dp_x[current_x] = x_sub
    //   Else:
    //     // We need to know dp_y[x_sub] and dp_x[x_sub].
    //     // This is a recursive call.
    //     // Since x_sub can be smaller or larger than current_x, we need memoization.
    //     // The values a[i] are positive, so x_add > current_x.
    //     // x_sub can be anything.
    //     // If x_sub == current_x, it's an infinite loop.
    //     // If x_sub is visited during the current path, it's an infinite loop.

    std::vector<bool> visited(n + 1, false); // For cycle detection in current path

    auto solve = [&](int start_x, long long initial_y, auto& self) -> long long {
        int current_x = start_x;
        long long current_y = initial_y;

        std::vector<int> path; // To detect cycles in the current path

        while (true) {
            if (current_x <= 0 || current_x > n) {
                return current_y;
            }

            // Check if this state has been computed
            if (dp_y[current_x] != -2) {
                if (dp_y[current_x] == -1) { // Infinite loop detected
                    return -1;
                }
                // State already computed, add its contribution and return
                return current_y + dp_y[current_x];
            }

            // Check for cycle in current path
            if (visited[current_x]) {
                // Cycle detected, mark all nodes in this cycle as -1 (infinite loop)
                for (int node : path) {
                    dp_y[node] = -1;
                }
                return -1;
            }

            visited[current_x] = true;
            path.push_back(current_x);

            long long val_a_x = a[current_x];
            int x_after_add = current_x + val_a_x;
            long long y_after_add = current_y + val_a_x;

            if (x_after_add <= 0 || x_after_add > n) {
                // Terminate after first step
                // Store result for current_x
                dp_y[current_x] = y_after_add - initial_y;
                dp_x[current_x] = x_after_add;
                visited[current_x] = false; // Backtrack visited
                return y_after_add;
            }

            long long val_a_x_add = a[x_after_add];
            int x_after_sub = x_after_add - val_a_x_add;
            long long y_after_sub = y_after_add + val_a_x_add;

            // Move to the next state
            current_x = x_after_sub;
            current_y = y_after_sub;
        }
    };

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for this run
        std::fill(dp_y.begin(), dp_y.end(), -2); // Reset DP table
        std::fill(dp_x.begin(), dp_x.end(), 0);
        std::fill(visited.begin(), visited.end(), false); // Reset visited for cycle detection

        // The actual solve function needs to store results in dp_y and dp_x
        // Let's refine the solve function to return a pair (final_x, final_y_diff)
        // or (-1, -1) for infinite loop.

        std::vector<std::pair<long long, int>> memo(n + 1, {-2, 0}); // {y_diff, final_x}

        // This lambda will compute the result for a given starting x,
        // assuming initial y is 0. It returns {y_diff, final_x}
        // y_diff is the total y accumulated from this point.
        // final_x is the x value at termination.
        // If infinite loop, returns {-1, -1}.
        auto compute_path = [&](int start_node, auto& self_ref) -> std::pair<long long, int> {
            if (start_node <= 0 || start_node > n) {
                return {0, start_node}; // Terminated, 0 additional y, x is start_node
            }
            if (memo[start_node].first != -2) {
                return memo[start_node]; // Already computed
            }
            if (visited[start_node]) {
                return memo[start_node] = {-1, -1}; // Cycle detected
            }

            visited[start_node] = true;

            long long val_a_x = a[start_node];
            int x_add = start_node + val_a_x;
            long long y_add_val = val_a_x;

            if (x_add <= 0 || x_add > n) {
                visited[start_node] = false; // Backtrack
                return memo[start_node] = {y_add_val, x_add};
            }

            long long val_a_x_add = a[x_add];
            int x_sub = x_add - val_a_x_add;
            long long y_sub_val = val_a_x_add;

            std::pair<long long, int> next_res = self_ref(x_sub, self_ref);
            visited[start_node] = false; // Backtrack

            if (next_res.first == -1) { // Infinite loop
                return memo[start_node] = {-1, -1};
            } else {
                return memo[start_node] = {y_add_val + y_sub_val + next_res.first, next_res.second};
            }
        };

        std::pair<long long, int> result = compute_path(1, compute_path);
        std::cout << result.first << "\n";
    }

    return 0;
}

