#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            continue;
        }

        // For each '1' at index i, consider it as the start of a potential good substring.
        // The substring is s[i...j].
        // Its length is len = j - i + 1.
        // Its value is val = f(s[i...j]).
        // We need len = val.

        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            int len = j - i + 1;

            // Update current_val: current_val = current_val * 2 + (s[j] - '0')
            // Check for overflow before multiplication.
            // If current_val * 2 + 1 exceeds 2 * n, then any further extension
            // will also exceed 2 * n.
            // The maximum possible length is n.
            // If val > n, then len = val is impossible since len <= n.
            // However, val can be up to 2*n to allow for some '0's before the '1'
            // that makes it equal to len.
            // The maximum possible value for len is n.
            // If current_val exceeds n + MAX_LEADING_ZEROS_TO_CHECK, we can stop.
            // MAX_LEADING_ZEROS_TO_CHECK is around 20 for n=2e5.
            // So if current_val > n + 20, we can break.
            // A safer upper bound for current_val is 2*n, because if val > n,
            // then len = val is impossible.
            // But we need to consider the case where val is slightly larger than n,
            // and we might have leading zeros before the first '1' of the substring.
            // The maximum length of a substring is N.
            // The maximum value of a binary string of length L is 2^L - 1.
            // If L = 20, 2^L - 1 is about 10^6.
            // If L = 18, 2^L - 1 is about 2.6 * 10^5.
            // So if len > 18, val will be much larger than len.
            // We only need to check for len up to about 18-20.
            // Let's use a slightly larger bound, say 2 * n.
            // If current_val becomes too large, it will never equal len.
            // The maximum len is n.
            // If current_val > n + 20 (a safe upper bound for max_len + max_leading_zeros_to_check),
            // we can break.
            // A simpler bound: if current_val > 2 * n, it's definitely too large.
            // For n=2e5, 2*n = 4e5. This fits in long long.
            if (current_val > 2 * n) { // Optimization: if value is too large, it can't be equal to len
                break;
            }

            current_val = current_val * 2 + (s[j] - '0');

            if (current_val == len) {
                count++;
            }
        }
    }

    // Handle substrings consisting only of '0's.
    // A substring s[l...r] of all '0's has value 0.
    // Its length is len = r - l + 1.
    // We need len = 0, which is impossible for a non-empty substring.
    // So, no good substrings consist only of '0's.

    // Now, consider substrings s[l...r] where s[l] is '0'.
    // These substrings have leading zeros.
    // Let s[l...r] be such a substring.
    // Its value is f(s[l...r]).
    // Its length is len = r - l + 1.
    // We need len = f(s[l...r]).

    // Iterate through all possible starting positions l.
    // If s[l] is '0', we need to find the first '1' in s[l...r].
    // Let this be at index k. So s[k] = '1' and s[l...k-1] are all '0's.
    // The value f(s[l...r]) is f(s[k...r]).
    // The length is r - l + 1.
    // We need r - l + 1 = f(s[k...r]).

    // We can iterate through all possible ending positions r.
    // For each r, we look for '1's to its left.
    // Let's find the previous '1' for each position.
    std::vector<int> prev_one(n);
    int last_one_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            last_one_idx = i;
        }
        prev_one[i] = last_one_idx;
    }

    for (int r = 0; r < n; ++r) {
        // If s[r] is '0', we can potentially extend a substring ending at r.
        // If s[r] is '1', it's already handled by the first loop (where s[i] was '1').
        // The first loop counts substrings s[i...j] where s[i] is '1'.
        // The current loop counts substrings s[l...r] where s[l] is '0' and s[k] is '1' for some k > l.

        // We are looking for substrings s[l...r] where s[l] = '0'.
        // Let k be the index of the first '1' in s[l...r]. So l <= k <= r.
        // The value is f(s[k...r]).
        // The length is r - l + 1.
        // We need r - l + 1 = f(s[k...r]).

