                // s[k] is the first '1' in s[k...r].
                // The value of s[k...r] is current_val.
                // We need to find l such that s[l...k-1] are all '0's.
                // The length is r - l + 1.
                // We need r - l + 1 = current_val.
                // This means l = r + 1 - current_val.

                // Check if l is valid:
                // 1. l >= 0
                // 2. l <= k (because s[k] is the first '1' in s[l...r])
                // 3. s[l...k-1] must all be '0's. This means prev_one[k-1] must be less than l.
                //    (If k=0, then prev_one[-1] is not applicable, but l must be 0, so s[0] is '1' and this case is handled by first loop)

                if (current_val == 0) { // f(s[k...r]) cannot be 0 if s[k]='1'
                    // This case should not happen if s[k]='1'
                    // current_val is built from right to left, so it's 0 only if all chars are '0'
                    // but s[k] is '1'.
                    // This means current_val will be at least 1.
                }

                int l = r + 1 - static_cast<int>(current_val);

                if (l >= 0 && l <= k) {
                    // Check condition 3: s[l...k-1] must be all '0's.
                    // This is true if the last '1' before k is at an index less than l.
                    // If k=0, then prev_one[k-1] is not applicable.
                    // If k > 0, then prev_one[k-1] is the index of the last '1' before k.
                    // If prev_one[k-1] < l, it means all characters from l to k-1 are '0's.
                    if (k == 0 || prev_one[k-1] < l) {
                        count++;
                    }
                }
            }

            // Update current_val for s[k-1...r]
            // current_val = (s[k-1]-'0') * 2^(r-(k-1)) + current_val
            // This is not how f() works. f() is value of s[k...r].
            // When we move k to k-1, the new string is s[k-1...r].
            // The value of s[k-1...r] is (s[k-1]-'0') * 2^(r-(k-1)) + f(s[k...r]).
            // This is equivalent to:
            // current_val = current_val + (s[k-1]-'0') * 2^(r-(k-1))
            // This is wrong. f(s_l...s_r) is sum_{i=0}^{len-1} (s_{r-i}-'0') * 2^i.
            // So f(s_k...s_r) = (s_r-'0')*2^0 + (s_{r-1}-'0')*2^1 + ... + (s_k-'0')*2^(r-k).
            // When k decreases to k-1, the new string is s_{k-1}...s_r.
            // f(s_{k-1}...s_r) = (s_r-'0')*2^0 + ... + (s_k-'0')*2^(r-k) + (s_{k-1}-'0')*2^(r-(k-1)).
            // This is f(s_k...s_r) + (s_{k-1}-'0')*2^(r-(k-1)).
            // This is also wrong.
            // The value of s[k...r] is `val_k`.
            // The value of s[k-1...r] is `val_{k-1}`.
            // `val_{k-1}` = `val_k` + (s[k-1]-'0') * 2^(r-(k-1)).
            // This is correct.
            // The `current_val` in this loop is `f(s[k...r])`.
            // When k decreases, the new `current_val` should be `f(s[k-1...r])`.
            // This is `f(s[k...r]) + (s[k-1]-'0') * 2^(r-(k-1))`.
            // This is `current_val + (s[k-1]-'0') * (1LL << (r-(k-1)))`.
            // This is the correct way to update the value.

            // Check for overflow before adding.
            // If current_val + (1LL << (r-(k-1))) exceeds 2*n, then break.
            // The maximum value of r-(k-1) is n-1. So 1LL << (n-1) can be very large.
            // This approach is problematic because 2^(r-(k-1)) can be huge.
            // Example: s = "000000000000000000001" (20 zeros, then 1)
            // r = 20, k = 20. s[k]='1'. current_val = 1.
            // l = 20+1-1 = 20. Valid. count++.
            // k = 19. s[k]='0'. current_val = 1 + 0 * 2^(20-19) = 1.
            // k = 18. s[k]='0'. current_val = 1 + 0 * 2^(20-18) = 1.
            // This is not how f() works. f() is the value of the binary string.
            // f("01") = 1. f("001") = 1. f("10") = 2.
            // The value of s[k...r] is what we need.
            // The first loop correctly calculates f(s[i...j]) by iterating j.
            // The second loop should also calculate f(s[k...r]) correctly.

            // Let's restart the logic for the second loop.
            // For each r, we want to find l such that s[l...r] is good.
            // This means r - l + 1 = f(s[l...r]).
            // Let k be the first '1' in s[l...r]. So s[l...k-1] are '0's.
            // Then f(s[l...r]) = f(s[k...r]).
            // So we need r - l + 1 = f(s[k...r]).
            // This implies l = r + 1 - f(s[k...r]).
            // We also need l <= k and s[l...k-1] to be all '0's.

            // Iterate k from r down to 0.
            // If s[k] == '1':
            //   Calculate val_k_r = f(s[k...r]).
            //   If val_k_r is too large (e.g., > n + 20), break.
            //   Let l = r + 1 - val_k_r.
            //   If l is valid (0 <= l <= k) AND s[l...k-1] are all '0's (i.e., prev_one[k-1] < l if k > 0):
            //     count++.

            // To calculate f(s[k...r]) efficiently:
            // We can iterate k from r down to 0.
            // Maintain `current_val_suffix` which is f(s[k...r]).
            // Maintain `power_of_2` which is 2^(r-k).
            // When k decreases to k-1:
            // `current_val_suffix` = `current_val_suffix` + (s[k-1]-'0') * `power_of_2`.
            // `power_of_2` = `power_of_2` * 2.
            // This is still problematic because `power_of_2` can overflow.

            // The maximum length of s[k...r] is n.
            // If r-k+1 > 60, then f(s[k...r]) can exceed 2^60, which is too large for long long.
            // But we only care if f(s[k...r]) is around n (2e5).
            // If r-k+1 > 20, then f(s[k...r]) will be at least 2^20 = 10^6, which is > n.
            // So we only need to consider substrings s[k...r] of length at most ~20.
            // This means r-k+1 <= 20, or k >= r - 19.

            // So, for each r, iterate k from max(0, r - 19) up to r.
            // If s[k] == '1':
            //   Calculate val_k_r = f(s[k...r]).
            //   Let l = r + 1 - val_k_r.
            //   If l is valid (0 <= l <= k) AND s[l...k-1] are all '0's (i.e., prev_one[k-1] < l if k > 0):
            //     count++.
        }
    }

    // Re-implement the second part (substrings starting with '0')
    // For each r, iterate k from r down to max(0, r - 20) (or some small constant like 20-25).
    // This ensures that the length of s[k...r] is small, so its value f(s[k...r]) won't overflow
    // and won't be excessively large compared to n.
    // If s[k] is '1', then s[k...r] is a candidate for the '1'-part of a good substring s[l...r].
    // Calculate val = f(s[k...r]).
    // We need r - l + 1 = val. So l = r + 1 - val.
    // Check if l is valid:
    // 1. l >= 0
    // 2. l <= k (because s[k] is the first '1' in s[l...r])
    // 3. All characters s[l...k-1] must be '0's. This means prev_one[k-1] < l (if k > 0).

    for (int r = 0; r < n; ++r) {
        long long current_val_suffix = 0; // This will be f(s[k...r])
        long long power_of_2 = 1; // This will be 2^(r-k)

        // Iterate k from r down to 0.
        // We only need to go back about 20-25 positions because if r-k+1 > 20,
        // then f(s[k...r]) >= 2^20 = 1048576, which is much larger than n (2e5).
        // So, val will be too large to equal len (which is at most n).
        // A safe upper bound for length of s[k...r] is around 20.
        // So k should be at least r - 20.
        for (int k = r; k >= std::max(0, r - 20); --k) { // Max length of s[k...r] is 21
            if (s[k] == '1') {
                current_val_suffix += power_of_2;
            }

            // Now current_val_suffix holds f(s[k...r])
            // If current_val_suffix is 0, it means s[k...r] is all '0's, which is impossible if s[k]='1'.
            // If current_val_suffix is too large, it can't be equal to len.
            // len = r - l + 1. Max len is n.
            // If current_val_suffix > n, then it's impossible for len = current_val_suffix.
            // However, we need to consider the length of the full substring s[l...r], which is r-l+1.
            // The value is f(s[k...r]).
            // So we need r-l+1 = f(s[k...r]).
            // If f(s[k...r]) > n, then it's impossible.
            if (current_val_suffix > n) { // Optimization: if value is too large, it can't be equal to len
                break; // No need to check smaller k values for this r, as current_val_suffix will only grow
            }

            // Calculate l based on the condition: r - l + 1 = current_val_suffix
            int l = r + 1 - static_cast<int>(current_val_suffix);

            // Check validity of l:
            // 1. l must be a valid index: l >= 0
            // 2. s[k] must be the first '1' in s[l...r]: l <= k
            // 3. All characters s[l...k-1] must be '0's.
            //    This is true if the last '1' before k (i.e., prev_one[k-1]) is at an index less than l.
            //    If k=0, then there are no characters before s[k], so this condition is vacuously true.
            if (l >= 0 && l <= k) {
                if (k == 0 || prev_one[k-1] < l) {
                    count++;
                }
            }

            // Prepare for next iteration (k-1):
            // power_of_2 will be 2^(r-(k-1))
            // Check for overflow before multiplying power_of_2.
            // If power_of_2 * 2 exceeds n, it's fine, as long as current_val_suffix doesn't exceed n.
            // The maximum value of power_of_2 needed is 2^20. This fits in long long.
            if (k > 0) { // Only update if k-1 is a valid index
                power_of_2 *= 2;
            }
        }
    }

    std::cout << count << "\n";
}

