    }

    // Second pass: Verify all operations with the chosen `initial_a`.
    // `current_deltas` needs to be reset for this verification pass.
    std::fill(current_deltas.begin(), current_deltas.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_deltas[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

