                min_y = std::max(min_y, y);
            }
            // If robot cannot move right (f3=0), it must end up at X <= x
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If robot cannot move up (f2=0), it must end up at Y <= y
            if (f2 == 0) {
                max_y = std::min(max_y, y);
