long long get_max_reach(long long current_pos, long long time_limit, long long target_pos) {
    if (target_pos < current_pos) { // Moving left
        return current_pos; // If target is left, max reach is current_pos
    } else { // Moving right or staying
        return current_pos + time_limit;
    }
}

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> current_h = h;
    int p_idx = 0;
    int h_idx = 0;

    while (p_idx < m) {
        if (h_idx >= n) {
            return false; // No more heads to cover remaining tracks
        }

        long long current_head_pos = current_h[h_idx];
        long long p_val = p[p_idx];

        // Case 1: Current head can cover p_val by moving left or staying
        if (p_val <= current_head_pos + T) {
            // The head can reach p_val.
            // Now, find the maximum track this head can cover to the right.
            // This head will move to cover p_val, and then continue right as much as possible.
            // The total distance moved is T.
            // If p_val is to the left of current_head_pos, say current_head_pos - k,
            // then k steps are used to reach p_val. Remaining steps: T - k.
            // Max right reach: p_val + (T - k) = p_val + T - (current_head_pos - p_val) = 2*p_val + T - current_head_pos.
            // This is equivalent to: current_head_pos + T - 2 * std::max(0LL, current_head_pos - p_val)
            // Or simply, the head moves to p_val, then moves right for T - abs(current_head_pos - p_val) steps.
            long long max_right_reach = p_val + (T - std::abs(current_head_pos - p_val));

            // Consume all p_i that can be covered by this head
            while (p_idx < m && p[p_idx] <= max_right_reach) {
                p_idx++;
            }
            h_idx++; // Move to the next head
        } else {
            // Current head cannot reach p_val.
            // This head must be used to cover tracks to its right, or it's too far left.
            // If p_val is too far right for current_head_pos + T, then this head cannot cover p_val.
            // We must use the next head.
            h_idx++;
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max coord) + 10^10 (max coord)
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    int id;
    long long v, d, p;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_in_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_in_line.push_back({i + 1, v_val, d_val, p_val});
    }

    std::vector<int> cured_children_ids;

    while (!children_in_line.empty()) {
        Child current_child = children_in_line.front();
        children_in_line.pop_front();
        cured_children_ids.push_back(current_child.id);

        long long v_cry_effect = current_child.v;
        long long d_cry_chain_effect = 0;

        auto it = children_in_line.begin();
        while (it != children_in_line.end()) {
            // Apply chain reaction cry effect from previous children who left
            it->p -= d_cry_chain_effect;

            // Apply current child's cry effect
            if (v_cry_effect > 0) {
                it->p -= v_cry_effect;
                v_cry_effect--;
            }

            if (it->p < 0) {
                d_cry_chain_effect += it->d;
                it = children_in_line.erase(it); // Child leaves, iterator invalidated
            } else {
                ++it; // Move to the next child
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

