#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();
    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // min_r_for_l[i] stores the minimum r (1-indexed) such that s[i..r] contains the pattern.
    // If no such r exists, it remains n+1.
    std::vector<int> min_r_for_l(n + 1, n + 1);

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through all possible k values
        // The maximum possible k is such that x + 2k < n
        // So 2k < n - x, k < (n - x) / 2
        // We can limit k to a small constant, say 20, because for larger k,
        // the pattern x, x+k, x+2k would be very spread out.
        // If k is large, say k >= 20, then x+2k >= x+40.
        // If such a pattern exists, it would imply that for any l,
        // the minimum r would be at least x+2k.
        // The problem constraints on N (300,000) suggest that an O(N*K_small) approach
        // for finding the first occurrence of the pattern might be feasible.
        // Let's check k up to 20.
        // If k > 20, then x+2k - x = 2k > 40.
        // The maximum length of a substring without the pattern is bounded.
        // It's known that any binary string of length 40 must contain a 3-term arithmetic progression.
        // This means if a pattern exists, it must exist within a relatively small window.
        // So, we only need to check k up to a small constant, say 20.
        // The actual bound is 9 for binary strings.
        // For example, 0011001100110011001100110011001100110011 (length 40) has no pattern.
        // 00110011001100110011001100110011001100110 (length 41) has 0_1 0_21 0_41.
        // So, k can be up to (40-1)/2 = 19.
        // Let's use a slightly larger bound, say 25, to be safe.
        for (int k = 1; k <= 25 && x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern s_x = s_{x+k} = s_{x+2k}
                // This pattern starts at index x (0-indexed) and ends at index x+2k (0-indexed).
                // For any l (1-indexed) such that l <= x+1,
                // the minimum r (1-indexed) required to contain this pattern is x+2k+1.
                // So, for l from 1 to x+1, we update min_r_for_l[l].
                int current_r_val = x + 2 * k + 1; // 1-indexed end of pattern
                for (int l_idx = 0; l_idx <= x; ++l_idx) { // l_idx is 0-indexed start of substring
                    min_r_for_l[l_idx + 1] = std::min(min_r_for_l[l_idx + 1], current_r_val);
                }
            }
        }
    }

    // Calculate invalid pairs
    // An invalid pair (l, r) is one where s[l..r] does NOT contain the pattern.
    // This means r < min_r_for_l[l].
    // For each l (1-indexed), the number of invalid r's is min_r_for_l[l] - l.
    // If min_r_for_l[l] is n+1, it means no pattern exists starting at or after l,
    // so all r from l to n are invalid. The count is n - l + 1.
    // This is correctly handled by min_r_for_l[l] - l.
    for (int l = 1; l <= n; ++l) {
        invalid_pairs += (min_r_for_l[l] - l);
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <iostream>
