    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long count = 0;

        // Use as many 5s as possible
        count += diff / 5;
        diff %= 5;

        // Handle remaining diff (0, 1, 2, 3, 4)
        if (diff == 1 || diff == 2) {
