#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // This means all f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long min_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
    std::vector<int> best_partition(n, 1); // All in subsequence 1

    // Case 2: At least one element in each subsequence.
    // This means there will be f values of type a_i + a_j and a_i + a_j + h.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-1].value + a[n-2].value + h.
    // The minimum f value of type a_i + a_j + h is a[0].value + a[1].value + h.
    // The maximum f value of type a_i + a_j is a[n-1].value + a[n-2].value.

    // Consider the partition where a[0] is in subsequence 2, and all other elements are in subsequence 1.
    // min_f:
    //   - a[0] + a[1] + h (diff subs)
    //   - a[1] + a[2] (same subs)
    //   So, min_f = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    // max_f:
    //   - a[n-1] + a[n-2] (same subs)
    //   - a[n-1] + a[0] + h (diff subs)
    //   So, max_f = std::max(a[n-1].value + a[n-2].value, a[n-1].value + a[0].value + h)

    // Let's analyze the minimum and maximum values for this specific partition:
    // Subsequence 1: {a[1], a[2], ..., a[n-1]}
    // Subsequence 2: {a[0]}
    //
    // Pairs within subsequence 1: (a_i, a_j) where i, j >= 1.
    //   Min sum: a[1].value + a[2].value
    //   Max sum: a[n-1].value + a[n-2].value
    //
    // Pairs between subsequence 1 and subsequence 2: (a[0], a_j) where j >= 1.
    //   Min sum: a[0].value + a[1].value + h
    //   Max sum: a[0].value + a[n-1].value + h
    //
    // Overall min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // Overall max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //
    // Goodness = max_f - min_f

    long long current_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    long long current_max_f = std::max(a[n - 1].value + a[n - 2].value, a[0].value + a[n - 1].value + h);
    long long current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        std::fill(best_partition.begin(), best_partition.end(), 1);
        best_partition[a[0].original_index] = 2;
    }

    // Consider the partition where a[n-1] is in subsequence 2, and all other elements are in subsequence 1.
    // Subsequence 1: {a[0], a[1], ..., a[n-2]}
    // Subsequence 2: {a[n-1]}
    //
    // Pairs within subsequence 1: (a_i, a_j) where i, j <= n-2.
    //   Min sum: a[0].value + a[1].value
    //   Max sum: a[n-2].value + a[n-3].value
    //
    // Pairs between subsequence 1 and subsequence 2: (a[n-1], a_j) where j <= n-2.
    //   Min sum: a[n-1].value + a[0].value + h
    //   Max sum: a[n-1].value + a[n-2].value + h
    //
    // Overall min_f = std::min(a[0].value + a[1].value, a[n-1].value + a[0].value + h)
    // Overall max_f = std::max(a[n-2].value + a[n-3].value, a[n-1].value + a[n-2].value + h)
    //
    // Goodness = max_f - min_f

    current_min_f = std::min(a[0].value + a[1].value, a[n - 1].value + a[0].value + h);
    current_max_f = std::max(a[n - 2].value + a[n - 3].value, a[n - 1].value + a[n - 2].value + h);
    current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        std::fill(best_partition.begin(), best_partition.end(), 1);
        best_partition[a[n - 1].original_index] = 2;
    }

    // Consider the partition where a[0] and a[n-1] are in subsequence 2, and all other elements are in subsequence 1.
    // Subsequence 1: {a[1], ..., a[n-2]}
    // Subsequence 2: {a[0], a[n-1]}
    //
    // If n=2, this is the same as Case 1 (all in one subseq).
    // If n=3, Subseq 1: {a[1]}, Subseq 2: {a[0], a[2]}.
    //   Pairs within Subseq 1: None.
    //   Pairs within Subseq 2: a[0]+a[2].
    //   Pairs between: a[0]+a[1]+h, a[1]+a[2]+h.
    //   min_f = min(a[0]+a[2], a[0]+a[1]+h, a[1]+a[2]+h)
    //   max_f = max(a[0]+a[2], a[0]+a[1]+h, a[1]+a[2]+h)
    //   Goodness = max_f - min_f

    if (n >= 2) { // This partition is only distinct if n >= 2
        long long min_f_val, max_f_val;

        // Values from pairs within subsequence 1 (a[1]...a[n-2])
        long long min_same1 = -1, max_same1 = -1;
        if (n - 2 >= 2) { // If there are at least 2 elements in subseq 1
            min_same1 = a[1].value + a[2].value;
            max_same1 = a[n - 2].value + a[n - 3].value;
        }

        // Values from pairs within subsequence 2 (a[0], a[n-1])
        long long min_same2 = a[0].value + a[n - 1].value;
        long long max_same2 = a[0].value + a[n - 1].value;

        // Values from pairs between subsequences (a[0] or a[n-1] with a[1]...a[n-2])
        long long min_diff = -1, max_diff = -1;
        if (n - 2 >= 1) { // If there is at least 1 element in subseq 1
            min_diff = a[0].value + a[1].value + h;
            max_diff = a[n - 1].value + a[n - 2].value + h;
        } else { // n=2, subseq 1 is empty. Only a[0], a[n-1] in subseq 2.
            // This case is covered by Case 1 (all in one subseq)
            // and also by the previous two cases (one element in subseq 2).
            // If n=2, a[0] and a[1] are the only elements.
            // If a[0] in subseq 2, a[1] in subseq 1: f(a[0],a[1]) = a[0]+a[1]+h. min_f=max_f=a[0]+a[1]+h. Goodness=0.
            // If a[0], a[1] in subseq 1: f(a[0],a[1]) = a[0]+a[1]. min_f=max_f=a[0]+a[1]. Goodness=0.
            // The goodness is 0 if n=2.
            // The current min_goodness will be 0 if n=2.
        }

        // Determine overall min_f and max_f
        std::vector<long long> candidates_min, candidates_max;
        if (min_same1 != -1) {
            candidates_min.push_back(min_same1);
            candidates_max.push_back(max_same1);
        }
        candidates_min.push_back(min_same2);
        candidates_max.push_back(max_same2);
        if (min_diff != -1) {
            candidates_min.push_back(min_diff);
            candidates_max.push_back(max_diff);
        }

        if (!candidates_min.empty()) {
            min_f_val = candidates_min[0];
            for (size_t i = 1; i < candidates_min.size(); ++i) {
                min_f_val = std::min(min_f_val, candidates_min[i]);
            }
            max_f_val = candidates_max[0];
            for (size_t i = 1; i < candidates_max.size(); ++i) {
                max_f_val = std::max(max_f_val, candidates_max[i]);
            }

            current_goodness = max_f_val - min_f_val;

            if (current_goodness < min_goodness) {
                min_goodness = current_goodness;
                std::fill(best_partition.begin(), best_partition.end(), 1);
                best_partition[a[0].original_index] = 2;
                best_partition[a[n - 1].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[a[i].original_index] = a[i].value;
            y[a[i].original_index] = b[(i + n - 1) % n].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
