#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of costs can exceed int if n is large, though here n is also 100.
                     // Using long long for d and days_remaining is safer for intermediate calculations.
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];
        long long days_remaining = d;

        for (int i = 1; i < n; ++i) { // Iterate from pile 2 (index 1) to pile n (index n-1)
            int pile_index = i;
            int haybales_in_pile = a[pile_index];
            long long cost_per_haybale = pile_index; // Cost to move from pile (index+1) to pile 1 is index days

            if (cost_per_haybale == 0) { // This case should only happen for pile 1 itself, which is skipped
                continue;
            }

            if (days_remaining >= cost_per_haybale) {
                // Calculate how many haybales can be moved from this pile
                long long haybales_possible_to_move = days_remaining / cost_per_haybale;

                long long haybales_to_move = std::min((long long)haybales_in_pile, haybales_possible_to_move);

                current_a1 += haybales_to_move;
                days_remaining -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

