int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_R_pos = -1; // Represents the last 'R' cell index, or -1 for cell 0.
                             // The distance from last_R_pos to the current 'R' cell
                             // must be covered by d.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed).
                // The distance from the previous 'R' cell (or 0) to this 'R' cell
                // is (i+1) - (last_R_pos + 1) + 1 = i - last_R_pos.
                // If last_R_pos was -1 (meaning we are coming from cell 0),
                // the distance is (i+1) - 0 = i+1.
                // This is equivalent to (i+1) - (last_R_pos + 1) + 1 if last_R_pos is -1,
                // then last_R_pos + 1 = 0. So (i+1) - 0 = i+1.
                // The distance is (current_cell_idx) - (previous_cell_idx).
                // current_cell_idx is i+1.
                // previous_cell_idx is last_R_pos + 1 (if last_R_pos is not -1).
                // If last_R_pos is -1, previous_cell_idx is 0.
                // So, the distance is (i+1) - (last_R_pos == -1 ? 0 : last_R_pos + 1).
                // This simplifies to (i+1) - (last_R_pos + 1) if we consider last_R_pos as -1 for cell 0.
                // The actual distance is (i+1) - (last_R_pos + 1) + 1.
                // Let's use 0-indexed positions for calculation:
                // The previous "safe" position was `last_R_pos`.
                // The current "safe" position is `i`.
                // The distance between them is `i - last_R_pos`.
                // We need to be able to jump from `last_R_pos` to `i`.
                // The required `d` must be at least `i - last_R_pos`.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // to the target cell n+1.
        // The last 'R' cell was at index `last_R_pos`.
        // The target cell is `n+1`.
        // The distance from `last_R_pos` to `n+1` is `(n+1) - (last_R_pos + 1)`.
        // This is `n - last_R_pos`.
        max_dist = std::max(max_dist, n - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

