#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int suffix_start_idx = n - 1;

    // Find the end of the non-increasing suffix
    while (suffix_start_idx > 0 && a[suffix_start_idx - 1] >= a[suffix_start_idx]) {
        suffix_start_idx--;
    }

    // Find the end of the non-decreasing suffix
    while (suffix_start_idx > 0 && a[suffix_start_idx - 1] <= a[suffix_start_idx]) {
        suffix_start_idx--;
    }

    std::cout << suffix_start_idx << std::endl;
}

