    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements of the original array (sorted)
    int right_ptr = 0; // Pointer for elements to be placed (from the sorted array)
    while (right_ptr < n) {
        if (a[right_ptr] > a[left_ptr]) {
            // If the element at right_ptr is greater than the element at left_ptr,
            // we can place a[right_ptr] at the position where a[left_ptr] originally stood.
            // This contributes to our count.
            count++;
            left_ptr++; // Move to the next position in the original array
            right_ptr++; // Move to the next available element to place
        } else {
            // If a[right_ptr] is not greater than a[left_ptr],
            // we cannot use a[right_ptr] for the current a[left_ptr] position.
            // We need a larger element, so we try the next element from the sorted array.
            right_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    std::vector<std::string> result(4);

    long long total_toys = a + b + c + d;

    if (total_toys == 1) {
        result[0] = (a == 1) ? "Ya" : "Tidak";
        result[1] = (b == 1) ? "Ya" : "Tidak";
        result[2] = (c == 1) ? "Ya" : "Tidak";
        result[3] = (d == 1) ? "Ya" : "Tidak";
    } else {
        // Box 1: (-inf, -1]
        // Can be reached if final product is negative and magnitude >= 1.
        // Final product is negative if odd number of negative factors.
        // Final product magnitude >= 1 if at least one factor has magnitude >= 1,
        // or if all factors have magnitude < 1 but their product eventually grows >= 1.
        // This is the most complex case.
        // A toy in Box 1 or Box 2 is negative.
        // A toy in Box 3 or Box 4 is positive.
        // Number of negative toys: a + b
        // If (a + b) is odd, final product is negative.
        // If (a + b) is even, final product is positive.

        // For Box 1 (negative, magnitude >= 1):
        // Need (a+b) to be odd.
        // Need to be able to get magnitude >= 1.
        // If a > 0 or d > 0, we have at least one toy with magnitude >= 1.
        // If a=0 and d=0, all initial toys have magnitude < 1.
        // In this case, the final product will always have magnitude < 1.
        // So, if a=0 and d=0, Box 1 is impossible.
        // If a > 0 or d > 0:
        //   If (a+b) is odd, Box 1 is possible.
        //   If (a+b) is even, Box 1 is impossible (final product positive).
        // Exception: if a=1, b=0, c=0, d=0, then total_toys=1, handled above.
        // If a=0, b=0, c=0, d=0, not allowed by A+B+C+D > 0.

        bool box1_possible = false;
        if ((a + b) % 2 != 0) { // Final product must be negative
            if (a > 0 || d > 0) { // At least one initial toy has magnitude >= 1
                box1_possible = true;
            } else { // All initial toys have magnitude < 1 (b > 0 or c > 0)
                // If all initial toys have magnitude < 1, the final product will also have magnitude < 1.
                // So, it cannot be in Box 1.
                box1_possible = false;
            }
        }
        result[0] = box1_possible ? "Ya" : "Tidak";

        // Box 2: (-1, 0)
        // Can be reached if final product is negative and magnitude < 1.
        // Need (a+b) to be odd.
        // Need to be able to get magnitude < 1.
        // This is always possible unless all initial toys have magnitude >= 1 (i.e., b=0 and c=0).
        // If b=0 and c=0, and a+d > 0, then all toys have magnitude >= 1.
        // The product of two toys with magnitude >= 1 is >= 1.
        // So if b=0 and c=0, the final product will have magnitude >= 1.
        // Thus, if b=0 and c=0, Box 2 is impossible.
        // If b > 0 or c > 0:
        //   If (a+b) is odd, Box 2 is possible.
        //   If (a+b) is even, Box 2 is impossible (final product positive).

        bool box2_possible = false;
        if ((a + b) % 2 != 0) { // Final product must be negative
            if (b > 0 || c > 0) { // At least one initial toy has magnitude < 1
                box2_possible = true;
            } else { // All initial toys have magnitude >= 1 (a > 0 or d > 0)
                // If all initial toys have magnitude >= 1, the final product will also have magnitude >= 1.
                // So, it cannot be in Box 2.
                box2_possible = false;
            }
        }
        result[1] = box2_possible ? "Ya" : "Tidak";

        // Box 3: (0, 1)
        // Can be reached if final product is positive and magnitude < 1.
        // Need (a+b) to be even.
        // Need to be able to get magnitude < 1.
        // This is always possible unless all initial toys have magnitude >= 1 (i.e., b=0 and c=0).
        // If b=0 and c=0, then all toys have magnitude >= 1. The product will be >= 1.
        // So if b=0 and c=0, Box 3 is impossible.
        // If b > 0 or c > 0:
        //   If (a+b) is even, Box 3 is possible.
        //   If (a+b) is odd, Box 3 is impossible (final product negative).

        bool box3_possible = false;
        if ((a + b) % 2 == 0) { // Final product must be positive
            if (b > 0 || c > 0) { // At least one initial toy has magnitude < 1
                box3_possible = true;
            } else { // All initial toys have magnitude >= 1 (a > 0 or d > 0)
                // If all initial toys have magnitude >= 1, the final product will also have magnitude >= 1.
                // So, it cannot be in Box 3.
                box3_possible = false;
            }
        }
        result[2] = box3_possible ? "Ya" : "Tidak";

        // Box 4: [1, inf)
        // Can be reached if final product is positive and magnitude >= 1.
        // Need (a+b) to be even.
        // Need to be able to get magnitude >= 1.
        // This is always possible unless all initial toys have magnitude < 1 (i.e., a=0 and d=0).
        // If a=0 and d=0, then all toys have magnitude < 1. The product will be < 1.
        // So if a=0 and d=0, Box 4 is impossible.
        // If a > 0 or d > 0:
        //   If (a+b) is even, Box 4 is possible.
        //   If (a+b) is odd, Box 4 is impossible (final product negative).

        bool box4_possible = false;
        if ((a + b) % 2 == 0) { // Final product must be positive
            if (a > 0 || d > 0) { // At least one initial toy has magnitude >= 1
                box4_possible = true;
            } else { // All initial toys have magnitude < 1 (b > 0 or c > 0)
                // If all initial toys have magnitude < 1, the final product will also have magnitude < 1.
                // So, it cannot be in Box 4.
                box4_possible = false;
            }
        }
        result[3] = box4_possible ? "Ya" : "Tidak";
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

