#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // ending at index i, if we were to make a[i] = i.
    // This means a[0] >= 0, a[1] >= 1, ..., a[i] >= i.
    // Let's call this 'left_reach'.
    // left_reach[i] = true if a[i] can be made to be 'i' (or more)
    // while maintaining a[j] = j for j < i.
    // More accurately, it's the maximum length of a strictly increasing prefix
    // starting from index 0.
    // We need a[i] >= i for the prefix 0, 1, ..., i to be possible.
    // If a[i] < i, then we cannot form 0, 1, ..., i.
    // The actual values don't have to be 0, 1, ..., i.
    // They just need to be strictly increasing.
    // The minimum values for a strictly increasing sequence of length L starting at index 0
    // would be 0, 1, ..., L-1.
    // So, we need a[i] >= i for all i in the prefix.

    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len = i + 1;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // starting at index i, if we were to make a[i] = n-1-i.
    // This means a[n-1] >= 0, a[n-2] >= 1, ..., a[i] >= n-1-i.
    // Let's call this 'right_reach'.
    // The minimum values for a strictly decreasing sequence of length L ending at index n-1
    // would be L-1, L-2, ..., 0.
    // So, we need a[i] >= n-1-i for all i in the suffix.

    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_len = n - i;
        } else {
            break;
        }
    }

    // A sharpened array requires a peak k (1-indexed, so k-1 is 0-indexed).
    // The left part is a_0 < a_1 < ... < a_{k-1}.
    // The right part is a_{k-1} > a_k > ... > a_{n-1}.
    // The length of the left part is k.
    // The length of the right part is n - (k-1).
    // The total length of the array is n.
    // The peak element a_{k-1} is part of both the increasing prefix and the decreasing suffix.
    // The increasing prefix has length `left_len`. This means we can form `0, 1, ..., left_len-1`.
    // The decreasing suffix has length `right_len`. This means we can form `right_len-1, ..., 1, 0` from right to left.
    // If we can find a peak `k-1` (0-indexed) such that it's covered by both `left_len` and `right_len`,
    // then it's possible.
    // The peak `k-1` must be reachable from the left (i.e., `k-1 < left_len`).
    // The peak `k-1` must be reachable from the right (i.e., `n-(k-1) <= right_len`).
    // This means `k-1` must be an index `i` such that `i < left_len` AND `n-1-i < right_len`.
    // Or, more simply, the total length of the array must be less than or equal to the sum of the
    // maximum possible increasing prefix length and maximum possible decreasing suffix length,
    // minus one (because the peak element is counted in both).
    // `left_len + right_len - 1 >= n`
    // This condition means there is at least one index `i` that is part of both the
    // `left_len` prefix and `right_len` suffix.
    // The indices covered by `left_len` are `0, ..., left_len-1`.
    // The indices covered by `right_len` are `n-right_len, ..., n-1`.
    // We need these two ranges to overlap.
    // The first index of the right_len range is `n-right_len`.
    // The last index of the left_len range is `left_len-1`.
    // Overlap exists if `n-right_len <= left_len-1`.
    // Which simplifies to `n <= left_len + right_len - 1`.

    if (left_len + right_len - 1 >= n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
