#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            if (discriminant < 0) { // Should not happen if d >= 4, but for floating point safety
                std::cout << "N\n";
            } else {
                double sqrt_discriminant = std::sqrt(discriminant);
                double a = (d + sqrt_discriminant) / 2.0;
                double b = (d - sqrt_discriminant) / 2.0;

                // Ensure a and b are non-negative.
                // Since d >= 4, d^2 >= 4d, so d^2 - 4d >= 0.
                // sqrt(d^2 - 4d) <= d (because d^2 - 4d <= d^2).
                // So d - sqrt(d^2 - 4d) >= 0.
                // Thus, both a and b will be non-negative.

                std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
            }
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the range is just pos[1].
        // For m > 1, we need to expand the range to include m.
        // The numbers 1 to m-1 are already covered by current_min_idx and current_max_idx.
        // We need to include m.
        // The new min_idx will be min(current_min_idx, pos[m])
        // The new max_idx will be max(current_max_idx, pos[m])

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1 to m.
        // This means its length must be m.
        // Length = current_max_idx - current_min_idx + 1
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

