// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // The problem statement implies that patterns are always 18 digits long
    // by saying "length no more than 18" for query patterns and
    // "supplemented with 0-s from the left" for both.
    // A fixed length of 18 (max digits for 10^18-1) simplifies matching.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern to 18 digits with '0's from the left
            // This means appending '0's to the right of the reversed pattern string
            while (s.length() < 18) {
                s = '0' + s;
            }
            // The to_parity_pattern function generates patterns in reverse order of digits.
            // So, a query pattern 's' like "010" means rightmost digit even, next odd, next even.
            // If we reverse 's' to "010" (still "010"), and then pad to 18, it becomes "01000...0".
            // This matches the format generated by to_parity_pattern.
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

