long long solve() {
    long long a, b;
    std::cin >> a >> b;

    if (a == b) {
        return 0;
    }

    long long diff = std::abs(a - b);
    long long count = 0;

    // Greedy approach for change-making with denominations 1, 2, 5
    // This is optimal for these specific denominations.
    // We prioritize larger denominations.
    count += diff / 5;
    diff %= 5;

    if (diff == 0) {
        return count;
    } else if (diff == 1) {
        // Options for 1:
        // 1. +1 (1 press)
        // 2. +2 -1 (2 presses)
        // 3. +5 -2 -2 (3 presses)
        // 4. +5 -2 -1 -1 (4 presses)
        // 5. +5 -1 -1 -1 -1 (5 presses)
        // The best is 1 press.
        return count + 1;
    } else if (diff == 2) {
        // Options for 2:
        // 1. +2 (1 press)
        // 2. +1 +1 (2 presses)
        // 3. +5 -2 -1 (3 presses)
        // 4. +5 -1 -1 -1 (4 presses)
        // The best is 1 press.
        return count + 1;
    } else if (diff == 3) {
        // Options for 3:
        // 1. +1 +1 +1 (3 presses)
        // 2. +2 +1 (2 presses)
        // 3. +5 -2 (2 presses)
        // The best is 2 presses.
        return count + 2;
    } else { // diff == 4
        // Options for 4:
        // 1. +1 +1 +1 +1 (4 presses)
        // 2. +2 +1 +1 (3 presses)
        // 3. +2 +2 (2 presses)
        // 4. +5 -1 (2 presses)
        // The best is 2 presses.
        return count + 2;
    }
}

