#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reverse of a permutation always has the same fingerprint.
    // If the original permutation is not a palindrome, its reverse is a different permutation.
    // A permutation cannot be a palindrome if n > 1, because elements must be distinct.
    // For example, if p = [1, 2, 1], it's a palindrome but not a permutation.
    // If p = [1, 2, 3], p_rev = [3, 2, 1]. F(p) = sort([3, 5]) = [3, 5]. F(p_rev) = sort([5, 3]) = [3, 5].
    // Since all elements in a permutation are distinct, p_i != p_{n-i+1} for at least one i
    // unless n=1 (which is not allowed, n>=2) or n=2 and p=[1,2] or p=[2,1].
    // For n=2, p=[1,2], p_rev=[2,1]. These are different.
    // For n=2, p=[2,1], p_rev=[1,2]. These are different.
    // So, for any n >= 2, p_rev will always be different from p unless p is a palindrome.
    // However, a permutation cannot be a palindrome if n > 1 because all elements must be distinct.
    // For example, if n=3, p=[1,2,3]. p_rev=[3,2,1]. Different.
    // If p_1 = p_n, then p is not a permutation (unless n=1).
    // If p_i = p_{n-i+1} for all i, then p_1 = p_n, p_2 = p_{n-1}, etc.
    // If n is odd, p_{(n+1)/2} = p_{(n+1)/2}, which is fine.
    // But for p to be a palindrome, it would require p_1 = p_n, p_2 = p_{n-1}, etc.
    // Since all elements must be distinct, this is only possible if n=1.
    // For n >= 2, p_i != p_j for i != j.
    // Thus, p_i != p_{n-i+1} for at least one i, unless n=1.
    // So, p is never a palindrome for n >= 2.
    // Therefore, reversing the permutation always yields a different permutation with the same fingerprint.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

