#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n >= 2) with the same fingerprint.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // Let p' be the reversed permutation: p'_i = p_{n-i+1}.
    // p' = [p_n, p_{n-1}, ..., p_2, p_1]
    // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // Since addition is commutative, the set of sums {p_i+p_{i+1}} is the same
    // as the set of sums {p_{n-i+1}+p_{n-i}} (just in reverse order).
    // Therefore, F(p) and F(p') will be identical after sorting.
    // For n >= 2, p and p' are different unless p is a palindrome,
    // but even if p is a palindrome, the problem guarantees a solution exists.
    // However, the simplest solution is just to reverse the given permutation.
    // The example cases confirm this behavior.
    // For n=2, p=[1,2], p'=[2,1]. F(p)=[3], F(p')=[3].
    // For n=6, p=[2,1,6,5,4,3], p'=[3,4,5,6,1,2].
    // F(p) = sort([3,7,11,9,7]) = [3,7,7,9,11]
    // F(p') = sort([7,9,11,7,3]) = [3,7,7,9,11]
    // The example output for n=6 is [1,2,5,6,3,4], which is not the reverse.
    // This implies that there can be multiple solutions, and reversing is just one.
    // The problem asks for *any* valid solution. Reversing is the simplest.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

