int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of days can exceed int if n=100, a_i=100
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long haybales_in_pile1 = a[0]; // Start with initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            long long distance = i; // Distance from pile i+1 to pile 1 is i

            // If we have enough days to move at least one haybale from this pile
            if (d >= distance) {
                // Calculate how many haybales can be moved from this pile
                // Each haybale costs 'distance' days.
                // We have 'a[i]' haybales in this pile.
                // We have 'd' days remaining.
                long long haybales_to_move = std::min((long long)a[i], d / distance);

                haybales_in_pile1 += haybales_to_move;
                d -= haybales_to_move * distance;
            } else {
                // If we don't even have enough days to move one haybale from this pile,
                // we can't move any haybales from further piles either.
                break; 
            }
        }
        std::cout << haybales_in_pile1 << std::endl;
    }
    return 0;
}

