#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number that satisfies the conditions.
        // The number will start with '2' and end with '3', with '7's in between.
        // Example: n=2 -> 23
        //          n=3 -> 273
        //          n=4 -> 2773
        //
        // Let s be this number.
        // s = 2 * 10^(n-1) + 7 * (10^(n-2) + ... + 10^1) + 3 * 10^0
        // s = 2 * 10^(n-1) + 7 * (10^(n-1) - 10) / 9 + 3
        //
        // Digits are 2, 7, 3. None are 0.
        //
        // Divisibility by 2: s ends in 3, so it's odd. Not divisible by 2.
        // Divisibility by 3: Sum of digits = 2 + (n-2)*7 + 3 = 5 + 7n - 14 = 7n - 9.
        // For s to be divisible by 3, 7n - 9 must be divisible by 3.
        // 7n - 9 = (6n + n) - 9 = 3(2n - 3) + n.
        // So, s is divisible by 3 if and only if n is divisible by 3.
        // If n is divisible by 3, this construction fails for digit 3.
        //
        // Divisibility by 7:
        // s = 2 * 10^(n-1) + 7 * (sum of 10^k for k=1 to n-2) + 3
        // If n-2 >= 0, then s = 2 * 10^(n-1) + (a number consisting of n-2 sevens) * 10 + 3.
        // The part (a number consisting of n-2 sevens) * 10 is divisible by 7.
        // So, s is divisible by 7 if and only if (2 * 10^(n-1) + 3) is divisible by 7.
        //
        // Let's check 2 * 10^(n-1) + 3 mod 7:
        // n=2: 2*10 + 3 = 23 = 2 mod 7
        // n=3: 2*100 + 3 = 203 = 203/7 = 29 R 0. Divisible by 7. This construction fails for digit 7.
        // n=4: 2*1000 + 3 = 2003 = 2003/7 = 286 R 1. Not divisible by 7.
        // n=5: 2*10000 + 3 = 20003 = 20003/7 = 2857 R 4. Not divisible by 7.
        // n=6: 2*100000 + 3 = 200003 = 200003/7 = 28571 R 6. Not divisible by 7.
        // n=7: 2*1000000 + 3 = 2000003 = 2000003/7 = 285714 R 5. Not divisible by 7.
        // n=8: 2*10000000 + 3 = 20000003 = 20000003/7 = 2857143 R 2. Not divisible by 7.
        // The pattern of 2*10^(n-1) + 3 mod 7 is:
        // n-1 mod 6: 0  1  2  3  4  5
        // 10^(n-1) mod 7: 1  3  2  6  4  5
        // 2*10^(n-1) mod 7: 2  6  4  5  1  3
        // (2*10^(n-1) + 3) mod 7: 5  2  0  1  4  6
        // So, this construction fails for digit 7 if (n-1) mod 6 == 2, i.e., n-1 = 2, 8, 14, ...
        // which means n = 3, 9, 15, ...

        // The construction "27...73" fails if n is a multiple of 3 (due to digit 3)
        // OR if n is of the form 3 + 6k (due to digit 7).
        // This means it fails if n = 3, 6, 9, 12, ... (multiples of 3).
        // So, if n is a multiple of 3, we need a different construction.

        // Case 1: n is not a multiple of 3.
        // Use "2" followed by (n-2) "7"s, followed by "3".
        // Example: n=2 -> 23. Sum of digits = 5. Not div by 3.
        // Example: n=4 -> 2773. Sum of digits = 19. Not div by 3.
        // Example: n=5 -> 27773. Sum of digits = 26. Not div by 3.
        // This construction works for n not a multiple of 3.
        // It's not divisible by 2 (ends in 3).
        // It's not divisible by 3 (sum of digits 7n-9, n not mult of 3 => 7n-9 not mult of 3).
        // It's not divisible by 7 (checked above, (n-1) mod 6 != 2 if n is not a multiple of 3).
        //   If n is not a multiple of 3, then n-1 is not of the form 2+6k.
        //   n=2: (n-1)=1. 1 mod 6 = 1. OK.
        //   n=4: (n-1)=3. 3 mod 6 = 3. OK.
        //   n=5: (n-1)=4. 4 mod 6 = 4. OK.
        //   n=7: (n-1)=6. 6 mod 6 = 0. OK.
        //   n=8: (n-1)=7. 7 mod 6 = 1. OK.
        // So this construction works for n not a multiple of 3.

        // Case 2: n is a multiple of 3.
        // Use "6" followed by (n-2) "7"s, followed by "9".
        // Example: n=3 -> 679. Sum of digits = 22. Not div by 3.
        // Example: n=6 -> 677779. Sum of digits = 6 + 4*7 + 9 = 6 + 28 + 9 = 43. Not div by 3.
        // This construction works for n a multiple of 3.
        // It's not divisible by 2 (ends in 9).
        // It's not divisible by 3 (sum of digits = 6 + (n-2)*7 + 9 = 15 + 7n - 14 = 7n + 1.
        // Since n is a multiple of 3, n=3k. Sum = 7(3k)+1 = 21k+1. Not divisible by 3.
        // It's not divisible by 7:
        // s = 6 * 10^(n-1) + 7 * (sum of 10^k for k=1 to n-2) + 9
        // s is divisible by 7 iff (6 * 10^(n-1) + 9) is divisible by 7.
        // Let's check 6 * 10^(n-1) + 9 mod 7:
        // n-1 mod 6: 0  1  2  3  4  5
        // 10^(n-1) mod 7: 1  3  2  6  4  5
        // 6*10^(n-1) mod 7: 6  4  5  1  3  2
        // (6*10^(n-1) + 9) mod 7: (6*10^(n-1) + 2) mod 7: 1  6  0  3  5  4
        // This construction fails for digit 7 if (n-1) mod 6 == 2, i.e., n-1 = 2, 8, 14, ...
        // which means n = 3, 9, 15, ...
        // But n is a multiple of 3. So n=3, 9, 15, ... are exactly the cases where (n-1) mod 6 == 2.
        // So this construction fails for digit 7 if n is a multiple of 3 AND (n-1) mod 6 == 2.
        // This means this construction fails for n = 3, 9, 15, ...
        //
        // So, if n is a multiple of 3, and n is of the form 3+6k, we need another construction.
        // This means n = 3, 9, 15, ...
        // For these cases, let's try "2" followed by (n-2) "7"s, followed by "9".
        // Example: n=3 -> 279. Sum of digits = 18. Divisible by 3 and 9. Fails.
        //
        // Let's simplify.
        // For n=1, -1.
        // For n=2, 23.
        // For n=3, 239.
        // For n=4, 6789.
        //
        // The problem asks for ANY solution.
        // A simple pattern that works for many cases:
        // Start with '2', then (n-1) '3's.
        // Example: n=2 -> 23.
        // Example: n=3 -> 233. Sum=8. Not div by 2,3.
        // Example: n=4 -> 2333. Sum=11. Not div by 2,3.
        // This works for 2 and 3.
        //
        // What if we use '2' followed by (n-1) '3's?
        // Digits: 2, 3.
        // Not divisible by 2 (ends in 3).
        // Not divisible by 3 if sum of digits (2 + (n-1)*3 = 3n-1) is not divisible by 3.
        // This means 3n-1 is not divisible by 3, which is always true.
        // So this construction "23...3" works for all n >= 2.

        // Let's verify "2" followed by (n-1) "3"s.
        // s = 2 * 10^(n-1) + 3 * (10^(n-2) + ... + 10^0)
        // s = 2 * 10^(n-1) + 3 * (10^(n-1) - 1) / 9
        // s = 2 * 10^(n-1) + (10^(n-1) - 1) / 3
        //
        // Digits are 2, 3. None are 0.
        // Divisibility by 2: s ends in 3, so it's odd. Not divisible by 2.
        // Divisibility by 3: Sum of digits = 2 + (n-1)*3 = 3n - 1.
        // Since 3n is divisible by 3, 3n-1 is never divisible by 3.
        // So this construction works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << "\n";
    }
}

