        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // We can copy min_val to a[i] as many times as possible
            // without a[i] exceeding k.
            // Each copy adds min_val to a[i].
            // The number of times we can add min_val to a[i] is (k - a[i]) / min_val.
            operations += (k - a[i]) / min_val;
        }
        std::cout << operations << "\n";
    }
    return 0;
}

