    bool first_half_T_val_assigned_to_0 = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use 2.0 for floating point division to handle T being odd
            p[i] = 0;
        } else if (a[i] > T / 2.0) {
            p[i] = 1;
        } else { // a[i] == T / 2.0
            // This case only happens if T is even.
            // If T is odd, T/2.0 will have a .5, and a[i] is integer, so a[i] == T/2.0 is false.
            // If T is even, T/2.0 is an integer.
            if (!first_half_T_val_assigned_to_0) {
                p[i] = 0;
                first_half_T_val_assigned_to_0 = true;
            } else {
                p[i] = 1;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
