int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long n = 1; // Represents the number of stairs in the current staircase
        while (true) {
            // Cost for a nice staircase with n stairs is (2^n - 1) * (2^n) / 2
            // This is equivalent to (2^(n+1) - 1) * 2^n / 2 - (2^n - 1) * 2^(n-1) / 2
            // No, the cost is (2^(n+1) - 1) * 2^n / 2.
            // The cost for a nice staircase with k stairs is (2^(k+1) - 1) * 2^k / 2.
            // The problem states the cost for a staircase with n stairs is (2^(n+1) - 1) * 2^n / 2.
            // Let's re-evaluate the cost.
            // The cost for a nice staircase with k stairs is (2^(k+1) - 1) * 2^k / 2.
