#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;
        long long count = n / m;

        std::vector<long long> cycle_last_digits;
        cycle_last_digits.reserve(10);
        long long current_val = m;
        for (int i = 0; i < 10; ++i) {
            cycle_last_digits.push_back(current_val % 10);
            current_val += m;
        }

        long long sum_of_cycle = 0;
        for (long long digit : cycle_last_digits) {
            sum_of_cycle += digit;
        }

        long long full_cycles = count / 10;
        long long remaining_elements = count % 10;

        long long total_sum = full_cycles * sum_of_cycle;

        for (int i = 0; i < remaining_elements; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

