    // n = 7
    // 1. Find the end of the non-increasing suffix.
    //    `p = n - 1 = 6`.
    //    While `p > 0` and `a[p-1] >= a[p]`:
    //    `p=6`: `a[5]=5, a[6]=2`. `5 >= 2` is true. `p` becomes `5`.
    //    `p=5`: `a[4]=4, a[5]=5`. `4 >= 5` is false. Loop terminates.
    //    So `p = 5`. This means `a[5...6]` (`[5,2]`) is the non-increasing suffix.

    // 2. Find the start of the non-decreasing prefix that can combine with the suffix.
    //    `q = p = 5`.
    //    While `q > 0` and `a[q-1] <= a[q]`:
    //    `q=5`: `a[4]=4, a[5]=5`. `4 <= 5` is true. `q` becomes `4`.
    //    `q=4`: `a[3]=8, a[4]=4`. `8 <= 4` is false. Loop terminates.
    //    So `q = 4`. This means `a[4...5]` (`[4,5]`) is the non-decreasing prefix.

    // The good array starts at index `q`. The length of the prefix to erase is `q`.
    // For `[4, 3, 3, 8, 4, 5, 2]`, `q=4`. Output should be 4. This matches the example.

    // Example `[1, 2, 3, 4]`
    // n = 4
    // 1. `p = 3`.
    //    `p=3`: `a[2]=3, a[3]=4`. `3 >= 4` is false. Loop terminates.
    //    So `p = 3`. `a[3...3]` (`[4]`) is the non-increasing suffix.

    // 2. `q = p = 3`.
    //    `q=3`: `a[2]=3, a[3]=4`. `3 <= 4` is true. `q` becomes `2`.
    //    `q=2`: `a[1]=2, a[2]=3`. `2 <= 3` is true. `q` becomes `1`.
    //    `q=1`: `a[0]=1, a[1]=2`. `1 <= 2` is true. `q` becomes `0`.
    //    `q=0`: Loop terminates (`q > 0` is false).
    //    So `q = 0`. `a[0...3]` (`[1,2,3,4]`) is the non-decreasing prefix.

    // Output `q = 0`. This matches the example.

    // Example `[1, 1, 1]`
    // n = 3
    // 1. `p = 2`.
    //    `p=2`: `a[1]=1, a[2]=1`. `1 >= 1` is true. `p` becomes `1`.
    //    `p=1`: `a[0]=1, a[1]=1`. `1 >= 1` is true. `p` becomes `0`.
    //    `p=0`: Loop terminates.
    //    So `p = 0`. `a[0...2]` (`[1,1,1]`) is the non-increasing suffix.

    // 2. `q = p = 0`.
    //    `q=0`: Loop terminates.
    //    So `q = 0`. `a[0...0]` (`[1]`) is the non-decreasing prefix.
    // Output `q = 0`. This matches the example.

    // Example `[1, 3, 1, 4, 5, 3, 2]`
    // n = 7
    // 1. `p = 6`.
    //    `p=6`: `a[5]=3, a[6]=2`. `3 >= 2` is true. `p` becomes `5`.
    //    `p=5`: `a[4]=5, a[5]=3`. `5 >= 3` is true. `p` becomes `4`.
    //    `p=4`: `a[3]=4, a[4]=5`. `4 >= 5` is false. Loop terminates.
    //    So `p = 4`. `a[4...6]` (`[5,3,2]`) is the non-increasing suffix.

    // 2. `q = p = 4`.
    //    `q=4`: `a[3]=4, a[4]=5`. `4 <= 5` is true. `q` becomes `3`.
    //    `q=3`: `a[2]=1, a[3]=4`. `1 <= 4` is true. `q` becomes `2`.
    //    `q=2`: `a[1]=3, a[2]=1`. `3 <= 1` is false. Loop terminates.
    //    So `q = 2`. `a[2...4]` (`[1,4,5]`) is the non-decreasing prefix.

    // Output `q = 2`. This matches the example.

    // Example `[5, 4, 3, 2, 3]`
    // n = 5
    // 1. `p = 4`.
    //    `p=4`: `a[3]=2, a[4]=3`. `2 >= 3` is false. Loop terminates.
    //    So `p = 4`. `a[4...4]` (`[3]`) is the non-increasing suffix.

    // 2. `q = p = 4`.
    //    `q=4`: `a[3]=2, a[4]=3`. `2 <= 3` is true. `q` becomes `3`.
    //    `q=3`: `a[2]=3, a[3]=2`. `3 <= 2` is false. Loop terminates.
    //    So `q = 3`. `a[3...4]` (`[2,3]`) is the non-decreasing prefix.

    // Output `q = 3`. This matches the example.

    // The logic seems correct.

    int p_idx = n - 1;
    while (p_idx > 0 && a[p_idx - 1] >= a[p_idx]) {
        p_idx--;
    }

    int q_idx = p_idx;
    while (q_idx > 0 && a[q_idx - 1] <= a[q_idx]) {
        q_idx--;
    }

    std::cout << q_idx << std::endl;
}

