        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the range is just pos[1].
        // For m > 1, we expand the range to include m.
        // The new number m is at pos[m].
        // We need to update current_min_idx and current_max_idx
        // to cover the range [1, ..., m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly numbers 1 to m.
        // This means its length must be m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

