            // d^2 - 4d = d(d-4)
            // If d=4, discriminant = 0.
            // If d>4, discriminant > 0.

            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a, b >= 0.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d=4, sqrt_discriminant = 0. a1 = 4/2 = 2, b1 = 4/2 = 2. Both >= 0.
            // If d>4, d-4 > 0, so sqrt_discriminant > 0.
            // d + sqrt_discriminant > 0. So a1 > 0.
            // We need to check if d - sqrt_discriminant >= 0.
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since d >= 0, we can square both sides)
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So, b1 will always be non-negative when d >= 4.

