#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the length of the longest possible strictly increasing prefix starting from 0
    // That is, find the largest 'i' such that a[0] >= 0, a[1] >= 1, ..., a[i] >= i.
    // The actual values would be b[0]=0, b[1]=1, ..., b[i]=i.
    int prefix_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            prefix_len++;
        } else {
            break;
        }
    }

    // Calculate the length of the longest possible strictly decreasing suffix ending at 0
    // That is, find the largest 'j' such that a[n-1] >= 0, a[n-2] >= 1, ..., a[n-j] >= j-1.
    // The actual values would be b[n-1]=0, b[n-2]=1, ..., b[n-j]=j-1.
    int suffix_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[n - 1 - i] >= i) {
            suffix_len++;
        } else {
            break;
        }
    }

    // If the sum of the lengths of these two potential parts is greater than or equal to n,
    // it means there's an overlap or they meet perfectly, implying a valid peak 'k' can be formed.
    // For example, if prefix_len = 3 and suffix_len = 3 for n=4,
    // it means a[0]>=0, a[1]>=1, a[2]>=2 AND a[3]>=0, a[2]>=1, a[1]>=2.
    // The peak could be at index 1 (0-indexed), where b[0]=0, b[1]=2, b[2]=1, b[3]=0.
    // This requires a[1] >= 2.
    // The condition prefix_len + suffix_len > n means there is at least one index `i`
    // such that `i < prefix_len` and `n-1-i < suffix_len`.
    // This `i` would be a candidate for the peak `k-1` (0-indexed).
    // Specifically, if `prefix_len + suffix_len > n`, it means there is at least one index `p`
    // such that `p` is covered by the prefix condition (`a[p] >= p`) AND `p` is covered by the suffix condition
    // (`a[p] >= (n-1-p)`).
    // If such a `p` exists, we can set `b[p]` to `max(p, n-1-p)` and construct the rest.
    // Since `a[p]` must be greater than or equal to both `p` and `n-1-p`, it can be the peak.
    // The condition `prefix_len + suffix_len > n` is equivalent to `prefix_len >= n - suffix_len + 1`.
    // This means the prefix covers at least up to index `n - suffix_len`.
    // The suffix covers from index `n - suffix_len` to `n-1`.
    // So, index `n - suffix_len` is covered by both.
    // The value at this index `a[n - suffix_len]` must be `>= n - suffix_len` (from prefix)
    // and `>= (n-1) - (n - suffix_len)` (from suffix) which is `>= suffix_len - 1`.
    // Since `prefix_len + suffix_len > n` implies `prefix_len >= n - suffix_len + 1`,
    // the index `n - suffix_len` is within the valid range for the prefix.
    // And `n - suffix_len` is also within the valid range for the suffix.
    // So, there is at least one index `p` that can be the peak.
    if (prefix_len + suffix_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

