        prefix_max[i] = current_max;

        if (current_is_perm) {
            if (val < 1 || val > i + 1 || seen_prefix[val]) {
                current_is_perm = false;
            } else {
                seen_prefix[val] = true;
                if (current_max == i + 1) {
                    prefix_is_perm[i + 1] = true;
                }
            }
        }
    }

    // Calculate suffix_max and check suffix permutations
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix
    current_max = 0;
    current_is_perm = true;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        if (val > current_max) {
            current_max = val;
        }
        suffix_max[i] = current_max;

        if (current_is_perm) {
            int len = n - i;
            if (val < 1 || val > len || seen_prefix[val]) {
                current_is_perm = false;
            } else {
                seen_prefix[val] = true;
                if (current_max == len) {
                    suffix_is_perm[len] = true;
                }
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
