struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareElementA);
    std::sort(B.begin(), B.end(), compareElementB);

    std::vector<long long> result_A_prime(m);
    std::vector<int> B_original_indices_sorted_by_A_value(m);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This is because F(n, k) = n / (k+1).
    // To maximize sum(A_i' / (B_i + 1)), we sort A in ascending order and B in ascending order.
    // Then we pair A[i] with B[i].
    // However, the problem asks for A' such that sum F(A_i', B_i) is maximized.
    // This means we need to assign A_j to B_i.
    // The function F(n, k) = n / (k+1).
    // We want to maximize sum_{i=1 to m} A'_i / (B_i + 1).
    // Let C_i = 1 / (B_i + 1). We want to maximize sum A'_i * C_i.
    // To maximize sum X_i * Y_i, if X is a permutation of sorted_X and Y is a permutation of sorted_Y,
    // we should pair sorted_X[i] with sorted_Y[i].
    // So, we sort A in ascending order.
    // We sort B in ascending order.
    // Let A_sorted be A after sorting.
    // Let B_sorted be B after sorting.
    // We want to assign A_sorted[j] to B_sorted[j].
    // The original B values are B[i].value.
    // The original A values are A[i].value.
    // We need to output A' such that A'_k is assigned to B_k (original B_k).
    // So, we need to find which A_value (from sorted A) corresponds to which original B_index.
    // The sorted A values are A[0].value, A[1].value, ..., A[m-1].value.
    // The sorted B values are B[0].value, B[1].value, ..., B[m-1].value.
    // We pair A[j].value with B[j].value.
    // The B[j].value corresponds to original index B[j].original_index.
    // So, for the original B at index B[j].original_index, we assign A[j].value.
    // This means result_A_prime[B[j].original_index] = A[j].value.

    for (int i = 0; i < m; ++i) {
        result_A_prime[B[i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

