#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to append at most 3 elements.
        // Let S be current_sum and X be current_xor_sum.
        // We want S' = 2 * X'.
        // S' = S + b1 + b2 + ...
        // X' = X ^ b1 ^ b2 ^ ...
        //
        // Strategy: Append two elements.
        // Let b1 = X.
        // New XOR sum X' = X ^ b1 = X ^ X = 0.
        // New sum S' = S + b1 = S + X.
        //
        // Now we need S' = 2 * X' to hold.
        // S + X = 2 * 0
        // S + X = 0.
        // This is only true if S=0 and X=0, which is not generally the case.
        //
        // Let's try to make the final XOR sum X' equal to some value Y,
        // and the final sum S' equal to 2Y.
        //
        // Consider appending two elements: b1 and b2.
        // Let b1 = X.
        // The XOR sum becomes X ^ X = 0.
        // The sum becomes S + X.
        //
        // Now we need to append b2 such that:
        // (S + X + b2) = 2 * (0 ^ b2)
        // S + X + b2 = 2 * b2
        // S + X = b2
        //
        // So, if we append b1 = X and b2 = S + X, the new array will have:
        // Sum S' = S + X + (S + X) = 2 * (S + X)
        // XOR sum X' = X ^ X ^ (S + X) = 0 ^ (S + X) = S + X
        //
        // Check condition: S' = 2 * X'
        // 2 * (S + X) = 2 * (S + X)
        // This holds!
        //
        // So we can always append two elements: X and (S + X).
        // The problem states a_i are non-negative.
        // X is non-negative. S is non-negative. So S+X is non-negative.
        // The values can be large, up to 10^9 for a_i.
        // S can be up to 10^5 * 10^9 = 10^14.
        // X can be up to 2^30 - 1 (approx 10^9).
        // S+X can be up to 10^14 + 10^9, which fits in long long.
        // The problem states b_i can be up to 10^18.
        // So this solution is valid.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << "\n";
        std::cout << b1 << " " << b2 << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

