// Function to convert a long long integer to its 18-digit parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's (even) from the left to make it 18 digits long
    while (pattern.length() < 18) {
        pattern += '0';
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get correct order
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to 18 digits
            std::string query_pattern = s;
            while (query_pattern.length() < 18) {
                query_pattern = '0' + query_pattern;
            }
            std::cout << counts[query_pattern] << "\n";
        }
    }

    return 0;
}

