#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> p(n);
    int split_digit = -1;

    // Find the first digit 'k' such that d_i > k for some i, and d_j < k for some j > i.
    // This 'k' will be the boundary between S1 and S2.
    // All digits <= k will be colored 1, all digits > k will be colored 2.
    // This is a greedy approach. We try to find the smallest possible 'k' that works.
    // If we find such a 'k', then S1 will contain all d_i <= k, and S2 will contain all d_i > k.
    // S1 will be sorted if all d_i <= k are in non-decreasing order.
    // S2 will be sorted if all d_i > k are in non-decreasing order.
    // The combined sequence will be sorted if S1 is sorted, S2 is sorted, and max(S1) <= min(S2).
    // By definition, max(S1) <= k and min(S2) > k, so max(S1) < min(S2) is guaranteed.
    // Thus, we only need to ensure S1 and S2 are sorted internally.

    // Iterate through possible split digits from 0 to 9.
    for (int k = 0; k <= 9; ++k) {
        std::vector<int> current_p(n);
        int last1 = -1; // Last digit in S1
        int last2 = -1; // Last digit in S2
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < k) {
                // Must be color 1
                if (digit < last1) {
                    possible = false;
                    break;
                }
                current_p[i] = 1;
                last1 = digit;
            } else if (digit > k) {
                // Must be color 2
                if (digit < last2) {
                    possible = false;
                    break;
                }
                current_p[i] = 2;
                last2 = digit;
            } else { // digit == k
                // Can be color 1 or 2. Prefer color 2 if it maintains sorted order.
                // This is the crucial part: if digit == k, we can assign it to S1 or S2.
                // To make S1 and S2 sorted, we should assign it to S2 if it's greater than or equal to last2.
                // Otherwise, assign it to S1 if it's greater than or equal to last1.
                // If it can be assigned to both, assigning to S2 is generally better for S1's non-decreasing property.
                // If it can be assigned to neither, it's impossible for this k.

                // Option 1: Assign to color 2
                if (digit >= last2) {
                    current_p[i] = 2;
                    last2 = digit;
                } else if (digit >= last1) { // Option 2: Assign to color 1
                    current_p[i] = 1;
                    last1 = digit;
                } else { // Cannot assign to either
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            split_digit = k;
            p = current_p;
            break; // Found a valid coloring for this k, so we can stop.
        }
    }

    if (split_digit != -1) {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i];
        }
        std::cout << "\n";
    } else {
        std::cout << "-\n";
    }
}

