#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    std::vector<std::vector<int>> pos_char_map(L, std::vector<int>(26, 0));
    for (int i = 0; i < L; ++i) {
        pos_char_map[i][s[i] - 'a']++;
    }

    std::vector<std::vector<int>> count_pairs(26, std::vector<int>(26, 0));
    for (int i = 0; i < L; ++i) {
        count_pairs[s[i] - 'a'][s[(i + 1) % L] - 'a']++;
    }

    std::vector<std::vector<int>> count_char_char_dist(26, std::vector<int>(26, 0));
    for (int i = 0; i < L; ++i) {
        for (int j = 0; j < L; ++j) {
            if (i == j) continue;
            count_char_char_dist[s[i] - 'a'][s[j] - 'a']++;
        }
    }

    double total_win_prob = 0.0;

    for (int k_val = 0; k_val < L; ++k_val) { // Iterate over all possible true k values
        char first_char_val = s[k_val];
        int first_char_idx = first_char_val - 'a';

        // Find all k' such that s[k'] == first_char_val
        std::vector<int> possible_k_prime;
        for (int idx : char_indices[first_char_idx]) {
            possible_k_prime.push_back(idx);
        }

        if (possible_k_prime.size() == 1) {
            total_win_prob += 1.0; // k is uniquely determined by t[0]
            continue;
        }

        // Vasya needs to choose p to maximize win probability for this first_char_val
        double max_win_prob_for_char = 0.0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed p, what is the probability of winning?
            // Vasya knows t[0] and t[p].
            // t[0] = first_char_val
            // t[p] = s[(k_val + p) % L]
            char second_char_val = s[(k_val + p) % L];
            int second_char_idx = second_char_val - 'a';

            int count_matches = 0;
            for (int kp : possible_k_prime) {
                if (s[(kp + p) % L] == second_char_val) {
                    count_matches++;
                }
            }

            if (count_matches == 1) {
                max_win_prob_for_char = std::max(max_win_prob_for_char, 1.0);
            } else {
                // If count_matches > 1, Vasya loses for this (p, t[p]) pair.
                // The probability of winning for this (p, t[p]) is 0.
                // This is not quite right. Vasya chooses p *before* knowing t[p].
                // He chooses p to maximize the probability of winning *given t[0]*.
                // The probability of winning for a given t[0] and chosen p is:
                // sum over all possible t[p] (P(t[p] | t[0]) * I(win | t[0], t[p]))
                // where I is 1 if win, 0 if lose.

                // Let's re-evaluate for a fixed first_char_val and chosen p:
                // Vasya knows t[0] = first_char_val.
                // He chooses p.
                // He will be told t[p].
                // For each possible value of t[p] (say char_X):
                //   Count how many k' in possible_k_prime satisfy s[(k'+p)%L] == char_X.
                //   If this count is 1, he wins for this char_X.
                //   If this count > 1, he loses for this char_X.
                // The probability of winning for this (first_char_val, p) is:
                // (sum over char_X where count is 1) of (count of k' in possible_k_prime such that s[(k'+p)%L] == char_X) / possible_k_prime.size()

                std::vector<int> char_X_counts(26, 0); // counts how many k' in possible_k_prime map to char_X at pos p
                for (int kp : possible_k_prime) {
                    char_X_counts[s[(kp + p) % L] - 'a']++;
                }

                double current_p_win_prob = 0.0;
                for (int c = 0; c < 26; ++c) {
                    if (char_X_counts[c] == 1) { // If only one k' maps to this char_X
                        current_p_win_prob += 1.0; // This k' is uniquely determined
                    }
                }
                current_p_win_prob /= possible_k_prime.size();
                max_win_prob_for_char = std::max(max_win_prob_for_char, current_p_win_prob);
            }
        }
        total_win_prob += max_win_prob_for_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i + 1 < s.length()) {
            adj[s[i]].insert(s[i+1]);
            adj[s[i+1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_in_layout;
    char start_node = '\0';

    // Find a starting node for a path (degree 1 or an isolated node)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (used_in_s.count(c)) { // If character is in password
            if (adj[c].size() <= 1) { // Degree 0 or 1
                start_node = c;
                break;
            }
        }
    }

    // If all characters in password have degree 2, it's a cycle.
    // This is invalid for a linear keyboard layout.
    // Or if there are no characters in password (s.length() == 0, but constraint is |s| >= 1)
    // Or if s.length() == 1, then start_node will be s[0] and adj[s[0]] will be empty.
    if (start_node == '\0' && !used_in_s.empty()) {
        // This means all characters in used_in_s have degree 2.
        // This forms a cycle, which cannot be part of a simple path.
        // Example: abcda -> a-b-c-d-a (cycle)
        std::cout << "NO\n";
        return;
    }

    // If s.length() == 1, start_node will be s[0]
    if (s.length() == 1) {
        start_node = s[0];
    }


    if (start_node != '\0') {
        char current = start_node;
        char prev = '\0'; // Sentinel for the previous character

        while (current != '\0' && visited_in_layout.find(current) == visited_in_layout.end()) {
            layout += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters from the password were included in the generated layout segment
    if (layout.length() < used_in_s.size()) {
        // This means there were multiple disjoint paths/components in the graph formed by 's'
        // or a cycle was detected that wasn't handled by the start_node logic (e.g., a cycle not containing start_node)
        // The start_node logic should have caught cycles if all nodes in 's' have degree 2.
        // If layout.length() < used_in_s.size(), it means some characters from 's' were not reachable from start_node.
        // This implies multiple connected components within the graph of 's', which is not allowed for a single path.
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    if (layout.length() == 26) {
        std::cout << "YES\n";
        std::cout << layout << "\n";
    } else {
        // This case should ideally not be reached if the logic is correct,
        // as we always add all 26 characters.
        // It might indicate an issue with the graph construction or traversal.
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

