#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max length for which 2^L-1 is still within a reasonable range for comparison
    // 2^18 = 262144. If L=19, 2^19 = 524288.
    // If L=20, 2^20 = 1048576.
    // The maximum length of s is 2e5.
    // If a substring has length L, its value can be at most 2^L-1.
    // If L > 18, then 2^L-1 > 2e5.
    // So, if a substring starts with '1', its value will be at least 2^(L-1).
    // If L-1 > 18, then 2^(L-1) > 2e5.
    // This means if L > 19, and the substring starts with '1', its value will be > n.
    // So, for substrings starting with '1', we only need to check lengths up to ~19-20.
    // For substrings starting with '0', the value can be small even for large L.
    // The maximum length of a substring is N = 2e5.
    // The maximum value of f(t) we care about is N.
    // If f(t) = N, then t must have at most ceil(log2(N+1)) bits.
    // ceil(log2(2e5+1)) is 18.
    // So, if a substring has length L > 18, and its value is L, it must start with '0'.
    // If it starts with '1', its value is at least 2^(L-1).
    // If L-1 >= 18, then 2^(L-1) >= 2^18 = 262144 > N.
    // So, for substrings starting with '1', we only need to check lengths up to 19.
    // For substrings starting with '0', we can have large lengths.

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: Substring starts with '1'
        if (s[l] == '1') {
            long long current_val = 0;
            // Iterate through possible ending positions r, forming substrings s[l...r]
            // The maximum length we need to check for '1'-starting substrings is limited.
            // If length is L, value is at least 2^(L-1).
            // If L-1 >= 18, then value >= 2^18 = 262144.
            // Since L <= N = 2e5, if value >= 262144, then value > L.
            // So we only need to check L-1 < 18, i.e., L < 19.
            // Max length to check is 18.
            // So r-l+1 <= 18.
            // r <= l + 17.
            for (int r = l; r < std::min(n, l + 18); ++r) { // Check up to length 18 (r-l+1 <= 18)
                current_val = (current_val << 1) | (s[r] - '0');
                if (current_val == (r - l + 1)) {
                    good_substrings_count++;
                }
            }
        } else { // Case 2: Substring starts with '0'
            // For substrings starting with '0', the value can be small even for large lengths.
            // We need to find the first '1' to the right of l.
            // All substrings s[l...r] where s[l...k-1] are '0's and s[k] is '1'
            // will have value f(s[k...r]).
            // Let's find the first '1' at or after index l.
            int first_one_idx = -1;
            for (int k = l; k < n; ++k) {
                if (s[k] == '1') {
                    first_one_idx = k;
                    break;
                }
            }

            if (first_one_idx == -1) { // All remaining characters are '0's
                // The only good substring starting with '0' is "0" itself, if its length is 0.
                // But length is r-l+1 >= 1. So f("0")=0, length=1. Not good.
                // f("00")=0, length=2. Not good.
                // No good substrings if all are '0's.
                // This is handled by the loop below, current_val will be 0, and r-l+1 will be >= 1.
                // So 0 == r-l+1 will never be true.
                continue;
            }

            // Now we are considering substrings s[l...r] where s[l...first_one_idx-1] are '0's.
            // The actual binary value is determined by s[first_one_idx...r].
            // Let's iterate from first_one_idx to n-1.
            long long current_val = 0;
            for (int r = first_one_idx; r < n; ++r) {
                current_val = (current_val << 1) | (s[r] - '0');
                // The length of the substring s[l...r] is (r - l + 1).
                // The value is current_val.
                // We need to check if current_val == (r - l + 1).
                // The maximum possible value for current_val is N (2e5).
                // If current_val exceeds N + (first_one_idx - l), it's too large.
                // The maximum length of a substring is N.
                // If current_val > N, it cannot be equal to r-l+1.
                // So we can stop early if current_val gets too large.
                // The maximum length of s is 2e5.
                // If current_val > 2e5, it cannot be equal to r-l+1.
                // The maximum length of the effective binary part (s[first_one_idx...r]) is r - first_one_idx + 1.
                // If this length exceeds 19, then current_val will be > 2^18 = 262144.
                // So we can limit r to first_one_idx + 18.
                if (r - first_one_idx >= 19 && current_val > n) { // current_val > n is a safe upper bound
                    break;
                }

                // Check if current_val is equal to the length of s[l...r]
                // The length is (r - l + 1).
                // The value is current_val.
                // We need to check if current_val == (r - l + 1).
                // Also, current_val must be positive for this to be possible,
                // as r-l+1 is always positive.
                if (current_val > 0 && current_val == (r - l + 1)) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

