bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0; // The previous element in the non-decreasing array
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long lower_bound_for_b_i = prev_b;

        // Case 1: a[i] >= prev_b
        // We need b[i] >= prev_b.
        // If a[i] is already >= prev_b, we can potentially keep a[i] as b[i].
        // The cost to change a[i] to a[i] is 0.
        // The cost to change a[i] to prev_b is (prev_b - a[i] + m) % m.
        // If a[i] >= prev_b:
        //   If a[i] can be prev_b (i.e., (prev_b - a[i] + m) % m <= x), then we can set b[i] = prev_b.
        //   Otherwise, we must set b[i] = a[i].
        // If a[i] < prev_b:
        //   We must increment a[i] to at least prev_b.
        //   The minimum increment needed is (prev_b - a[i]).
        //   If (prev_b - a[i]) <= x, we can set b[i] = prev_b.
        //   Otherwise, it's impossible to make b[i] >= prev_b with x operations.

        if (current_a >= lower_bound_for_b_i) {
            // We need to check if we can make current_a into lower_bound_for_b_i.
            // The cost would be (lower_bound_for_b_i - current_a + m) % m.
            // If current_a is already lower_bound_for_b_i, cost is 0.
            // If current_a > lower_bound_for_b_i, cost is m - (current_a - lower_bound_for_b_i).
            // This is equivalent to (lower_bound_for_b_i - current_a + m) % m.
            long long cost_to_make_equal_to_prev_b = (lower_bound_for_b_i - current_a + m) % m;
            if (cost_to_make_equal_to_prev_b <= x) {
                // We can make b_i = prev_b. So we do.
                // prev_b remains prev_b.
            } else {
                // We cannot make b_i = prev_b.
                // Since current_a >= prev_b, and we can't decrease it to prev_b (by wrapping around),
                // we must keep b_i = current_a.
                prev_b = current_a;
            }
        } else { // current_a < lower_bound_for_b_i
            // We must increment current_a to at least lower_bound_for_b_i.
            // The minimum increment needed is lower_bound_for_b_i - current_a.
