// dp[x] stores a pair: {final_y_delta, final_x_pos} if starting from x and performing step_add then step_sub.
// final_y_delta is the total y added from this point until termination.
// final_x_pos is the x value at termination.
// We need to distinguish between the two types of moves:
// 1. x -> x + a[x] (y += a[x])
// 2. x -> x - a[x] (y += a[x])
// Let's define a function `solve(current_x, current_y, is_add_step)`
// This is too complex. The problem states "first step 2, then step 3".
// This means from a state (x, y), we first do (x+a[x], y+a[x]), then from that new state, we do (x+a[x]-a[x+a[x]], y+a[x]+a[x+a[x]]).
// This is the key: the `a_x` in step 3 is `a_{new_x}` from step 2.

// Let's define a function `calculate_result(start_x, a_values, n)`
// This function will simulate the process for a given starting x.
// To optimize, we can use dynamic programming.
// Let `dp[x]` store the result of starting the "step 2, step 3" sequence from position `x`.
// `dp[x]` will be a pair: `{total_y_added, final_x_position}`.
// `total_y_added` is the sum of `a_val`s added to `y` from this point.
// `final_x_position` is the `x` value when the program terminates.
// If it doesn't terminate, we can use a special value like `{-1, -1}` or `{-1, 0}`.

// The `a` array is 1-indexed. `a_values[0]` is unused.
// `a_values[1]` is the `i` we are testing.
// `a_values[2]` to `a_values[n]` are given.

std::vector<long long> a_global; // Use global or pass by reference to avoid copying
std::vector<std::pair<long long, int>> memo; // memo[x] = {y_delta, final_x}
std::vector<bool> visited; // To detect cycles (non-termination)
std::vector<bool> in_recursion_stack; // To detect cycles during DFS

int N_global;

// Recursive function to calculate the result starting from a given x
// Returns {y_delta, final_x_pos}
std::pair<long long, int> solve(int current_x) {
    // Base cases for termination
    if (current_x <= 0 || current_x > N_global) {
        return {0, current_x}; // No y added, x is current_x
    }

    // Check memoization table
    if (visited[current_x]) {
        return memo[current_x];
    }

    // Detect cycle (non-termination)
    if (in_recursion_stack[current_x]) {
        // We've encountered this x before in the current path, so it's a cycle.
        // Mark as non-terminating.
        // Use a special value like {-1, 0} to indicate non-termination.
        // The 0 for final_x is arbitrary, as it won't be used.
        memo[current_x] = {-1, 0};
        visited[current_x] = true;
        return memo[current_x];
    }

    in_recursion_stack[current_x] = true;

    long long val_at_x = a_global[current_x];

    // Step 2: x = x + val_at_x, y = y + val_at_x
    int next_x_after_add = current_x + val_at_x;
    long long y_added_step2 = val_at_x;

    // Check termination after step 2
    if (next_x_after_add <= 0 || next_x_after_add > N_global) {
        in_recursion_stack[current_x] = false;
        memo[current_x] = {y_added_step2, next_x_after_add};
        visited[current_x] = true;
        return memo[current_x];
    }

    // Step 3: x = next_x_after_add - a[next_x_after_add], y = y + a[next_x_after_add]
    long long val_at_next_x = a_global[next_x_after_add];
    int next_x_after_sub = next_x_after_add - val_at_next_x;
    long long y_added_step3 = val_at_next_x;

    // Recursively solve for the state after step 3
    std::pair<long long, int> result_from_next_state = solve(next_x_after_sub);

    in_recursion_stack[current_x] = false;

    // If the recursive call indicated non-termination, propagate it.
    if (result_from_next_state.first == -1) {
        memo[current_x] = {-1, 0};
        visited[current_x] = true;
        return memo[current_x];
    }

    // Combine results
    long long total_y_delta = y_added_step2 + y_added_step3 + result_from_next_state.first;
    int final_x_pos = result_from_next_state.second;

    memo[current_x] = {total_y_delta, final_x_pos};
    visited[current_x] = true;
    return memo[current_x];
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    N_global = n;

    a_global.resize(n + 1); // 1-indexed
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_global[i];
    }

    // For each i from 1 to n-1, set a_global[1] = i and run the program.
    // We need to re-initialize memoization tables for each run,
    // or structure the DP such that a_global[1] is a parameter.
    // Since a_global[1] changes, the DP state for x=1 changes.
    // However, for x > 1, the DP state is independent of a_global[1].
    // So, we can compute DP for x=2 to n once.
    // Then for each i, we only need to compute for x=1.

    // Initialize memoization tables for x=2 to n.
    // This part is tricky. The problem asks to run for a_1 = i.
    // This means the entire `a` array changes for each run.
    // If `a_1` is `i`, then `a_2, ..., a_n` are fixed.
    // The `solve` function depends on `a_global`.
    // So, for each `i`, we set `a_global[1] = i`, then clear and re-run `solve(1)`.
    // This means `solve` will re-calculate everything.
    // This would be O(N^2) in total, which is too slow (2*10^5)^2 = 4*10^10.

    // The key observation is that `a_global[1]` only affects the first step.
    // If `x` becomes `x_prime` where `x_prime > 1`, then `a_global[x_prime]` is fixed.
    // So, the results for `solve(x)` where `x > 1` are independent of `a_global[1]`.
    // We can precompute `solve(x)` for `x = 2, ..., n`.

    // Initialize memoization tables for the fixed part of `a_global`.
    memo.assign(n + 1, {0, 0});
    visited.assign(n + 1, false);
    in_recursion_stack.assign(n + 1, false);

    // Precompute results for x from 2 to n.
    // We iterate from n down to 2 to ensure dependencies are met if there's a forward jump.
    // However, DFS handles arbitrary jumps.
    for (int x_val = 2; x_val <= n; ++x_val) {
        if (!visited[x_val]) {
            solve(x_val);
        }
    }

    // Now, for each i (1 to n-1), we set a_global[1] = i and calculate the result for x=1.
    for (int i = 1; i < n; ++i) {
        a_global[1] = i;

        // Reset memoization for x=1 only.
        // The results for x > 1 are still valid.
        memo[1] = {0, 0};
        visited[1] = false;
        in_recursion_stack[1] = false;

        std::pair<long long, int> result = solve(1);

        if (result.first == -1) {
            std::cout << -1 << "\n";
        } else {
            // Initial y is 0. The result.first is the total y_delta.
            std::cout << result.first << "\n";
        }
    }

    return 0;
}

