int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // Calculate the maximum possible number of ones in a string derived from 'a'
    // that has the same length as 'b'.
    // The string 'a' can grow by appending its parity.
    // If 'a' has an even number of ones, appending '0' keeps the count of ones the same.
    // If 'a' has an odd number of ones, appending '1' increases the count of ones by one.
    // After appending '1', the count of ones becomes even, so subsequent appends will be '0'.
    // So, the maximum number of ones we can achieve is either current_ones or current_ones + 1 (if current_ones is odd).

    int max_ones_a_possible;
    if (ones_a % 2 == 1) { // If initial 'a' has odd number of ones
        max_ones_a_possible = ones_a + 1; // We can append '1', increasing ones count by 1
    } else { // If initial 'a' has even number of ones
        max_ones_a_possible = ones_a; // We can only append '0', keeping ones count the same
    }

    // To transform 'a' into 'b', 'b' must be a suffix of some string 'a_prime'
    // that can be generated from 'a' by appending parities.
    // The length of 'a_prime' must be at least |b|.
    // The number of ones in 'b' must be less than or equal to the maximum possible ones
    // in any string derived from 'a' that has length |b|.

    // If the number of ones in 'b' is greater than the maximum possible ones in 'a'
    // (even after potentially adding one if 'a' had odd ones), then it's impossible.
    if (ones_b > max_ones_a_possible) {
        std::cout << "NO\n";
        return 0;
    }

    // If the length of 'a' is less than the length of 'b', we must append characters.
    // This means we must be able to reach a state where the string has length |b|
    // and the correct number of ones.
    // If ones_b <= max_ones_a_possible, it is always possible to construct a string
    // of length |b| with exactly ones_b ones, provided we can reach that length.
    // We can always append '0's (if current parity is even) or '1' then '0's (if current parity is odd)
    // until the string length is |b|.
    // The only constraint is that the number of ones in 'b' must be achievable.
    // Since we can always remove characters from the front, any string 'a_prime'
    // that can be formed by appending parities, and has 'b' as a suffix,
    // means we can transform 'a' to 'b'.
    // The crucial part is that we can always extend 'a' to be arbitrarily long
    // by appending parities. If the current string has length L and we need length |b|,
    // and L < |b|, we just append |b| - L characters.
    // The number of ones in 'b' must be achievable from 'a'.
    // If ones_a is odd, we can make it ones_a + 1.
    // If ones_a is even, we can only make it ones_a.
    // So, if ones_b <= ones_a (if ones_a is even) OR ones_b <= ones_a + 1 (if ones_a is odd),
    // then it's possible.

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] = a_0[i] + current_delta[i]
    std::vector<long long> current_delta(n, 0);

    // Iterate operations in reverse to find upper bounds for a_0[i]
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Initialize a_0 based on b. If b[i] is still LLONG_MAX, it means no type 2 query constrained it.
    // In this case, we can set a_0[i] to a value that satisfies the |a_i| <= 10^9 constraint.
    // A safe choice is 0, as it's within bounds and doesn't violate any max constraints.
    std::vector<long long> a0(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            a0[i] = 0;
        } else {
            a0[i] = b[i];
        }
    }

    // Verify the solution
    std::fill(current_delta.begin(), current_delta.end(), 0);
    std::vector<long long> current_a = a0;

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array
    for (int i = 0; i < n; ++i) {
        if (a0[i] < -1000000000LL || a0[i] > 1000000000LL) {
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long office_cry_effect = children[i].v;
        long long cumulative_hall_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cumulative hall cry effect from previous children who ran away
            children[j].p -= cumulative_hall_cry_effect;

            // Apply office cry effect from current child
            if (office_cry_effect > 0) {
                children[j].p -= office_cry_effect;
                office_cry_effect--;
            }

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_hall_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

