    //
    // This implies `elements[0]` is in one group, and `elements[1]` and `elements[n-1]` are in the other.
    //
    // Let's try a partition where `elements[0]` is in group 1, and all other elements `elements[1]...elements[n-1]` are in group 2.
    // This is exactly partition 2 we already calculated.
    //
    // What if `elements[0]` and `elements[1]` are in group 1, and `elements[2]...elements[n-1]` are in group 2?
    // Min f:
    //   - From group 1: elements[0].value + elements[1].value
    //   - From group 2: elements[2].value + elements[3].value (if n >= 4)
    //   - From different groups: elements[0].value + elements[2].value + h
    //   So, min_f = elements[0].value + elements[1].value (always the smallest possible)
    // Max f:
    //   - From group 1: elements[0].value + elements[1].value
    //   - From group 2: elements[n-1].value + elements[n-2].value (if n >= 4)
    //   - From different groups: elements[1].value + elements[n-1].value + h
    //   So, max_f = max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h)
    //   Goodness = max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h) - (elements[0].value + elements[1].value)
    //
    // Let's call this partition P_C.
    // This partition puts elements[0] and elements[1] in group 1, and the rest in group 2.
    // This ensures elements[0]+elements[1] is the minimum.
    // The maximum will be max(elements[n-1]+elements[n-2], elements[1]+elements[n-1]+h).
    //
    // This is the third candidate.
    // min_f_PC = elements[0].value + elements[1].value;
    // long long max_f_PC;
    // if (n == 2) { // elements[0], elements[1] in group 1. Group 2 is empty.
    //     max_f_PC = elements[0].value + elements[1].value;
    // } else {
    //     max_f_PC = std::max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h);
    // }
    //
    // The logic for max_f_PC needs to be careful.
    // If n=2, elements[0], elements[1] are in group 1. No elements in group 2. No cross-group pairs.
    // max_f_PC = elements[0].value + elements[1].value.
    // This is the same as goodness1 for n=2.
    //
    // If n=3, elements[0], elements[1] in group 1. elements[2] in group 2.
    // Pairs:
    //   Same group: (elements[0], elements[1]) -> elements[0]+elements[1]
    //   Diff group: (elements[0], elements[2]) -> elements[0]+elements[2]+h
    //               (elements[1], elements[2]) -> elements[1]+elements[2]+h
    // min_f_PC = elements[0].value + elements[1].value
    // max_f_PC = elements[1].value + elements[2].value + h
    // Goodness = (elements[1].value + elements[2].value + h) - (elements[0].value + elements[1].value)
    //
    // If n >= 3:
    // min_f_PC = elements[0].value + elements[1].value;
    // max_f_PC = std::max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h);
    // long long goodness_PC = max_f_PC - min_f_PC;
    //
    // This is the third candidate.
    //
    // Let's re-evaluate the three candidates:
    // Candidate 1: All in group 1.
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[n-1].value + elements[n-2].value
    //   Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    //   Partition: all 1s.
    //
    // Candidate 2: elements[0] in group 1, elements[1...n-1] in group 2.
    //   min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h) (if n >= 3)
    //           elements[0].value + elements[1].value + h (if n == 2)
    //   max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h) (if n >= 3)
    //           elements[0].value + elements[1].value + h (if n == 2)
    //   Goodness = max_f - min_f
    //   Partition: elements[0] is 1, others are 2.
    //
    // Candidate 3: elements[0], elements[1] in group 1, elements[2...n-1] in group 2.
    //   min_f = elements[0].value + elements[1].value
    //   max_f = std::max(elements[n-1].value + elements[n-2].value, elements[1].value + elements[n-1].value + h) (if n >= 3)
    //           elements[0].value + elements[1].value (if n == 2, group 2 is empty)
    //   Goodness = max_f - min_f
    //   Partition: elements[0], elements[1] are 1, others are 2.

    // Re-calculate goodness1 (all 1s)
    current_min_goodness = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }

    // Calculate goodness for Candidate 2
    if (n >= 2) { // This partition is valid for n >= 2
        long long min_f_cand2;
        if (n == 2) {
            min_f_cand2 = elements[0].value + elements[1].value + h;
        } else { // n >= 3
            min_f_cand2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        }
        long long max_f_cand2 = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
        long long goodness_cand2 = max_f_cand2 - min_f_cand2;

        if (goodness_cand2 < current_min_goodness) {
            current_min_goodness = goodness_cand2;
            best_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    // Calculate goodness for Candidate 3
    if (n >= 3) { // This partition is valid for n >= 3
        long long min_f_cand3 = elements[0].value + elements[1].value;
        long long max_f_cand3 = std::max(elements[n - 1].value + elements[n - 2].value, elements[1].value + elements[n - 1].value + h);
        long long goodness_cand3 = max_f_cand3 - min_f_cand3;

        if (goodness_cand3 < current_min_goodness) {
            current_min_goodness = goodness_cand3;
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << current_min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

