#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r (1-indexed) such that [l, r] contains a bad triplet.
                                                // Initialized to n+1, meaning no such r found yet for that l.

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Check for k=1
        if (x + 2 < n) {
            if (s[x] == s[x + 1] && s[x + 1] == s[x + 2]) {
                // Found a triplet s[x] = s[x+1] = s[x+2]
                // This triplet spans from index x to x+2.
                // Any (l, r) such that l <= x+1 and r >= x+3 will contain this triplet.
                // We are interested in the minimum r for each l.
                // For l from 1 to x+1, the minimum r is x+3.
                // So, for l in [1, x+1], update min_r_for_l[l] = min(min_r_for_l[l], x+3).
                // Since we iterate x from left to right, x+3 is non-decreasing.
                // This means for a fixed l, the first x that satisfies l <= x+1 will give the smallest x+3.
                // However, we need to update for all l up to x+1.
                // The current x is the smallest starting point for this triplet.
                // So, for any l from 1 to x+1, this triplet (x, x+1, x+2) is valid.
                // The rightmost index involved is x+2. So r must be at least x+3 (1-indexed).
                // We want to find the smallest r for each l.
                // For l_idx from 0 to x, min_r_for_l[l_idx+1] should be at most x+3.
                // We can update min_r_for_l[l_idx+1] = std::min(min_r_for_l[l_idx+1], x+3).
                // This update needs to be done for all l_idx from 0 to x.
                // The smallest l_idx for which this triplet is valid is 0.
                // The largest l_idx for which this triplet is valid is x.
                // So for l from 1 to x+1, the minimum r is x+3.
                for (int l_idx = 0; l_idx <= x; ++l_idx) {
                    min_r_for_l[l_idx + 1] = std::min(min_r_for_l[l_idx + 1], x + 3);
                }
            }
        }

        // Check for k=2
        if (x + 4 < n) {
            if (s[x] == s[x + 2] && s[x + 2] == s[x + 4]) {
                // Found a triplet s[x] = s[x+2] = s[x+4]
                // This triplet spans from index x to x+4.
                // For l from 1 to x+1, the minimum r is x+5.
                for (int l_idx = 0; l_idx <= x; ++l_idx) {
                    min_r_for_l[l_idx + 1] = std::min(min_r_for_l[l_idx + 1], x + 5);
                }
            }
        }
    }

    long long total_count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one r for this l
            // All r from min_r_for_l[l] to n are valid.
            total_count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
