bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    for (int i = 0; i < m; ++i) { // Iterate through target tracks
        long long current_p = p[i];

        // Find the first head that can potentially cover current_p
        // This head must be able to reach current_p, i.e., h[head_idx] - T <= current_p
        // And it must be available (head_idx < n)
        while (head_idx < n && h[head_idx] + T < current_p) {
            head_idx++;
        }

        if (head_idx == n) { // No head can reach current_p
            return false;
        }

        // Now, h[head_idx] is the first head that can reach current_p (or is to its right)
        // If h[head_idx] - T > current_p, then no head from head_idx onwards can reach current_p
        // because h is sorted. This case is covered by the previous loop.
        // The previous loop ensures h[head_idx] + T >= current_p.
        // We need to ensure h[head_idx] - T <= current_p.
        if (h[head_idx] - T > current_p) {
            return false; // current_p is too far left for any remaining head
        }

        // If we reach here, h[head_idx] can cover current_p.
        // Now, we need to cover as many subsequent tracks as possible with this head.
        // This head can cover tracks up to h[head_idx] + T.
        // So, advance i as long as p[i] is within this range.
        long long max_reach = h[head_idx] + T;
        while (i < m && p[i] <= max_reach) {
            i++;
        }
        i--; // Decrement i because the outer loop will increment it again
        head_idx++; // Move to the next head for the next uncovered track
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance (10^10) + 10^10 = 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // k_left: number of items taken from the left (0 to n)
    for (int k_left = 0; k_left <= n; ++k_left) {
        int k_right = n - k_left; // Number of items taken from the right

        long long current_energy = 0;

        // Base energy for items taken from left
        current_energy += prefix_sum[k_left] * l;

        // Base energy for items taken from right
        current_energy += (prefix_sum[n] - prefix_sum[k_left]) * r;

        // Add penalty for consecutive left actions
        if (k_left > k_right) {
            current_energy += (long long)(k_left - k_right - 1) * Ql;
        }
        // Add penalty for consecutive right actions
        else if (k_right > k_left) {
            current_energy += (long long)(k_right - k_left - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
