int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1
    int current_or_mask = 0;    // All bits are 0
    int current_xor_mask = 0;   // All bits are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_and_mask &= x;
            current_or_mask &= x;
            current_xor_mask &= x;
        } else if (op_char == '|') {
            current_and_mask |= x;
            current_or_mask |= x;
            current_xor_mask |= x;
        } else if (op_char == '^') {
            current_and_mask ^= x;
            current_or_mask ^= x;
            current_xor_mask ^= x;
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // Determine the final AND constant
    // If a bit is 0 in current_and_mask, it means the final result for that bit will be 0, regardless of input.
    // If a bit is 1 in current_and_mask, it means the final result for that bit depends on the input and subsequent OR/XOR.
    // So, the effective AND mask is current_and_mask.
    // We need to find a value `and_val` such that `(x & and_val)` correctly sets bits to 0.
    // This `and_val` should be `current_and_mask`.
    // However, we need to consider the effect of OR and XOR on the bits that are 1 in current_and_mask.
    // Let's use the 0 and 1 values.
    // For an input bit `b`, the final bit is `(b & current_and_mask_bit) | current_or_mask_bit ^ current_xor_mask_bit`.
    // This is equivalent to `(b & A) | O ^ X`.
    // We need to find A', O', X' such that `(b & A') | O' ^ X'` is equivalent.

    // Let's find the final values for input 0 and input 1023 (all 1s).
    // For input 0:
    // 0 & current_and_mask = 0
    // 0 | current_or_mask = current_or_mask
    // current_or_mask ^ current_xor_mask = final_val_for_0
    int final_val_for_0 = (0 & current_and_mask) | current_or_mask ^ current_xor_mask;

    // For input 1023 (all 1s):
    // 1023 & current_and_mask = current_and_mask
    // current_and_mask | current_or_mask = current_and_mask | current_or_mask
    // (current_and_mask | current_or_mask) ^ current_xor_mask = final_val_for_1023
    int final_val_for_1023 = (1023 & current_and_mask) | current_or_mask ^ current_xor_mask;

    // Now we need to find A, O, X such that:
    // (0 & A) | O ^ X = final_val_for_0
    // (1023 & A) | O ^ X = final_val_for_1023

    // From the first equation: O ^ X = final_val_for_0
    // So, X = O ^ final_val_for_0

    // Substitute X into the second equation:
    // (1023 & A) | O ^ (O ^ final_val_for_0) = final_val_for_1023
    // (1023 & A) | O ^ O ^ final_val_for_0 = final_val_for_1023
    // (1023 & A) | 0 ^ final_val_for_0 = final_val_for_1023
    // (1023 & A) | final_val_for_0 = final_val_for_1023

    // This means that for each bit `i`:
    // `(1 & A_i) | final_val_for_0_i = final_val_for_1023_i`
    // If `final_val_for_0_i` is 0: `A_i = final_val_for_1023_i`
    // If `final_val_for_0_i` is 1: `1 | final_val_for_0_i = final_val_for_1023_i` which means `1 = final_val_for_1023_i`.
    // So if `final_val_for_0_i` is 1, then `final_val_for_1023_i` must be 1. In this case, `A_i` can be 0 or 1.
    // To minimize operations, we want to maximize A (i.e., keep bits as 1 if possible).
    // So, if `final_val_for_0_i` is 1, `A_i` should be 1.

    // Let's construct A, O, X.
    // A: If `final_val_for_0_i` is 0, `A_i` is `final_val_for_1023_i`.
    //    If `final_val_for_0_i` is 1, `A_i` is 1.
    // This can be written as `A = (~final_val_for_0 & final_val_for_1023) | final_val_for_0`.
    // Which simplifies to `A = final_val_for_1023 | final_val_for_0`.
    // This is the `A` that makes `(1023 & A) | final_val_for_0 = final_val_for_1023` true.
    // Let's verify:
    // If `final_val_for_0_i` is 0: `A_i = final_val_for_1023_i`. Then `(1 & A_i) | 0 = A_i = final_val_for_1023_i`. Correct.
    // If `final_val_for_0_i` is 1: `A_i = 1`. Then `(1 & 1) | 1 = 1 = final_val_for_1023_i`. Correct.
    int A = final_val_for_1023 | final_val_for_0;

    // O: We want to find O such that `O ^ X = final_val_for_0`.
    // And `(1023 & A) | O ^ X = final_val_for_1023`.
    // We have `(1023 & A) | final_val_for_0 = final_val_for_1023`.
    // This means `O` should be chosen such that `O ^ X` is `final_val_for_0`.
    // The simplest choice for `O` is `final_val_for_0`.
    // Then `X` would be `0`.
    // Let's try this: `A = final_val_for_1023 | final_val_for_0`, `O = final_val_for_0`, `X = 0`.
    // Check:
    // `(0 & A) | O ^ X = (0 & A) | final_val_for_0 ^ 0 = final_val_for_0`. Correct.
    // `(1023 & A) | O ^ X = (1023 & (final_val_for_1023 | final_val_for_0)) | final_val_for_0 ^ 0`
    // `= (final_val_for_1023 | final_val_for_0) | final_val_for_0`
    // `= final_val_for_1023 | final_val_for_0`.
    // This is not necessarily `final_val_for_1023`.
    // Example: final_val_for_0 = 1, final_val_for_1023 = 0.
    // A = 0 | 1 = 1.
    // O = 1, X = 0.
    // (1023 & 1) | 1 ^ 0 = 1 | 1 = 1. Expected 0. Fails.

    // Let's rethink. We need to find A, O, X such that:
    // 1. `(0 & A) | O ^ X = final_val_for_0`  => `O ^ X = final_val_for_0`
    // 2. `(1023 & A) | O ^ X = final_val_for_1023` => `(1023 & A) | final_val_for_0 = final_val_for_1023`

    // From (2), for each bit `i`:
    // `(1 & A_i) | final_val_for_0_i = final_val_for_1023_i`
    // This implies:
    // If `final_val_for_0_i` is 0: `A_i = final_val_for_1023_i`.
    // If `final_val_for_0_i` is 1: `final_val_for_1023_i` must be 1. In this case, `A_i` can be 0 or 1.
    // To minimize operations, we want to use `&` only if necessary.
    // If `final_val_for_0_i` is 1, and `final_val_for_1023_i` is 1, then `A_i` can be 1.
    // So, `A_i = final_val_for_1023_i` if `final_val_for_0_i` is 0.
    // `A_i = 1` if `final_val_for_0_i` is 1.
    // This means `A = (~final_val_for_0 & final_val_for_1023) | final_val_for_0`.
    // This is `A = final_val_for_1023 | final_val_for_0`.
    // This `A` is the largest possible `A` that satisfies the condition.
    // Let's call this `and_const`.
    int and_const = final_val_for_1023 | final_val_for_0;

    // Now we have `(x & and_const)`.
    // We need to apply `| or_const ^ xor_const` to this.
    // Let `y = x & and_const`.
    // We need `y | or_const ^ xor_const` to be the final result.
    // For `x=0`, `y=0`. So `0 | or_const ^ xor_const = final_val_for_0`.
    // This means `or_const ^ xor_const = final_val_for_0`.
    // For `x=1023`, `y = 1023 & and_const`.
    // So `(1023 & and_const) | or_const ^ xor_const = final_val_for_1023`.
    // Substitute `or_const ^ xor_const = final_val_for_0`:
    // `(1023 & and_const) | final_val_for_0 = final_val_for_1023`.
    // This is exactly how we derived `and_const`.

    // Now we need to find `or_const` and `xor_const` such that `or_const ^ xor_const = final_val_for_0`.
    // We want to minimize operations.
    // If `final_val_for_0` is 0, we can use `or_const = 0, xor_const = 0`.
    // If `final_val_for_0` is non-zero, we can use `or_const = final_val_for_0, xor_const = 0` (one OR op).
    // Or `or_const = 0, xor_const = final_val_for_0` (one XOR op).
    // Let's choose `or_const = final_val_for_0` and `xor_const = 0`.
    int or_const = final_val_for_0;
    int xor_const = 0;

    // The sequence of operations is:
    // `& and_const`
    // `| or_const`
    // `^ xor_const`

    // Add operations if their constant is not the identity.
    if (and_const != 1023) { // & 1023 does nothing
        result_ops.push_back({'&', and_const});
    }
    if (or_const != 0) { // | 0 does nothing
        result_ops.push_back({'|', or_const});
    }
    if (xor_const != 0) { // ^ 0 does nothing
        result_ops.push_back({'^', xor_const});
    }

    // The above logic produces at most 3 operations.
    // This is always sufficient.

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_r = sum of r from 1 to b-1
    // Sum_r = (b-1) * b / 2
    // Since MOD is prime and > 2, we can use modular inverse for /2
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;

    // Modular inverse of 2 modulo 1000000007 is (1000000007 + 1) / 2 = 500000004
    long long inv2 = 500000004; 
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum_k_term = sum of (k*b + 1) from k=1 to a
    // Sum_k_term = sum of (k*b) + sum of (1)
    // Sum_k_term = b * (sum of k from 1 to a) + a
    // Sum_k_term = b * (a * (a+1) / 2) + a
    long long sum_k_part1 = (a * (a + 1)) % MOD;
    sum_k_part1 = (sum_k_part1 * inv2) % MOD;
    sum_k_part1 = (sum_k_part1 * b) % MOD;

    long long sum_k_part2 = a % MOD;

    long long sum_k_term = (sum_k_part1 + sum_k_part2) % MOD;

    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

