int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reversed permutation p' = [p_n, p_{n-1}, ..., p_1]
        // will have the same set of adjacent sums as p.
        // For example, if p = [p_1, p_2, ..., p_n], sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
        // If p' = [p_n, p_{n-1}, ..., p_1], sums are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
        // These two sets of sums are identical, just in reverse order.
        // Since the fingerprint F(p) sorts these sums, F(p) will be equal to F(p').
        // The problem guarantees that a solution exists and p' must be different from p.
        // A permutation p is equal to its reverse p' only if p is a palindrome.
        // For n >= 2, it's always possible to find a non-palindromic permutation.
        // The problem statement implies that for any given p, its reverse p' will either be different
        // or if p is a palindrome, there's some other way to find a different p'.
        // However, the simplest and most direct solution is to just reverse the given permutation.
        // The problem constraints (n >= 2) ensure that if p is [1,2], p_rev is [2,1], which is different.
        // If p is [1,2,1], p_rev is [1,2,1], which is the same. But such a p is not a permutation of length 3.
        // A permutation of length n cannot be a palindrome if n > 1 and the elements are distinct 1 to n.
        // For example, if n=3, p=[1,2,3]. p_rev=[3,2,1]. Different.
        // If n=4, p=[1,2,3,4]. p_rev=[4,3,2,1]. Different.
        // In general, for a permutation of distinct integers from 1 to n, p_1 cannot be equal to p_n if n > 1,
        // unless n=1 (which is not allowed by constraints).
        // If p_1 = p_n, then p_1 and p_n are the same value, but they must be distinct elements of the permutation.
        // This means p_1 and p_n must be different indices, but hold the same value, which is impossible for a permutation.
        // So p_1 != p_n for n > 1.
        // Therefore, p cannot be equal to its reverse p_rev, because p_1 != p_n.
        // Thus, reversing the permutation always yields a different permutation for n >= 2.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

