        long long distance = pile_index; // distance from pile 0 (pile 1 in 1-indexed)

        if (days_remaining <= 0) {
            break;
        }

        if (distance == 0) { // Should not happen for i > 0
            continue;
        }

        // Calculate how many haybales can be moved from pile i to pile 0
        // Each haybale costs 'distance' days
        long long haybales_can_move_from_this_pile = a[i];
        long long max_haybales_by_days = days_remaining / distance;

        long long haybales_to_move = std::min(haybales_can_move_from_this_pile, max_haybales_by_days);

        current_a1 += haybales_to_move;
        days_remaining -= haybales_to_move * distance;
    }

    std::cout << current_a1 << std::endl;
}

