#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // If a[i] was 1 or -1, it contributes to has_pos_one/has_neg_one for elements before it.
            // But we are iterating backwards, so we need to update has_pos_one/has_neg_one *after* checking a[i].
            // The current has_pos_one/has_neg_one values are for elements a[0]...a[i-1].
            // So, if a[i] is 1 or -1, it doesn't affect operations for a[i] itself,
            // but it would affect operations for a[k] where k > i.
            // Since we are iterating backwards, we consider a[i] as a target.
            // The has_pos_one/has_neg_one flags should reflect elements a[0]...a[i-1].
            // The flags are updated *after* processing a[i].
        } else if (a[i] < b[i]) {
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }
        // Update has_pos_one and has_neg_one for the prefix a[0...i-1]
        // by removing a[i]'s contribution.
        // This is effectively what happens when we move to i-1.
        // The flags `has_pos_one` and `has_neg_one` should represent if there's a 1 or -1
        // available in the prefix a[0...i-1].
        // So, if a[i] was 1, it means there was a 1 available for elements a[k] where k > i.
        // When we consider a[i-1], a[i] is no longer available as a source.
        // However, the problem states that a[i] itself is never changed.
        // So, the initial `has_pos_one` and `has_neg_one` flags should be based on the *original* array `a`.
        // Let's re-evaluate.
        // The flags `has_pos_one` and `has_neg_one` should indicate if there is an element `a_k` with `k < i`
        // such that `a_k = 1` or `a_k = -1`.
        // So, we need to maintain these flags as we iterate.
        // The initial scan for `has_pos_one` and `has_neg_one` is for the entire array `a`.
        // This is incorrect. The flags must be for `a[0...i-1]`.
    }

    // Correct approach: Iterate from left to right, maintaining prefix information.
    // The flags `has_pos_one` and `has_neg_one` should indicate if there is a 1 or -1
    // in the prefix `a[0...i-1]`.
    // For `a[0]`, it cannot be changed by any other element, as there are no `k < 0`.
    // So `a[0]` must be equal to `b[0]`.
    // For `a[i]`, it can be changed by `a[k]` where `k < i`.
    // So, we need to know if there's a `1` or `-1` in `a[0...i-1]`.

    has_pos_one = false; // Reset for the correct logic
    has_neg_one = false; // Reset for the correct logic
    possible = true;

    if (a[0] != b[0]) {
        possible = false;
    } else {
        if (a[0] == 1) has_pos_one = true;
        if (a[0] == -1) has_neg_one = true;

        for (int i = 1; i < n; ++i) {
            if (a[i] < b[i]) { // Need to increase a[i]
                if (!has_pos_one) {
                    possible = false;
                    break;
                }
            } else if (a[i] > b[i]) { // Need to decrease a[i]
                if (!has_neg_one) {
                    possible = false;
                    break;
                }
            }
            // If a[i] == b[i], no operation needed.
            // Update flags for the next iteration (i+1)
            if (a[i] == 1) has_pos_one = true;
            if (a[i] == -1) has_neg_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

