#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        // The frog starts at cell 0.
        // It needs to reach cell n+1.
        // It can only jump right from cell 0.
        // If it lands on cell i (1 <= i <= n) and s[i-1] is 'L', it can only jump left.
        // This means to make progress towards n+1, the frog must only land on cells i
        // where s[i-1] is 'R', or jump directly to n+1.
        // Effectively, the frog can only jump right.
        // The problem asks for the minimum d such that the frog can reach n+1.
        // This means the frog must be able to jump from its current position 'curr_pos'
        // to some 'next_pos' such that 'next_pos - curr_pos <= d'.
        // The frog can only jump to cells 'i' where s[i-1] is 'R', or to n+1.
        // So, we are looking for the maximum gap between consecutive 'R' cells (including 0 and n+1).

        int max_gap = 0;
        int last_R_pos = 0; // Represents cell 0, which is always a valid starting point for a right jump.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If s[i] is 'R', it means cell i+1 is a valid landing spot for a right jump.
                // The distance from the last valid right-jump cell (last_R_pos) to this cell (i+1)
                // is (i+1) - last_R_pos.
                // The frog must be able to cover this distance with d.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell.
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // (or cell 0 if no 'R's) to the target n+1.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

