    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    bool n_found = false;

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        if (max_val_in_row == n - 1 && !n_found) {
            // This element p[i] must be n.
            // If there are multiple such rows, it means n-1 is not present in the permutation.
            // But the problem guarantees a valid permutation from 1 to n.
            // So, if max_val_in_row is n-1, p[i] must be n.
            // If n-1 is not present in the permutation, then the max value in any row
            // would be at most n-2 (if n is not p[i]) or n (if n is p[i]).
            // The only way max_val_in_row can be n-1 is if p[i] = n.
            // This logic is slightly flawed. max_val_in_row being n-1 means that
            // there exists some p[j] = n-1 and p[i] > p[j], or p[i] = n-1.
            // If p[i] = n, then max_val_in_row would be n-1 (if n-1 exists).
            // If p[i] < n, then max_val_in_row would be p[i] (if p[i] is greater than all other p[j] < p[i])
            // or some p[j] < p[i].
            // The key insight is that if p[i] = n, then for all j != i, min(p[i], p[j]) = p[j].
            // So the values in row i (excluding a[i][i]) are exactly all other p[j]'s.
            // The maximum of these values would be n-1.
            // If p[i] < n, then max_val_in_row would be p[i] (if p[i] is greater than all p[j] < p[i])
            // or some p[j] < p[i].
            // In any case, if p[i] < n, then max_val_in_row <= p[i] < n.
            // So, if max_val_in_row == n-1, it implies p[i] must be n.
            p[i] = n;
            n_found = true;
        } else {
            p[i] = max_val_in_row;
        }
    }

    // If n was not found (meaning n-1 was not present in the input matrix as a max_val_in_row),
    // it implies that n-1 was the largest value in the permutation, and n was not present.
    // This contradicts the problem statement that it's a permutation of 1 to n.
    // The only way max_val_in_row can be n-1 is if p[i] = n.
    // If n-1 is not present in the permutation, then the max value in any row
    // would be at most n-2 (if n is not p[i]) or n (if n is p[i]).
    // The problem guarantees a solution.
    // The logic for finding 'n' is: if p[i] = n, then max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = n-1.
    // If p[i] < n, then max_{j!=i} min(p[i], p[j]) <= p[i] < n.
    // So, the element p[k] that is equal to n is the one for which max_{j!=k} a[k][j] = n-1.
    // If there are multiple such elements, it means n-1 is not in the permutation, which is impossible.
    // So there is exactly one such element.
    // The problem states "guaranteed that there is at least one solution".
    // If n-1 is not present in the permutation, then the max value in any row would be at most n-2 (if n is not p[i]) or n (if n is p[i]).
    // This means if n-1 is not present, then the max_val_in_row for p[i]=n would be n-2 (if n-2 is the largest other element).
    // This is the tricky part. The problem guarantees a permutation of 1 to n.
    // So, n-1 must be present.
    // Thus, the logic `if (max_val_in_row == n - 1 && !n_found)` correctly identifies the position of `n`.
    // If `n_found` is still false after the loop, it means no row had `n-1` as its maximum.
    // This implies that `n-1` is not present in the permutation, which is a contradiction.
    // So `n_found` must be true.

    // The problem states "guaranteed that there is at least one solution that is consistent with the information given."
    // This implies that exactly one `max_val_in_row` will be `n-1`.
    // If `n_found` is false after the loop, it means `n-1` was not the maximum in any row.
    // This can only happen if `n-1` is not in the permutation, which is impossible.
    // So, `n_found` must be true.

    // The logic for finding 'n' is:
    // If p[i] = n, then for all j != i, min(p[i], p[j]) = p[j].
    // So, the values in row i (excluding a[i][i]) are exactly all other p[j]'s.
    // The maximum of these values would be n-1.
    // If p[i] < n, then max_{j!=i} min(p[i], p[j]) <= p[i] < n.
    // So, the element p[k] that is equal to n is the one for which max_{j!=k} a[k][j] = n-1.
    // This is the only position where p[i] can be n.
    // All other p[i] values are correctly identified as max_val_in_row.

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

