int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k_max = n / m;

        if (k_max == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long last_digit_m = m % 10;

        // Precompute the sum of last digits for one cycle (10 iterations)
        // The sequence of last digits (i*m)%10 repeats every 10 values of i.
        // (i*m)%10, ((i+1)*m)%10, ..., ((i+9)*m)%10
        // The sum of these 10 last digits is constant for any i.
        // Example: m=14. Last digits: 4, 8, 2, 6, 0, 4, 8, 2, 6, 0. Sum = 40.
        // This is because (i*m)%10 is equivalent to ( (i%10) * (m%10) ) % 10
        // if m is not a multiple of 10.
        // More generally, (i*m)%10 is (i * (m%10)) % 10 if m is not a multiple of 10.
        // If m is a multiple of 10, then (i*m)%10 is always 0.
        // The sequence of last digits of (i*m) is periodic with period 10.
        // (1*m)%10, (2*m)%10, ..., (10*m)%10 is one full cycle.

        long long sum_one_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_one_cycle += (static_cast<long long>(i) * last_digit_m) % 10;
        }

        long long num_full_cycles = k_max / 10;
        long long remaining_terms = k_max % 10;

        long long total_sum = num_full_cycles * sum_one_cycle;

        for (long long i = 1; i <= remaining_terms; ++i) {
            total_sum += (i * last_digit_m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are both pos[1].
        // Length is 1. Max value is 1. Min value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover the range
        // from min(pos[1], ..., pos[m]) to max(pos[1], ..., pos[m]).

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the segment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This means its length must be exactly m.
        // The length of the segment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

