int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // The quadratic equation is a^2 - d*a + d = 0
        // Discriminant = (-d)^2 - 4*1*d = d^2 - 4d
        double discriminant = d * d - 4 * d;

        if (discriminant < 0) { // No real solutions
            std::cout << "N\n";
        } else {
            // Solutions for 'a' are (d +/- sqrt(discriminant)) / 2
            double sqrt_discriminant = std::sqrt(discriminant);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b = d - a

            // We need a and b to be non-negative.
            // Since d >= 0, and sqrt_discriminant >= 0, a1 will always be >= 0.
            // We need to check if b1 is non-negative.
            // b1 = d - (d + sqrt_discriminant) / 2 = (2d - d - sqrt_discriminant) / 2 = (d - sqrt_discriminant) / 2
            // For b1 to be non-negative, d - sqrt_discriminant >= 0, which means d >= sqrt_discriminant.
            // Squaring both sides (since d >= 0 and sqrt_discriminant >= 0), d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So, if discriminant >= 0, both solutions for 'a' (and their corresponding 'b' values) will be non-negative.
            // We can just pick one pair, e.g., (a1, b1).

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

