void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if it's possible to form an increasing sequence from left
    // a_i must be at least i-1 to form 0, 1, 2, ..., i-1
    // If a_i < i-1, then it's impossible to make a_i = i-1 or greater
    // while maintaining a_1 < ... < a_i.
    // So, we need a_i >= i-1 for all i in the increasing part.
    // The maximum possible length of the increasing part from the left
    // is limited by the first index 'i' where a[i] < i.
    // Let's find the first index 'i' (0-indexed) such that a[i] < i.
    // All elements before this index can potentially be part of the increasing sequence.
    int left_limit = n;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_limit = i;
            break;
        }
    }

    // Check if it's possible to form a decreasing sequence from right
    // a_i must be at least n-1-i to form ..., 2, 1, 0
    // If a_i < n-1-i, then it's impossible to make a_i = n-1-i or greater
    // while maintaining a_n > ... > a_i.
    // So, we need a_i >= n-1-i for all i in the decreasing part.
    // The maximum possible length of the decreasing part from the right
    // is limited by the first index 'i' (from right) where a[i] < n-1-i.
    // Let's find the first index 'i' (0-indexed) such that a[i] < n-1-i.
    // All elements after this index can potentially be part of the decreasing sequence.
    int right_limit = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_limit = i;
            break;
        }
    }

    // If left_limit > right_limit, it means there is at least one index 'k'
    // such that a[k] >= k (for the increasing part) AND a[k] >= n-1-k (for the decreasing part).
    // This 'k' can be the peak.
    // The condition left_limit > right_limit means that the "valid" range for the peak
    // from the left (indices 0 to left_limit-1) overlaps with the "valid" range for the peak
    // from the right (indices right_limit+1 to n-1).
    // Specifically, if left_limit is the first index where a[i] < i, then all indices
    // 0, ..., left_limit-1 satisfy a[j] >= j.
    // If right_limit is the first index (from right) where a[i] < n-1-i, then all indices
    // right_limit+1, ..., n-1 satisfy a[j] >= n-1-j.
    // If left_limit > right_limit, it means there is at least one index `k` such that
    // `k < left_limit` and `k > right_limit`.
    // For such a `k`, `a[k] >= k` and `a[k] >= n-1-k`.
    // This `k` can be chosen as the peak.
    if (left_limit > right_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

