void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number that satisfies the conditions.
        // The strategy is to use '2' as the first digit and '3' for all subsequent digits.
        // This number will be 233...3 (n-1 times '3').
        // Let's check the conditions for s = 233...3:
        // 1. s > 0: True.
        // 2. s consists of n digits: True, as we construct it with n digits.
        // 3. No digit in s equals 0: True, all digits are 2 or 3.
        // 4. s is not divisible by any of its digits:
        //    The digits are 2 and 3.
        //    Is s divisible by 2? No, because the last digit is 3 (odd).
        //    Is s divisible by 3? The sum of digits is 2 + (n-1)*3.
        //    If n=2, s=23. Sum of digits = 2+3=5. Not divisible by 3.
        //    If n=3, s=233. Sum of digits = 2+3+3=8. Not divisible by 3.
        //    In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    For s to be divisible by 3, 3n - 1 must be divisible by 3.
        //    However, 3n is always divisible by 3, so 3n - 1 will never be divisible by 3.
        //    Thus, s is never divisible by 3.
        // This construction works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

