void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want to find b1, b2, ... such that (current_sum + sum_b) = 2 * (current_xor_sum ^ xor_b)
    // Let S' = current_sum + sum_b
    // Let X' = current_xor_sum ^ xor_b
    // We want S' = 2 * X'

    // Strategy: Append at most 3 elements.
    // It's always possible to achieve this by appending at most 2 elements.
    // Let's try to append two elements, say P and Q.
    // We want (current_sum + P + Q) = 2 * (current_xor_sum ^ P ^ Q)

    // Consider P = current_xor_sum.
    // Then current_xor_sum ^ P = current_xor_sum ^ current_xor_sum = 0.
    // The equation becomes (current_sum + current_xor_sum + Q) = 2 * (0 ^ Q)
    // (current_sum + current_xor_sum + Q) = 2 * Q
    // current_sum + current_xor_sum = Q

    // So, if we append P = current_xor_sum and Q = current_sum + current_xor_sum,
    // the new sum will be S' = current_sum + current_xor_sum + (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // The new XOR sum will be X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum) = 0 ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum
    // Then S' = 2 * X' holds.

    // The two elements to append are:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum

    // These values can be large, up to 10^5 * 10^9 + 10^9 approx 10^14, which fits in long long.
    // The problem statement says b_i can be up to 10^18.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

