int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The two classes must have odd sizes.
        // Let the sizes be 2k_A+1 and 2k_B+1.
        // (2k_A+1) + (2k_B+1) = 2n
        // 2k_A + 2k_B + 2 = 2n
        // k_A + k_B + 1 = n
        // k_A + k_B = n - 1

        // The median of a class of size 2k+1 is the (k+1)-th element.
        // For Class A, median is a_A[k_A].
        // For Class B, median is a_B[k_B].

        // To minimize the difference between medians, we should pick the medians
        // from the sorted full array that are as close as possible.
        // The smallest possible median for any class is a[0].
        // The largest possible median for any class is a[2n-1].

        // Consider the case where one class takes the smallest n elements
        // and the other class takes the largest n elements.
        // This is not necessarily true, as class sizes can vary.
        // However, the problem statement implies that the optimal strategy
        // involves picking the medians from the "middle" of the sorted array.

        // If we sort all 2n students, a_0, a_1, ..., a_{2n-1}.
        // The smallest possible median for a class of size 2k+1 is a[k].
        // The largest possible median for a class of size 2k+1 is a[2n-1-k].

        // The key insight is that to minimize the difference, we should make the medians
        // as close as possible.
        // If we pick a[n-1] as the median for one class and a[n] as the median for the other,
        // we need to ensure that these elements can indeed be medians.

        // If a[n-1] is the median of Class A (size 2k_A+1), then Class A must contain
        // at least k_A elements smaller than or equal to a[n-1] and k_A elements
        // greater than or equal to a[n-1].
        // If a[n] is the median of Class B (size 2k_B+1), then Class B must contain
        // at least k_B elements smaller than or equal to a[n] and k_B elements
        // greater than or equal to a[n].

        // The most balanced partition in terms of indices is to split the sorted array
        // into two halves: [a_0, ..., a_{n-1}] and [a_n, ..., a_{2n-1}].
        // If we assign a_0, ..., a_{n-1} to Class A and a_n, ..., a_{2n-1} to Class B,
        // this would mean each class has n students.
        // However, n can be even or odd. If n is even, this is not allowed.
        // If n is odd, then each class has n students, and the median of Class A would be
        // a_{(n-1)/2} and the median of Class B would be a_{n + (n-1)/2}.

        // The problem simplifies significantly if we realize that the optimal strategy
        // is to pick the (n-1)-th element and the n-th element (0-indexed) from the
        // globally sorted array as the medians of the two classes.
        // Let's try to prove this.
        // Suppose we have two classes A and B with medians M_A and M_B.
        // Let M_A be the (k_A+1)-th element of A and M_B be the (k_B+1)-th element of B.
        // In the global sorted array, M_A = a_i and M_B = a_j for some i, j.
        // Without loss of generality, assume M_A <= M_B.
        // To make M_A the median of A, A must contain at least k_A elements <= M_A and k_A elements >= M_A.
        // To make M_B the median of B, B must contain at least k_B elements <= M_B and k_B elements >= M_B.

        // Consider the elements a[n-1] and a[n].
        // Can we always construct two classes such that a[n-1] is the median of one and a[n] is the median of the other?
        // Let Class A have median a[n-1] and Class B have median a[n].
        // We need to form Class A with size 2k_A+1 and Class B with size 2k_B+1 such that k_A+k_B = n-1.
        // For Class A to have median a[n-1]:
        // It needs k_A elements <= a[n-1] and k_A elements >= a[n-1].
        // We can pick a[n-1] itself.
        // We have n-1 elements a[0], ..., a[n-2] which are <= a[n-1]. We can pick k_A of these.
        // We have n elements a[n], ..., a[2n-1] which are >= a[n-1]. We can pick k_A of these.
        // For Class B to have median a[n]:
        // It needs k_B elements <= a[n] and k_B elements >= a[n].
        // We can pick a[n] itself.
        // We have n elements a[0], ..., a[n-1] which are <= a[n]. We can pick k_B of these.
        // We have n-1 elements a[n+1], ..., a[2n-1] which are >= a[n]. We can pick k_B of these.

        // The simplest way to achieve this is to make both classes of size n.
        // This is only possible if n is odd.
        // If n is odd, then 2k+1 = n implies k = (n-1)/2.
        // Class A: median a[n-1]. We need (n-1)/2 elements <= a[n-1] and (n-1)/2 elements >= a[n-1].
        // We can pick a[0], ..., a[(n-1)/2 - 1] (total (n-1)/2 elements)
        // We pick a[n-1] as the median.
        // We pick a[n], ..., a[n + (n-1)/2 - 1] (total (n-1)/2 elements).
        // This forms Class A: {a[0], ..., a[(n-1)/2 - 1], a[n-1], a[n], ..., a[n + (n-1)/2 - 1]}.
        // This class has size (n-1)/2 + 1 + (n-1)/2 = n.
        // The elements used are a[0]...a[(n-1)/2-1], a[n-1], a[n]...a[n+(n-1)/2-1].

        // Class B: median a[n]. We need (n-1)/2 elements <= a[n] and (n-1)/2 elements >= a[n].
        // We can pick a[(n-1)/2], ..., a[n-2] (total n-1 - (n-1)/2 = (n-1)/2 elements).
        // We pick a[n] as the median.
        // We pick a[n + (n-1)/2], ..., a[2n-1] (total 2n-1 - (n + (n-1)/2) + 1 = n-1 - (n-1)/2 = (n-1)/2 elements).
        // This forms Class B: {a[(n-1)/2], ..., a[n-2], a[n], a[n + (n-1)/2], ..., a[2n-1]}.
        // This class has size (n-1)/2 + 1 + (n-1)/2 = n.

        // This construction works if n is odd.
        // The elements used are:
        // For A: a[0]...a[(n-1)/2-1], a[n-1], a[n]...a[n+(n-1)/2-1]
        // For B: a[(n-1)/2]...a[n-2], a[n], a[n+(n-1)/2]...a[2n-1]
        // All elements from a[0] to a[2n-1] are used exactly once.
        // The medians are a[n-1] and a[n]. The difference is a[n] - a[n-1].

        // What if n is even?
        // Then n is not an odd number, so we cannot have two classes of size n.
        // The smallest odd size is 1. The largest odd size is 2n-1.
        // The sum of sizes is 2n.
        // Let sizes be $S_A = 2k_A+1$ and $S_B = 2k_B+1$.
        // $S_A + S_B = 2n$.
        // $k_A + k_B = n-1$.

        // The crucial observation is that the median of a sorted array of $2k+1$ elements is the $(k+1)$-th element.
        // If we sort all $2n$ students, $a_0, a_1, \dots, a_{2n-1}$.
        // We want to pick two elements $a_i$ and $a_j$ to be the medians.
        // To minimize $|a_j - a_i|$, we should pick $a_i$ and $a_j$ to be adjacent in the sorted array.
        // The smallest possible difference is $a_{k+1} - a_k$ for some $k$.
        // Can we always make $a_{n-1}$ and $a_n$ the medians of two classes?
        // Yes.
        // Let Class A have median $a_{n-1}$ and Class B have median $a_n$.
        // We need to construct Class A with $2k_A+1$ students and Class B with $2k_B+1$ students,
        // such that $k_A+k_B = n-1$.

        // For Class A (median $a_{n-1}$):
        // We need $k_A$ elements $\le a_{n-1}$ and $k_A$ elements $\ge a_{n-1}$.
        // We can pick $a_{n-1}$ itself.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ that are $\le a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ that are $\ge a_{n-1}$.
        // We can pick $k_A$ elements from $a_0, \dots, a_{n-2}$ and $k_A$ elements from $a_n, \dots, a_{2n-1}$.
        // This is possible if $k_A \le n-1$ and $k_A \le n$.

        // For Class B (median $a_n$):
        // We need $k_B$ elements $\le a_n$ and $k_B$ elements $\ge a_n$.
        // We can pick $a_n$ itself.
        // We have $n$ elements $a_0, \dots, a_{n-1}$ that are $\le a_n$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ that are $\ge a_n$.
        // We can pick $k_B$ elements from $a_0, \dots, a_{n-1}$ and $k_B$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        // This is possible if $k_B \le n$ and $k_B \le n-1$.

        // We need to find $k_A, k_B$ such that $k_A+k_B = n-1$ and all these conditions hold.
        // The conditions are $k_A \le n-1$, $k_B \le n-1$.
        // Since $k_A+k_B = n-1$, if $k_A \le n-1$, then $k_B = n-1-k_A \ge 0$.
        // If $k_B \le n-1$, then $k_A = n-1-k_B \ge 0$.
        // So we just need to pick any valid $k_A$ (e.g., $k_A=0$, then $k_B=n-1$).
        // If $k_A=0$, Class A has size 1, median $a_{n-1}$.
        // Class A = {$a_{n-1}$}. This is valid.
        // Then $k_B=n-1$. Class B has size $2(n-1)+1 = 2n-1$. Median $a_n$.
        // For Class B: need $n-1$ elements $\le a_n$ and $n-1$ elements $\ge a_n$.
        // We have $a_0, \dots, a_{n-2}$ (n-1 elements) and $a_{n+1}, \dots, a_{2n-1}$ (n-1 elements).
        // We can form Class B as $\{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This uses $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The remaining element is $a_{n-1}$, which is used for Class A.
        // All students are assigned. Both classes have odd sizes (1 and 2n-1).
        // The medians are $a_{n-1}$ and $a_n$.
        // The difference is $|a_n - a_{n-1}|$.

        // This construction always works for any $n \ge 1$.
        // The minimum difference is always $a_n - a_{n-1}$ after sorting.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

