int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    for (int i = 0; i <= n; ++i) { // i is the number of items taken from the left
        int j = n - i; // j is the number of items taken from the right

        long long current_energy = 0;

        // Cost for items taken from the left
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Cost for items taken from the right
        // The sum of weights for items taken from the right is total_sum - prefix_sum[i]
        // which is (prefix_sum[n] - prefix_sum[i])
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for consecutive same-side picks
        if (i > j) { // More items from left than right
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            current_energy += (j - i - 1) * Qr;
        }
        // If i == j, no extra penalty from this rule

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::accumulate, though not strictly needed for bitwise OR

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Declare a 2D vector to store the matrix b.
    // Using int as values can be up to 10^9 or -1.
    std::vector<std::vector<int>> b(n, std::vector<int>(n));

    // Read the matrix b.
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> b[i][j];
        }
    }

    // Declare a vector to store the restored sequence a.
    // Initialize with zeros.
    std::vector<int> a(n);

    // For each element a_i in the sequence:
    // a_i can be restored by taking the bitwise OR of all b_ij where j != i.
    // This is because a_i & a_j = b_ij.
    // If a bit is set in b_ij, it must be set in a_i.
    // If a bit is set in a_i, it might not be set in a_j, making b_ij not have that bit.
    // However, if we OR all b_ij for a fixed i, any bit that is set in a_i
    // will be present in at least one a_i & a_j (unless a_j is 0 for all j!=i,
    // but even then, a_i itself would be 0 if all b_ij are 0).
    // The problem guarantees a solution exists and a_i <= 10^9.
    // The maximum possible value for a_i is 2^30 - 1 (approx 10^9).
    // The bitwise OR of all b_ij (j != i) will correctly reconstruct a_i.
    for (int i = 0; i < n; ++i) {
        int current_a_i = 0; // Initialize with 0 for bitwise OR operation
        for (int j = 0; j < n; ++j) {
            if (i == j) {
                continue; // Skip diagonal elements (b_ii = -1)
            }
            current_a_i |= b[i][j]; // Perform bitwise OR
        }
        a[i] = current_a_i;
    }

    // Print the restored sequence a.
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

