void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int p = 0; p <= 9; ++p) {
        std::string coloring(n, ' ');
        char last1 = '0' - 1; // Sentinel for the last digit colored 1
        char last2 = '0' - 1; // Sentinel for the last digit colored 2
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (p + '0')) {
                // Must be color 1
                if (current_digit < last1) {
                    possible_p = false;
                    break;
                }
                coloring[i] = '1';
                last1 = current_digit;
            } else if (current_digit > (p + '0')) {
                // Must be color 2
                if (current_digit < last2) {
                    possible_p = false;
                    break;
                }
                coloring[i] = '2';
                last2 = current_digit;
            } else { // current_digit == (p + '0')
                // Can be color 1 or 2
                // Try to put it in color 2 if possible, to keep color 1 digits small
                if (current_digit >= last2) {
                    coloring[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    coloring[i] = '1';
                    last1 = current_digit;
                } else {
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

