// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means we must remove some prime factors from p such that the resulting number
        // is no longer divisible by q. To maximize x, we should remove the minimum necessary
        // factors.
        // The strategy is to iterate through each distinct prime factor 'r' of q.
        // For each 'r', we find the largest power of 'r' that divides p, say r^k.
        // We then form a candidate x by dividing p by r^k, and then multiplying by r^(k-1).
        // This is equivalent to p / r.
        // More precisely, we find the largest power of r, say r^a, such that r^a divides p
        // and r^a divides q. We want to reduce the power of r in p such that it's less than
        // the power of r in q.
        // The simplest way to ensure x is not divisible by q is to remove all factors of r
        // from p that are also factors of q, until x is no longer divisible by q.
        // The largest such x will be p / (r^k) where r^k is the highest power of r that divides p,
        // and r is a prime factor of q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long r : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by r until it's no longer divisible by q
            // This means we need to find the highest power of r that divides p, say r^k.
            // Then we form a candidate x = p / r^k * r^(k-1) = p / r.
            // This ensures that the power of r in x is one less than in p.
            // If p / r is still divisible by q, we need to remove more factors of r.
            // The goal is to find the largest x = p / (r^k) such that x % q != 0.
            // This means we need to find the smallest k such that p / (r^k) is not divisible by q.
            // Or, equivalently, find the largest x = p / (r^k) such that x % q != 0.

            long long temp_p = p;
            while (temp_p % q == 0) {
                temp_p /= r;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is Sum_r = (b * (b - 1) / 2) % MOD
    // Since b can be up to 10^7, b*(b-1) can be large, so we need to handle division by 2.
    // (b-1) * b is always even, so (b-1)*b/2 is an integer.
    // We need modular inverse for division by 2 if we do (b-1) * b % MOD * inv(2) % MOD.
    // A simpler way is to divide one of the factors by 2 before multiplication,
    // ensuring the result is still an integer.
    long long sum_r_term;
    if ((b - 1) % 2 == 0) {
        sum_r_term = ((b - 1) / 2) % MOD;
        sum_r_term = (sum_r_term * (b % MOD)) % MOD;
    } else {
        sum_r_term = (b % MOD) / 2; // b is even
        sum_r_term = (sum_r_term * ((b - 1) % MOD)) % MOD;
    }

    // Sum of (k * b + 1) from k=1 to a
    // This is Sum_k = Sum_{k=1 to a} (k * b + 1)
    // Sum_k = b * Sum_{k=1 to a} k + Sum_{k=1 to a} 1
    // Sum_k = b * (a * (a + 1) / 2) + a
    // This is Sum_k = (b % MOD * (a * (a + 1) / 2) % MOD + a % MOD) % MOD

    long long sum_k_term_part1;
    if (a % 2 == 0) {
        sum_k_term_part1 = (a / 2) % MOD;
        sum_k_term_part1 = (sum_k_term_part1 * ((a + 1) % MOD)) % MOD;
    } else {
        sum_k_term_part1 = ((a + 1) / 2) % MOD;
        sum_k_term_part1 = (sum_k_term_part1 * (a % MOD)) % MOD;
    }

    sum_k_term_part1 = (sum_k_term_part1 * (b % MOD)) % MOD;

    long long sum_k_term_part2 = a % MOD;

    long long sum_k_term = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> in_password(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        in_password[s[i] - 'a'] = true;
        if (i + 1 < s.length()) {
            adj[s[i] - 'a'].insert(s[i+1]);
            adj[s[i+1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find a starting point for a path
    // A starting point must be a character that is in the password
    // and has only one required neighbor (an endpoint of a path segment).
    // Or, if the password is just one character, that character itself.
    char start_char = 0;
    bool found_start = false;

    if (s.length() == 1) {
        start_char = s[0];
        found_start = true;
    } else {
        for (int i = 0; i < 26; ++i) {
            if (in_password[i] && adj[i].size() == 1) {
                start_char = (char)('a' + i);
                found_start = true;
                break;
            }
        }
    }

    // If no such start_char is found, it means all characters in the password
    // have 2 required neighbors (forming a cycle or a single long path where
    // we haven't found an endpoint yet).
    // Or, it means the password is empty (not possible by constraints)
    // or all characters in password have 0 neighbors (password length 1, handled above).
    // If all characters in password have 2 neighbors, it means they form a cycle.
    // A cycle is not possible on a single-row keyboard (which is a path).
    // However, if the password itself forms a path, and we pick any character
    // from the password, we can start building the layout from there.
    // The only case where `found_start` might be false is if `s` is empty,
    // or if all characters in `s` have degree 2 in the adjacency graph.
    // If all characters in `s` have degree 2, it means they form a cycle.
    // A cycle is not allowed.
    // Example: "abacaba" -> a-b, a-c. 'b' has 1 neighbor 'a'. 'c' has 1 neighbor 'a'.
    // So 'b' or 'c' would be a start.
    // Example: "abcde" -> 'a' has 1, 'e' has 1.
    // Example: "abac" -> 'b' has 1, 'c' has 1.
    // The only way `found_start` is false is if the graph formed by `s` is not a path.
    // If it's a path, it must have two endpoints with degree 1.
    // If it's a cycle, all nodes have degree 2. This is impossible for a linear keyboard.
    // So, if `found_start` is false here, it implies an impossible layout.
    // However, the problem statement guarantees no adjacent equal characters.
    // This implies that the graph formed by the password characters must be a path or a collection of paths.
    // If it's a path, it must have endpoints.
    // The only case where `found_start` could be false is if the password characters form a cycle.
    // For example, if s = "abac", a-b, b-a, a-c, c-a.
    // adj['a'] = {'b', 'c'} (size 2)
    // adj['b'] = {'a'} (size 1)
    // adj['c'] = {'a'} (size 1)
    // Here, 'b' or 'c' would be a start.
    // What if s = "abacaba"?
    // adj['a'] = {'b', 'c'} (size 2)
    // adj['b'] = {'a'} (size 1)
    // adj['c'] = {'a'} (size 1)
    // 'b' or 'c' would be a start.
    // The only way `found_start` is false is if all characters in `s` have degree 2.
    // This would mean the password forms a cycle, e.g., "abcad".
    // a-b, b-c, c-a, a-d.
    // adj['a'] = {'b', 'c', 'd'} (size 3) -> already caught by adj[i].size() > 2 check.
    // So, if we reach here, `found_start` must be true, unless `s` is empty (not possible).
    // If `s` is not empty, and all `adj[i].size() <= 2`, then there must be at least one character with `adj[i].size() <= 1`.
    // If `s.length() == 1`, `s[0]` has `adj[s[0]-'a'].size() == 0`.
    // If `s.length() > 1`, there must be at least two characters with `adj[i].size() == 1` (endpoints of the path).
    // So `found_start` will always be true if `s` is not empty.

    char current_char = start_char;
    if (found_start) {
        while (current_char != 0 && !visited[current_char - 'a']) {
            layout += current_char;
            visited[current_char - 'a'] = true;

            char next_char = 0;
            for (char neighbor : adj[current_char - 'a']) {
                if (!visited[neighbor - 'a']) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Check if all characters from the password are included in the layout
    for (int i = 0; i < 26; ++i) {
        if (in_password[i] && !visited[i]) {
            // This means there's a disconnected component or a cycle
            // that couldn't be traversed from the chosen start_char.
            // This implies an impossible layout.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in the password
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

