int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    int k = static_cast<int>(std::sqrt(n));

    // The permutation will be constructed by blocks.
    // Each block will be printed in decreasing order.
    // The blocks themselves will be arranged such that the first element of a block
    // is greater than the first element of the previous block.
    // This structure ensures that LIS and LDS lengths are close to sqrt(n).

    // Example for n=4, k=2:
    // Block 1: [2, 1]
    // Block 2: [4, 3]
    // Result: [2, 1, 4, 3]
    // LIS: [2, 4] or [1, 3] (length 2)
    // LDS: [2, 1] or [4, 3] (length 2)
    // Sum = 4

    // Example for n=5, k=2:
    // Block 1: [2, 1]
    // Block 2: [4, 3]
    // Block 3: [5] (remaining elements)
    // Result: [2, 1, 4, 3, 5]
    // LIS: [2, 4, 5] or [1, 3, 5] (length 3)
    // LDS: [2, 1] or [4, 3] (length 2)
    // Sum = 5

    // The strategy is to print numbers in blocks of size k,
    // but within each block, print them in decreasing order.
    // The blocks are arranged such that the smallest number in a block
    // is greater than the largest number in the previous block.
    // This is achieved by printing numbers from (i*k + k) down to (i*k + 1).

    for (int i = 0; i < n; ++i) {
        // Calculate the starting value for the current block.
        // The current block starts at (i / k) * k + 1.
        // The numbers in this block are (i / k) * k + 1, ..., (i / k) * k + k.
        // We want to print them in decreasing order.
        // The number to print at index i is:
        // (i / k) * k + k - (i % k)
        // This effectively groups numbers into blocks of size k,
        // and reverses each block.

        // Example: n=4, k=2
        // i=0: (0/2)*2 + 2 - (0%2) = 0*2 + 2 - 0 = 2
        // i=1: (1/2)*2 + 2 - (1%2) = 0*2 + 2 - 1 = 1
        // i=2: (2/2)*2 + 2 - (2%2) = 1*2 + 2 - 0 = 4
        // i=3: (3/2)*2 + 2 - (3%2) = 1*2 + 2 - 1 = 3
        // Output: 2 1 4 3

        // Example: n=5, k=2
        // i=0: 2
        // i=1: 1
        // i=2: 4
        // i=3: 3
        // i=4: (4/2)*2 + 2 - (4%2) = 2*2 + 2 - 0 = 6. This is wrong.
        // The formula (i / k) * k + k - (i % k) works for numbers 1 to k*k.
        // For remaining numbers, we need to handle them.

        // A simpler way: iterate through blocks.
        // For each block, print numbers in decreasing order.
        // The last block might be smaller than k.

        // The numbers are 1 to n.
        // We want to print them in groups of k, reversed.
        // Group 1: k, k-1, ..., 1
        // Group 2: 2k, 2k-1, ..., k+1
        // ...
        // Group m: m*k, m*k-1, ..., (m-1)*k+1
        // The last group: n, n-1, ..., (m-1)*k+1 (if n is not a multiple of k)

        // Let's iterate from n down to 1.
        // When we encounter a number `j` that is the start of a block (j % k == 0 or j == n),
        // we print the block `j, j-1, ..., j-k+1` (or until 1).
        // This is equivalent to printing `k, k-1, ..., 1`, then `2k, 2k-1, ..., k+1`, etc.

        // The current number to print is `val`.
        // The block it belongs to is `ceil(val / k)`.
        // The numbers in this block are `(block_idx-1)*k + 1` to `block_idx*k`.
        // We want to print them in reverse order.

        // Let's try a different construction:
        // Iterate `i` from `0` to `n-1`.
        // The value to print at index `i` is `(i / k) * k + k - (i % k)`.
        // This works for `i` up to `k*k - 1`.
        // For `i >= k*k`, the values are `k*k + 1, k*k + 2, ..., n`.
        // These remaining values should be printed in increasing order.
        // This is because they form a short increasing subsequence at the end,
        // which doesn't significantly increase LDS, but helps LIS.

        // Let's re-evaluate the construction:
        // We want to print blocks of size `k` in decreasing order.
        // The blocks themselves are arranged in increasing order of their minimum element.
        // Example: n=4, k=2
        // Block 1: [2, 1]
        // Block 2: [4, 3]
        // Output: 2 1 4 3

        // Example: n=5, k=2
        // Block 1: [2, 1]
        // Block 2: [4, 3]
        // Block 3: [5] (remaining element)
        // Output: 2 1 4 3 5

        // This can be implemented by iterating `i` from `0` to `n-1`.
        // For each `i`, we determine which block it belongs to.
        // `block_start_val = (i / k) * k + 1`
        // `block_end_val = (i / k) * k + k`
        // The value at index `i` should be `block_end_val - (i % k)`.
        // This works for `i` such that `block_end_val <= n`.
        // For the last block, `block_end_val` might be greater than `n`.
        // In that case, the block goes from `(i / k) * k + 1` to `n`.
        // The values should be `n, n-1, ..., (i / k) * k + 1`.

        // Let's use a loop that iterates through the numbers 1 to n.
        // We will print numbers in groups.
        // `current_val` goes from `1` to `n`.
        // `block_start` is the beginning of the current block.
        // `block_end` is the end of the current block.

        int current_num = 1;
        while (current_num <= n) {
            int block_end = std::min(n, current_num + k - 1);
            // Print numbers from block_end down to current_num
            for (int j = block_end; j >= current_num; --j) {
                std::cout << j << " ";
            }
            current_num = block_end + 1;
        }
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit j (0 to 9), we need to know what it becomes if input bit is 0, and if input bit is 1.
    // bit_val_if_0[j] = final value of bit j if initial bit j was 0
    // bit_val_if_1[j] = final value of bit j if initial bit j was 1
    std::vector<int> bit_val_if_0(10); // Initially, if input bit is 0, output bit is 0
    std::vector<int> bit_val_if_1(10); // Initially, if input bit is 1, output bit is 1

    for (int j = 0; j < 10; ++j) {
        bit_val_if_0[j] = 0;
        bit_val_if_1[j] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int j = 0; j < 10; ++j) {
            int x_j = (x >> j) & 1; // j-th bit of constant x

            if (op_char == '&') {
                bit_val_if_0[j] = bit_val_if_0[j] & x_j;
                bit_val_if_1[j] = bit_val_if_1[j] & x_j;
            } else if (op_char == '|') {
                bit_val_if_0[j] = bit_val_if_0[j] | x_j;
                bit_val_if_1[j] = bit_val_if_1[j] | x_j;
            } else if (op_char == '^') {
                bit_val_if_0[j] = bit_val_if_0[j] ^ x_j;
                bit_val_if_1[j] = bit_val_if_1[j] ^ x_j;
            }
        }
    }

    // Now, we have the final transformation for each bit.
    // We need to find constants A, B, C such that:
    // ( ( (input & A) | B ) ^ C ) produces the same result.
    // Or, more generally, we can use up to 3 operations.
    // Let's try to construct the constants for a minimal set of operations.

    // Target values for the constants for the simplified operations
    int final_and_const = 1023; // All bits 1 initially for AND
    int final_or_const = 0;     // All bits 0 initially for OR
    int final_xor_const = 0;    // All bits 0 initially for XOR

    for (int j = 0; j < 10; ++j) {
        // For each bit j, we have (bit_val_if_0[j], bit_val_if_1[j])
        // This pair represents the function f_j(input_bit_j)
        //
        // Case 1: (0, 0) -> f_j(0)=0, f_j(1)=0. This means bit j is always 0.
        //   To achieve this:
        //   AND constant must have bit j as 0.
        //   OR constant must have bit j as 0.
        //   XOR constant must have bit j as 0.
        //   (x & 0) | 0 ^ 0 = 0
        if (bit_val_if_0[j] == 0 && bit_val_if_1[j] == 0) {
            final_and_const &= ~(1 << j); // Set j-th bit of AND constant to 0
            // final_or_const remains 0 for this bit
            // final_xor_const remains 0 for this bit
        }
        // Case 2: (0, 1) -> f_j(0)=0, f_j(1)=1. This means bit j is unchanged.
        //   To achieve this:
        //   AND constant must have bit j as 1.
        //   OR constant must have bit j as 0.
        //   XOR constant must have bit j as 0.
        //   (x & 1) | 0 ^ 0 = x
        else if (bit_val_if_0[j] == 0 && bit_val_if_1[j] == 1) {
            // final_and_const remains 1 for this bit
            // final_or_const remains 0 for this bit
            // final_xor_const remains 0 for this bit
        }
        // Case 3: (1, 0) -> f_j(0)=1, f_j(1)=0. This means bit j is flipped.
        //   To achieve this:
        //   AND constant must have bit j as 1.
        //   OR constant must have bit j as 0.
        //   XOR constant must have bit j as 1.
        //   (x & 1) | 0 ^ 1 = ~x
        else if (bit_val_if_0[j] == 1 && bit_val_if_1[j] == 0) {
            // final_and_const remains 1 for this bit
            // final_or_const remains 0 for this bit
            final_xor_const |= (1 << j); // Set j-th bit of XOR constant to 1
        }
        // Case 4: (1, 1) -> f_j(0)=1, f_j(1)=1. This means bit j is always 1.
        //   To achieve this:
        //   AND constant must have bit j as 1.
        //   OR constant must have bit j as 1.
        //   XOR constant must have bit j as 0.
        //   (x & 1) | 1 ^ 0 = 1
        else if (bit_val_if_0[j] == 1 && bit_val_if_1[j] == 1) {
            // final_and_const remains 1 for this bit
            final_or_const |= (1 << j); // Set j-th bit of OR constant to 1
            // final_xor_const remains 0 for this bit
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If any bit of AND constant is 0, we need an AND operation
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If any bit of OR constant is 1, we need an OR operation
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If any bit of XOR constant is 1, we need an XOR operation
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

