                int k_val = (left_one_run[i] + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 0; // Stays 0
                }
            } else { // 1s on both sides
                int k_val = (std::min(left_one_run[i], right_one_run[i]) + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 0; // Stays 0
                }
            }
        } else { // Current element is 1
            // Find nearest 0 to the left
            int l = i - left_zero_run[i];
            // Find nearest 0 to the right
            int r = i + right_zero_run[i];

            if (l < 0 && r >= n) { // All ones
                // max_k remains 0, final_a remains all ones
            } else if (l < 0) { // Only 0s to the right
                int k_val = (right_zero_run[i] + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 1; // Stays 1
                }
            } else if (r >= n) { // Only 0s to the left
                int k_val = (left_zero_run[i] + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 1; // Stays 1
                }
            } else { // 0s on both sides
                int k_val = (std::min(left_zero_run[i], right_zero_run[i]) + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 1; // Stays 1
                }
            }
        }
    }

    // Determine final_a based on max_k
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int l = i - left_one_run[i];
            int r = i + right_one_run[i];

            int dist_to_nearest_one;
            if (l < 0 && r >= n) { // All zeros
                dist_to_nearest_one = n + 1; // Effectively infinity
            } else if (l < 0) { // Only 1s to the right
                dist_to_nearest_one = right_one_run[i];
            } else if (r >= n) { // Only 1s to the left
                dist_to_nearest_one = left_one_run[i];
            } else { // 1s on both sides
                dist_to_nearest_one = std::min(left_one_run[i], right_one_run[i]);
            }

            if (dist_to_nearest_one <= max_k) {
                final_a[i] = 1;
            } else {
                final_a[i] = 0;
            }
        } else { // a[i] == 1
            int l = i - left_zero_run[i];
            int r = i + right_zero_run[i];

            int dist_to_nearest_zero;
            if (l < 0 && r >= n) { // All ones
                dist_to_nearest_zero = n + 1; // Effectively infinity
            } else if (l < 0) { // Only 0s to the right
                dist_to_nearest_zero = right_zero_run[i];
            } else if (r >= n) { // Only 0s to the left
                dist_to_nearest_zero = left_zero_run[i];
            } else { // 0s on both sides
                dist_to_nearest_zero = std::min(left_zero_run[i], right_zero_run[i]);
            }

            if (dist_to_nearest_zero <= max_k) {
                final_a[i] = 0;
            } else {
                final_a[i] = 1;
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate many such values.
using ll = long long;

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_1 is varied, a_2 to a_n are fixed.
    // We use 1-based indexing for a, so vector size n+1.
    std::vector<ll> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp[i][0] stores the final y value if starting at x=i and performing step 2 (x+a[i], y+a[i])
    // dp[i][1] stores the final y value if starting at x=i and performing step 3 (x-a[i], y+a[i])
    // dp[i][0] and dp[i][1] also store -1 if non-terminating.
    std::vector<std::vector<ll>> dp(n + 1, std::vector<ll>(2, 0));
    // visited[i][0] and visited[i][1] track states during DFS to detect cycles.
    // 0: not visited, 1: visiting, 2: visited
    std::vector<std::vector<int>> visited(n + 1, std::vector<int>(2, 0));

    // Function to compute dp values using DFS
    // current_x: current x position
    // op_type: 0 for step 2 (x+a[x]), 1 for step 3 (x-a[x])
    ll solve(int current_x, int op_type) {
        // Base cases for termination
        if (current_x <= 0 || current_x > n) {
            return 0; // Terminated, no further y accumulation
        }

        // If already computed, return stored value
        if (visited[current_x][op_type] == 2) {
            return dp[current_x][op_type];
        }
        // If currently visiting, it means we found a cycle
        if (visited[current_x][op_type] == 1) {
            return -1; // Indicate non-termination
        }

        // Mark as visiting
        visited[current_x][op_type] = 1;

        ll next_x;
        int next_op_type;
        ll current_a_val = a[current_x];

        if (op_type == 0) { // Step 2: x + a[x], y + a[x]
            next_x = current_x + current_a_val;
            next_op_type = 1; // Next operation is step 3
        } else { // op_type == 1, Step 3: x - a[x], y + a[x]
            next_x = current_x - current_a_val;
            next_op_type = 0; // Next operation is step 2
        }

        ll res;
        if (next_x <= 0 || next_x > n) {
            res = current_a_val; // Terminated, add current a_x
        } else {
            ll next_val = solve(next_x, next_op_type);
            if (next_val == -1) {
                res = -1; // Propagate non-termination
            } else {
                res = current_a_val + next_val;
            }
        }

        // Store result and mark as visited
        dp[current_x][op_type] = res;
        visited[current_x][op_type] = 2;
        return res;
    }

    // Compute all possible dp states
    for (int i = 1; i <= n; ++i) {
        solve(i, 0); // Compute for step 2
        solve(i, 1); // Compute for step 3
    }

    // For each i from 1 to n-1, set a[1] = i and run the program
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for this run

        // Initial state: x=1, y=0. First operation is step 2.
        // The value of y accumulated from a[1] is a[1].
        // The next state is (1 + a[1], y + a[1]), and the next operation is step 3.
        ll initial_a1_val = a[1];
        ll next_x = 1 + initial_a1_val;

        ll final_y;
        if (next_x <= 0 || next_x > n) {
            final_y = initial_a1_val; // Terminated after first step 2
        } else {
            ll remaining_y = dp[next_x][1]; // Get result from (next_x, step 3)
            if (remaining_y == -1) {
                final_y = -1; // Non-terminating
            } else {
                final_y = initial_a1_val + remaining_y;
            }
        }
        std::cout << final_y << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> current_delta(n, 0);

    // Initialize initial_a based on type 2 operations
    // For each type 2 operation (2 l r m), we know that for some j in [l, r],
    // initial_a[j] + (sum of d's applied to j up to this point) = m.
    // To satisfy this with minimal initial_a[j], we can set initial_a[j] = m - (sum of d's).
    // To satisfy all type 2 operations, we need to find initial_a[j] such that
    // initial_a[j] <= m - (sum of d's for j) for all type 2 operations covering j.
    // So, initial_a[j] = min(m - (sum of d's for j)) over all relevant type 2 ops.
    // If no type 2 operation covers j, we can set initial_a[j] to 0.

    // Initialize initial_a to a very large value (effectively infinity)
    // This allows us to take minimums correctly.
    // We use 2 * 10^9 as a safe upper bound, as initial_a[i] can be up to 10^9.
    // The maximum possible m is 5*10^7, min d is -10^4.
    // The maximum number of type 1 operations is 5000.
    // So, sum of d's can be 5000 * 10^4 = 5*10^7.
    // m - sum_d can be 5*10^7 - (-5*10^7) = 10^8.
    // So 2*10^9 is a safe initial value.
    for (int i = 0; i < n; ++i) {
        initial_a[i] = 2000000000LL; // A value larger than 10^9
    }

    // Calculate initial_a values
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // For elements not constrained by any type 2 operation, set initial_a[j] to 0.
    // This is because 0 is within the allowed range [-10^9, 10^9] and satisfies
    // the condition initial_a[j] <= m - current_delta[j] for any m.
    // If initial_a[j] is still 2*10^9, it means it was never updated by a type 2 op.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == 2000000000LL) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta for verification
    std::vector<long long> current_a = initial_a;

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_delta[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        bool possible = true;
        long long prev_val = 0; // The minimum value for the current element to be >= prev_val

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];

            // Case 1: current_a + mid >= prev_val
            // This means current_a can be transformed to current_a + x where 0 <= x <= mid
            // and current_a + x >= prev_val.
            // If current_a >= prev_val, we can just keep it as current_a (x=0).
            // If current_a < prev_val, we need to increment it.
            // The smallest value it can take is current_a + (prev_val - current_a) = prev_val.
            // This requires (prev_val - current_a) increments.
            // If (prev_val - current_a) <= mid, then it's possible.
            // In this case, the new prev_val for the next element is max(prev_val, current_a).

            // Case 2: current_a + mid < prev_val
            // This means even if we increment current_a by mid, it's still less than prev_val.
            // This can only happen if current_a is very small and prev_val is large.
            // For example, a[i]=0, prev_val=5, mid=3. Then 0+3=3 < 5.
            // In this scenario, we must use the wrap-around property.
            // We need to transform current_a to (current_a + x) % m such that it is >= prev_val.
            // The only way this is possible is if (current_a + x) % m >= prev_val.
            // This implies that current_a + x must be >= prev_val + m.
            // The smallest value current_a can take is current_a + (m - current_a + prev_val) % m.
            // This requires (m - current_a + prev_val) % m increments.
            // If this number of increments is <= mid, then it's possible.
            // In this case, the new prev_val for the next element is prev_val.

            if (current_a <= prev_val) {
                // We need to make current_a become at least prev_val.
                // Option 1: Increment current_a to prev_val. This requires (prev_val - current_a) operations.
                // If (prev_val - current_a) <= mid, then it's possible.
                // The value becomes prev_val.
                // Option 2: Increment current_a past m-1 and wrap around.
                // This means current_a becomes (current_a + x) % m.
                // If we want it to be >= prev_val, it must be current_a + x >= prev_val + m.
                // The smallest value it can take is prev_val.
                // This requires (m - current_a + prev_val) operations.
                // If (m - current_a + prev_val) % m <= mid, then it's possible.
                // The value becomes prev_val.

                // If current_a + mid >= prev_val, we can achieve prev_val by incrementing current_a.
                // The number of increments needed is prev_val - current_a.
                // If this is <= mid, then we can achieve prev_val.
                // The next prev_val remains prev_val.
                if (current_a + mid < prev_val) { // Even with max increments, current_a is less than prev_val
                    possible = false;
                    break;
                }
                // If current_a + mid >= prev_val, we can make it prev_val.
                // So prev_val for the next element remains prev_val.
            } else { // current_a > prev_val
                // We need to decide if we keep current_a or increment it.
                // If we keep it, it's current_a. This is >= prev_val.
                // If we increment it, it becomes (current_a + x) % m.
                // We want to keep the value as small as possible, but >= prev_val.
                // If current_a is already >= prev_val, we can keep it as current_a.
                // The next prev_val would be current_a.
                // However, we could also increment current_a such that it wraps around and becomes smaller.
                // For example, a[i]=6, prev_val=0, m=7, mid=1.
                // If we keep 6, next prev_val is 6.
                // If we increment 6 by 1, it becomes (6+1)%7 = 0.
                // This is also >= prev_val (0).
                // This requires 1 operation, which is <= mid.
                // In this case, the next prev_val would be 0.
                // We want to choose the smallest possible value for the current element that is >= prev_val.
                // This means we want to choose between current_a and (current_a + x) % m where x <= mid.
                // Specifically, we want to check if we can make current_a wrap around to a value >= prev_val.
                // This happens if (current_a + mid) % m < current_a.
                // If (current_a + mid) % m < prev_val, then we cannot make it wrap around to a value >= prev_val.
                // So we must keep it as current_a.
                // If (current_a + mid) % m >= prev_val, then we can make it wrap around to a value >= prev_val.
                // The smallest such value is prev_val.
                // So we can choose prev_val for the current element.

                // Check if we can make current_a wrap around to a value >= prev_val.
                // This means (current_a + x) % m >= prev_val for some x <= mid.
                // The smallest value current_a can take by wrapping around is 0 (if current_a + mid >= m).
                // If current_a + mid >= m, then we can achieve any value from 0 to (current_a + mid) % m.
                // If prev_val is in this range [0, (current_a + mid) % m], then we can set current_a to prev_val.
                // This is equivalent to checking if (current_a + mid) % m < current_a.
                // If (current_a + mid) % m < current_a, it means we wrapped around.
                // If after wrapping around, the value is still >= prev_val, then we can use prev_val.
                // This condition is: (current_a + mid) % m < current_a AND (current_a + mid) % m >= prev_val.
                // More simply, if current_a + mid >= m, then we can potentially wrap around.
                // If prev_val <= (current_a + mid) % m, then we can achieve prev_val.
                // If prev_val > (current_a + mid) % m, then we cannot achieve prev_val by wrapping around to a smaller value.
                // In this case, we must keep current_a as current_a.

                // If current_a + mid >= m AND prev_val <= (current_a + mid) % m, then we can choose prev_val.
                // Otherwise, we must choose current_a.

                // This logic is simpler:
                // If current_a is already >= prev_val, we have two choices for the current element:
                // 1. Keep it as current_a. This is valid.
                // 2. Increment it by some x <= mid such that (current_a + x) % m is >= prev_val.
                //    The smallest such value is prev_val, if it's achievable.
                //    This is achievable if (current_a + mid) % m >= prev_val AND current_a + mid >= m.
                //    Or, if current_a + mid < m, then we can't wrap around to a smaller value.
                //    So we must keep current_a.

                // If current_a + mid >= m (meaning we can wrap around) AND prev_val <= (current_a + mid) % m,
                // then we can choose prev_val for the current element.
                // Otherwise, we must choose current_a.

                // This is equivalent to: if current_a + mid >= m AND prev_val <= (current_a + mid) % m,
                // then we can set prev_val for the next iteration to prev_val.
                // Otherwise, we must set prev_val for the next iteration to current_a.

                // Let's re-evaluate:
                // We need to find a value `b_i` such that `b_i >= prev_val` and `b_i` is achievable from `a_i` with `mid` operations.
                // `b_i` can be `(a_i + x) % m` where `0 <= x <= mid`.
                // If `a_i + mid < m`:
                //   Then `b_i` must be `a_i + x`.
                //   Since `a_i > prev_val`, we can choose `x=0`, so `b_i = a_i`. This is valid.
                //   So `prev_val` for next iteration becomes `a_i`.
                // If `a_i + mid >= m`: (wrap-around is possible)
                //   Then `b_i` can be `a_i + x` (if `a_i + x < m`) or `(a_i + x) % m` (if `a_i + x >= m`).
                //   The possible values for `b_i` are in `[a_i, m-1]` and `[0, (a_i + mid) % m]`.
                //   We need `b_i >= prev_val`.
                //   If `prev_val` is in `[0, (a_i + mid) % m]`, then we can choose `b_i = prev_val`.
                //   This is possible if `prev_val <= (a_i + mid) % m`.
                //   In this case, we can set `prev_val` for the next iteration to `prev_val`.
                //   Otherwise (`prev_val > (a_i + mid) % m`), we cannot achieve `prev_val` by wrapping around.
                //   We must choose `b_i = a_i`.
                //   So `prev_val` for next iteration becomes `a_i`.

                // Combining these:
                // If `a_i + mid < m`:
                //   `prev_val` for next iteration becomes `a_i`.
                // Else (`a_i + mid >= m`):
                //   If `prev_val <= (a_i + mid) % m`:
                //     `prev_val` for next iteration remains `prev_val`.
                //   Else (`prev_val > (a_i + mid) % m`):
                //     `prev_val` for next iteration becomes `a_i`.

                // This can be simplified:
                // If `a_i + mid < m` OR `prev_val > (a_i + mid) % m`:
                //   `prev_val` for next iteration becomes `a_i`.
                // Else (`a_i + mid >= m` AND `prev_val <= (a_i + mid) % m`):
                //   `prev_val` for next iteration remains `prev_val`.

                // This is correct. If we can achieve prev_val by wrapping around, we prefer it because it's smaller.
                // Otherwise, we must use a_i.
                if (current_a + mid < m || prev_val > (current_a + mid) % m) {
                    // Cannot achieve prev_val by wrapping around, or no wrap around possible.
                    // So we must use current_a.
                    prev_val = current_a;
                } else {
                    // We can achieve prev_val by wrapping around.
                    // So prev_val for next iteration remains prev_val.
                }
            }
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order based on value
    // If values are equal, original index doesn't matter for sorting,
    // but we need to preserve original indices for the final output.
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& x, const Element& y) {
        return x.value > y.value;
    });

    std::vector<long long> result_a_prime(m);

    // Pair sorted A with sorted B
    // a_elements[i].value (smallest) should be paired with b_elements[i].value (largest)
    // The result_a_prime array should store the A values at the original indices of B.
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to dentist

        long long current_v_effect = children[i].v;
        long long total_d_effect_from_chain = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effect from child i's crying
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Apply cumulative effect from children who cried and left
            children[j].p -= total_d_effect_from_chain;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect_from_chain += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

// Function to calculate the parity of a string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int parity_a = calculate_parity(a);
    int parity_b = calculate_parity(b);

    // The minimum number of '1's in string 'a' that can be achieved
    // by appending parity bits is parity_a.
    // If parity_a is 0, it means 'a' has an even number of '1's.
    // We can append '0's indefinitely, keeping the '1's count even.
    // If parity_a is 1, it means 'a' has an odd number of '1's.
    // We can append '1', making the '1's count even.
    // So, the minimum number of '1's we can achieve is parity_a.
    // If parity_a is 0, min_ones_a_reachable = 0.
    // If parity_a is 1, min_ones_a_reachable = 1.
    // This is equivalent to parity_a itself.

    // The maximum number of '1's in string 'a' that can be achieved
    // by appending parity bits is the current count of '1's plus 1 (if parity_a is 1).
    // If parity_a is 0, we can only append '0', so '1's count doesn't change.
    // If parity_a is 1, we can append '1', so '1's count increases by 1.
    // So, the maximum number of '1's we can achieve is (count of '1's in original 'a') + parity_a.

    // Let's count ones in original 'a'
    int ones_in_a_orig = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a_orig++;
        }
    }

    // The maximum number of '1's we can ever have in a string derived from 'a'
    // by appending parity bits is ones_in_a_orig + parity_a.
    // This is because if parity_a is 0, we append '0', ones count doesn't change.
    // If parity_a is 1, we append '1', ones count increases by 1, and the new parity becomes 0.
    // After that, we can only append '0's, so the ones count never increases further.
    int max_ones_a_reachable = ones_in_a_orig + parity_a;

    // Count ones in 'b'
    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // Condition 1: The number of '1's in 'b' must be less than or equal to the maximum '1's reachable from 'a'.
    if (ones_in_b > max_ones_a_reachable) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must be less than or equal to the length of 'a'
    // after 'a' has been potentially extended to match the '1's count of 'b'.
    // If ones_in_b is less than ones_in_a_orig, we must have removed characters from 'a'.
    // If ones_in_b is greater than ones_in_a_orig, we must have appended '1' (if parity_a was 1)
    // and then removed characters.
    // If ones_in_b == ones_in_a_orig and parity_a == 1, we must have appended '1' and then removed it.
    // This is equivalent to saying that the length of 'b' must be at most
    // the length of 'a' plus the number of '1's we needed to add to 'a' to reach ones_in_b.
    // The number of '1's we needed to add is (ones_in_b - ones_in_a_orig).
    // This is only possible if parity_a was 1 and ones_in_b == ones_in_a_orig + 1.
    // Otherwise, if ones_in_b <= ones_in_a_orig, we don't need to add '1's.
    // The effective length of 'a' that we can work with is its current length plus
    // any '1's we might have appended.
    // If parity_a is 1, we can append a '1', increasing length by 1.
    // So, the effective maximum length of 'a' we can achieve before removing characters
    // is |a| + parity_a.
    if (b.length() > a.length() + parity_a) {
        std::cout << "NO\n";
        return 0;
    }

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_ranges_left(n);
    std::vector<long long> head_ranges_right(n);

    for (int i = 0; i < n; ++i) {
        head_ranges_left[i] = h[i] - T;
        head_ranges_right[i] = h[i] + T;
    }

    int p_idx = 0;
    int h_idx = 0;

    while (p_idx < m) {
        // Find the first head that can reach p[p_idx]
        while (h_idx < n && head_ranges_right[h_idx] < p[p_idx]) {
            h_idx++;
        }

        if (h_idx == n) { // No head can reach current p[p_idx]
            return false;
        }

        // If head h_idx can reach p[p_idx]
        if (head_ranges_left[h_idx] <= p[p_idx]) {
            // This head can cover tracks up to head_ranges_right[h_idx]
            long long current_head_coverage_limit = head_ranges_right[h_idx];
            while (p_idx < m && p[p_idx] <= current_head_coverage_limit) {
                p_idx++;
            }
            h_idx++; // Move to the next head for the remaining tracks
        } else {
            // The current head h_idx is too far to the right to cover p[p_idx]
            // (i.e., head_ranges_left[h_idx] > p[p_idx])
            // This means no head from h_idx onwards can cover p[p_idx]
            // because h_i are sorted, so head_ranges_left[i] are also sorted.
            return false;
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max coord) - 1 (min coord) + 10^10 (max coord) - 1 (min coord)
                                    // A safer upper bound is max(p_i) - min(h_i) or max(h_i) - min(p_i)
                                    // Max p_i is 10^10, min h_i is 1. So 10^10 is a good estimate.
                                    // If one head needs to cover a range of 10^10, it takes 10^10 time.
                                    // If one head needs to cover p_1 and p_m, it takes (p_m - p_1)/2 + min(p_m-h_i, h_i-p_1)
                                    // A loose upper bound is 2 * 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[i] stores the minimum r (1-indexed) such that s[i-1...r-1] contains a pattern.
                                                // If no such r exists, it's n+1.

    for (int x = 0; x < n; ++x) { // x is 0-indexed
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern s[x] = s[x+k] = s[x+2k]
                // The pattern spans from index x to x+2k (0-indexed)
                // In 1-indexed terms, this is from x+1 to x+2k+1.
                // Any substring s[l-1...r-1] that contains this pattern must satisfy:
                // l-1 <= x  => l <= x+1
                // r-1 >= x+2k => r >= x+2k+1

                // For a fixed l (1-indexed), the smallest r (1-indexed) that contains this pattern
                // is x+2k+1, provided l <= x+1.
                // So, for all l from 1 to x+1, we can potentially update min_r_for_l[l].
                // We want to find the smallest r for each l.
                // Since we iterate x from left to right, and k from small to large,
                // x+2k+1 will generally be increasing.
                // For a given x and k, the pattern ends at x+2k (0-indexed).
                // The 1-indexed start of the pattern is x+1.
                // The 1-indexed end of the pattern is x+2k+1.

                // We need to update min_r_for_l[l] for all l such that 1 <= l <= x+1.
                // The minimum r for such l would be x+2k+1.
                // However, we only need to update for l such that x+1 - l <= 2.
                // This is because if x+1 - l > 2, then l < x-1.
                // If l < x-1, then the pattern s[x]=s[x+k]=s[x+2k] is "far" from l.
                // There might be a shorter pattern starting at l or l+1 or l+2.
                // The maximum possible k is 2.
                // If k=1, pattern is s[x]s[x+1]s[x+2]. Length 3.
                // If k=2, pattern is s[x]s[x+2]s[x+4]. Length 5.
                // The maximum length of a pattern we care about is 5 (for k=2).
                // If k >= 3, the pattern length is 2k+1 >= 7.
                // For any pattern s[x]=s[x+k]=s[x+2k], its length is 2k+1.
                // If 2k+1 > 6, then any substring of length 6 cannot contain this pattern.
                // So we only need to consider k=1 and k=2.
                // For k=1, pattern is s[x]s[x+1]s[x+2]. Length 3.
                // For k=2, pattern is s[x]s[x+2]s[x+4]. Length 5.
                // The maximum length of a pattern we need to consider is 5.
                // This means if a substring s[l-1...r-1] contains a pattern,
                // then r-l+1 >= 3.
                // The crucial observation is that if a substring $s[l \dots r]$ contains a pattern $s_x = s_{x+k} = s_{x+2k}$,
                // then it must contain such a pattern where $k \le 2$.
                // Proof: If $k \ge 3$, then $x+2k - x = 2k \ge 6$.
                // The indices are $x, x+k, x+2k$.
                // If $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 3$, then the length of the segment is $2k+1 \ge 7$.
                // Consider any substring $s[l \dots r]$ that contains this pattern.
                // If $r-l+1 \ge 7$, then it contains this pattern.
                // If $r-l+1 < 7$, it cannot contain this pattern.
                // So we only need to check for $k=1$ and $k=2$.
                // This significantly limits the search space for $k$.

                // For k=1: pattern s[x]s[x+1]s[x+2]. Ends at x+2.
                // For k=2: pattern s[x]s[x+2]s[x+4]. Ends at x+4.
                // The maximum end index is x+4.
                // The minimum start index is x.
                // So for a pattern starting at x (0-indexed), it ends at most at x+4.
                // The 1-indexed range is [x+1, x+5].
                // For any l (1-indexed) such that l <= x+1, the minimum r (1-indexed)
                // that contains this pattern is x+2k+1.
                // We need to update min_r_for_l[l] for l from max(1, x+1-4) to x+1.
                // The maximum length of a pattern is 5 (for k=2).
                // So, if a pattern starts at x (0-indexed), it ends at x+2k (0-indexed).
                // The 1-indexed range is [x+1, x+2k+1].
                // We need to update min_r_for_l[l] for l from max(1, x+1 - (2k+1) + 1) to x+1.
                // This simplifies to max(1, x+1 - 2k) to x+1.
                // Since we only consider k=1 and k=2, max(1, x+1-4) to x+1 is sufficient.
                // This means l can be x+1, x, x-1, x-2, x-3.
                // For example, if pattern is s[x]s[x+1]s[x+2], it ends at x+2.
                // For l=x+1, min_r_for_l[x+1] = min(min_r_for_l[x+1], x+3).
                // For l=x, min_r_for_l[x] = min(min_r_for_l[x], x+3).
                // For l=x-1, min_r_for_l[x-1] = min(min_r_for_l[x-1], x+3).
                // For l=x-2, min_r_for_l[x-2] = min(min_r_for_l[x-2], x+3).
                // For l=x-3, min_r_for_l[x-3] = min(min_r_for_l[x-3], x+3).
                // This is because a pattern of length 3 can be contained in a substring of length 3, 4, 5, 6.
                // A pattern of length 5 can be contained in a substring of length 5, 6.
                // The maximum length of a substring we need to consider is 6.
                // So, for a pattern ending at index `end_idx` (0-indexed),
                // and starting at `start_idx` (0-indexed),
                // we update `min_r_for_l[l]` for `l` from `max(1, end_idx - 6 + 2)` to `start_idx + 1`.
                // The `+2` is because `end_idx - 6 + 1` is the 0-indexed start, so `+1` for 1-indexed `l`.
                // `end_idx - 6 + 2` is `end_idx - 4`.
                // So `l` goes from `max(1, x+2k+1 - 4)` to `x+1`.
                // This is `max(1, x+2k-3)` to `x+1`.
                // Since $k \le 2$, $2k-3 \le 1$. So $x+2k-3 \le x+1$.
                // The range of $l$ is $max(1, x+2k-3)$ to $x+1$.
                // This is a small constant number of $l$ values.

                int pattern_end_1_indexed = x + 2 * k + 1;
                int pattern_start_1_indexed = x + 1;

                // The maximum length of a substring we need to check is 6.
                // If a pattern ends at pattern_end_1_indexed, and starts at pattern_start_1_indexed,
                // then any l such that pattern_start_1_indexed - l <= 5 (i.e., l >= pattern_start_1_indexed - 5)
                // and l <= pattern_start_1_indexed will have this pattern.
                // The actual range of l to update is from max(1, pattern_start_1_indexed - 5) to pattern_start_1_indexed.
                // For each such l, the minimum r is pattern_end_1_indexed.
                for (int l_val = std::max(1, pattern_start_1_indexed - 5); l_val <= pattern_start_1_indexed; ++l_val) {
                    min_r_for_l[l_val] = std::min(min_r_for_l[l_val], pattern_end_1_indexed);
                }
            }
            if (k == 2) break; // Optimization: only need to check k=1 and k=2
        }
    }

    long long total_count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one r for this l
            // All r from min_r_for_l[l] to n are valid.
            total_count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s' = s2 + s1.
    // If s' is a palindrome and s' != s, then k=1 is the answer.
    // Iterate through all possible cut positions.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // If k=2 is the answer, it means no single cut and swap works.
    // This implies that for any cut point i, s[0...i-1] + s[i...n-1] -> s[i...n-1] + s[0...i-1] is either s or not a palindrome.
    //
    // Consider the structure of the string s.
    // s is a palindrome.
    // If all characters in s are the same (e.g., "aaaaa"), then any rearrangement of pieces will result in the same string "aaaaa".
    // In this case, it's impossible to form a different string.
    // We can check this by counting unique characters.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Why?
    // Consider the string s = "abacaba".
    // If we cut it into s[0...n-2] and s[n-1], i.e., "abacab" and "a".
    // Rearranging gives "a" + "abacab" = "aabacab". This is not a palindrome.
    //
    // The problem statement guarantees s is a palindrome.
    // If not all characters are the same, then there must be at least two distinct characters.
    // Since s is a palindrome, it must have at least two distinct characters if n > 1.
    // If n=1, it's "a", all same, impossible.
    //
    // If n is odd, say "abacaba", n=7.
    // s[0] = 'a', s[1] = 'b', s[2] = 'a', s[3] = 'c', s[4] = 'a', s[5] = 'b', s[6] = 'a'.
    //
    // Consider cutting s into three pieces:
    // s[0] | s[1...n-2] | s[n-1]
    // For example, "a" | "bacab" | "a" for "abacaba".
    // Rearrange to s[n-1] | s[1...n-2] | s[0]
    // This would be "a" | "bacab" | "a" = "abacaba". This is s.
    //
    // What if we cut s into s[0...i-1], s[i...j-1], s[j...n-1]?
    //
    // Let's consider the property that if s is a palindrome and not all characters are the same,
    // then s can always be cut into two pieces s1, s2 such that s2+s1 is a palindrome.
    // This is not true. Example: "nolon". n=5.
    // "n" + "olon" -> "olonn" (not pal)
    // "no" + "lon" -> "lonno" (not pal)
    // "nol" + "on" -> "onnol" (not pal)
    // "nolo" + "n" -> "nnolo" (not pal)
    // For "nolon", k=1 doesn't work.
    // But "nolon" is not all same chars. So the answer is 2.
    //
    // The logic is:
    // 1. If all characters in `s` are the same (e.g., "aaaa"), then any rearrangement of pieces will result in the same string `s`. So, it's "Impossible".
    // 2. Otherwise (if `s` contains at least two distinct characters), we try `k=1`. If any single cut and swap `s_1 + s_2 -> s_2 + s_1` results in a palindrome `s'` different from `s`, then `k=1` is the answer.
    // 3. If `k=1` doesn't work, but `s` has at least two distinct characters, then `k=2` is always possible.
    //    Consider `s = s_0 s_1 ... s_{n-1}`.
    //    Since `s` is a palindrome and not all characters are the same, there must be some `i` such that `s_i != s_0`.
    //    Consider cutting `s` into `s_0`, `s_1...s_{n-1}`. This is `s_0` and `s_1...s_{n-1}`.
    //    This is a single cut.
    //    The problem states that if `k=1` doesn't work, then `k=2` is the answer.
    //    This is a known property for palindromes: if a palindrome `s` is not composed of all identical characters, and no single cut and swap yields a new palindrome, then two cuts are sufficient.
    //    A common way to achieve this is to cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
    //    Then rearrange to `s[n-1]`, `s[1...n-2]`, `s[0]`.
    //    Since `s` is a palindrome, `s[0] == s[n-1]`. So this rearrangement gives `s[0] + s[1...n-2] + s[n-1]`, which is `s`.
    //    This specific rearrangement doesn't work.
    //
    //    However, the problem asks for *any* rearrangement.
    //    If `s` is a palindrome and not all characters are the same, then `s` must have length `n >= 2`.
    //    If `n` is even, `s = P P^R` where `P` is the first half and `P^R` is its reverse.
    //    Example: "otto". `P="ot"`, `P^R="to"`. `s="otto"`.
    //    Cut "ot" | "to". Swap: "to" | "ot" = "toot". This is a palindrome and `!= "otto"`. So `k=1`.
    //    Example: "kinnikkinnik". `P="kinnik"`, `P^R="kinnik"`. `s="kinnikkinnik"`.
    //    Cut "kinnik" | "kinnik". Swap: "kinnik" | "kinnik" = "kinnikkinnik". This is `s`.
    //    But for "kinnikkinnik", `k=1` is possible. Cut "kinnikkin" | "nik". Swap: "nik" + "kinnikkin" = "nikkinnikkin". This is a palindrome and `!= s`.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 is the answer.
    // The only "Impossible" case is when all characters are the same.
    // This is because if there are at least two distinct characters, we can always find a way to make two cuts and rearrange to form a new palindrome.
    // For example, take `s = s_0 s_1 ... s_{n-1}`.
    // Since `s` is a palindrome and not all characters are the same, there exists some `i` such that `s_i != s_0`.
    // Consider the string `s'` formed by taking `s_0 s_1 ... s_{n-2}` and moving `s_{n-1}` to the beginning.
    // `s' = s_{n-1} s_0 s_1 ... s_{n-2}`.
    // Since `s` is a palindrome, `s_0 = s_{n-1}`. So `s' = s_0 s_0 s_1 ... s_{n-2}`.
    // This is not necessarily a palindrome.
    //
    // The crucial observation is that if `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least two distinct characters.
    // If `n` is odd, `s = X c X^R` where `c` is the middle character.
    // If `n` is even, `s = X X^R`.
    //
    // If `s` is a palindrome and not all characters are the same, then `s` has a structure like `a...b...a` where `a != b`.
    // Consider `s` without its first and last characters: `s.substr(1, n-2)`.
    // This substring `s.substr(1, n-2)` is also a palindrome.
    // If `s.substr(1, n-2)` is not all same characters, then we can apply the same logic recursively.
    // If `s.substr(1, n-2)` *is* all same characters, say `b...b`, then `s` looks like `a b...b a`.
    // Example: "ababa". `s.substr(1,3)` is "bab".
    // Example: "racecar". `s.substr(1,5)` is "aceca".
    //
    // The problem statement implies that if `k=1` doesn't work, and it's not "Impossible", then `k=2` is the answer.
    // This is a standard result for palindromes:
    // A palindrome `s` can be rearranged into a different palindrome `s'` using one cut if and only if `s` is not of the form `X X^R` where `X` is a palindrome itself, or `s` is not of the form `X c X^R` where `X` is a palindrome.
    // More simply, if `s` is a palindrome and not all characters are the same, and `k=1` doesn't work, then `k=2` is the answer.
    // This is because we can always find a way to make two cuts and rearrange.
    // For example, take `s = s_0 s_1 ... s_{n-1}`.
    // Cut `s` into `s_0`, `s_1...s_{n-1}`. This is one cut.
    // If `s_0` is moved to the end, we get `s_1...s_{n-1} s_0`.
    // Since `s_0 = s_{n-1}`, this is `s_1...s_{n-1} s_{n-1}`.
    // This is not necessarily a palindrome.
    //
    // The simplest way to get a new palindrome with two cuts is to take `s_0`, `s_1...s_{n-2}`, `s_{n-1}`.
    // Rearrange them as `s_0`, `s_{n-1}`, `s_1...s_{n-2}`. This is not a palindrome.
    //
    // The logic for k=2 being always possible (if not all chars are same and k=1 fails) is based on the fact that
    // if `s` is a palindrome and not all characters are the same, then `s` must have at least two distinct characters.
    // Let `s = c_0 c_1 ... c_{n-1}`.
    // Since `s` is a palindrome, `c_i = c_{n-1-i}`.
    // Since not all characters are the same, there exists some `j` such that `c_j != c_0`.
    // Consider the string `s'` formed by rotating `s` by one character: `s' = c_{n-1} c_0 c_1 ... c_{n-2}`.
    // Since `c_{n-1} = c_0`, `s' = c_0 c_0 c_1 ... c_{n-2}`.
    // This `s'` is not necessarily a palindrome.
    //
    // The problem statement implies that if `k=1` doesn't work, and it's not "Impossible", then `k=2` is the answer.
    // This is a common pattern in competitive programming problems where small `k` values are tested.
    // The "Impossible" case is correctly identified as all characters being the same.
    // If `s` has at least two distinct characters, and `k=1` doesn't yield a solution, then `k=2` must be the answer.
    // This is because if `s` is a palindrome and not all characters are the same, then `s` can always be cut into three pieces and rearranged to form a new palindrome.
    // For example, consider `s = s_0 s_1 ... s_{n-1}`.
    // If `n` is odd, `s = X c X^R`.
    // If `n` is even, `s = X X^R`.
    //
    // The simplest argument for `k=2` is that if `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least two distinct characters.
    // If `s` is not all same characters, then `s` has at least one character `c_i` such that `c_i != c_0`.
    // Consider the string `s'` formed by taking `s` and moving its first character to the end.
    // `s' = s_1 s_2 ... s_{n-1} s_0`.
    // This `s'` is not necessarily a palindrome.
    //
    // The problem is essentially asking for the smallest `k`.
    // `k=0` is impossible.
    // `k=1` is checked.
    // If `k=1` fails, and `s` is not all same characters, then `k=2` is the answer.
    // This is a known property for palindromes. If a palindrome `s` is not monochromatic (all same characters),
    // then it is always possible to form a new palindrome `s'` by cutting `s` into at most 3 pieces (i.e., `k <= 2`).
    // The only case where it's impossible is if all characters are the same.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Greedy approach for denominations 5, 2, 1
        // This works because 1, 2, 5 form a canonical coin system.
        // For example, if diff = 4, greedy would be 0*5 + 2*2 + 0*1 = 2 presses.
        // If diff = 3, greedy would be 0*5 + 1*2 + 1*1 = 2 presses.
        // If diff = 1, greedy would be 0*5 + 0*2 + 1*1 = 1 press.

        ans += diff / 5;
        diff %= 5;

        if (diff == 4) { // e.g., 9 -> 5+2+2 (3 presses) or 5+5-1 (3 presses)
                         // 4 -> 2+2 (2 presses)
            ans += 2;
        } else if (diff == 3) { // e.g., 8 -> 5+2+1 (3 presses)
                                // 3 -> 2+1 (2 presses)
            ans += 2;
        } else if (diff == 2) { // e.g., 7 -> 5+2 (2 presses)
                                // 2 -> 2 (1 press)
            ans += 1;
        } else if (diff == 1) { // e.g., 6 -> 5+1 (2 presses)
                                // 1 -> 1 (1 press)
            ans += 1;
        }
        // If diff is 0, nothing to add.

        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1)
    // All pairs (a_i, a_j) are in the same subsequence.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long min_goodness = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> best_partition(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences
    // We need to consider the minimum and maximum possible f values.
    // The minimum possible sum a_i + a_j is a[0].value + a[1].value.
    // The maximum possible sum a_i + a_j is a[n-2].value + a[n-1].value.

    // If a[0] and a[1] are in different subsequences, min_f could be a[0].value + a[1].value + h.
    // If a[0] and a[1] are in the same subsequence, min_f could be a[0].value + a[1].value.

    // If a[n-2] and a[n-1] are in different subsequences, max_f could be a[n-2].value + a[n-1].value + h.
    // If a[n-2] and a[n-1] are in the same subsequence, max_f could be a[n-2].value + a[n-1].value.

    // Consider a partition where a[0] is in subsequence 1, and a[1]...a[n-1] are in subsequence 2.
    // This is a specific type of partition.
    // Let's try to put a[0] in subseq 1, and a[1]...a[n-1] in subseq 2.
    // This means a[0] is different from all other elements.
    // All pairs (a[i], a[j]) for i,j >= 1 are in the same subsequence (subseq 2).
    // Pairs involving a[0] are (a[0], a[k]) for k >= 1, these are in different subsequences.
    // Pairs not involving a[0] are (a[i], a[j]) for i,j >= 1, these are in the same subsequence.

    // min_f:
    //   - If a[0] is paired with a[1]: a[0].value + a[1].value + h (different subsequences)
    //   - If a[1] is paired with a[2]: a[1].value + a[2].value (same subsequence)
    //   So, min_f = min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    // max_f:
    //   - If a[0] is paired with a[n-1]: a[0].value + a[n-1].value + h (different subsequences)
    //   - If a[n-2] is paired with a[n-1]: a[n-2].value + a[n-1].value (same subsequence)
    //   So, max_f = max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value)

    // This specific partition strategy is:
    // a[0] in subseq 1
    // a[1], ..., a[n-1] in subseq 2
    //
    // min_f_val:
    //   - a[0] + a[1] + h (diff)
    //   - a[1] + a[2] (same, if n >= 3)
    //   min_f_val = min(a[0].value + a[1].value + h, (n >= 3 ? a[1].value + a[2].value : std::numeric_limits<long long>::max()))
    //
    // max_f_val:
    //   - a[0] + a[n-1] + h (diff)
    //   - a[n-2] + a[n-1] (same, if n >= 3)
    //   max_f_val = max(a[0].value + a[n-1].value + h, (n >= 3 ? a[n-2].value + a[n-1].value : std::numeric_limits<long long>::min()))
    //
    // If n=2:
    //   min_f_val = a[0].value + a[1].value + h
    //   max_f_val = a[0].value + a[1].value + h
    //   goodness = 0
    // This is covered by the general logic.

    long long current_min_f = std::min(a[0].value + a[1].value + h, (n >= 3 ? a[1].value + a[2].value : std::numeric_limits<long long>::max()));
    long long current_max_f = std::max(a[0].value + a[n-1].value + h, (n >= 3 ? a[n-2].value + a[n-1].value : std::numeric_limits<long long>::min()));

    if (n == 2) { // Special case for n=2, only one pair (a[0], a[1])
        current_min_f = a[0].value + a[1].value + h;
        current_max_f = a[0].value + a[1].value + h;
    }

    long long current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition.assign(n, 2);
        best_partition[a[0].original_index] = 1;
    }

    // Consider a partition where a[0], a[1] are in subseq 1, and a[2]...a[n-1] are in subseq 2.
    // This is not necessarily optimal.
    // The key observation is that the minimum possible sum is a[0]+a[1] and maximum is a[n-1]+a[n-2].
    // The values of f are either (x+y) or (x+y+h).
    // The range of (x+y) is [a[0]+a[1], a[n-2]+a[n-1]].
    // The range of (x+y+h) is [a[0]+a[1]+h, a[n-2]+a[n-1]+h].

    // If we have both types of pairs (same and different subsequences):
    // min_f = min(a[0]+a[1], a[0]+a[1]+h) = a[0]+a[1]
    // max_f = max(a[n-2]+a[n-1], a[n-2]+a[n-1]+h) = a[n-2]+a[n-1]+h
    // Goodness = (a[n-2]+a[n-1]+h) - (a[0]+a[1])
    // This is the goodness if we force both types of pairs to exist.
    // This happens if we put a[0] in subseq 1, and a[n-1] in subseq 2, and also have at least two elements in subseq 1 and at least two elements in subseq 2.
    // For example, a[0] in subseq 1, a[1] in subseq 1, a[2] in subseq 2, a[3] in subseq 2.
    // This is a general case.
    // The minimum f value will be a[0].value + a[1].value (if a[0] and a[1] are in the same group).
    // The maximum f value will be a[n-2].value + a[n-1].value + h (if a[n-2] and a[n-1] are in different groups).
    // Or, if a[0] and a[1] are in different groups, min_f could be a[0].value + a[1].value + h.
    // Or, if a[n-2] and a[n-1] are in the same group, max_f could be a[n-2].value + a[n-1].value.

    // Let's consider the four critical values:
    // V1 = a[0].value + a[1].value
    // V2 = a[0].value + a[1].value + h
    // V3 = a[n-2].value + a[n-1].value
    // V4 = a[n-2].value + a[n-1].value + h

    // If all elements are in one group (already handled):
    // min_f = V1, max_f = V3. Goodness = V3 - V1.

    // If we have at least one pair in the same group AND at least one pair in different groups:
    // The overall min_f will be min(min_same, min_diff).
    // The overall max_f will be max(max_same, max_diff).
    //
    // To minimize goodness, we want min_f to be as large as possible and max_f to be as small as possible.
    //
    // Consider the partition where a[0] is in group 1, and a[1], ..., a[n-1] are in group 2.
    // min_f = min(a[0]+a[1]+h, a[1]+a[2]) (if n>=3, else just a[0]+a[1]+h)
    // max_f = max(a[0]+a[n-1]+h, a[n-2]+a[n-1]) (if n>=3, else just a[0]+a[n-1]+h)
    // This was already calculated.

    // Consider the partition where a[0], ..., a[n-2] are in group 1, and a[n-1] is in group 2.
    // min_f = min(a[0]+a[1], a[0]+a[n-1]+h) (if n>=3, else just a[0]+a[n-1]+h)
    // max_f = max(a[n-3]+a[n-2], a[n-2]+a[n-1]+h) (if n>=3, else just a[n-2]+a[n-1]+h)
    //
    // Let's calculate this:
    current_min_f = std::min(a[0].value + a[1].value, (n >= 3 ? a[0].value + a[n-1].value + h : std::numeric_limits<long long>::max()));
    current_max_f = std::max(a[n-3].value + a[n-2].value, (n >= 3 ? a[n-2].value + a[n-1].value + h : std::numeric_limits<long long>::min()));

    if (n == 2) { // Special case for n=2, only one pair (a[0], a[1])
        current_min_f = a[0].value + a[1].value + h;
        current_max_f = a[0].value + a[1].value + h;
    } else if (n == 3) { // Special case for n=3
        // a[0], a[1] in group 1; a[2] in group 2
        // Same pairs: (a[0], a[1]) -> a[0]+a[1]
        // Diff pairs: (a[0], a[2]) -> a[0]+a[2]+h, (a[1], a[2]) -> a[1]+a[2]+h
        current_min_f = std::min(a[0].value + a[1].value, a[0].value + a[2].value + h);
        current_max_f = std::max(a[0].value + a[1].value, a[1].value + a[2].value + h);
    }

    current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition.assign(n, 1);
        best_partition[a[n-1].original_index] = 2;
    }

    // The general case where we have elements in both groups, and h is small enough
    // such that the range of (x+y) and (x+y+h) overlap or are close.
    // The minimum possible f value is a[0].value + a[1].value (if they are in the same group).
    // The maximum possible f value is a[n-2].value + a[n-1].value + h (if they are in different groups).
    // This goodness is (a[n-2].value + a[n-1].value + h) - (a[0].value + a[1].value).
    // This is achieved if we put a[0] and a[1] in group 1, and a[n-2] and a[n-1] in group 2.
    // For example, a[0] in group 1, a[1] in group 1, a[2]...a[n-1] in group 2.
    // This is the same as the second partition strategy considered.
    // Or a[0]...a[n-2] in group 1, a[n-1] in group 2. This is the third partition strategy.

    // The crucial observation is that the minimum f value is either a[0]+a[1] or a[0]+a[1]+h.
    // The maximum f value is either a[n-2]+a[n-1] or a[n-2]+a[n-1]+h.
    //
    // Let min_sum = a[0].value + a[1].value
    // Let max_sum = a[n-2].value + a[n-1].value
    //
    // Possible min_f values: min_sum, min_sum + h
    // Possible max_f values: max_sum, max_sum + h
    //
    // If we have only same-group pairs: min_f = min_sum, max_f = max_sum. Goodness = max_sum - min_sum.
    // If we have only diff-group pairs (n=2, or n>2 and all elements are split such that no two are in same group, e.g. n=3, 1,2,1):
    //   min_f = min_sum + h, max_f = max_sum + h. Goodness = max_sum - min_sum.
    //
    // If we have both same-group and diff-group pairs:
    //   min_f = min(min_sum, min_sum + h) = min_sum
    //   max_f = max(max_sum, max_sum + h) = max_sum + h
    //   Goodness = (max_sum + h) - min_sum
    //
    // So, the candidates for minimum goodness are:
    // 1. max_sum - min_sum (achieved by putting all in one group, or all in different groups if n=2)
    // 2. (max_sum + h) - min_sum (achieved by having both same-group and diff-group pairs)
    //
    // The second case (max_sum + h) - min_sum is only possible if we can construct a partition
    // where a[0] and a[1] are in the same group, AND a[n-2] and a[n-1] are in different groups.
    // This is possible if n >= 3.
    // For example, put a[0], a[1] in group 1. Put a[2], ..., a[n-1] in group 2.
    // Then (a[0], a[1]) is a same-group pair.
    // (a[n-2], a[n-1]) is a same-group pair (if n-1 >= 2).
    // (a[0], a[n-1]) is a diff-group pair.
    //
    // Let's re-evaluate the candidates for min_goodness:
    // Candidate 1: All elements in one group.
    //   min_f = a[0].value + a[1].value
    //   max_f = a[n-2].value + a[n-1].value
    //   Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    //   This is already `min_goodness` initialized.

    // Candidate 2: Partition where a[0] is in group 1, and a[1]...a[n-1] are in group 2.
    //   min_f = min(a[0].value + a[1].value + h, (n >= 3 ? a[1].value + a[2].value : std::numeric_limits<long long>::max()))
    //   max_f = max(a[0].value + a[n-1].value + h, (n >= 3 ? a[n-2].value + a[n-1].value : std::numeric_limits<long long>::min()))
    //   This was already calculated and updated `min_goodness`.

    // Candidate 3: Partition where a[0]...a[n-2] are in group 1, and a[n-1] is in group 2.
    //   min_f = min(a[0].value + a[1].value, (n >= 3 ? a[0].value + a[n-1].value + h : std::numeric_limits<long long>::max()))
    //   max_f = max(a[n-3].value + a[n-2].value, (n >= 3 ? a[n-2].value + a[n-1].value + h : std::numeric_limits<long long>::min()))
    //   This was already calculated and updated `min_goodness`.

    // What if n=2?
    // Initial min_goodness = (a[0]+a[1]) - (a[0]+a[1]) = 0. Partition: 1 1.
    // Second case (a[0] in 1, a[1] in 2):
    //   min_f = a[0]+a[1]+h, max_f = a[0]+a[1]+h. Goodness = 0. Partition: 1 2.
    // Both give 0. The code handles this correctly.

    // The only remaining case is when n >= 3 and we have a partition that forces
    // a[0]+a[1] to be the minimum (same group) AND a[n-2]+a[n-1]+h to be the maximum (different groups).
    // This requires a[0], a[1] to be in the same group, and a[n-2], a[n-1] to be in different groups.
    // This is possible if we put a[0], a[1] in group 1, and a[n-1] in group 2.
    // What about a[n-2]? If a[n-2] is in group 1, then (a[n-2], a[n-1]) is a diff-group pair.
    // If a[n-2] is in group 2, then (a[n-2], a[n-1]) is a same-group pair.
    //
    // Consider the partition: a[0] in group 1, a[1] in group 1, a[2]...a[n-2] in group 2, a[n-1] in group 2.
    // This is not general enough.
    //
    // The minimum possible value of f is `a[0].value + a[1].value`.
    // The maximum possible value of f is `a[n-2].value + a[n-1].value + h`.
    // This goodness is `(a[n-2].value + a[n-1].value + h) - (a[0].value + a[1].value)`.
    // This can be achieved if we put a[0] and a[1] in group 1, and a[n-1] in group 2.
    // To ensure a[n-2] and a[n-1] are in different groups, we must put a[n-2] in group 1.
    // So, partition: a[0], a[1], a[n-2] in group 1. All others (a[2]...a[n-3]) in group 2. a[n-1] in group 2.
    // This is only valid if n >= 4.
    //
    // If n=3: a[0], a[1] in group 1. a[2] in group 2.
    //   min_f = a[0]+a[1] (same)
    //   max_f = a[1]+a[2]+h (diff)
    //   Goodness = (a[1]+a[2]+h) - (a[0]+a[1])
    //   This is a candidate.
    if (n >= 3) {
        current_goodness = (a[n-1].value + a[n-2].value + h) - (a[0].value + a[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition.assign(n, 2); // Default to group 2
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 1;
        }
    }

    std::cout << min_goodness << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

