int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Use 5s
        presses += diff / 5;
        diff %= 5;

        // Now diff can be 0, 1, 2, 3, 4
        if (diff == 0) {
            // No more presses needed
        } else if (diff == 1) {
            // Can be 1 (+1 or -1)
            presses += 1;
        } else if (diff == 2) {
            // Can be 1 (+2 or -2)
            presses += 1;
        } else if (diff == 3) {
            // Can be 2 (+1, +2 or -1, -2)
            presses += 2;
        } else if (diff == 4) {
