#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n>=2 is guaranteed) and results in the same fingerprint.
    // The sums of adjacent elements for p = [p_1, p_2, ..., p_n] are:
    // [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n]
    // The sums of adjacent elements for p_rev = [p_n, p_{n-1}, ..., p_1] are:
    // [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1]
    // This second list is simply the first list in reverse order.
    // Since the fingerprint involves sorting these sums, the sorted lists will be identical.
    // A reversed permutation p' is different from p unless p is a palindrome.
    // However, even if p is a palindrome, p' is still p, but the problem guarantees
    // that a *different* permutation exists.
    // The simplest approach that works for all cases is to reverse the permutation.
    // If p is [1, 2], p_rev is [2, 1]. F([1,2]) = sort([3]) = [3]. F([2,1]) = sort([3]) = [3].
    // These are different.
    // The problem statement guarantees that for every permutation satisfying the input constraints,
    // a solution exists. Reversing is the simplest and most robust solution.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

