        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Start with initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            int pile_idx = i; // 0-indexed pile index
            int pile_num = i + 1; // 1-indexed pile number

            int cost_per_haybale = pile_idx; // Days to move one haybale from pile_num to pile 1

            if (d >= cost_per_haybale) { // Check if we have enough days to move at least one haybale
                int haybales_available = a[pile_idx];

                // Calculate how many haybales we can move from this pile
                // It's limited by available haybales and available days
                int haybales_to_move = std::min(haybales_available, d / cost_per_haybale);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // If we don't have enough days for even one haybale from this pile,
                // we won't have enough for subsequent piles either (as cost increases).
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

