#include <iostream>
#include <numeric> // For std::accumulate (though not strictly needed for this approach)
#include <map>     // For std::map

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // If val is 1, and count is 3, we have 1, 1, 1.
        // We can combine two 1s to make a 2. Then we have 1, 2.
        // This is equivalent to having a sum of 3.
        // The problem is asking if we can *form* 2048, not if the sum is 2048.
        // The operation is merging, which means we can effectively sum up values
        // as long as they are powers of two and we have enough to merge.
        // For example, if we have 1, 1, 1, 1, we can make 2, 2, then 4.
        // This is equivalent to having a total sum of 4.
        // So, we can just sum up all numbers less than or equal to 2048.
        // If the sum is >= 2048, we can always form 2048.
        // Example: {1024, 512, 512, 4} -> sum = 2040.
        // 512+512 -> 1024. Multiset becomes {1024, 1024, 4}.
        // 1024+1024 -> 2048. Multiset becomes {2048, 4}. Win.
        // The sum of values <= 2048 is the key.
        current_sum += static_cast<long long>(val) * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

