#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] = N, then min(p[i], p[j]) = p[j] for all j!=i.
        // So max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = N-1.
        // If p[i] < N, then there is some p[k] = N.
        // Then min(p[i], p[k]) = p[i].
        // So max_{j!=i} min(p[i], p[j]) will be at least p[i].
        // In fact, it will be exactly p[i] because for any p[j] > p[i], min(p[i], p[j]) = p[i].
        // And for any p[j] < p[i], min(p[i], p[j]) = p[j] < p[i].
        // So the maximum value in row i (excluding a[i][i]) is p[i] if p[i] < N.
        // If p[i] = N, the maximum value is N-1.
        // To distinguish these two cases, we can check if max_val_in_row is N-1.
        // If it is N-1, then p[i] must be N. Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

