int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available (c + m + x) / 3
        // 2. The number of coders available (c)
        // 3. The number of mathematicians available (m)
        // Since each team must have at least one coder and at least one mathematician,
        // the number of teams cannot exceed min(c, m).
        // Also, the total number of students used for k teams is 3k.
        // So, 3k <= c + m + x.
        // Combining these, k <= min(c, m, (c + m + x) / 3).

        long long ans = std::min({c, m, (c + m + x) / 3});

        std::cout << ans << "\n";
    }
    return 0;
}

