    int left = 1;
    int right = k + 1; // The largest number used in the initial zigzag to generate k distinct differences

    // Generate the first k+1 elements using a zigzag pattern
    // This pattern ensures k distinct differences: k, k-1, ..., 1
    // Example: for k=2, right=3. Sequence: 1, 3, 2. Differences: |1-3|=2, |3-2|=1.
    // Example: for k=3, right=4. Sequence: 1, 4, 2, 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...) corresponds to left pointer
            std::cout << left++;
        } else { // Odd index (1, 3, 5, ...) corresponds to right pointer
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // The remaining elements (from k+2 to n) can be appended in increasing order.
    // This will only introduce a difference of 1 with the last element printed,
    // which is already covered by the zigzag pattern (since k >= 1).
    // The last element printed from the zigzag is either `left-1` or `right+1`.
    // If `k` is even, the last element printed was `right+1` (which is `k/2 + 1` if `k` is even, or `(k+1)/2` if `k` is odd).
    // If `k` is odd, the last element printed was `left-1` (which is `(k+1)/2 + 1` if `k` is odd, or `k/2 + 1` if `k` is even).
    // In both cases, the next number in sequence will be `k+2`.
    // The difference will be `| (last_zigzag_val) - (k+2) |`.
    // However, the simplest way to ensure no new differences are introduced is to append them in increasing order.
    // The numbers used so far are from 1 to k+1.
    // The next available number is k+2.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

