    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // Since d >= 4, discriminant will be non-negative.
            // d^2 - 4d = d(d-4). If d=4, disc=0. If d>4, disc>0.
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a and b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d=4, sqrt_discriminant=0, a1=b1=2. Both non-negative.
            // If d>4, d-4 > 0, so sqrt_discriminant > 0.
            // d + sqrt_discriminant > 0. So a1 > 0.
            // d - sqrt_discriminant:
            // We know d^2 - 4d >= 0 => d^2 >= 4d.
            // Since d > 0, d >= 4.
            // So d >= sqrt(4d).
            // d >= sqrt(d^2 - (d^2 - 4d))
            // d >= sqrt(d^2 - discriminant)
            // d >= sqrt(d^2 - (d^2 - 4d)) = sqrt(4d)
            // d >= sqrt(4d) is true for d >= 4.
            // So d - sqrt(d^2 - 4d) >= 0.
            // Thus, b1 is also non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

