void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of 'val' in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. Its length is 1.
        // For m > 1, we consider the number 'm'.
        // We need to expand the current segment [min_idx, max_idx] to include 'm'.
        // The new 'm' must be either to the left of min_idx or to the right of max_idx.
        // If it's between min_idx and max_idx, it means it was already included when we processed a smaller 'm'.
        // This is guaranteed by the problem statement: "a permutation of numbers 1, 2, ..., m".
        // This implies that the segment must contain exactly 1, 2, ..., m.
        // So, for each m, we find the position of m.
        // We then update the overall minimum and maximum indices seen so far for numbers 1 to m.

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // The length of the segment containing all numbers from 1 to m is (current_max_idx - current_min_idx + 1).
        // If this length is equal to m, then the segment [p[current_min_idx], ..., p[current_max_idx]]
        // contains exactly m distinct numbers, which are 1, 2, ..., m.
        // Thus, m is beautiful.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

