void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if a peak can exist at index k (0-indexed)
    // For a peak at k, we need:
    // a[0] < a[1] < ... < a[k]
    // a[k] > a[k+1] > ... > a[n-1]

    // This implies:
    // For i from 0 to k-1: a[i] must be at least i.
    // For i from k+1 to n-1: a[i] must be at least (n-1-i).

    // We need to find if there exists *any* k (0 <= k < n) such that
    // a[k] can be the peak.
    // For a[k] to be a peak, it must be possible to make
    // b[0] = 0, b[1] = 1, ..., b[k-1] = k-1
    // b[k] = some value >= k-1 and >= n-k
    // b[k+1] = n-k-2, ..., b[n-1] = 0

    // The minimum value for a[i] in the increasing part is i.
    // The minimum value for a[i] in the decreasing part is (n-1-i).

    // Let's find the leftmost index `l` such that `a[l] < l`.
    // If `a[i] >= i` for all `i` from `0` to `n-1`, then any `k` could potentially be a peak
    // from the left side's perspective.
    // If `a[i] < i` for some `i`, then `i` cannot be part of the strictly increasing sequence
    // `0, 1, ..., i`. The peak `k` must be less than `i`.
    // So, `l` is the first index where the increasing sequence requirement fails.
    // Any potential peak `k` must be `k < l`.

    int l = 0;
    while (l < n && a[l] >= l) {
        l++;
    }
    // After this loop, `l` is the first index where `a[l] < l`, OR `l == n`.
    // If `l == n`, it means `a[i] >= i` for all `i`.
    // The valid range for `k` from the left side is `0` to `l-1`.

    // Similarly, let's find the rightmost index `r` such that `a[r] < (n-1-r)`.
    // If `a[i] >= (n-1-i)` for all `i` from `0` to `n-1`, then any `k` could potentially be a peak
    // from the right side's perspective.
    // If `a[i] < (n-1-i)` for some `i`, then `i` cannot be part of the strictly decreasing sequence
    // `..., (n-1-i), ..., 0`. The peak `k` must be greater than `i`.
    // So, `r` is the first index from the right where the decreasing sequence requirement fails.
    // Any potential peak `k` must be `k > r`.

    int r = n - 1;
    while (r >= 0 && a[r] >= (n - 1 - r)) {
        r--;
    }
    // After this loop, `r` is the first index from the right where `a[r] < (n-1-r)`, OR `r == -1`.
    // If `r == -1`, it means `a[i] >= (n-1-i)` for all `i`.
    // The valid range for `k` from the right side is `r+1` to `n-1`.

    // A valid peak `k` must satisfy both conditions:
    // `k` must be in `[0, l-1]` (from left side)
    // `k` must be in `[r+1, n-1]` (from right side)

    // So, we need to check if there is any `k` such that `r+1 <= k <= l-1`.
    // This is equivalent to checking if `r+1 <= l-1`, or `r < l-1`.
    // Or, more simply, if `r < l`.

    if (r < l) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

