    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (from the sorted array)
    int right_ptr = 0; // Pointer for elements to be compared against (from the sorted array)

    // We want to find a permutation B of A such that B[i] > A[i] for max i.
    // If we sort A to get A_sorted, we can try to match A_sorted[right_ptr] with
    // an element A_sorted[left_ptr] such that A_sorted[left_ptr] > A_sorted[right_ptr].
    // To maximize the count, we should try to use the smallest possible element
    // from the available larger elements for each A_sorted[right_ptr].
    // This means we iterate through A_sorted[right_ptr] from smallest to largest.
    // For each A_sorted[right_ptr], we try to find the smallest A_sorted[left_ptr]
    // that is strictly greater than A_sorted[right_ptr].
    // If we find such a pair, we increment count and advance both pointers.
    // If A_sorted[left_ptr] is not greater than A_sorted[right_ptr], it means
    // A_sorted[left_ptr] cannot be placed to be greater than A_sorted[right_ptr].
    // In this case, we must advance left_ptr to find a larger element.
    // The right_ptr should only advance when a successful match is made.

    while (left_ptr < n && right_ptr < n) {
        if (a[left_ptr] > a[right_ptr]) {
            // We found an element a[left_ptr] that can be placed
            // at a position where a[right_ptr] originally stood.
            // This contributes to our count.
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // a[left_ptr] is not greater than a[right_ptr].
            // This means a[left_ptr] cannot be used to "beat" a[right_ptr].
            // We need a larger element for a[right_ptr], so we advance left_ptr.
            left_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

