// Function to check if Box 1 can be the special box
// Box 1: (-inf, -1]
bool can_be_box1(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // The number of negative factors is A + B.
    // So, (A + B) must be odd.

    // Case 2: Final product has magnitude >= 1.
    // This is the tricky part. We need to ensure we can achieve this.

    // If A > 0, we have at least one toy with value <= -1.
    // If D > 0, we have at least one toy with value >= 1.
    // If A + D > 0, we have at least one toy with magnitude >= 1.

    // If A + B is odd:
    //   If A + D > 0: We have at least one toy with magnitude >= 1.
    //     We can try to make the final product negative and magnitude >= 1.
    //     If we have any toy in Box 1 or Box 4, we can potentially keep the magnitude large.
    //     If we have an odd number of negative toys (A+B is odd), we can make the final product negative.
    //     If we have at least one toy in Box 1 or Box 4 (A+D > 0), we can potentially make the magnitude >= 1.
    //     Consider the case where all other toys are in Box 2 or Box 3.
    //     If we have A+D > 0, we can always ensure the magnitude is >= 1.
    //     Example: Pick a toy from Box 1 or 4. Multiply it with a toy from Box 2 or 3.
    //     If we multiply a large magnitude toy with a small magnitude toy, the result can be small or large.
    //     However, if we have A+D > 0, we can always ensure the final product has magnitude >= 1.
    //     We can always pair up toys from B and C to make them positive and small.
    //     Then multiply with A or D.
    //     If A+D > 0, we can always achieve magnitude >= 1.
    //     Example: If we have a toy with value 10. We can multiply it by 0.1, result is 1.
    //     If we have a toy with value 10. We can multiply it by 0.01, result is 0.1.
    //     But we can choose the order. We can multiply all B and C toys first.
    //     If B+C > 0, we can make a product in (0,1).
    //     If A+D > 0, we can always ensure the magnitude is >= 1.
    //     The only way to get magnitude < 1 is if all toys have magnitude < 1 (A=0, D=0).
    //     So, if A+D > 0, we can always achieve magnitude >= 1.
    //     Thus, if (A+B) is odd AND (A+D > 0), Box 1 is possible.

    // What if A+D = 0? This means all toys are in Box 2 or Box 3.
    // In this case, all fun values are in (-1, 0) U (0, 1).
    // Any product of such values will also be in (-1, 0) U (0, 1).
    // So, if A+D = 0, the final toy will always be in Box 2 or Box 3.
    // Thus, Box 1 is impossible if A+D = 0.

    // So, Box 1 is possible if and only if (A + B) is odd AND (A + D > 0).
    return ((A + B) % 2 != 0) && (A + D > 0);
}

// Function to check if Box 2 can be the special box
// Box 2: (-1, 0)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // So, (A + B) must be odd.

    // Case 2: Final product has magnitude < 1.
    // This is the tricky part.

    // If A+D = 0, all toys are in Box 2 or Box 3.
    // Any product of such values will have magnitude < 1.
    // So, if A+D = 0, the final toy will always be in Box 2 or Box 3.
    // If A+D = 0 AND (A+B) is odd, then Box 2 is possible.
    // (A+D = 0 implies A=0, D=0. So (A+B) is odd means B is odd).
    // So, if B is odd and A=0, D=0, Box 2 is possible.

    // If A+D > 0: We have at least one toy with magnitude >= 1.
    // Can we still make the final product have magnitude < 1?
    // Yes, if we have enough "small" toys (from B or C) to "dilute" the large ones.
    // Example: 10 * 0.01 = 0.1.
    // We can always achieve magnitude < 1 if there are at least two toys in total.
    // If total_toys == 1, then the toy is already in its box.
    // If total_toys == 1 and the toy is in Box 2 (B=1, A=C=D=0), then Box 2 is possible.
    // If total_toys > 1:
    //   We can always pick a toy with magnitude >= 1 (from A or D) and multiply it by a toy with magnitude < 1 (from B or C).
    //   If we have A+D > 0 and B+C > 0, we can always make a product with magnitude < 1.
    //   Example: Take a toy from A or D (e.g., value 10). Take a toy from B or C (e.g., value 0.01).
    //   Multiply them: 10 * 0.01 = 0.1. This is in Box 3.
    //   We can always ensure the final product has magnitude < 1 if total_toys > 1.
    //   The only exception is if all toys have magnitude >= 1 (B=0, C=0).
    //   If B=0 and C=0, then all toys are in Box 1 or Box 4.
    //   In this case, any product will have magnitude >= 1. So Box 2 is impossible.
    //   So, if B+C > 0, we can always achieve magnitude < 1.

    // Combining conditions:
    // Box 2 is possible if:
    // 1. (A + B) is odd (for negative sign)
    // 2. (B + C > 0) OR (total_toys == 1 AND B == 1) (for magnitude < 1)
    //    The (total_toys == 1 AND B == 1) part handles the base case where the single toy is already in Box 2.
    //    If total_toys > 1: we need B+C > 0 to ensure we can make magnitude < 1.
    //    If B+C = 0, then all toys are in A or D, so magnitude will always be >= 1.

    if ((A + B) % 2 != 0) { // Need negative sign
        if (total_toys == 1) {
            return B == 1; // Only one toy, must be in Box 2
        } else {
            return (B + C > 0); // Need at least one toy from B or C to make magnitude < 1
        }
    }
    return false;
}

// Function to check if Box 3 can be the special box
// Box 3: (0, 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Final product is positive.
    // This requires an even number of negative factors.
    // So, (A + B) must be even.

    // Case 2: Final product has magnitude < 1.
    // Similar logic to Box 2 for magnitude.
    // Box 3 is possible if:
    // 1. (A + B) is even (for positive sign)
    // 2. (B + C > 0) OR (total_toys == 1 AND C == 1) (for magnitude < 1)

    if ((A + B) % 2 == 0) { // Need positive sign
        if (total_toys == 1) {
            return C == 1; // Only one toy, must be in Box 3
        } else {
            return (B + C > 0); // Need at least one toy from B or C to make magnitude < 1
        }
    }
    return false;
}

// Function to check if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Final product is positive.
    // This requires an even number of negative factors.
    // So, (A + B) must be even.

    // Case 2: Final product has magnitude >= 1.
    // Similar logic to Box 1 for magnitude.
    // Box 4 is possible if:
    // 1. (A + B) is even (for positive sign)
    // 2. (A + D > 0) OR (total_toys == 1 AND D == 1) (for magnitude >= 1)
    //    The (total_toys == 1 AND D == 1) part handles the base case where the single toy is already in Box 4.
    //    If total_toys > 1: we need A+D > 0 to ensure we can make magnitude >= 1.
    //    If A+D = 0, then all toys are in B or C, so magnitude will always be < 1.

    if ((A + B) % 2 == 0) { // Need positive sign
        if (total_toys == 1) {
            return D == 1; // Only one toy, must be in Box 4
        } else {
            return (A + D > 0); // Need at least one toy from A or D to make magnitude >= 1
        }
    }
    return false;
}


