// Function to check if a sub-array is a permutation of length 'len'
// It uses a frequency array (or boolean array) and checks max value.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    // All numbers from 1 to len must be present
    // This is implicitly checked by `seen[val]` and `val > len`
    // and `max_val` must be `len` if all numbers from 1 to len are present.
    // However, the `seen` array check is sufficient.
    // If all numbers from 1 to len are present, then max_val must be len.
    // If max_val is not len, it means some number > len was present (caught by val > len)
    // or some number <= len was missing (caught by seen[val] not all true for 1..len).
    // The `seen` array check is robust.
    return max_val == len;
}

// Optimized check for permutation using prefix/suffix maximums and counts
// This function precomputes prefix/suffix properties to speed up checks.
void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix properties
    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    int distinct_count = 0;

    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val > n || seen_prefix[val]) { // Value out of range or duplicate
            // This prefix cannot be a permutation, nor can any longer prefix
            // that includes this element.
            // We can break or just let it propagate false.
            // For simplicity, we'll just mark it false and continue.
            // The distinct_count and current_max will be incorrect for permutation check
            // but prefix_is_perm will be false.
            distinct_count = -1; // Indicate invalid state
        } else {
            seen_prefix[val] = true;
            if (distinct_count != -1) { // Only increment if still valid
                distinct_count++;
                if (val > current_max) {
                    current_max = val;
                }
            }
        }
        prefix_max[i] = current_max;
        if (distinct_count != -1 && distinct_count == (i + 1) && current_max == (i + 1)) {
            prefix_is_perm[i] = true;
        }
    }

    // Precompute suffix properties
    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n, false);
    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    distinct_count = 0;

    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        if (val > n || seen_suffix[val]) {
            distinct_count = -1;
        } else {
            seen_suffix[val] = true;
            if (distinct_count != -1) {
                distinct_count++;
                if (val > current_max) {
                    current_max = val;
                }
            }
        }
        suffix_max[i] = current_max;
        if (distinct_count != -1 && distinct_count == (n - i) && current_max == (n - i)) {
            suffix_is_perm[i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 is the length of the first permutation p1
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        // Check if prefix a[0...l1-1] is a permutation of length l1
        // Check if suffix a[l1...n-1] is a permutation of length l2
        if (prefix_is_perm[l1 - 1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

