void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // The condition for a good array is S = 2 * X.
    // We need to append at most 3 elements.
    // Let the current sum be S and current XOR sum be X.
    // We want to find b1, b2, b3 such that (S + b1 + b2 + b3) = 2 * (X ^ b1 ^ b2 ^ b3).

    // Strategy:
    // 1. Append X.
    //    New sum S' = S + X
    //    New XOR sum X' = X ^ X = 0
    //    Condition: S' = 2 * X'  => S + X = 2 * 0 => S + X = 0.
    //    This is generally not true unless S=0 and X=0.
    //    However, if we append X, the XOR sum becomes 0.
    //    Now we need to make the sum 0.
    //    The current sum is S + X.
    //    We need to append another element 'y' such that (S + X + y) = 2 * (0 ^ y) = 2 * y.
    //    So, S + X + y = 2 * y  => S + X = y.
    //    So, we can append X and then (S + X).
    //    The elements to append are X and (S + X).
    //    The new array will have sum S + X + (S + X) = 2 * (S + X).
    //    The new array will have XOR sum X ^ X ^ (S + X) = 0 ^ (S + X) = S + X.
    //    The condition S_new = 2 * X_new becomes 2 * (S + X) = 2 * (S + X), which is always true.
    //    This strategy uses 2 elements: X and (S + X).

    // Output 2 elements: current_xor_sum and current_sum + current_xor_sum
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

