#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm> // For std::reverse

// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "000000000000000000"; // Max 18 digits, 0 is even
    }
    std::string pattern = "";
    for (int i = 0; i < 18; ++i) { // Numbers up to 10^18 have at most 18 digits
        if (n == 0) {
            pattern += '0'; // Pad with '0' (even) if number is shorter
        } else {
            pattern += ((n % 10) % 2 == 0 ? '0' : '1');
            n /= 10;
        }
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get standard order
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the pattern s to 18 digits with '0's from the left
            std::string padded_s = std::string(18 - s.length(), '0') + s;
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
