#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (int x = 0; x <= 9; ++x) { // Iterate through all possible pivot digits (0-9)
        std::string current_result(n, ' ');
        char last1 = '0'; // Last digit in sequence 1
        char last2 = '0'; // Last digit in sequence 2
        bool valid_x = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < x + '0') { // Digit is strictly less than pivot
                if (digit < last1) { // Violates non-decreasing for color 1
                    valid_x = false;
                    break;
                }
                current_result[i] = '1';
                last1 = digit;
            } else if (digit > x + '0') { // Digit is strictly greater than pivot
                if (digit < last2) { // Violates non-decreasing for color 2
                    valid_x = false;
                    break;
                }
                current_result[i] = '2';
                last2 = digit;
            } else { // Digit is equal to pivot
                // Try to assign to color 2 first if possible, to keep color 1 digits smaller
                if (digit < last2) { // Cannot assign to color 2 without violating non-decreasing
                    if (digit < last1) { // Cannot assign to color 1 either
                        valid_x = false;
                        break;
                    }
                    current_result[i] = '1';
                    last1 = digit;
                } else { // Can assign to color 2
                    current_result[i] = '2';
                    last2 = digit;
                }
            }
        }

        if (valid_x) {
            // After assigning all digits, check the final condition:
            // last digit of S1 <= first digit of S2.
            // In our construction, last1 is the maximum digit assigned to color 1.
            // last2 is the minimum digit assigned to color 2.
            // This is implicitly handled by the logic:
            // - All digits < x are '1'.
            // - All digits > x are '2'.
            // - Digits == x are either '1' or '2'.
            //   - If '1', they must be >= last '1' digit.
            //   - If '2', they must be >= last '2' digit.
            // The critical part is that any digit '1' must be <= any digit '2'.
            // Our strategy ensures this:
            // Any digit colored '1' is either < x or = x.
            // Any digit colored '2' is either > x or = x.
            // If a digit '1' is < x and a digit '2' is > x, then '1' < '2'.
            // If a digit '1' is = x and a digit '2' is > x, then '1' < '2'.
            // If a digit '1' is < x and a digit '2' is = x, then '1' < '2'.
            // The only case where it's not immediately obvious is if both are = x.
            // But if a digit '1' is = x and a digit '2' is = x, then '1' == '2', which is fine.
            // The crucial part is that all digits colored '1' must be <= all digits colored '2'.
            // Our construction ensures this by partitioning around 'x'.
            // The only remaining check is that last1 <= first_digit_in_S2.
            // Our logic for assigning 'x' digits (preferring '2' if possible)
            // ensures that last1 will be as small as possible, and first_digit_in_S2
            // will be as large as possible among the 'x' digits.
            // If last1 is an 'x' digit, and first_digit_in_S2 is an 'x' digit, they are equal.
            // If last1 is < x, and first_digit_in_S2 is x, then last1 < first_digit_in_S2.
            // If last1 is < x, and first_digit_in_S2 is > x, then last1 < first_digit_in_S2.
            // So, the conditions are met.

            result = current_result;
            possible = true;
            break; // Found a valid coloring, no need to check other x values
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

