    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val = (b - 1) * b / 2;
    sum_r_val %= MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_kb_plus_1_val
    // sum_{k=1 to a} (k * b + 1) = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a

    long long sum_k_val = a * (a + 1) / 2;
    sum_k_val %= MOD;

    long long sum_kb_plus_1_val = (b % MOD * sum_k_val) % MOD;
    sum_kb_plus_1_val = (sum_kb_plus_1_val + a % MOD) % MOD;

    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

