#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i + 1 < s.length()) {
            adj[s[i]].insert(s[i+1]);
            adj[s[i+1]].insert(s[i]);
        }
    }

    // Check degrees
    for (char c : used_in_s) {
        if (adj[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;
    char current_char = '\0';

    // Find a starting point for the path (a character with degree 1 or a single character if s.length() == 1)
    if (!s.empty()) {
        bool found_start = false;
        for (char c : used_in_s) {
            if (adj[c].size() <= 1) { // Degree 0 for single char password, degree 1 for path end
                current_char = c;
                found_start = true;
                break;
            }
        }
        // If all characters in s have degree 2, it means there's a cycle.
        // This is only possible if s itself forms a cycle, e.g., "abacaba" where a-b, b-a, a-c, c-a.
        // But the problem states "for each pair of adjacent characters in s, they should be adjacent on the keyboard".
        // If s forms a cycle, say 'a'-'b'-'c'-'a', then 'a' has degree 2 (connected to 'b' and 'c').
        // This is fine. The issue is if the graph formed by s has multiple components or a component that is not a path.
        // If all characters in used_in_s have degree 2, it means they form one or more cycles.
        // A single cycle can be laid out as a path by breaking one edge.
        // However, if there are multiple cycles or a cycle with branches, it's impossible.
        // The degree check (adj[c].size() > 2) already handles branches.
        // So, if we reach here and all used_in_s chars have degree 2, it means it's a single cycle.
        // We can pick any char as a start.
        if (!found_start && !used_in_s.empty()) {
            current_char = *used_in_s.begin(); // Pick any char from the cycle
            found_start = true;
        }
        if (!found_start && s.length() == 1) { // Special case for single character password
            current_char = s[0];
            found_start = true;
        }
    }

    if (current_char != '\0') { // If there are characters from the password
        while (current_char != '\0' && visited_in_layout.find(current_char) == visited_in_layout.end()) {
            layout_str += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (visited_in_layout.find(neighbor) == visited_in_layout.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Check if all characters from 's' were included in the layout_str
    if (layout_str.length() != used_in_s.size()) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

