struct Result {
    long long final_y;
    bool terminates;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] unused, a[1] will be set for each run
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp[i] stores the result for starting with x=i and performing step 3 (x = x - a[x], y = y + a[x])
    // after having just performed step 2 (x = x + a[x], y = y + a[x]) from some previous state.
    // More precisely, dp[i] stores the result if the program is currently at x=i and the next operation is step 2.
    // This is because the problem states "The program executes steps 2 and 3 (first step 2, then step 3) repeatedly".
    // So, if we are at x, we first do step 2, then step 3, then step 2, etc.
    // The dp state should represent the outcome from a given x *before* step 2 is applied.
    // Let's redefine: dp[i] stores the final y value if the program starts at x=i and the next operation is step 2.
    // If it doesn't terminate, it's -2 (to distinguish from -1 for cycle).
    std::vector<long long> dp(n + 1, -2); // -2 indicates not computed yet

    // visited_path[i] stores the current path's y value when we are at x=i.
    // This helps detect cycles. If we encounter x=i again and visited_path[i] is not -1,
    // it means we are in a cycle.
    std::vector<long long> visited_path_y(n + 1, -1); // -1 indicates not visited in current path

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run

        // Reset visited_path_y for each new run starting from a[1]
        std::fill(visited_path_y.begin(), visited_path_y.end(), -1);

        long long current_x = 1;
        long long current_y = 0;
        bool cycle_detected = false;
        bool terminated = false;

        // Stack to keep track of the path for cycle detection and DP update
        std::vector<std::pair<long long, long long>> path_stack; // Stores (x, y_at_x)

        while (!terminated && !cycle_detected) {
            if (current_x <= 0 || current_x > n) {
                terminated = true;
                break;
            }

            // Check if this state has been computed before
            if (dp[current_x] != -2) {
                if (dp[current_x] == -1) { // Previously determined to be part of an infinite loop
                    cycle_detected = true;
                } else { // Previously computed and terminates
                    current_y += dp[current_x];
                }
                terminated = true;
                break;
            }

            // Check for cycle in current path
            if (visited_path_y[current_x] != -1) {
                cycle_detected = true;
                break;
            }

            // Mark current state as visited in this path
            visited_path_y[current_x] = current_y;
            path_stack.push_back({current_x, current_y});

            // Step 2: x = x + a[x], y = y + a[x]
            long long val_at_x_step2 = a[current_x];
            current_x += val_at_x_step2;
            current_y += val_at_x_step2;

            if (current_x <= 0 || current_x > n) {
                terminated = true;
                break;
            }

            // Step 3: x = x - a[x], y = y + a[x]
            long long val_at_x_step3 = a[current_x]; // Note: a[current_x] is the new x after step 2
            current_x -= val_at_x_step3;
            current_y += val_at_x_step3;
        }

        if (cycle_detected) {
            std::cout << -1 << "\n";
            // Mark all states in the detected cycle as -1 (infinite loop)
            for (const auto& p : path_stack) {
                dp[p.first] = -1;
