    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Calculate total_delta_j for each element j
    // total_delta_j is the sum of all 'd' values applied to a[j]
    std::vector<long long> total_delta(n, 0);
    std::vector<long long> current_delta_prefix_sum(n + 1, 0); // For efficient range updates

    for (const auto& op : ops) {
        if (op.type == 1) {
            current_delta_prefix_sum[op.l] += op.val;
            if (op.r + 1 < n) {
                current_delta_prefix_sum[op.r + 1] -= op.val;
            }
        }
    }

    long long current_delta_val = 0;
    for (int j = 0; j < n; ++j) {
        current_delta_val += current_delta_prefix_sum[j];
        total_delta[j] = current_delta_val;
    }

    // Initialize initial_b_j values
    // For each type 2 operation (l, r, m), we know that max(b_j + total_delta_j) = m
    // This implies b_j + total_delta_j <= m for all j in [l, r]
    // So, b_j <= m - total_delta_j
    // We want to maximize b_j to satisfy constraints, so we take the minimum of these upper bounds.
    std::vector<long long> b(n, std::numeric_limits<long long>::max()); // Initialize with a very large value

    for (const auto& op : ops) {
        if (op.type == 2) {
            for (int j = op.l; j <= op.r; ++j) {
                b[j] = std::min(b[j], op.val - total_delta[j]);
            }
        }
    }

    // If b[j] is still max_long_long, it means it was never constrained by a type 2 operation.
    // We can set it to 0 (or any value within |10^9| bounds)
    // The problem statement says "all numbers in his array didn't exceed 10^9 in their absolute value".
    // Setting to 0 is a safe choice.
    for (int j = 0; j < n; ++j) {
        if (b[j] == std::numeric_limits<long long>::max()) {
            b[j] = 0;
        }
    }

    // Verify the solution
    // Simulate operations with the found initial array 'b'
    // Use a segment tree or similar for efficient range max queries and updates.
    // Given N, M <= 5000, a simple O(N) simulation for each operation is O(N*M), which is 2.5 * 10^7, acceptable.

    std::vector<long long> a = b; // Current state of the array

    // For efficient range updates and queries, we can use a difference array for updates
    // and then reconstruct the array for queries.
    // Or, since N is small enough, we can just apply updates directly.

    // To handle updates and queries efficiently for verification, we can use a segment tree.
    // However, a simpler approach for verification is to re-calculate the current array state
    // for each query.

    // Let's use a difference array for current_delta_for_verification
    // This tracks the sum of 'd' values applied *so far* to each element.
    std::vector<long long> current_delta_for_verification(n, 0);
    std::vector<long long> diff_array_for_verification(n + 1, 0);

    for (const auto& op : ops) {
