        long long chain_d_cry = 0; // Accumulates d_j cries from children leaving due to chain reaction

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue; // This child has already left
            }

            // Apply cry from the treated child (v_i)
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated chain cry (d_j)
            children[j].p -= chain_d_cry;

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].in_line = false; // Child j leaves
                chain_d_cry += children[j].d; // Add child j's d_j to chain reaction
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;
    long long second_min_a = elements[1].value;
    long long second_max_a = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // f values are all a_i + a_j.
    // Min f = min_a + second_min_a
    // Max f = max_a + second_max_a
    // Goodness = (max_a + second_max_a) - (min_a + second_min_a)
    long long goodness_all_same = (max_a + second_max_a) - (min_a + second_min_a);
    std::vector<int> partition_all_same(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is min_a + second_min_a (if min_a and second_min_a are in the same group).
    // The minimum possible f value is min_a + elements[k].value + h (if min_a and elements[k].value are in different groups).
    // The maximum possible f value is max_a + second_max_a (if max_a and second_max_a are in the same group).
    // The maximum possible f value is max_a + elements[k].value + h (if max_a and elements[k].value are in different groups).

    // Consider the partition where elements[0] is in S1 and all others are in S2.
    // Or elements[0] is in S2 and all others are in S1.
    // This is equivalent to one element in one group, and n-1 elements in the other.
    // Let S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    // f values:
    //   - elements[i] + elements[j] for i,j >= 1 (in S2)
    //   - elements[0] + elements[j] + h for j >= 1 (elements[0] in S1, elements[j] in S2)

    // Min f:
    //   - min_a + second_min_a (if elements[0] and elements[1] are in the same group, but they are not here)
    //   - elements[1] + elements[2] (if n >= 3, from S2)
    //   - elements[0] + elements[1] + h (from S1-S2 interaction)
    // So, min_f = std::min(elements[1] + elements[2], elements[0] + elements[1] + h) if n >= 3.
    // If n=2, only elements[0] + elements[1] + h is possible.

    // Max f:
    //   - max_a + second_max_a (from S2)
    //   - elements[0] + max_a + h (from S1-S2 interaction)
    // So, max_f = std::max(max_a + second_max_a, elements[0] + max_a + h) if n >= 3.
    // If n=2, only elements[0] + elements[1] + h is possible.

    // Let's analyze the specific partition: elements[0] in S1, elements[1...n-1] in S2.
    // Min possible f:
    //   - If n=2: elements[0].value + elements[1].value + h
    //   - If n > 2: std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    long long min_f_split_one_vs_rest;
    if (n == 2) {
        min_f_split_one_vs_rest = elements[0].value + elements[1].value + h;
    } else {
        min_f_split_one_vs_rest = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    }

    // Max possible f:
    //   - If n=2: elements[0].value + elements[1].value + h
    //   - If n > 2: std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    long long max_f_split_one_vs_rest;
    if (n == 2) {
        max_f_split_one_vs_rest = elements[0].value + elements[1].value + h;
    } else {
        max_f_split_one_vs_rest = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
    }

    long long goodness_split_one_vs_rest = max_f_split_one_vs_rest - min_f_split_one_vs_rest;
    std::vector<int> partition_split_one_vs_rest(n);
    partition_split_one_vs_rest[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_split_one_vs_rest[elements[i].original_index] = 2;
    }

    // Compare the two strategies
    if (goodness_all_same <= goodness_split_one_vs_rest) {
        std::cout << goodness_all_same << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_all_same[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_split_one_vs_rest << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_split_one_vs_rest[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <numeric> // For std::accumulate (C++11) or manual loop

// Function to calculate the parity of a 01-string
// Returns 1 if odd number of '1's, 0 otherwise.
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate parity of string b
    int parity_b = calculate_parity(b);

    // The maximum number of '1's we can have in 'a' after appending parities
    // is its current count plus the number of characters we can append.
    // The maximum length of 'a' can be 1000.
    // If we append '1's, the count of '1's increases.
    // If we append '0's, the count of '1's stays the same.
    // So, the maximum possible count of '1's in 'a' (or any string derived from 'a' by appending)
    // is its initial count plus its initial length (if all appended characters were '1's).
    // However, a simpler approach is to consider the maximum possible parity sum.
    // If parity_a is 0, we can append a '0', and parity remains 0.
    // If parity_a is 1, we can append a '1', and parity remains 0.
    // If parity_a is 0, we can append a '0', and parity remains 0.
    // If parity_a is 0, we can append a '1' (if we first make parity 1), and parity becomes 1.
    //
    // The key insight is that if we have a string `s` with `P` ones:
    // - If `P` is even (parity 0), we can append '0'. The new string `s0` has `P` ones, parity 0.
    // - If `P` is odd (parity 1), we can append '1'. The new string `s1` has `P+1` ones, parity 0.
    // In both cases, after one append operation, we can always reach a state where the string has an even number of ones.
    // Once a string has an even number of ones (parity 0), we can append '0's indefinitely, maintaining parity 0.
    // Or, if we want to change parity to 1, we need to append a '1'. This means the current string must have had an odd number of ones.
    //
    // Let's re-evaluate:
    // If current_parity is 0:
    //   Append '0'. New string has same number of '1's. New parity is 0.
    //   This means we can always maintain parity 0 if we start with it.
    // If current_parity is 1:
    //   Append '1'. New string has one more '1'. New parity is 0.
    //   This means we can always reach parity 0 from parity 1 in one step.
    //
    // So, any string `a` can be extended to `a'` such that `a'` has parity 0,
    // and `a'` can be further extended to `a''` such that `a''` has parity 0.
    // This means we can always make the parity 0, and then keep it 0.
    //
    // The only way to get a parity of 1 is if the *final* appended character makes it 1.
    // This means the string *before* the last append must have had an odd number of ones.
    //
    // Let `ones_a` be the count of '1's in `a`.
    // Let `ones_b` be the count of '1's in `b`.
    //
    // We can always increase the length of `a` by appending characters.
    // The maximum number of '1's we can effectively "generate" in `a`
    // is `ones_a` plus the number of characters we can append.
    // The maximum length of `a` is 1000.
    // The maximum length of `b` is 1000.
    //
    // If `|a| < |b|`, we must append `|b| - |a|` characters to `a` *at least*.
    // The maximum number of '1's we can have in `a` after appending is:
    // `ones_a` + (number of '1's we can append).
    //
    // Consider the total number of '1's we can achieve in `a` by appending.
    // Let `N_a` be the count of '1's in `a`.
    // If `N_a` is even, we can append '0's, keeping `N_a` even.
    // If `N_a` is odd, we can append '1', making `N_a+1` even.
    // So, we can always reach an even number of '1's.
    //
    // The maximum number of '1's we can have in `a` (before removing prefix)
    // is `ones_a` if `parity_a` is 0, or `ones_a + 1` if `parity_a` is 1.
    // This is because if `parity_a` is 1, we can append a '1' to make it `parity_a + 1` (which is even).
    // If `parity_a` is 0, we can append a '0' to keep it `parity_a` (which is even).
    // In both cases, we can achieve an even number of '1's.
    //
    // Let `max_ones_a_effective` be the maximum number of '1's we can have in `a`
    // such that its parity is 0.
    // If `parity_a` is 0, `max_ones_a_effective = ones_a`.
    // If `parity_a` is 1, `max_ones_a_effective = ones_a + 1`.
    // This can be simplified to `max_ones_a_effective = ones_a + parity_a`.
    //
    // Now, we need to check if `b` can be a suffix of `a` (after some operations).
    // This means `b` must have `ones_b` '1's.
    //
    // Condition 1: The number of '1's in `b` must be less than or equal to the
    // maximum effective '1's we can generate in `a`.
    // `ones_b <= max_ones_a_effective`
    // `ones_b <= ones_a + parity_a`
    //
    // Condition 2: The length of `b` must be less than or equal to the length of `a`
    // after we've potentially appended characters.
    // We can always append characters until `a` is long enough.
    // The only constraint is that `a` cannot become empty.
    // But `b` is never empty (length >= 1).
    // So, if `ones_b <= ones_a + parity_a`, we can always make `a` long enough
    // and with the correct number of '1's (or more '1's than needed, which is fine).
    //
    // Example 1: a = 01011, b = 0110
    // ones_a = 3, parity_a = 1
    // ones_b = 2, parity_b = 0
    // max_ones_a_effective = ones_a + parity_a = 3 + 1 = 4
    // Is ones_b <= max_ones_a_effective? 2 <= 4. YES.
    // Output: YES. Correct.
    //
    // Example 2: a = 0011, b = 1110
    // ones_a = 2, parity_a = 0
    // ones_b = 3, parity_b = 1
    // max_ones_a_effective = ones_a + parity_a = 2 + 0 = 2
    // Is ones_b <= max_ones_a_effective? 3 <= 2. NO.
    // Output: NO. Correct.

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // If parity_a is 1, we can append a '1' to make the count of ones `ones_a + 1` (which is even).
    // If parity_a is 0, we can append a '0' to keep the count of ones `ones_a` (which is even).
    // So, the maximum number of '1's we can have in a string derived from 'a'
    // that has an even parity is `ones_a` if `ones_a` is even, or `ones_a + 1` if `ones_a` is odd.
    // This is equivalent to `ones_a + (ones_a % 2)`.
    int max_possible_even_ones_in_a_prefix = ones_a + (ones_a % 2);

    // If `b` has an odd number of '1's, then the string `a'` from which `b` is a suffix
    // must also have had an odd number of '1's.
    // This means `max_possible_even_ones_in_a_prefix` is not directly applicable for `b`'s parity.
    //
    // Let's simplify:
    // We can always make the number of '1's in `a` equal to `ones_a` or `ones_a + 1`.
    // If `ones_a` is even, we can make it `ones_a` (by appending '0's) or `ones_a + 1` (by appending '1' after making it odd).
    // If `ones_a` is odd, we can make it `ones_a` (by appending '0' after making it even) or `ones_a + 1` (by appending '1').
    //
    // The crucial point is that we can always increase the count of '1's by at most 1
    // to achieve a desired parity for the *final* string `a'` from which `b` is a suffix.
    //
    // If `ones_b` is the count of '1's in `b`:
    // We need to be able to form a string `a_prime` (by appending to `a`) such that `b` is a suffix of `a_prime`.
    // The number of '1's in `a_prime` must be at least `ones_b`.
    //
    // Let `current_ones_a = ones_a`.
    // We can append characters.
    // If `current_ones_a` is even, we can append '0'. `current_ones_a` remains even.
    // If `current_ones_a` is odd, we can append '1'. `current_ones_a` becomes even.
    // So, we can always reach an even number of '1's.
    //
    // If we want to achieve `ones_b` '1's in `b`:
    // The maximum number of '1's we can have in `a` (before removing prefix) is `ones_a` if `ones_a` is even,
    // or `ones_a + 1` if `ones_a` is odd.
    // This is `ones_a + (ones_a % 2)`.
    //
    // If `ones_b` is greater than `ones_a + (ones_a % 2)`, it's impossible.
    // Otherwise, it's always possible.
    //
    // This logic seems sound and covers both examples.

    if (ones_b <= (ones_a + (ones_a % 2))) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    int h_idx = 0; // Current index for heads

    while (p_idx < m && h_idx < n) {
        // Find the first target track that can be covered by the current head h_idx
        // A head h_idx can cover tracks in [h[h_idx] - T, h[h_idx] + T]
        // If p[p_idx] is too far to the left of h[h_idx] - T, this head cannot cover it.
        // This implies that p[p_idx] must be covered by a previous head.
        // Since we are iterating p_idx and h_idx in increasing order,
        // if p[p_idx] < h[h_idx] - T, it means p[p_idx] cannot be covered by h[h_idx]
        // and also cannot be covered by any h[k] where k > h_idx (because h[k] > h[h_idx]).
        // This situation should not happen if the previous heads covered their assigned tracks correctly.
        // The greedy strategy is to assign the leftmost available head to cover the leftmost uncovered target track.

        // If p[p_idx] is to the left of the current head's range, this head cannot cover it.
        // This means p[p_idx] must have been covered by a previous head.
        // However, our greedy approach ensures we always try to cover p[p_idx] with the current h_idx.
        // If p[p_idx] is too far left for h[h_idx] to cover, it means it's impossible with this T.
        // But this is not quite right. We need to find *a* head for p[p_idx].
        // The greedy strategy should be: for the current head h[h_idx], cover as many tracks as possible
        // starting from p[p_idx].

        // If the current head h[h_idx] cannot reach p[p_idx] (p[p_idx] is too far left),
        // then p[p_idx] must have been covered by a previous head.
        // But we are processing p_idx sequentially. So if p[p_idx] is not covered, it means it needs a head.
        // If h[h_idx] is too far right to cover p[p_idx] (i.e., p[p_idx] < h[h_idx] - T),
        // then this T is not enough, or the previous heads didn't cover enough.
        // This is the critical part of the greedy strategy.
        // We need to find the first head h[h_idx] such that h[h_idx] + T >= p[p_idx].
        // If such a head is found, it can potentially cover p[p_idx].
        // If h[h_idx] - T > p[p_idx], then h[h_idx] is too far right to cover p[p_idx] from its left side.
        // This means p[p_idx] must be covered by a head h[k] with k < h_idx.
        // If we are at p_idx, and h_idx is the first head we are considering,
        // then p[p_idx] must be covered by h[h_idx] or a later head.
        // So, we need to find the first h[h_idx] such that h[h_idx] + T >= p[p_idx].
        // If h[h_idx] - T > p[p_idx], then h[h_idx] is too far right.
        // We need to advance h_idx until h[h_idx] - T <= p[p_idx].
        // This means h[h_idx] is potentially able to cover p[p_idx].

        // Find the first head h[h_idx] that can potentially cover p[p_idx]
        // (i.e., h[h_idx] is not too far to the right of p[p_idx])
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            // This head h[h_idx] cannot reach p[p_idx] even by moving right T steps.
            // So, p[p_idx] must be covered by a later head.
            // This is incorrect. If h[h_idx] + T < p[p_idx], then h[h_idx] cannot cover p[p_idx].
            // This means p[p_idx] must be covered by some h[k] where k > h_idx.
            // We should advance h_idx to find a head that can cover p[p_idx].
            h_idx++;
        }

        if (h_idx == n) {
            // No more heads, but there are still target tracks to cover.
            return false;
        }

        // Now, h[h_idx] is the first head that *might* be able to cover p[p_idx].
        // Specifically, h[h_idx] + T >= p[p_idx].
        // We need to check if h[h_idx] can reach p[p_idx] from its left side.
        // If p[p_idx] < h[h_idx] - T, then h[h_idx] is too far right to cover p[p_idx].
        // This means p[p_idx] cannot be covered by h[h_idx] or any subsequent head (since h are sorted).
        // So, if p[p_idx] < h[h_idx] - T, it's impossible.
        if (p[p_idx] < h[h_idx] - T) {
            return false;
        }

        // At this point, h[h_idx] can cover p[p_idx].
        // It can cover tracks in the range [h[h_idx] - T, h[h_idx] + T].
        // We greedily cover all p_j that fall into this range.
        long long current_head_max_reach = h[h_idx] + T;
        while (p_idx < m && p[p_idx] <= current_head_max_reach) {
            p_idx++;
        }
        h_idx++; // Move to the next head
    }

    return p_idx == m; // All target tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // The maximum possible distance is between the furthest p and furthest h,
    // or between the closest p and closest h.
    // A safe upper bound is the distance between the first p and last h, or vice versa,
    // or simply the maximum possible coordinate value.
    // Max coordinate is 10^10. So max diff is 10^10.
    long long high = 20000000000LL; // A sufficiently large upper bound (e.g., max_coord - min_coord)
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1 (two pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (three pieces)
    // The problem statement guarantees that s is a palindrome.
    // If all characters in s are the same (e.g., "qqqq"), then no matter how we cut and reorder,
    // the resulting string will always be the same string of identical characters, which is s itself.
    // In this specific case, it's impossible to form a new string different from s.
    // We can check this by counting distinct characters.
    // If there's only one distinct character, it's impossible.

    // Count distinct characters
    std::vector<bool> seen_char(26, false);
    int distinct_chars = 0;
    for (char c : s) {
        if (!seen_char[c - 'a']) {
            seen_char[c - 'a'] = true;
            distinct_chars++;
        }
    }

    if (distinct_chars <= 1) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If we reach here, it means k=1 didn't work, but there are at least two distinct characters.
    // For any palindrome s with length > 1 and at least two distinct characters,
    // it's always possible to achieve a new palindrome with k=2 cuts.
    // Consider the cut s[0...i-1] | s[i] | s[i+1...n-1].
    // For example, for "nolon", cuts "no|l|on" can be reordered to "on|l|no".
    // This is always possible if n > 1 and not all characters are the same.
    // The strategy is to take the first character s[0], the middle part s[1...n-2], and the last character s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // Let s_prefix = s[0], s_middle = s[1...n-2], s_suffix = s[n-1].
    // Original: s_prefix + s_middle + s_suffix
    // New string: s_suffix + s_middle + s_prefix
    // Since s_prefix == s_suffix, this new string is identical to the original.
    // This doesn't work.

