void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The simplest way to get a different permutation with the same fingerprint
    // is to reverse the original permutation.
    // The sums of adjacent elements will be the same set, just in reverse order.
    // For example, if p = [p1, p2, p3], sums are [p1+p2, p2+p3].
    // If p_rev = [p3, p2, p1], sums are [p3+p2, p2+p1].
    // The set of sums {p1+p2, p2+p3} is the same as {p3+p2, p2+p1}.
    // Therefore, their sorted versions (fingerprints) will be identical.

    std::vector<int> p_prime = p;
    std::reverse(p_prime.begin(), p_prime.end());

    // This strategy works unless p is a palindrome (p == p_prime).
    // The problem statement guarantees a solution exists.
    // For n >= 2, if p is a palindrome, it means p_i = p_{n-1-i}.
    // For example, if n=3, p=[1,2,3], p_rev=[3,2,1]. Different.
    // If n=3, p=[1,3,1], not a permutation.
    // If n=4, p=[1,2,2,1], not a permutation.
    // A permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2)
    // or if n is odd and the middle element is fixed, and the pairs are swapped.
    // E.g., for n=3, p=[1,2,3] -> p_rev=[3,2,1].
    // For n=4, p=[1,2,3,4] -> p_rev=[4,3,2,1].
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // Since all elements 1 to n are distinct, this can only happen if n=1.
    // For n >= 2, p cannot be a palindrome.
    // Example: if p = [1,2,3,4], p_rev = [4,3,2,1]. These are different.
    // If p = [1,2,1], this is not a permutation because 1 appears twice.
    // If p = [1,3,2], p_rev = [2,3,1]. Different.
    // The only way p == p_rev is if p_i == p_{n-1-i} for all i.
    // But since p is a permutation, all p_i are distinct.
    // If p_i == p_{n-1-i}, then for i != n-1-i, we would have p_i = p_{n-1-i}
    // which contradicts distinctness unless i = n-1-i.
    // This means n-1 must be an even number, so n is odd, and i = (n-1)/2 is the middle element.
    // For example, if n=3, p=[p_0, p_1, p_2]. If p is a palindrome, p_0=p_2.
    // But p_0 and p_2 must be distinct in a permutation.
    // This implies that p cannot be a palindrome for n >= 2.
    // Therefore, reversing the permutation always yields a different permutation.

    for (int i = 0; i < n; ++i) {
        std::cout << p_prime[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

