int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // Skip a[i][i] which is 0
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This is because if p[i] is not n, then there must be some p[k] = n.
        // Then a[i][k] = min(p[i], p[k]) = min(p[i], n) = p[i].
        // And p[i] must be the maximum value in row i, because all other p[j] < p[i]
        // would result in a[i][j] = p[j] < p[i], and all other p[j] > p[i]
        // would result in a[i][j] = p[i].
        // So, max_val_in_row is either p[i] (if p[i] < n) or n-1 (if p[i] = n).
        // The problem guarantees a solution exists.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

