int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // Total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of (h/2) / n = h / (2n).
    // Let x_k be the distance from the apex to the k-th cut.
    // The triangle formed by the apex and the k-th cut has height x_k.
    // Due to similarity, its base will be (x_k / h) * 1 = x_k / h.
    // The area of this smaller triangle is (1/2) * (x_k / h) * x_k = x_k^2 / (2h).
    //
    // The first piece is from the apex to the first cut. Its area should be h/(2n).
    // So, x_1^2 / (2h) = h / (2n)
    // x_1^2 = h^2 / n
    // x_1 = sqrt(h^2 / n) = h / sqrt(n)
    //
    // The k-th cut (from the apex) encloses k pieces.
    // So, the area of the triangle from the apex to the k-th cut must be k * (h / (2n)).
    // x_k^2 / (2h) = k * (h / (2n))
    // x_k^2 = k * h^2 / n
    // x_k = sqrt(k * h^2 / n) = h * sqrt(k / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int k = 1; k < n; ++k) {
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we'll use for the alternating part

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    // Example: k=3, right=4. Sequence: 1, 4, 2, 3
    // Diffs: |1-4|=3, |4-2|=2, |2-3|=1. Distinct diffs: {1,2,3}
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...)
            std::cout << left++;
        } else { // Odd index (1, 3, 5, ...)
            std::cout << right--;
        }
        if (i < n - 1) {
            std::cout << " ";
        }
    }

    // For the remaining n - (k+1) elements, just append them in increasing order.
    // This will only introduce a difference of 1, which is already present.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << " " << i;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += c;
                open_count++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && open_count > close_count) {
                result += c;
                close_count++;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of multiples of m up to n

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute the sum of last digits for one cycle (10 multiples)
        // The last digit of i*m is (i*m) % 10.
        // The sequence of last digits (m%10, 2m%10, ..., 10m%10) repeats.
        // We need to sum these 10 values.
        long long sum_of_first_10_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_10_last_digits += (static_cast<long long>(i) * m) % 10;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * sum_of_first_10_last_digits;

        // Calculate the sum for the remaining multiples
        long long remaining_multiples = k % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

