            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // Or d = 0, which is handled above.
        if (d < 4) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

