#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // starting from a_1, given that a_i must be at least i-1.
    // This means a_i >= i-1 for i=1, ..., k.
    // We can achieve this if a_i_original >= i-1.
    int prefix_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            prefix_len++;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // ending at a_n, given that a_i must be at least n-i.
    // This means a_i >= n-i for i=k, ..., n.
    // We can achieve this if a_i_original >= n-i.
    int suffix_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) { // a[i] >= distance from end (0-indexed)
            suffix_len++;
        } else {
            break;
        }
    }

    // If the sum of the maximum possible prefix length and suffix length
    // is greater than n, it means there's an overlap, and thus a 'k'
    // can be found where the conditions are met.
    // The condition prefix_len + suffix_len > n implies that there is at least
    // one index 'k' that is covered by both the potential increasing prefix
    // and the potential decreasing suffix.
    // For example, if prefix_len = 3 and suffix_len = 3 for n=4:
    // prefix covers indices 0, 1, 2.
    // suffix covers indices 1, 2, 3.
    // Overlap at indices 1, 2. So k can be 1 or 2.
    if (prefix_len + suffix_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

