// Function to check if a sub-array is a permutation of its length
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len <= 0) {
        return false; // A permutation must have positive length
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix permutation validity
    std::vector<bool> is_prefix_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_prefix(n + 1, false); // Max possible value is n, but current length is i+1
        int max_val_prefix = 0;
        bool possible_prefix = true;
        for (int i = 0; i < n; ++i) {
            int current_len = i + 1;
            int val = a[i];
            if (val < 1 || val > current_len || seen_prefix[val]) {
                possible_prefix = false;
            }
            if (possible_prefix) {
                seen_prefix[val] = true;
                if (val > max_val_prefix) {
                    max_val_prefix = val;
                }
                if (max_val_prefix == current_len) {
                    is_prefix_perm[current_len] = true;
                }
            }
        }
    }

    // Precompute suffix permutation validity
    std::vector<bool> is_suffix_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_suffix(n + 1, false); // Max possible value is n, but current length is n-i
        int max_val_suffix = 0;
        bool possible_suffix = true;
        for (int i = n - 1; i >= 0; --i) {
            int current_len = n - i;
            int val = a[i];
            if (val < 1 || val > current_len || seen_suffix[val]) {
                possible_suffix = false;
            }
            if (possible_suffix) {
                seen_suffix[val] = true;
                if (val > max_val_suffix) {
                    max_val_suffix = val;
                }
                if (max_val_suffix == current_len) {
                    is_suffix_perm[current_len] = true;
                }
            }
        }
    }

    // Check all possible split points l1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

