void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Condition: current_sum = 2 * current_xor_sum
    // If already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
        return;
    }

    // We need to append at most 3 elements.
    // Let's try to append 2 elements.
    // Let the two elements be x and y.
    // New sum: S' = current_sum + x + y
    // New XOR sum: X' = current_xor_sum ^ x ^ y
    // We want S' = 2 * X'
    // current_sum + x + y = 2 * (current_xor_sum ^ x ^ y)

    // A simple strategy:
    // Append current_xor_sum.
    // New sum: S_1 = current_sum + current_xor_sum
    // New XOR sum: X_1 = current_xor_sum ^ current_xor_sum = 0
    // Now we need S_1 = 2 * X_1, which means S_1 = 0.
    // This is generally not true, as current_sum is positive.

    // Let's try to append two elements: current_xor_sum and current_sum + current_xor_sum.
    // This is the strategy derived from the problem analysis.
    // Let X = current_xor_sum
    // Let S = current_sum
    // We want to find b1, b2 such that S + b1 + b2 = 2 * (X ^ b1 ^ b2)
    // Consider b1 = X.
    // Then S + X + b2 = 2 * (X ^ X ^ b2) = 2 * (0 ^ b2) = 2 * b2
    // S + X = b2
    // So, b2 = S + X.
    // The two elements to append are X and S + X.

    // Let's verify this:
    // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum
    // New sum: S_new = current_sum + b1 + b2
    // S_new = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S_new = 2 * current_sum + 2 * current_xor_sum

    // New XOR sum: X_new = current_xor_sum ^ b1 ^ b2
    // X_new = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X_new = 0 ^ (current_sum + current_xor_sum)
    // X_new = current_sum + current_xor_sum

    // Check condition: S_new = 2 * X_new
    // (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This is always true.

    // So, we can always append 2 elements: current_xor_sum and current_sum + current_xor_sum.
    // These elements are non-negative since all initial elements are non-negative.
    // The maximum value for current_sum can be 10^5 * 10^9 = 10^14.
    // The maximum value for current_xor_sum can be around 2^30 (since a_i <= 10^9).
    // So current_sum + current_xor_sum can be up to 10^14 + 2^30, which fits in long long.

    std::cout << 2 << "\n";
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
}

