// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 digits long
    // The pattern is built from right to left, so we need to reverse it
    // and then pad. Or, more simply, just pad at the end.
    // Example: 241 -> "100" (right to left)
    // Padded to 18: "000000000000000100"
    // The problem states "i-th from the right digit", so the string should represent this.
    // If we build "100" for 241, then 1 is at index 0, 0 at index 1, 0 at index 2.
    // This means pattern[0] is the rightmost digit's parity.
    // So we need to pad with '0's at the end of this string to make it 18 chars.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's to 18 digits
            while (s.length() < 18) {
                s = '0' + s; // Pad from the left
            }
            // The problem states "i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
            // If pattern is "010", it means rightmost is 0, second from right is 1, third from right is 0.
            // Our get_parity_pattern generates "100" for 241, where '1' is rightmost.
            // So, for a query pattern "010", we need to reverse it to "010" (still "010") and then pad.
            // Let's re-evaluate the pattern string generation.
            // If s = "010", it means rightmost digit is even, second is odd, third is even.
            // For 241: 1 (odd), 4 (even), 2 (even).
            // Rightmost of 241 is 1 (odd). Rightmost of "010" is 0 (even). No match.
            // This implies the pattern string should be read from left to right for matching.
            // Let's re-read: "i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
            // This means if pattern is "010", then pattern[2] is the rightmost, pattern[1] is second, pattern[0] is third.
            // So, for a query pattern "010", we should reverse it to "010" and then pad.
            // Example: s = "010"
            // Reversed s_rev = "010"
            // Padded s_rev_padded = "000000000000000010"
            // This is the format our map keys are in.
            // So, for query pattern 's', we need to reverse it and then pad with '0's at the end to make it 18 chars.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
