#include <numeric> // For std::accumulate with bitwise OR

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Using a 2D vector to store the matrix b
    // The problem states b_ij = -1 for i=j, but we only care about i!=j
    // We can store the actual values or just read them and process
    std::vector<std::vector<int>> b(n, std::vector<int>(n));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> b[i][j];
        }
    }

    // Vector to store the restored sequence a
    std::vector<int> a(n);

    // For each a_i, we can reconstruct it by taking the bitwise OR
    // of all b_ij where j != i.
    // This works because a_i & a_j will only have a bit set if that bit
    // is set in both a_i and a_j.
    // If a bit is set in a_i, then for any j != i, a_i & a_j will either
    // have that bit set (if a_j also has it) or not (if a_j doesn't).
    // Taking the OR of all (a_i & a_j) for j != i will ensure that if a bit
    // is set in a_i, it will be present in at least one (a_i & a_j) (unless
    // all other a_j have that bit as 0, which is impossible if a_i has it set
    // and a_i is the OR of all a_i & a_j).
    // More formally, a_i = (a_i & a_1) | (a_i & a_2) | ... | (a_i & a_n) for j != i
    // This is because if a bit k is set in a_i, then a_i has 2^k.
    // Then for any j != i, (a_i & a_j) will have 2^k if a_j has 2^k, or 0 otherwise.
    // The OR of all these terms will have 2^k if at least one a_j (j!=i) has 2^k.
    // However, the problem guarantees a solution exists.
    // The key property is that a_i = OR_{j!=i} (a_i & a_j).
    // This is because if a bit is set in a_i, it must be set in a_i & a_j for *some* j.
    // If it were not set in any a_i & a_j for j != i, it would mean that for every j != i,
    // a_j does not have that bit set. But then a_i would be the only number with that bit set,
    // and a_i & a_j would be 0 for that bit for all j != i.
    // This implies a_i = 0 for that bit, which contradicts our assumption.
    // The only way this could fail is if n=1, but the problem handles n=1 with a_1=0.
    // For n > 1, if a bit is set in a_i, it must be set in at least one a_j (j!=i)
    // for the OR to reconstruct a_i. This is a property of the bitwise AND operation
    // in the context of a set of numbers.
    // The simplest way to think about it is that a_i is the "superset" of all a_i & a_j.
    // So, a_i must be equal to the bitwise OR of all a_i & a_j for j != i.

    for (int i = 0; i < n; ++i) {
        int current_or = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) {
                continue; // Skip b_ii which is -1
            }
            current_or |= b[i][j];
        }
        a[i] = current_or;
    }

    // Print the restored sequence
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

