// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the largest divisor of p
            // and it satisfies the condition x % q != 0.
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, then p is not a valid x.
        // We need to find the largest divisor of p that is not divisible by q.
        // This means we need to remove some prime factors from p such that
        // the resulting number is no longer divisible by q.

        // Get prime factors of q.
        // We only care about the distinct prime factors of q.
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        // For each distinct prime factor 'f' of q:
        // We want to find the largest divisor of p that is not divisible by q.
        // Consider removing 'f' from p until p is no longer divisible by q.
        // Specifically, we want to find the largest divisor of p, say x_f,
        // such that x_f is not divisible by q.
        // To do this, we can take p, and divide it by 'f' repeatedly until
        // the resulting number is no longer divisible by q.
        // The largest such x will be the maximum over all choices of 'f'.
        for (long long f : q_prime_factors) {
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= f;
            }
            // current_p is now a divisor of p that is not divisible by q.
            // It's formed by removing all factors of 'f' from p until p is no longer divisible by q.
            // This current_p is a candidate for max_x.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        int min_x = -100000;
        int max_x = 100000;
        int min_y = -100000;
        int max_y = 100000;

        for (int i = 0; i < n; ++i) {
            int x, y, f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1, y)
            // If f1 is 0, robot cannot move left.
            // This means it cannot reach any point with x < its current x.
            // So, the target X must be >= its current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2: can move up (x, y+1)
            // If f2 is 0, robot cannot move up.
            // This means it cannot reach any point with y > its current y.
            // So, the target Y must be <= its current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3: can move right (x+1, y)
            // If f3 is 0, robot cannot move right.
            // This means it cannot reach any point with x > its current x.
            // So, the target X must be <= its current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (x, y-1)
            // If f4 is 0, robot cannot move down.
            // This means it cannot reach any point with y < its current y.
            // So, the target Y must be >= its current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::max, std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k is less than the minimum moves required (max(abs_n, abs_m))
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k has the same parity as abs_n and abs_m
        // This means (k - abs_n) is even, and (k - abs_m) is even.
        // Also, (abs_n - abs_m) is even.
        if ((k % 2 == abs_n % 2) && (abs_n % 2 == abs_m % 2)) {
            std::cout << k << "\n";
        }
        // Case 3: k has different parity than abs_n and abs_m
        // This means (k - abs_n) is odd, and (k - abs_m) is odd.
        // Also, (abs_n - abs_m) is even.
        // We need to make two extra moves to change parity.
        // E.g., (0,0) -> (1,0) -> (0,0) costs 2 moves, changes parity of k by 2.
        // Or (0,0) -> (1,1) -> (0,0) costs 2 moves, changes parity of k by 2.
        // So, if k is odd and abs_n, abs_m are even, or vice versa, we need to use k-2 moves.
        else if ((k % 2 != abs_n % 2) && (abs_n % 2 == abs_m % 2)) {
            std::cout << k - 2 << "\n";
        }
        // Case 4: abs_n and abs_m have different parities.
        // This means (abs_n - abs_m) is odd.
        // In this case, k must also be odd to reach (abs_n, abs_m).
        // If k is even, it's impossible.
        else if (abs_n % 2 != abs_m % 2) {
            if (k % 2 == 0) { // k is even, but target has odd difference in coords
                std::cout << -1 << "\n";
            } else { // k is odd, target has odd difference in coords
                std::cout << k << "\n";
            }
        }
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (char split_char = '0'; split_char <= '9'; ++split_char) {
        std::string current_s1_str;
        std::string current_s2_str;
        std::string current_result(n, ' ');
        bool current_valid = true;

        char last_s1_digit = '0';
        char last_s2_digit = '0';
        bool switched_to_2_for_split_char = false;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < split_char) {
                // Must be color 1
                if (digit < last_s1_digit) {
                    current_valid = false;
                    break;
                }
                current_result[i] = '1';
                last_s1_digit = digit;
            } else if (digit > split_char) {
                // Must be color 2
                if (digit < last_s2_digit) {
                    current_valid = false;
                    break;
                }
                current_result[i] = '2';
                last_s2_digit = digit;
                switched_to_2_for_split_char = true; // If we see a digit > split_char, it's like we've passed the split_char boundary
            } else { // digit == split_char
                if (!switched_to_2_for_split_char) {
                    // Try to color 1
                    if (digit < last_s1_digit) {
                        // Cannot color 1, must color 2
                        if (digit < last_s2_digit) {
                            current_valid = false;
                            break;
                        }
                        current_result[i] = '2';
                        last_s2_digit = digit;
                        switched_to_2_for_split_char = true;
                    } else {
                        // Can color 1
                        current_result[i] = '1';
                        last_s1_digit = digit;
                    }
                } else {
                    // Already switched to 2 for split_char, or saw a digit > split_char
                    // Must color 2
                    if (digit < last_s2_digit) {
                        current_valid = false;
                        break;
                    }
                    current_result[i] = '2';
                    last_s2_digit = digit;
                }
            }
        }

        if (current_valid) {
            // Check the final condition: last_s1_digit <= first_s2_digit
            // This is implicitly handled by the logic for split_char digits.
            // If a digit 'X' is colored '1', last_s1_digit becomes 'X'.
            // If a digit 'X' is colored '2', last_s2_digit becomes 'X'.
            // The 'switched_to_2_for_split_char' ensures that once we start coloring 'X' as '2',
            // all subsequent 'X's are also '2'.
            // And any digit > 'X' is always '2'.
            // So, the sequence S1 is non-decreasing, S2 is non-decreasing.
            // The transition from S1 to S2 is handled by the split_char logic.
            // All digits in S1 are <= split_char. All digits in S2 are >= split_char.
            // So, last(S1) <= split_char <= first(S2) is guaranteed.

            result = current_result;
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

