    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // If N is even, Chanek wants to take N/2.
                // The only exception is if taking 1 sets up a better future for Chanek.
                // This happens when N/2 is even, and taking N/2 would leave an even number for the opponent,
                // allowing the opponent to take half.
                // If N/2 is odd, taking N/2 leaves an odd number for the opponent, forcing them to take 1.
                // So, if N is even:
                //   If N/2 is odd (e.g., N=6, N/2=3), Chanek takes N/2.
                //   If N/2 is even (e.g., N=4, N/2=2), Chanek takes 1. This leaves N-1 (odd) for opponent.
                //   This is the "optimal" strategy.
                // Let's re-check N=4:
                // Chanek takes 1. N=3. Chanek has 1.
                // Opponent takes 1. N=2. Opponent has 1.
                // Chanek takes 1. N=1. Chanek has 1+1=2.
                // Opponent takes 1. N=0. Opponent has 1+1=2.
                // Chanek gets 2.

                // Let's re-check N=4 with the simpler greedy strategy (always take N/2 if even):
                // Chanek takes 2. N=2. Chanek has 2.
                // Opponent takes 1. N=1. Opponent has 1.
                // Chanek takes 1. N=0. Chanek has 2+1=3.
                // Chanek gets 3.
                // So, for N=4, taking N/2 is better than taking 1.
                // This means the "optimal" strategy I derived above (take 1 if N/2 is even) is incorrect.
                // The simpler greedy strategy (always take N/2 if even) seems to be correct.

                // The only case where taking 1 is better than taking N/2 is if N/2 is very small,
                // and taking 1 allows Chanek to get a larger share later.
                // But N/2 is always >= 1 for N >= 2.
                // The problem states "Both players will try to maximize the number of coins they have."
                // This implies a minimax approach.

                // Let's consider the game state (N, current_player).
                // If N is odd: current_player takes 1. Next state (N-1, other_player).
                // If N is even: current_player chooses between (N-1, other_player) and (N/2, other_player).
                // The current player chooses the move that maximizes their final score.

                // Let f(N) be the maximum coins Chanek can get if N coins are remaining and it's Chanek's turn.
                // Let g(N) be the maximum coins Chanek can get if N coins are remaining and it's Opponent's turn.
                // Total coins = N_initial.
                // Chanek's score + Opponent's score = N_initial.
                // Maximize Chanek's score is equivalent to minimize Opponent's score.

                // If N is odd:
                //   Chanek's turn: Chanek takes 1. Chanek gets 1 + g(N-1).
                //   Opponent's turn: Opponent takes 1. Chanek gets f(N-1). (Opponent gets 1 + (N_initial - f(N-1)))

                // If N is even:
                //   Chanek's turn:
                //     Option 1: Take 1. Chanek gets 1 + g(N-1).
                //     Option 2: Take N/2. Chanek gets N/2 + g(N/2).
                //     Chanek chooses max(1 + g(N-1), N/2 + g(N/2)).
                //   Opponent's turn:
                //     Option 1: Opponent takes 1. Chanek gets f(N-1).
                //     Option 2: Opponent takes N/2. Chanek gets f(N/2).
                //     Opponent chooses to minimize Chanek's score, so Chanek gets min(f(N-1), f(N/2)).

                // This is a DP approach. N can be up to 10^18, so DP table is not feasible.
                // This suggests a pattern or a simpler greedy strategy.

                // Let's re-examine the greedy strategy:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This is the strategy implemented in the code.
                // Let's trace N=10 again with this strategy:
                // Chanek: N=10 (even). Takes 5. N=5. Chanek has 5.
                // Opponent: N=5 (odd). Takes 1. N=4. Opponent has 1.
                // Chanek: N=4 (even). Takes 2. N=2. Chanek has 5+2=7.
                // Opponent: N=2 (even). Takes 1. N=1. Opponent has 1+1=2.
                // Chanek: N=1 (odd). Takes 1. N=0. Chanek has 7+1=8.
                // Final: Chanek 8, Opponent 2.

                // What if Chanek took 1 when N=10?
                // Chanek: N=10 (even). Takes 1. N=9. Chanek has 1.
                // Opponent: N=9 (odd). Takes 1. N=8. Opponent has 1.
                // Chanek: N=8 (even). Takes 4. N=4. Chanek has 1+4=5.
                // Opponent: N=4 (even). Takes 2. N=2. Opponent has 1+2=3.
                // Chanek: N=2 (even). Takes 1. N=1. Chanek has 5+1=6.
                // Opponent: N=1 (odd). Takes 1. N=0. Opponent has 3+1=4.
                // Final: Chanek 6, Opponent 4.
                // In this case, taking N/2 (5 coins) was better than taking 1 coin (6 coins).
                // So the simple greedy strategy (take N/2 if even) seems to be correct.

                // The only remaining question is the N=2 case.
                // If N=2, N/2=1. So taking N/2 is equivalent to taking 1.
                // The code implements:
                // if (n % 2 != 0) { chanek_coins += 1; n -= 1; }
                // else { chanek_coins += n / 2; n /= 2; }
                // This is the simple greedy strategy.

                // Let's consider the case where N/2 is even.
                // N = 4k.
                // Chanek's turn, N=4k.
                // Option 1: Take 1. N becomes 4k-1 (odd). Chanek gets 1.
                //   Opponent takes 1. N becomes 4k-2 (even). Opponent gets 1.
                //   Chanek's turn, N=4k-2.
                // Option 2: Take N/2 = 2k. N becomes 2k (even). Chanek gets 2k.
                //   Opponent's turn, N=2k.
                //   Opponent takes N/4 = k. N becomes k. Opponent gets k.
                //   Chanek's turn, N=k.

                // This is a known game theory problem. The optimal strategy for the current player is:
                // If N is odd, take 1.
                // If N is even:
                //   If N/2 is odd, take N/2. (e.g., N=6, N/2=3. Take 3. Leaves 3 for opponent. Opponent takes 1. Leaves 2 for Chanek.)
                //   If N/2 is even, take 1. (e.g., N=4, N/2=2. Take 1. Leaves 3 for opponent. Opponent takes 1. Leaves 2 for Chanek.)
                // This is the strategy that was initially derived and then discarded.
                // Let's re-trace N=4 with this strategy:
                // Chanek: N=4 (even). N/2=2 (even). So Chanek takes 1. N=3. Chanek has 1.
                // Opponent: N=3 (odd). Opponent takes 1. N=2. Opponent has 1.
                // Chanek: N=2 (even). N/2=1 (odd). So Chanek takes N/2=1. N=1. Chanek has 1+1=2.
                // Opponent: N=1 (odd). Opponent takes 1. N=0. Opponent has 1+1=2.
                // Chanek gets 2.
                // This is worse than the simple greedy strategy (Chanek gets 3).
                // So the "take 1 if N/2 is even" rule is incorrect.

                // The simple greedy strategy (take N/2 if even, 1 if odd) is indeed the correct one.
                // The reasoning is that taking N/2 is always better or equal to taking 1 in terms of immediate gain.
                // And it reduces N faster, which is generally good.
                // The only time it might not be optimal is if it leaves a state where the opponent can gain significantly more.
                // But since the opponent also plays optimally, they will also take N/2 if N is even.
                // This means both players are trying to grab as much as possible.
                // This is a "take the biggest chunk" game.

                // Final check on the logic:
                // If N is odd, current player must take 1.
                // If N is even, current player can take 1 or N/2.
                //   Taking N/2 is always >= 1.
                //   If current player takes N/2, they get N/2 coins. Remaining N/2.
                //   If current player takes 1, they get 1 coin. Remaining N-1.
                //   The game is about maximizing own coins.
                //   Consider the total coins taken by Chanek.
                //   This is not a game where you want to leave a specific state for the opponent.
                //   It's a game where you want to maximize your own sum.
                //   The greedy choice of taking N/2 when N is even is optimal.
                //   This is because it gives the current player the largest possible immediate gain,
                //   and the opponent will also play greedily.
                //   The only exception is N=2, where N/2=1, so taking 1 is the only option.
                //   The code handles this implicitly.

                chanek_coins += n / 2;
                n /= 2;
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                n /= 2; // Opponent takes N/2
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

