    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_k = sum_{k=1 to a} k
    // sum_k = a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = (sum_k * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b - 1) * b / 2
    long long sum_r_val = b - 1;
    if (sum_r_val < 0) sum_r_val = 0; // Handle b=1 case where b-1 is 0
    long long sum_r = (sum_r_val % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // The total sum is sum_{k=1 to a} ((k * b + 1) * sum_{r=1 to b-1} r)
    // This simplifies to (sum_{k=1 to a} (k * b + 1)) * (sum_{r=1 to b-1} r)
    // sum_{k=1 to a} (k * b + 1) = b * (sum_{k=1 to a} k) + (sum_{k=1 to a} 1)
    // = b * sum_k + a

    long long term_k_b_plus_1 = (b % MOD * sum_k) % MOD;
    term_k_b_plus_1 = (term_k_b_plus_1 + (a % MOD)) % MOD;

    long long total_sum = (term_k_b_plus_1 * sum_r) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start = std::max(0, i);
        int block_end = std::min(n, i + k);

        for (int j = block_end - 1; j >= block_start; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c1 = s[k_actual]; // t[0] = s[k_actual]

        // Possible k values given c1
        const std::vector<int>& possible_k_indices = char_indices[c1 - 'a'];

        if (possible_k_indices.size() == 1) {
            // If only one k matches c1, Vasya wins immediately.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose p to maximize win probability for this c1.
        // Iterate over all possible p values (1 to L-1)
        double max_win_prob_for_c1 = 0.0;

        for (int p = 1; p < L; ++p) {
            // For a fixed p, count how many k's from possible_k_indices lead to a win.
            // A win means (s[k], s[(k+p)%L]) is unique among all possible_k_indices.

            // Map to store counts of (s[k], s[(k+p)%L]) pairs
            std::map<std::pair<char, char>, int> pair_counts;

            for (int k_cand : possible_k_indices) {
                char c2 = s[(k_cand + p) % L]; // t[p] = s[(k_cand + p) % L]
                pair_counts[{c1, c2}]++;
            }

            int wins_for_this_p = 0;
            for (const auto& entry : pair_counts) {
                if (entry.second == 1) {
                    wins_for_this_p++;
                }
            }

            max_win_prob_for_c1 = std::max(max_win_prob_for_c1, (double)wins_for_this_p / possible_k_indices.size());
        }
        total_win_prob += max_win_prob_for_c1;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
