void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited;
    char start_node = '\0';

    // Find a starting node for a path (degree 1) or a cycle (any node if all degree 2)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            start_node = c;
            break;
        }
    }

    // If no degree 1 node found, check for a cycle or isolated nodes
    if (start_node == '\0') {
        // Try to find any node that is part of the password string
        for (char c = 'a'; c <= 'z'; ++c) {
            if (adj.count(c)) {
                start_node = c;
                break;
            }
        }
    }

    // If start_node is still null, it means the password string was empty or only 1 char,
    // which means no adjacencies were required. Any layout is fine.
    // But problem constraints say 1 <= |s|, so this case won't happen for adj.count(c)
    // unless s has length 1. If s has length 1, adj is empty.
    // If s has length 1, start_node will be '\0'.
    // In this case, we can just print a-z.
    if (s.length() == 1) {
        std::cout << "YES\n";
        std::cout << "abcdefghijklmnopqrstuvwxyz\n";
        return;
    }


    // Traverse the graph to build the main part of the layout
    if (start_node != '\0') {
        char current = start_node;
        char prev = '\0'; // Sentinel for the previous node

        while (visited.find(current) == visited.end()) {
            layout_str += current;
            visited.insert(current);

            char next_node = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_node = neighbor;
                    break;
                }
            }

            if (next_node == '\0') { // End of path or cycle completed
                if (adj[current].size() == 2 && prev != '\0') { // If it's a cycle and we've returned to start_node's other neighbor
                    // This means we've traversed a cycle.
                    // The current node should have two neighbors, one is prev, the other is the one we started with.
                    // If we are at the end of a path, current should have degree 1.
                    // If we are at the end of a cycle, current should have degree 2, and both neighbors are visited.
                    // This check is for the case where we started in a cycle.
                    // If start_node was degree 2, and we traversed it, and now current has no unvisited neighbors,
                    // it means we completed a cycle.
                    // We need to check if all nodes in the cycle are visited.
                    // If start_node was degree 1, this means we reached the other end of the path.
                }
                break;
            }
            prev = current;
            current = next_node;
        }

        // Check if we formed a cycle and tried to add a character already in layout_str
        if (visited.find(current) != visited.end() && current == start_node && adj[start_node].size() == 2) {
            // This means we started at a degree 2 node and completed a cycle.
            // The layout_str already contains the cycle.
            // We need to ensure that all nodes in the cycle are indeed part of the layout_str.
            // And that no other nodes in adj are left unvisited.
            // If start_node was degree 2, and we traversed it, and current is start_node again,
            // it means we completed a cycle.
            // The problem is that if we start at a degree 2 node, we might pick one neighbor,
            // traverse the cycle, and then current becomes start_node again.
            // The loop condition `visited.find(current) == visited.end()` will then fail.
            // This is fine, the loop correctly stops.
        } else if (visited.find(current) != visited.end() && current != start_node) {
            // This means we found a cycle but didn't start at a degree 1 node.
            // This implies an invalid graph structure (e.g., a node with degree > 2, which was already checked).
            // Or a graph with multiple components where one is a cycle and we started in it.
            // Or a graph with a path that leads into a cycle.
            // This should not happen if the graph is a simple path or cycle.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unvisited characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout_str += c;
        }
    }

    // Final check: ensure all required adjacencies are met
    // This is implicitly handled by the graph construction and traversal.
    // If layout_str has 26 unique characters, and all adjacencies are degree <= 2,
    // then it must be a valid path or cycle.
    // The only remaining check is if the graph was disconnected and had multiple paths/cycles.
    // If there are multiple components that are paths/cycles, and they are not connected,
    // then we cannot form a single linear layout.
    // This would manifest as `adj` having multiple components.
    // Our traversal only builds one component. If `adj` has more than one component,
    // then `layout_str` will not contain all characters from `adj` after the first traversal.
    // And then we would append the rest of the alphabet.
    // This would mean that characters that *must* be adjacent are not.
    // Example: s="ab", s2="cd". Layout "abcd..." is not valid because 'b' and 'c' are not adjacent.
    // The current logic will build "ab", then append "cdef...". This is wrong.
    // We need to ensure that all characters that are part of `adj` are in the `layout_str`
    // and form a single connected component.

    // Check if all characters involved in adjacencies are part of the generated path/cycle
    std::set<char> adj_chars;
    for(const auto& pair : adj) {
        adj_chars.insert(pair.first);
    }

    if (layout_str.length() < 26) { // Should not happen if we append all remaining chars
        std::cout << "NO\n"; // This indicates an internal logic error or unexpected state
        return;
    }

    // Verify the generated layout
    std::map<char, int> char_pos;
    for (int i = 0; i < layout_str.length(); ++i) {
        char_pos[layout_str[i]] = i;
    }

    for (const auto& pair : adj) {
        char u = pair.first;
        for (char v : pair.second) {
            if (std::abs(char_pos[u] - char_pos[v]) != 1) {
                std::cout << "NO\n";
                return;
            }
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

