    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[i] = (count of 1s) - (count of 2s) for jars 1 to i
    // (0-indexed: a[0] to a[i-1])
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // diff_R[i] = (count of 1s) - (count of 2s) for jars 2n-i+1 to 2n
    // (0-indexed: a[2n-i] to a[2n-1])
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left
    // to achieve a certain difference.
    // key: diff_L[k_L] (difference after removing k_L jars from left)
    // value: k_L (number of jars removed)
    std::map<int, int> left_diff_to_removed_count;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff = diff_L[n] - diff_L[k_L]; // diff of remaining left jars
        if (left_diff_to_removed_count.find(current_diff) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[current_diff] = k_L;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removals

    // Iterate through possible removals from the right side
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_diff_R = diff_R[n] - diff_R[k_R]; // diff of remaining right jars
        int target_diff_L = -current_diff_R; // We need total_diff = 0, so diff_L + diff_R = 0

        if (left_diff_to_removed_count.count(target_diff_L)) {
            int k_L = left_diff_to_removed_count[target_diff_L];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we track how an input bit 'b' (0 or 1)
    // is transformed.
    // state[bit_pos][0] = result if input bit is 0
    // state[bit_pos][1] = result if input bit is 1
    // Initially, for an input 'x', the j-th bit is x_j.
    // So, if input bit is 0, output is 0. If input bit is 1, output is 1.
    std::vector<std::vector<int>> state(10, std::vector<int>(2));
    for (int i = 0; i < 10; ++i) {
        state[i][0] = 0; // If input bit is 0, current bit is 0
        state[i][1] = 1; // If input bit is 1, current bit is 1
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // i-th bit of the constant 'val'
            if (op_char == '&') {
                state[i][0] &= bit_val;
                state[i][1] &= bit_val;
            } else if (op_char == '|') {
                state[i][0] |= bit_val;
                state[i][1] |= bit_val;
            } else if (op_char == '^') {
                state[i][0] ^= bit_val;
                state[i][1] ^= bit_val;
            }
        }
    }

    // Now, 'state[i][0]' and 'state[i][1]' represent the final transformation
    // for the i-th bit.
    // We need to find a minimal sequence of operations to achieve this.
    // There are 4 possible transformations for each bit:
    // 1. (0,0) -> always 0
    // 2. (0,1) -> identity (input bit)
    // 3. (1,0) -> negation (1 - input bit)
    // 4. (1,1) -> always 1

    // We can represent these 4 transformations using 3 operations:
    // AND with A, OR with B, XOR with C.
    // Let's find A, B, C such that for any input bit 'b':
    // ((b & A_i) | B_i) ^ C_i == state[i][b]

    int final_and_val = 1023; // All bits 1
    int final_or_val = 0;     // All bits 0
    int final_xor_val = 0;    // All bits 0

    for (int i = 0; i < 10; ++i) {
        int s0 = state[i][0];
        int s1 = state[i][1];

        if (s0 == 0 && s1 == 0) { // Always 0
            // To make bit 'i' always 0:
            // (b & 0) | 0 ^ 0 = 0
            // (b & 0) | 1 ^ 1 = 0
            // (b & 1) | 0 ^ 1 = 0
            // (b & 1) | 1 ^ 0 = 0
            // Simplest: AND with 0, OR with 0, XOR with 0.
            // This means final_and_val's i-th bit must be 0.
            final_and_val &= ~(1 << i);
            // final_or_val's i-th bit can be 0 or 1.
            // final_xor_val's i-th bit can be 0 or 1.
            // Let's try to keep final_or_val and final_xor_val 0 if possible.
            // If final_and_val's i-th bit is 0, then (b & 0) is 0.
            // So we need (0 | B_i) ^ C_i = 0.
            // If B_i=0, C_i=0. If B_i=1, C_i=1.
            // We prefer B_i=0, C_i=0.
        } else if (s0 == 0 && s1 == 1) { // Identity (b)
            // To make bit 'i' identity:
            // (b & 1) | 0 ^ 0 = b
            // This means final_and_val's i-th bit must be 1.
            // final_or_val's i-th bit must be 0.
            // final_xor_val's i-th bit must be 0.
            final_and_val |= (1 << i);
            final_or_val &= ~(1 << i);
            final_xor_val &= ~(1 << i);
        } else if (s0 == 1 && s1 == 0) { // Negation (1-b)
            // To make bit 'i' negation:
            // (b & 1) | 0 ^ 1 = 1-b
            // This means final_and_val's i-th bit must be 1.
            // final_or_val's i-th bit must be 0.
            // final_xor_val's i-th bit must be 1.
            final_and_val |= (1 << i);
            final_or_val &= ~(1 << i);
            final_xor_val |= (1 << i);
        } else if (s0 == 1 && s1 == 1) { // Always 1
            // To make bit 'i' always 1:
            // (b & 0) | 1 ^ 0 = 1
            // (b & 1) | 1 ^ 0 = 1
            // Simplest: OR with 1, AND with 1, XOR with 0.
            // This means final_or_val's i-th bit must be 1.
            final_or_val |= (1 << i);
            // final_and_val's i-th bit can be 0 or 1.
            // final_xor_val's i-th bit can be 0 or 1.
            // If final_or_val's i-th bit is 1, then (X | 1) is 1.
            // So we need (1 ^ C_i) = 1. This means C_i=0.
            final_xor_val &= ~(1 << i);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_val != 1023) { // If any bit of AND constant is 0
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If any bit of OR constant is 1
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) { // If any bit of XOR constant is 1
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long m;
    std::cin >> n >> m;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1; // Maximum possible operations is m-1

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        bool possible = true;
        long long prev_val = 0; // The minimum possible value for a[i] after transformation

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];
            long long target_a;

            // Case 1: a[i] + mid >= prev_val
            // This means a[i] can be transformed to a value >= prev_val without wrapping around m.
            // The smallest such value is max(prev_val, current_a).
            // If current_a is already >= prev_val, we can keep it as current_a.
            // If current_a < prev_val, we must increment it to at least prev_val.
            // The maximum value it can become is (current_a + mid) % m.
            // If current_a + mid >= prev_val, then it's possible to make a[i] >= prev_val.
            // We set target_a to max(prev_val, current_a).
            if (current_a + mid >= prev_val) {
                target_a = std::max(prev_val, current_a);
            }
            // Case 2: a[i] + mid < prev_val
            // This means even if we increment a[i] by 'mid' (the maximum allowed),
            // it's still less than prev_val, assuming no wrap-around.
            // For a[i] to become >= prev_val, it must wrap around m.
            // This means (current_a + x) % m >= prev_val, where x <= mid.
            // The smallest value it can take is current_a.
            // If current_a is already >= prev_val, then it's fine.
            // If current_a < prev_val, then we need to increment it.
            // The only way to make it >= prev_val is if (current_a + x) % m >= prev_val
            // AND current_a + x >= m.
            // This means current_a must be able to reach prev_val by wrapping around.
            // The values it can take are [current_a, (current_a + mid) % m] if current_a + mid < m
            // OR [current_a, m-1] U [0, (current_a + mid) % m] if current_a + mid >= m.
            // We need to check if prev_val falls into this range.
            // Specifically, if current_a + mid < prev_val, it means we cannot reach prev_val
            // without wrapping around.
            // If current_a + mid < m, and current_a + mid < prev_val, then it's impossible.
            // If current_a + mid >= m, then it wraps around.
            // The values it can take are [current_a, m-1] and [0, (current_a + mid) % m].
            // If prev_val is in [current_a, m-1], then we can achieve it.
            // If prev_val is in [0, (current_a + mid) % m], then we can achieve it.
            // The only case where it's impossible is if prev_val is in ((current_a + mid) % m, current_a).
            // This is equivalent to saying:
            // If current_a + mid < prev_val, then we must have current_a + mid >= m.
            // And we must be able to reach prev_val.
            // This means (current_a + x) % m >= prev_val.
            // The smallest value we can achieve that is >= prev_val is prev_val itself.
            // This requires (prev_val - current_a + m) % m operations.
            // If (prev_val - current_a + m) % m <= mid, then it's possible.
            // Otherwise, it's not.
            else { // current_a + mid < prev_val
                // This implies that current_a must be incremented to wrap around m.
                // The values it can take are [current_a, m-1] and [0, (current_a + mid) % m].
                // If prev_val is in [current_a, m-1], then we can achieve it.
                // If prev_val is in [0, (current_a + mid) % m], then we can achieve it.
                // If prev_val is in ((current_a + mid) % m, current_a), then it's impossible.
                // This is the case where current_a + mid < prev_val, and current_a < prev_val.
                // We need to check if prev_val is reachable.
                // The values reachable are [current_a, m-1] and [0, (current_a + mid) % m].
                // If prev_val is not in [0, (current_a + mid) % m] AND prev_val is not in [current_a, m-1],
                // then it's impossible.
                // This simplifies to: if current_a <= prev_val, then we need to reach prev_val.
                // The number of increments needed is (prev_val - current_a + m) % m.
                // If this is > mid, then it's impossible.
                // If current_a > prev_val, then we need to reach prev_val.
                // This means we must wrap around.
                // The values we can reach are [current_a, m-1] and [0, (current_a + mid) % m].
                // If prev_val is in [0, (current_a + mid) % m], then it's possible.
                // Otherwise, it's not.
                // This is equivalent to checking if (current_a + mid) % m >= prev_val.
                // If current_a + mid < prev_val, it means (current_a + mid) is not large enough to reach prev_val
                // without wrapping.
                // If current_a + mid >= m, then it wraps.
                // The values it can take are [current_a, m-1] and [0, (current_a + mid) % m].
                // If prev_val is in [0, (current_a + mid) % m], then it's possible.
                // Otherwise, it's not.
                // This is the condition: (current_a + mid) % m < prev_val.
                // If this is true, then it's impossible.
                possible = false;
                break;
            }
            prev_val = target_a;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] is set per query
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, 0);
    std::vector<int> dp_x(n + 1, 0);
    std::vector<bool> visited(n + 1, false);
    std::vector<bool> in_stack(n + 1, false);

    for (int i = 1; i <= n; ++i) {
        if (visited[i]) {
            continue;
        }

        std::vector<int> path;
        int current_x = i;

        while (current_x >= 1 && current_x <= n && !visited[current_x] && !in_stack[current_x]) {
            in_stack[current_x] = true;
            path.push_back(current_x);

            long long val = a[current_x];
            int next_x = current_x + val; // This is the x after step 2

            if (next_x <= 0 || next_x > n) { // Terminates after step 2
                dp_y[current_x] = val;
                dp_x[current_x] = next_x;
                break;
            }

            // If it doesn't terminate after step 2, it proceeds to step 3
            // The x for the next iteration of the loop is current_x - val
            current_x = current_x - val;
        }

        // Handle cycle or already visited node
        if (current_x >= 1 && current_x <= n && in_stack[current_x]) { // Cycle detected
            for (int node : path) {
                dp_y[node] = -1;
                dp_x[node] = -1;
            }
        } else { // Terminated or reached an already computed node
            long long prev_y = (current_x <= 0 || current_x > n) ? 0 : dp_y[current_x];
            int prev_x = (current_x <= 0 || current_x > n) ? current_x : dp_x[current_x];

            for (int j = path.size() - 1; j >= 0; --j) {
                int node = path[j];
                long long val = a[node];

                if (dp_y[node] != 0) { // This node was set as terminating after step 2
                    // dp_y[node] already contains 'val', prev_y is 0
                    // dp_x[node] already contains 'node + val', prev_x is 'node + val'
                    // No need to update prev_y, prev_x for the next iteration
                } else {
                    dp_y[node] = val + val + prev_y;
                    dp_x[node] = prev_x;
                }
                prev_y = dp_y[node];
                prev_x = dp_x[node];
            }
        }

        for (int node : path) {
            visited[node] = true;
            in_stack[node] = false;
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run

        long long current_y = 0;
        int current_x = 1;

        // First step 2
        long long val1 = a[current_x];
        current_x = current_x + val1;
        current_y = current_y + val1;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
        } else {
            // First step 3
            long long val2 = a[current_x];
            current_x = current_x - val2;
            current_y = current_y + val2;

            if (current_x <= 0 || current_x > n) {
                std::cout << current_y << "\n";
            } else {
                if (dp_y[current_x] == -1) {
                    std::cout << -1 << "\n";
                } else {
                    std::cout << current_y + dp_y[current_x] << "\n";
                }
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Step 1: Initialize a_prime array with a very small value
    // a_prime[j] represents the maximum possible initial value for a[j]
    // based on type 2 operations.
    std::vector<long long> a_prime(n, LLONG_MAX);

    // Step 2: Process operations in reverse to determine upper bounds for a_prime
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (add d), then to find the initial value,
            // we need to subtract d from the current value.
            // So, if a_prime[j] was an upper bound for a[j] *after* this operation,
            // then a_prime[j] - d is an upper bound for a[j] *before* this operation.
            // We propagate this upper bound backwards.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (a_prime[j] != LLONG_MAX) { // Only propagate if an upper bound was set
                    a_prime[j] -= ops[i].val;
                }
            }
        } else { // type 2 operation (max query)
            // For a type 2 operation (l, r, m), we know that max(a[l...r]) = m.
            // This implies that for all j in [l, r], a[j] <= m.
            // So, we update a_prime[j] = min(a_prime[j], m) for j in [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a_prime[j] = std::min(a_prime[j], ops[i].val);
            }
        }
    }

    // Step 3: Construct the candidate initial array 'a'
    // If a_prime[j] is still LLONG_MAX, it means no type 2 operation
    // constrained its initial value. We can set it to 0.
    // Otherwise, a_prime[j] is the tightest upper bound for initial_a[j].
    // To satisfy max(a[l...r]) = m, we need at least one element in the range
    // to be exactly m. To minimize changes and satisfy all conditions,
    // we set initial_a[j] = a_prime[j].
    // If a_prime[j] was LLONG_MAX, we set it to 0.
    std::vector<long long> initial_a(n);
    for (int j = 0; j < n; ++j) {
        if (a_prime[j] == LLONG_MAX) {
            initial_a[j] = 0;
        } else {
            initial_a[j] = a_prime[j];
        }
    }

    // Step 4: Verify the constructed initial array
    // Simulate all operations with the constructed initial_a
    // and check if all type 2 conditions are met.
    std::vector<long long> current_a = initial_a;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // type 2 operation
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array
    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_v_cry = children[i].v;
        long long total_d_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry effect
            children[j].p -= total_d_cry_effect;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1).
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-2].value + elements[n-1].value
    // goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: The smallest element elements[0] is in one subsequence (e.g., 1),
    // and all other elements are in the other subsequence (e.g., 2).
    //
    // Pairs within subsequence 1: None (if n=1, but n>=2) or just elements[0] if n=1.
    // Pairs within subsequence 2: (elements[1], elements[2]), ..., (elements[n-2], elements[n-1])
    //   min_same = elements[1].value + elements[2].value
    //   max_same = elements[n-2].value + elements[n-1].value
    // Pairs across subsequences: (elements[0], elements[1]), ..., (elements[0], elements[n-1])
    //   min_diff = elements[0].value + elements[1].value + h
    //   max_diff = elements[0].value + elements[n-1].value + h
    //
    // Overall min_f = min(min_same, min_diff)
    // Overall max_f = max(max_same, max_diff)
    //
    // This strategy is good when h is large, making cross-subsequence pairs very large.
    // By isolating the smallest element, we try to make min_diff as small as possible
    // while keeping max_diff from being too large.
    //
    // Let's calculate min_f and max_f for this partition.
    //
    // Values of f:
    // 1. For (elements[i], elements[j]) where i,j >= 1: elements[i].value + elements[j].value
    //    Min: elements[1].value + elements[2].value
    //    Max: elements[n-2].value + elements[n-1].value
    // 2. For (elements[0], elements[j]) where j >= 1: elements[0].value + elements[j].value + h
    //    Min: elements[0].value + elements[1].value + h
    //    Max: elements[0].value + elements[n-1].value + h

    long long min_f_case2;
    long long max_f_case2;

    if (n == 2) {
        // Only one pair (elements[0], elements[1]). They are in different subsequences.
        // f = elements[0].value + elements[1].value + h
        min_f_case2 = elements[0].value + elements[1].value + h;
        max_f_case2 = elements[0].value + elements[1].value + h;
    } else { // n > 2
        long long min_same_sub2 = elements[1].value + elements[2].value;
        long long max_same_sub2 = elements[n - 2].value + elements[n - 1].value;
        long long min_diff_sub2 = elements[0].value + elements[1].value + h;
        long long max_diff_sub2 = elements[0].value + elements[n - 1].value + h;

        min_f_case2 = std::min(min_same_sub2, min_diff_sub2);
        max_f_case2 = std::max(max_same_sub2, max_diff_sub2);
    }
    long long goodness2 = max_f_case2 - min_f_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

