// Function to calculate the parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate initial parity of string b
    int parity_b = calculate_parity(b);

    // If parity_a is 0, it means string 'a' has an even number of '1's.
    // We can append '0' to 'a' any number of times.
    // So, if parity_a is 0, the effective maximum number of '1's we can have
    // in a string derived from 'a' is the current count of '1's.
    // If parity_a is 1, it means string 'a' has an odd number of '1's.
    // We can append '1' to 'a', which makes the new string have an even number of '1's.
    // Then we can append '0's.
    // So, if parity_a is 1, we can effectively increase the count of '1's by one,
    // and then append '0's.

    // The maximum number of '1's we can achieve in a string derived from 'a'
    // (by appending parities) is `count_ones_a` if `parity_a` is 0,
    // and `count_ones_a + 1` if `parity_a` is 1.
    // This is because if we append a '1', the parity flips to 0, and subsequent appends are '0'.
    // If we append a '0', the parity remains the same.
    // So, the maximum number of '1's we can ever have in a string derived from 'a'
    // (before removing leading characters) is `count_ones_a` if `parity_a` is 0,
    // and `count_ones_a + 1` if `parity_a` is 1.

    // Let's count ones in original 'a'
    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
        }
    }

    // Calculate the maximum possible number of '1's in a string that can be formed
    // by appending parities to 'a'.
    // If 'a' has an even number of '1's, we can only append '0's, so max '1's is `ones_in_a`.
    // If 'a' has an odd number of '1's, we can append '1' (making it even), then '0's.
    // So max '1's is `ones_in_a + 1`.
    int max_ones_reachable_from_a = ones_in_a + parity_a;

    // Count ones in 'b'
    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // Condition 1: The number of '1's in 'b' must not exceed the maximum '1's
    // we can generate from 'a'.
    bool condition1 = (ones_in_b <= max_ones_reachable_from_a);

    // Condition 2: The length of 'b' must be less than or equal to the length of 'a'
    // plus the number of '1's we added (if any).
    // This is implicitly handled by the `max_ones_reachable_from_a` logic.
    // If `ones_in_b` is less than or equal to `max_ones_reachable_from_a`,
    // it means we can potentially form a string with at least `ones_in_b` ones.
    // The length of such a string would be at least `ones_in_b` (if all are '1's)
    // and at most `length_a + (max_ones_reachable_from_a - ones_in_a)` (if we append all possible '1's).
    // The key insight is that we can always make the string longer by appending '0's
    // once the parity becomes 0 (or if it was 0 initially).
    // So, if `ones_in_b <= max_ones_reachable_from_a`, we can always construct a string
    // with `ones_in_b` ones and length at least `|b|`.
    // We can always make the string long enough by appending '0's.
    // For example, if `a = "01011"` (ones=3, parity=1, max_ones=4) and `b = "0110"` (ones=2).
    // `ones_in_b` (2) <= `max_ones_reachable_from_a` (4). This is true.
    // We can make `a` longer: `01011` -> `010111` (parity 1 appended) -> `0101110` (parity 0 appended) -> ...
    // We can always make the string long enough to contain `b` as a suffix,
    // as long as the '1' count matches.

    if (condition1) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

