int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that (l, r) contains a bad triplet.
                                                // Initialized to n+1, meaning no bad triplet starts at or after l.

    // Iterate through all possible x and k to find bad triplets
    // s[x] = s[x+k] = s[x+2k]
    // x is 0-indexed
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k)
                // This triplet starts at index x and ends at index x+2k.
                // Any (l, r) pair such that l <= x and r >= x+2k will contain this triplet.
                // We are interested in the minimum r for a given l.
                // The smallest possible r for this triplet is x+2k.
                // The smallest possible l for this triplet is x.
                // So, for any l from 0 to x, this triplet is contained if r >= x+2k.
                // We want to update min_r_for_l[l] for l from 0 to x.
                // However, we only need to update min_r_for_l[x] because if l' < x,
                // then min_r_for_l[l'] will be at least as small as min_r_for_l[x].
                // The problem asks for l, r such that 1 <= l <= r <= n.
                // So, 0-indexed l_idx, r_idx means 0 <= l_idx <= r_idx < n.
                // The triplet is s[x_idx], s[x_idx+k], s[x_idx+2k].
                // This triplet is contained in [l_idx, r_idx] if l_idx <= x_idx and r_idx >= x_idx+2k.
                // The smallest r_idx that contains this triplet is x_idx+2k.
                // So, for any l_idx from 0 to x_idx, the minimum r_idx is x_idx+2k.
                // We can update min_r_for_l[l_idx] = min(min_r_for_l[l_idx], x_idx+2k).
                // This is equivalent to saying that for any l_idx <= x_idx, the minimum r_idx is at most x_idx+2k.
                // We can optimize this by only considering the smallest k for a given x.
                // The problem states "at least one pair of integers x, k".
                // So, if s[x] = s[x+k] = s[x+2k], then for any l_idx <= x, the minimum r_idx is at most x+2k.
                // We need to find the minimum r_idx for each l_idx.
                // The current triplet (x, k) implies that for any l_idx from 0 to x,
                // a valid r_idx is x+2k.
                // So, we update min_r_for_l[l_idx] = min(min_r_for_l[l_idx], x+2k).
                // This means we need to update a range.
                // A simpler approach is to find the minimum r_idx for each l_idx.
                // For a fixed l_idx, we need to find min(x_idx+2k) over all x_idx, k such that
                // l_idx <= x_idx and s[x_idx]=s[x_idx+k]=s[x_idx+2k].
                // This is equivalent to finding the smallest x_idx+2k for any triplet that starts at or after l_idx.

                // Let's re-evaluate. We want to find the smallest r_idx for each l_idx.
                // For a given l_idx, we need to find min(x_idx+2k) such that l_idx <= x_idx and s[x_idx]=s[x_idx+k]=s[x_idx+2k].
                // This is exactly what min_r_for_l[l_idx] should store.
                // So, for each triplet (x, k), we update min_r_for_l[x] = min(min_r_for_l[x], x+2k).
                // This is because x is the smallest l_idx for which this specific triplet is valid.
                min_r_for_l[x] = std::min(min_r_for_l[x], x + 2 * k);
            }
        }
    }

    // Now, min_r_for_l[i] stores the minimum r_idx for a triplet starting exactly at i.
    // We need to propagate this information.
    // If min_r_for_l[i] is valid (i.e., < n+1), then for any l_idx < i,
    // min_r_for_l[l_idx] should be at most min_r_for_l[i].
    // This is because if a triplet exists starting at i, it also exists for any l_idx < i.
    // So, we can iterate backwards to find the true minimum r_idx for each l_idx.
    for (int i = n - 2; i >= 0; --i) { // Iterate from n-2 down to 0
        min_r_for_l[i] = std::min(min_r_for_l[i], min_r_for_l[i + 1]);
    }

    long long count = 0;
    for (int l_idx = 0; l_idx < n; ++l_idx) {
        if (min_r_for_l[l_idx] < n) { // If there is at least one triplet for this l_idx
            // The minimum r_idx that contains a triplet for this l_idx is min_r_for_l[l_idx].
            // Any r_idx from min_r_for_l[l_idx] to n-1 (inclusive) will also contain a triplet.
            // Number of such r_idx values is (n-1) - min_r_for_l[l_idx] + 1.
            count += (n - 1) - min_r_for_l[l_idx] + 1;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

