// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise
bool apply_median_smoothing(std::vector<int>& a) {
    int n = a.size();
    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        return false;
    }

    std::vector<int> b = a;
    bool changed = false;

    // b_1 = a_1 and b_n = a_n are handled by copying a to b initially

    for (int i = 1; i < n - 1; ++i) { // i corresponds to a_i, so indices a[i-1], a[i], a[i+1]
        // Median of a[i-1], a[i], a[i+1]
        // For 0s and 1s, this is equivalent to:
        // If a[i-1] == a[i+1], then b[i] = a[i-1] (or a[i+1])
        // If a[i-1] != a[i+1], then b[i] = a[i]
        // This is incorrect. The rule is:
        // If a[i-1] == a[i+1], then b[i] = a[i-1] (which is also a[i+1]).
        // If a[i-1] != a[i+1], then b[i] = a[i].
        // Example: 0 1 0 -> median is 0. Here a[i-1]=0, a[i+1]=0, so b[i]=0.
        // Example: 1 0 1 -> median is 1. Here a[i-1]=1, a[i+1]=1, so b[i]=1.
        // Example: 0 1 1 -> median is 1. Here a[i-1]=0, a[i+1]=1, so b[i]=a[i]=1.
        // Example: 1 0 0 -> median is 0. Here a[i-1]=1, a[i+1]=0, so b[i]=a[i]=0.

        // The correct median logic for 0s and 1s:
        // If a[i-1] == a[i+1], then b[i] = a[i-1] (or a[i+1]).
        // If a[i-1] != a[i+1], then b[i] = a[i].
        // This is equivalent to: b[i] = (a[i-1] + a[i] + a[i+1] >= 2) ? 1 : 0;
        // Or, more simply, b[i] = a[i-1] == a[i+1] ? a[i-1] : a[i];

        int median_val;
        if (a[i-1] == a[i+1]) {
            median_val = a[i-1];
        } else {
            median_val = a[i];
        }

        if (b[i] != median_val) {
            b[i] = median_val;
            changed = true;
        }
    }

    a = b;
    return changed;
}

