    long long low = 0;
    // A loose upper bound for T. Max possible distance between any p_i and h_i.
    // Or simply max(p_m, h_n) - min(p_1, h_1)
    long long high = std::max(p.back(), h.back()) - std::min(p[0], h[0]);
