    high = std::max(high, p.back() - h[0]); // Consider p_m and h_1
    high = std::max(high, h.back() - p[0]); // Consider h_n and p_1
    high = std::max(high, 0LL); // Ensure high is non-negative
    high += 1; // Add a small buffer, or just use a very large number like 2e10

    long long ans = high; // Initialize with a value that is definitely achievable or an upper bound

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

